pub const ExternalStdio = enum {
    capture,
    capture_stdout,
    /// Externals write to the shell's stdout and stderr but read script
    /// input, not the terminal. Used for the last stage of an interactive
    /// pipeline, where stdin is the pipe but output belongs to the tty.
    inherit_output,
    inherit,
};

pub const ExecuteOptions = struct {
    io: ?std.Io = null,
    allow_external: bool = false,
    features: compat.Features = .{},
    external_stdio: ExternalStdio = .capture,
    interactive: bool = false,
    foreground_terminal: bool = true,
    cancel: ?*completion.CancellationToken = null,
    arg_zero: []const u8 = "rush",
    source_path: ?[]const u8 = null,
    suppress_functions: bool = false,
    suppress_special_builtin_properties: bool = false,
    suppress_errexit: bool = false,
    ignore_errexit: bool = false,
    force_noninteractive_error_consequences: bool = false,
    default_path_lookup: bool = false,
    verbose_input_echo: bool = true,
    alias_timing_chunks: bool = true,
    completion_provider_only: bool = false,
};

const posix_shell_path = "/bin/sh";

const ExternalSpawnOptions = struct {
    argv: []const []const u8,
    environ_map: *const std.process.Environ.Map,
    stdin: std.process.SpawnOptions.StdIo = .inherit,
    stdout: std.process.SpawnOptions.StdIo = .inherit,
    stderr: std.process.SpawnOptions.StdIo = .inherit,
    pgid: ?std.posix.pid_t = null,
};

const PipelineStageStdin = struct {
    active: bool = false,
    file: ?std.Io.File = null,
};

threadlocal var pipeline_stage_stdin: PipelineStageStdin = .{};

const PipelineStageStdinGuard = struct {
    prior: PipelineStageStdin,

    fn restore(self: PipelineStageStdinGuard) void {
        pipeline_stage_stdin = self.prior;
    }
};

fn pushPipelineStageStdin(file: ?std.Io.File) PipelineStageStdinGuard {
    const guard: PipelineStageStdinGuard = .{ .prior = pipeline_stage_stdin };
    pipeline_stage_stdin = .{ .active = true, .file = file };
    return guard;
}

fn suspendPipelineStageStdin() PipelineStageStdinGuard {
    const guard: PipelineStageStdinGuard = .{ .prior = pipeline_stage_stdin };
    pipeline_stage_stdin = .{};
    return guard;
}

fn checkCanceled(options: ExecuteOptions) !void {
    if (options.cancel) |cancel| if (cancel.isCanceled()) return error.Canceled;
}

fn registerCancelableChild(options: ExecuteOptions, child: std.process.Child, process_group: bool) ?i32 {
    const cancel = options.cancel orelse return null;
    const pid = child.id orelse return null;
    const numeric_pid: i32 = @intCast(pid);
    if (process_group) cancel.registerProcessGroup(numeric_pid) else cancel.registerChild(numeric_pid);
    return numeric_pid;
}

fn unregisterCancelableChild(options: ExecuteOptions, pid: ?i32) void {
    const cancel = options.cancel orelse return;
    cancel.unregisterChild(pid orelse return);
}

fn completionCancelProcessGroup(options: ExecuteOptions) bool {
    return options.cancel != null and !options.interactive and options.external_stdio != .inherit;
}

fn cancellableExternalPgid(options: ExecuteOptions, requested_pgid: ?std.posix.pid_t) ?std.posix.pid_t {
    return requested_pgid orelse if (completionCancelProcessGroup(options)) 0 else null;
}

pub const ShellOptions = struct {
    pipefail: bool = false,
    emacs: bool = true,
    ignoreeof: bool = false,
    vi: bool = false,
    monitor: bool = false,
    noglob: bool = false,
    noclobber: bool = false,
    noexec: bool = false,
    notify: bool = false,
    nounset: bool = false,
    errexit: bool = false,
    xtrace: bool = false,
    verbose: bool = false,
    allexport: bool = false,
};

const shell_option_flags_max = 10;

fn shellOptionFlags(options: ShellOptions, buffer: *[shell_option_flags_max]u8) []const u8 {
    var len: usize = 0;
    if (options.allexport) {
        buffer[len] = 'a';
        len += 1;
    }
    if (options.notify) {
        buffer[len] = 'b';
        len += 1;
    }
    if (options.errexit) {
        buffer[len] = 'e';
        len += 1;
    }
    if (options.monitor) {
        buffer[len] = 'm';
        len += 1;
    }
    if (options.noclobber) {
        buffer[len] = 'C';
        len += 1;
    }
    if (options.noglob) {
        buffer[len] = 'f';
        len += 1;
    }
    if (options.noexec) {
        buffer[len] = 'n';
        len += 1;
    }
    if (options.nounset) {
        buffer[len] = 'u';
        len += 1;
    }
    if (options.verbose) {
        buffer[len] = 'v';
        len += 1;
    }
    if (options.xtrace) {
        buffer[len] = 'x';
        len += 1;
    }
    return buffer[0..len];
}

pub fn applyShellOptionShort(options: *ShellOptions, spelling: []const u8) bool {
    if (spelling.len < 2) return false;
    if (spelling[0] != '-' and spelling[0] != '+') return false;
    for (spelling[1..]) |option| switch (option) {
        'a', 'b', 'e', 'f', 'h', 'm', 'n', 'u', 'x', 'v', 'C' => {},
        else => return false,
    };

    const enabled = spelling[0] == '-';
    for (spelling[1..]) |option| switch (option) {
        'a' => options.allexport = enabled,
        'b' => options.notify = enabled,
        'e' => options.errexit = enabled,
        'f' => options.noglob = enabled,
        'h' => {},
        'm' => options.monitor = enabled,
        'n' => options.noexec = enabled,
        'u' => options.nounset = enabled,
        'x' => options.xtrace = enabled,
        'v' => options.verbose = enabled,
        'C' => options.noclobber = enabled,
        else => unreachable,
    };
    return true;
}

pub fn applyShellOptionName(options: *ShellOptions, name: []const u8, enabled: bool) bool {
    if (std.mem.eql(u8, name, "pipefail")) {
        options.pipefail = enabled;
        return true;
    }
    if (std.mem.eql(u8, name, "emacs")) {
        options.emacs = enabled;
        if (enabled) options.vi = false;
        return true;
    }
    if (std.mem.eql(u8, name, "ignoreeof")) {
        options.ignoreeof = enabled;
        return true;
    }
    if (std.mem.eql(u8, name, "vi")) {
        options.vi = enabled;
        options.emacs = !enabled;
        return true;
    }
    if (std.mem.eql(u8, name, "monitor")) {
        options.monitor = enabled;
        return true;
    }
    if (std.mem.eql(u8, name, "allexport")) {
        options.allexport = enabled;
        return true;
    }
    if (std.mem.eql(u8, name, "noglob")) {
        options.noglob = enabled;
        return true;
    }
    if (std.mem.eql(u8, name, "noclobber")) {
        options.noclobber = enabled;
        return true;
    }
    if (std.mem.eql(u8, name, "noexec")) {
        options.noexec = enabled;
        return true;
    }
    if (std.mem.eql(u8, name, "notify")) {
        options.notify = enabled;
        return true;
    }
    if (std.mem.eql(u8, name, "nolog")) {
        return true;
    }
    if (std.mem.eql(u8, name, "nounset")) {
        options.nounset = enabled;
        return true;
    }
    if (std.mem.eql(u8, name, "errexit")) {
        options.errexit = enabled;
        return true;
    }
    if (std.mem.eql(u8, name, "xtrace")) {
        options.xtrace = enabled;
        return true;
    }
    if (std.mem.eql(u8, name, "verbose")) {
        options.verbose = enabled;
        return true;
    }
    return false;
}

