fn appendRootCommandCandidate(
    allocator: std.mem.Allocator,
    builder: *CompletionBuilder,
    seen: *std.StringHashMapUnmanaged(void),
    name: []const u8,
    kind: completion.Kind,
    description: []const u8,
    context: CompletionEvalContext,
) !void {
    if (completion.fuzzyMatchRank(name, context.prefix) == null) return;
    if (seen.contains(name)) return;
    const seen_name = try allocator.dupe(u8, name);
    errdefer allocator.free(seen_name);
    try seen.put(allocator, seen_name, {});
    try builder.appendCandidate(allocator, .{
        .value = name,
        .description = description,
        .kind = kind,
        .replace_start = context.replace_start,
        .replace_end = context.replace_end,
    });
}

fn freeCompletionRule(allocator: std.mem.Allocator, rule: completion.Rule) void {
    allocator.free(rule.root);
    for (rule.path) |segment| allocator.free(segment);
    allocator.free(rule.path);
    if (rule.value) |value| allocator.free(value);
    if (rule.option.long) |long| allocator.free(long);
    if (rule.option.short) |short| allocator.free(short);
    if (rule.option.argument) |argument| allocator.free(argument);
    if (rule.option.exclusive_group) |group| allocator.free(group);
    if (rule.argument.state) |state| allocator.free(state);
    if (rule.argument.after_state) |state| allocator.free(state);
    if (rule.argument.after_value) |value| allocator.free(value);
    if (rule.description) |description| allocator.free(description);
    if (rule.source.manifest_path) |path| allocator.free(path);
    if (rule.source.companion_path) |path| allocator.free(path);
}

const MatchedCompletionOption = struct {
    takes_value: bool,
    attached_value: bool,
    name: []const u8,
    key: []const u8,
    spelling: []const u8,
    value: ?[]const u8 = null,
    exclusive_group: ?[]const u8 = null,
    repeatable: bool = false,
    terminates_options: bool = false,
};

const ShortOptionCluster = struct {
    valid: bool,
    takes_next_value: bool = false,
    unknown_offset: ?usize = null,
};

const AttachedCompletionOptionValue = struct {
    name: []const u8,
    spelling: []const u8,
    value_offset: usize,
};

fn attachedCompletionOptionValue(rules: []const completion.Rule, root: []const u8, path: []const []const u8, word: []const u8) ?AttachedCompletionOptionValue {
    if (attachedLongCompletionOptionValue(rules, root, path, word)) |attached| return attached;
    if (attachedShortCompletionOptionValue(rules, root, path, word)) |attached| return attached;
    return null;
}

fn attachedLongCompletionOptionValue(rules: []const completion.Rule, root: []const u8, path: []const []const u8, word: []const u8) ?AttachedCompletionOptionValue {
    const equals_index = std.mem.indexOfScalar(u8, word, '=') orelse return null;
    if (equals_index == 0) return null;
    const spelling = word[0..equals_index];
    const matched = findCompletionOption(rules, root, path, spelling) orelse return null;
    if (!matched.takes_value) return null;
    return .{
        .name = matched.name,
        .spelling = spelling,
        .value_offset = equals_index + 1,
    };
}

fn attachedShortCompletionOptionValue(rules: []const completion.Rule, root: []const u8, path: []const []const u8, word: []const u8) ?AttachedCompletionOptionValue {
    if (!isShortOptionCluster(word)) return null;
    var index: usize = 1;
    while (index < word.len) : (index += 1) {
        const matched = findShortCompletionOption(rules, root, path, word[index]) orelse return null;
        if (matched.takes_value) {
            if (index + 1 >= word.len) return null;
            return .{
                .name = matched.name,
                .spelling = word[0 .. index + 1],
                .value_offset = index + 1,
            };
        }
    }
    return null;
}

fn findCompletionOption(rules: []const completion.Rule, root: []const u8, path: []const []const u8, word: []const u8) ?MatchedCompletionOption {
    for (rules) |rule| {
        if ((rule.kind != .option and rule.kind != .dynamic_option_value) or !completionOptionRuleContextAppliesToPath(rule, root, path)) continue;
        const takes_value = rule.option.argument != null or rule.kind == .dynamic_option_value;
        const key = completionOptionKey(rule.option) orelse continue;
        if (rule.option.long) |long| {
            var spelling_buffer: [256]u8 = undefined;
            const spelling = std.fmt.bufPrint(&spelling_buffer, "--{s}", .{long}) catch return null;
            if (std.mem.eql(u8, word, spelling)) return .{ .takes_value = takes_value, .attached_value = false, .name = long, .key = key, .spelling = word, .exclusive_group = rule.option.exclusive_group, .repeatable = rule.option.repeatable, .terminates_options = rule.option.terminates_options };
            if (takes_value and std.mem.startsWith(u8, word, spelling) and word.len > spelling.len and word[spelling.len] == '=') {
                return .{ .takes_value = true, .attached_value = true, .name = long, .key = key, .spelling = word[0..spelling.len], .value = word[spelling.len + 1 ..], .exclusive_group = rule.option.exclusive_group, .repeatable = rule.option.repeatable, .terminates_options = rule.option.terminates_options };
            }
        }
        if (rule.option.short) |short| {
            var spelling_buffer: [32]u8 = undefined;
            const spelling = std.fmt.bufPrint(&spelling_buffer, "-{s}", .{short}) catch return null;
            if (std.mem.eql(u8, word, spelling)) return .{ .takes_value = takes_value, .attached_value = false, .name = short, .key = key, .spelling = word, .exclusive_group = rule.option.exclusive_group, .repeatable = rule.option.repeatable, .terminates_options = rule.option.terminates_options };
        }
    }
    return null;
}

fn findShortCompletionOption(rules: []const completion.Rule, root: []const u8, path: []const []const u8, short: u8) ?MatchedCompletionOption {
    for (rules) |rule| {
        if ((rule.kind != .option and rule.kind != .dynamic_option_value) or !completionOptionRuleContextAppliesToPath(rule, root, path)) continue;
        const option_short = rule.option.short orelse continue;
        if (option_short.len != 1 or option_short[0] != short) continue;
        const takes_value = rule.option.argument != null or rule.kind == .dynamic_option_value;
        const key = completionOptionKey(rule.option) orelse option_short;
        return .{ .takes_value = takes_value, .attached_value = false, .name = option_short, .key = key, .spelling = option_short, .exclusive_group = rule.option.exclusive_group, .repeatable = rule.option.repeatable, .terminates_options = rule.option.terminates_options };
    }
    return null;
}

fn analyzeShortOptionCluster(rules: []const completion.Rule, root: []const u8, path: []const []const u8, word: []const u8) ?ShortOptionCluster {
    if (!isShortOptionCluster(word)) return null;
    var index: usize = 1;
    while (index < word.len) : (index += 1) {
        const matched = findShortCompletionOption(rules, root, path, word[index]) orelse return .{ .valid = false, .unknown_offset = index };
        if (matched.takes_value) {
            return .{ .valid = true, .takes_next_value = index + 1 == word.len };
        }
    }
    return .{ .valid = true };
}

fn shortCompletionClusterTerminatesOptions(rules: []const completion.Rule, root: []const u8, path: []const []const u8, word: []const u8) bool {
    if (!isShortOptionCluster(word)) return false;
    var index: usize = 1;
    while (index < word.len) : (index += 1) {
        const matched = findShortCompletionOption(rules, root, path, word[index]) orelse return false;
        if (matched.terminates_options) return true;
        if (matched.takes_value) return false;
    }
    return false;
}

fn findCompletionSubcommand(rules: []const completion.Rule, root: []const u8, path: []const []const u8, word: []const u8) bool {
    for (rules) |rule| {
        if (rule.kind == .subcommand and completionRuleContextMatches(rule, root, path)) {
            if (rule.value) |value| if (std.mem.eql(u8, value, word)) return true;
        }
    }
    return false;
}

fn completionContextHasSubcommands(rules: []const completion.Rule, root: []const u8, path: []const []const u8) bool {
    for (rules) |rule| {
        if (rule.kind == .subcommand and completionRuleContextMatches(rule, root, path)) return true;
    }
    return false;
}

fn completionContextHasOptions(rules: []const completion.Rule, root: []const u8, path: []const []const u8) bool {
    for (rules) |rule| {
        if ((rule.kind == .option or rule.kind == .dynamic_option_value) and completionOptionRuleContextAppliesToPath(rule, root, path)) return true;
    }
    return false;
}

fn completionSubcommandPrefixMatches(rules: []const completion.Rule, root: []const u8, path: []const []const u8, prefix: []const u8) bool {
    for (rules) |rule| {
        if (rule.kind != .subcommand or !completionRuleContextMatches(rule, root, path)) continue;
        if (rule.value) |value| if (std.mem.startsWith(u8, value, prefix)) return true;
    }
    return false;
}

fn completionOptionPrefixMatches(rules: []const completion.Rule, root: []const u8, path: []const []const u8, prefix: []const u8) bool {
    for (rules) |rule| {
        if (rule.kind != .option or !completionOptionRuleContextAppliesToPath(rule, root, path)) continue;
        if (rule.option.long) |long| {
            var spelling_buffer: [256]u8 = undefined;
            const spelling = std.fmt.bufPrint(&spelling_buffer, "--{s}", .{long}) catch continue;
            if (std.mem.startsWith(u8, spelling, prefix)) return true;
        }
        if (rule.option.short) |short| {
            var spelling_buffer: [32]u8 = undefined;
            const spelling = std.fmt.bufPrint(&spelling_buffer, "-{s}", .{short}) catch continue;
            if (std.mem.startsWith(u8, spelling, prefix)) return true;
        }
    }
    return false;
}

pub fn completionOptionSuppressionForOption(context: CompletionSemanticContext, option: completion.Option) ?CompletionOptionSuppression {
    const key = completionOptionKey(option);
    if (key != null and !option.repeatable) {
        for (context.parsed_options) |parsed| {
            if (std.mem.eql(u8, parsed.key, key.?)) return .{ .reason = .already_present, .by = parsed.spelling };
        }
    }
    const group = option.exclusive_group orelse return null;
    for (context.parsed_options) |parsed| {
        const parsed_group = parsed.exclusive_group orelse continue;
        if (key != null and option.repeatable and std.mem.eql(u8, parsed.key, key.?)) continue;
        if (std.mem.eql(u8, parsed_group, group)) return .{ .reason = .exclusive_group, .by = parsed.spelling, .group = group };
    }
    return null;
}

pub fn completionOptionCandidateSuppression(rules: []const completion.Rule, context: CompletionSemanticContext, candidate: completion.Candidate) ?CompletionOptionSuppression {
    if (candidate.kind != .option) return null;
    const option = candidate.option orelse return null;
    const inherited_metadata = completionRuleOptionMetadataForCandidate(rules, context.root, context.path, candidate);
    var inherited_option = option;
    if (inherited_metadata) |metadata| {
        if (inherited_option.exclusive_group == null) inherited_option.exclusive_group = metadata.exclusive_group;
        inherited_option.repeatable = inherited_option.repeatable or metadata.repeatable;
        inherited_option.terminates_options = inherited_option.terminates_options or metadata.terminates_options;
    }
    return completionOptionSuppressionForOption(context, inherited_option);
}

const CompletionOptionMetadata = struct {
    exclusive_group: ?[]const u8 = null,
    repeatable: bool = false,
    terminates_options: bool = false,
};

fn completionRuleOptionMetadataForCandidate(rules: []const completion.Rule, root: []const u8, path: []const []const u8, candidate: completion.Candidate) ?CompletionOptionMetadata {
    for (rules) |rule| {
        if (rule.kind != .option or !completionOptionRuleContextAppliesToPath(rule, root, path)) continue;
        if (completionOptionSpellingMatches(rule.option, candidate.value)) return .{
            .exclusive_group = rule.option.exclusive_group,
            .repeatable = rule.option.repeatable,
            .terminates_options = rule.option.terminates_options,
        };
    }
    return null;
}

fn completionOptionKey(option: completion.Option) ?[]const u8 {
    if (option.long) |long| return long;
    if (option.short) |short| return short;
    return null;
}

fn completionOptionSpellingMatches(option: completion.Option, value: []const u8) bool {
    if (option.long) |long| {
        var spelling_buffer: [256]u8 = undefined;
        const spelling = std.fmt.bufPrint(&spelling_buffer, "--{s}", .{long}) catch return false;
        if (std.mem.eql(u8, spelling, value)) return true;
    }
    if (option.short) |short| {
        var spelling_buffer: [32]u8 = undefined;
        const spelling = std.fmt.bufPrint(&spelling_buffer, "-{s}", .{short}) catch return false;
        if (std.mem.eql(u8, spelling, value)) return true;
    }
    return false;
}

fn appendParsedCompletionOption(allocator: std.mem.Allocator, parsed_options: *std.ArrayList(CompletionParsedOption), matched: MatchedCompletionOption) !void {
    try parsed_options.append(allocator, .{
        .spelling = matched.spelling,
        .name = matched.name,
        .key = matched.key,
        .value = matched.value,
        .exclusive_group = matched.exclusive_group,
        .repeatable = matched.repeatable,
        .terminates_options = matched.terminates_options,
    });
}

fn setLastParsedCompletionOptionValue(parsed_options: *std.ArrayList(CompletionParsedOption), value: []const u8) void {
    if (parsed_options.items.len == 0) return;
    parsed_options.items[parsed_options.items.len - 1].value = value;
}

fn matchedCompletionOptionSuppression(parsed_options: []const CompletionParsedOption, matched: MatchedCompletionOption) ?CompletionOptionSuppression {
    if (!matched.repeatable) {
        for (parsed_options) |parsed| {
            if (std.mem.eql(u8, parsed.key, matched.key)) return .{ .reason = .already_present, .by = parsed.spelling };
        }
    }
    const group = matched.exclusive_group orelse return null;
    for (parsed_options) |parsed| {
        const parsed_group = parsed.exclusive_group orelse continue;
        if (matched.repeatable and std.mem.eql(u8, parsed.key, matched.key)) continue;
        if (std.mem.eql(u8, parsed_group, group)) return .{ .reason = .exclusive_group, .by = parsed.spelling, .group = group };
    }
    return null;
}

fn completionDiagnosticKindForOptionSuppression(suppression: CompletionOptionSuppression) CompletionDiagnosticKind {
    return switch (suppression.reason) {
        .already_present => .repeated_option,
        .exclusive_group => .conflicting_option,
    };
}

fn completionDiagnosticMessageForOptionSuppression(suppression: CompletionOptionSuppression) []const u8 {
    return switch (suppression.reason) {
        .already_present => "option may not be repeated",
        .exclusive_group => "option conflicts with previous option",
    };
}

fn appendShortCompletionClusterParsedOptions(allocator: std.mem.Allocator, parsed_options: *std.ArrayList(CompletionParsedOption), rules: []const completion.Rule, root: []const u8, path: []const []const u8, word: []const u8) !?CompletionOptionSuppression {
    if (!isShortOptionCluster(word)) return null;
    var first_suppression: ?CompletionOptionSuppression = null;
    var index: usize = 1;
    while (index < word.len) : (index += 1) {
        const matched = findShortCompletionOption(rules, root, path, word[index]) orelse return first_suppression;
        if (first_suppression == null) first_suppression = matchedCompletionOptionSuppression(parsed_options.items, matched);
        try parsed_options.append(allocator, .{
            .spelling = word,
            .name = matched.name,
            .key = matched.key,
            .value = if (matched.takes_value and index + 1 < word.len) word[index + 1 ..] else null,
            .exclusive_group = matched.exclusive_group,
            .repeatable = matched.repeatable,
            .terminates_options = matched.terminates_options,
        });
        if (matched.takes_value) return first_suppression;
    }
    return first_suppression;
}

fn builtinCompletionSawWord(context: CompletionSemanticContext, word: []const u8) bool {
    if (std.mem.eql(u8, context.previous, word)) return true;
    for (context.path) |segment| {
        if (std.mem.eql(u8, segment, word)) return true;
    }
    return false;
}

fn completionRuleContextMatches(rule: completion.Rule, root: []const u8, path: []const []const u8) bool {
    if (!std.mem.eql(u8, rule.root, root) or rule.path.len != path.len) return false;
    for (rule.path, path) |expected, actual| {
        if (!std.mem.eql(u8, expected, actual)) return false;
    }
    return true;
}

fn completionRuleContextAppliesToPath(rule: completion.Rule, root: []const u8, path: []const []const u8) bool {
    if (!std.mem.eql(u8, rule.root, root) or rule.path.len > path.len) return false;
    for (rule.path, path[0..rule.path.len]) |expected, actual| {
        if (!std.mem.eql(u8, expected, actual)) return false;
    }
    return true;
}

fn completionOptionRuleContextAppliesToPath(rule: completion.Rule, root: []const u8, path: []const []const u8) bool {
    return if (rule.option.inherit)
        completionRuleContextAppliesToPath(rule, root, path)
    else
        completionRuleContextMatches(rule, root, path);
}

fn completionDynamicRuleMatches(rule: completion.Rule, context: CompletionSemanticContext) bool {
    return switch (rule.kind) {
        .dynamic_subcommands => context.position == .subcommand and completionRuleContextMatches(rule, context.root, context.path),
        .dynamic_options => context.position == .option and completionRuleContextAppliesToPath(rule, context.root, context.path),
        .dynamic_argument => completionArgumentRuleMatches(rule, context),
        .dynamic_option_value => context.position == .option_value and completionOptionRuleContextAppliesToPath(rule, context.root, context.path) and completionOptionValueMatches(rule, context.option_value),
        else => false,
    };
}

fn completionArgumentRuleMatches(rule: completion.Rule, context: CompletionSemanticContext) bool {
    if (context.position != .subcommand and context.position != .argument) return false;
    if (!completionRuleContextMatches(rule, context.root, context.path)) return false;
    if (rule.argument.state) |state| {
        const active_state = context.argument_state orelse return false;
        return std.mem.eql(u8, state, active_state);
    }
    if (rule.argument.index) |index| {
        return context.argument_index == index or (rule.argument.repeatable and context.argument_index >= index);
    }
    return true;
}

fn completionActiveArgumentState(rules: []const completion.Rule, root: []const u8, path: []const []const u8, argument_index: usize, previous_state: ?[]const u8, previous_argument: []const u8) ?[]const u8 {
    for (rules, 0..) |rule, rule_index| {
        const state = completionArgumentStateForRule(rules, root, path, rule, rule_index) orelse continue;
        if (completionExplicitArgumentStateMatches(rule.argument, state, argument_index, previous_state, previous_argument)) return state;
    }

    var implicit_index: usize = 0;
    for (rules, 0..) |rule, rule_index| {
        const state = completionArgumentStateForRule(rules, root, path, rule, rule_index) orelse continue;
        if (completionArgumentStateHasExplicitTransition(rule.argument)) continue;
        if (argument_index == implicit_index or (rule.argument.repeatable and argument_index >= implicit_index)) return state;
        implicit_index += 1;
    }
    return null;
}

fn completionArgumentStateForRule(rules: []const completion.Rule, root: []const u8, path: []const []const u8, rule: completion.Rule, rule_index: usize) ?[]const u8 {
    if (rule.kind != .dynamic_argument or !completionRuleContextMatches(rule, root, path)) return null;
    const state = rule.argument.state orelse return null;
    for (rules[0..rule_index]) |previous| {
        if (previous.kind != .dynamic_argument or !completionRuleContextMatches(previous, root, path)) continue;
        if (previous.argument.state) |previous_state| {
            if (std.mem.eql(u8, previous_state, state)) return null;
        }
    }
    return state;
}

fn completionArgumentStateHasExplicitTransition(argument: completion.Argument) bool {
    return argument.index != null or argument.after_state != null or argument.after_value != null;
}

fn completionExplicitArgumentStateMatches(argument: completion.Argument, state: []const u8, argument_index: usize, previous_state: ?[]const u8, previous_argument: []const u8) bool {
    if (argument.index) |index| {
        if (argument_index == index or (argument.repeatable and argument_index >= index)) return true;
    }
    if (argument.after_state) |after_state| {
        if (previous_state) |active| {
            if (std.mem.eql(u8, active, after_state) or (argument.repeatable and std.mem.eql(u8, active, state))) return true;
        }
    }
    if (argument.after_value) |after_value| {
        if (std.mem.eql(u8, previous_argument, after_value)) return true;
        if (argument.repeatable) {
            if (previous_state) |active| if (std.mem.eql(u8, active, state)) return true;
        }
    }
    return false;
}

fn completionOptionValueMatches(rule: completion.Rule, option_value: ?CompletionOptionValue) bool {
    const active = option_value orelse return false;
    if (rule.option.long) |long| if (std.mem.eql(u8, active.name, long)) return true;
    if (rule.option.short) |short| if (std.mem.eql(u8, active.name, short)) return true;
    return rule.option.long == null and rule.option.short == null;
}

fn completionValueGrammarForOption(rules: []const completion.Rule, root: []const u8, path: []const []const u8, option_value: CompletionOptionValue) completion.ValueGrammar {
    for (rules) |rule| {
        if (rule.value_grammar.isEmpty()) continue;
        if (rule.kind != .option and rule.kind != .dynamic_option_value) continue;
        if (!completionOptionRuleContextAppliesToPath(rule, root, path)) continue;
        if (!completionOptionValueMatches(rule, option_value)) continue;
        return rule.value_grammar;
    }
    return .{};
}

const ActiveCompletionValueSegment = struct {
    prefix: []const u8,
    replace_start: usize,
    context: CompletionValueSegment,
};

fn activeCompletionValueSegment(prefix: []const u8, replace_start: usize, grammar: completion.ValueGrammar) ActiveCompletionValueSegment {
    var segment_start: usize = 0;
    if (grammar.list_separator) |separator| {
        if (std.mem.findScalarLast(u8, prefix, separator)) |index| segment_start = index + 1;
    }

    var item = prefix[segment_start..];
    var segment = item;
    var segment_replace_start = replace_start + segment_start;
    if (grammar.key_prefix) |key_prefix| {
        if (item.len != 0 and item[0] == key_prefix) {
            item = item[1..];
            segment = item;
            segment_replace_start += 1;
        }
    }
    var position: CompletionValuePosition = if (grammar.key_value_separator == null) .item else .key;
    var key: []const u8 = "";
    if (grammar.key_value_separator) |separator| {
        if (std.mem.indexOfScalar(u8, item, separator)) |index| {
            position = .value;
            key = item[0..index];
            segment = item[index + 1 ..];
            segment_replace_start += index + 1;
        }
    }

    return .{
        .prefix = segment,
        .replace_start = segment_replace_start,
        .context = .{
            .segment = segment,
            .list_separator = grammar.list_separator,
            .key_value_separator = grammar.key_value_separator,
            .position = position,
            .key = key,
        },
    };
}

fn completionEvalContextWithValueGrammar(context: CompletionEvalContext, grammar: completion.ValueGrammar) CompletionEvalContext {
    if (grammar.isEmpty()) return context;
    var segmented = context;
    const active = activeCompletionValueSegment(context.prefix, context.replace_start, grammar);
    segmented.prefix = active.prefix;
    segmented.replace_start = active.replace_start;
    segmented.value_segment = active.context;
    return segmented;
}

// Completion candidates are deduplicated by the edit they would apply:
// replacement span plus inserted value. The first source wins so metadata stays
// deterministic across static and dynamic structured rules.
fn completionCandidateIdentityMatches(a: completion.Candidate, b: completion.Candidate) bool {
    return a.replace_start == b.replace_start and
        a.replace_end == b.replace_end and
        std.mem.eql(u8, a.value, b.value);
}

fn completionCommandPath(allocator: std.mem.Allocator, context: CompletionSemanticContext) ![]const u8 {
    if (context.root.len == 0) return allocator.alloc(u8, 0);
    var path: std.ArrayList(u8) = .empty;
    errdefer path.deinit(allocator);
    try path.appendSlice(allocator, context.root);
    for (context.path) |segment| {
        try path.append(allocator, ' ');
        try path.appendSlice(allocator, segment);
    }
    return path.toOwnedSlice(allocator);
}

fn isOptionLike(word: []const u8) bool {
    return word.len > 1 and word[0] == '-';
}

fn isShortOptionCluster(word: []const u8) bool {
    return word.len > 2 and word[0] == '-' and word[1] != '-';
}

fn deinitSeenCompletionNames(allocator: std.mem.Allocator, seen: *std.StringHashMapUnmanaged(void)) void {
    var iter = seen.iterator();
    while (iter.next()) |entry| allocator.free(entry.key_ptr.*);
    seen.deinit(allocator);
}

const PromptStyle = struct {
    fg: vaxis.Color = .default,
    bg: vaxis.Color = .default,
    bold: bool = false,
    dim: bool = false,
    italic: bool = false,
    underline: bool = false,
    blink: bool = false,
    reverse: bool = false,
    strikethrough: bool = false,

    fn hasStyle(self: PromptStyle) bool {
        return self.fg != .default or
            self.bg != .default or
            self.bold or
            self.dim or
            self.italic or
            self.underline or
            self.blink or
            self.reverse or
            self.strikethrough;
    }
};

pub const LoopControlKind = enum {
    break_loop,
    continue_loop,
};

pub const LoopControl = struct {
    kind: LoopControlKind,
    levels: usize,
};

pub const PositionalParams = struct {
    params: [][]const u8 = &.{},
    count: []const u8 = "0",
    joined: []const u8 = "",
    owned: bool = false,

    pub fn set(self: *PositionalParams, allocator: std.mem.Allocator, args: []const []const u8) !void {
        self.deinit(allocator);
        var params = try allocator.alloc([]const u8, args.len);
        errdefer allocator.free(params);
        var initialized: usize = 0;
        errdefer for (params[0..initialized]) |param| allocator.free(param);
        for (args, 0..) |arg, index| {
            params[index] = try allocator.dupe(u8, arg);
            initialized += 1;
        }
        const count = try std.fmt.allocPrint(allocator, "{d}", .{args.len});
        errdefer allocator.free(count);
        const joined = try joinParams(allocator, params);
        errdefer allocator.free(joined);
        self.* = .{ .params = params, .count = count, .joined = joined, .owned = true };
    }

    pub fn rebuildDerived(self: *PositionalParams, allocator: std.mem.Allocator) !void {
        if (self.owned) {
            allocator.free(self.count);
            allocator.free(self.joined);
        }
        self.count = try std.fmt.allocPrint(allocator, "{d}", .{self.params.len});
        self.joined = try joinParams(allocator, self.params);
        self.owned = true;
    }

    pub fn deinit(self: *PositionalParams, allocator: std.mem.Allocator) void {
        if (self.owned) {
            for (self.params) |param| allocator.free(param);
            allocator.free(self.params);
            allocator.free(self.count);
            allocator.free(self.joined);
        }
        self.* = .{};
    }
};

pub const CallFrame = struct {
    positionals: PositionalParams = .{},

    pub fn deinit(self: *CallFrame, allocator: std.mem.Allocator) void {
        self.positionals.deinit(allocator);
        self.* = undefined;
    }
};

const TrapSignalAction = struct {
    signal: std.posix.SIG,
    previous: std.posix.Sigaction,
};

pub const FunctionValue = struct {
    body: []const u8,
    program: ir.Program,
    redirections: []ir.Redirection,

    pub fn deinit(self: *FunctionValue, allocator: std.mem.Allocator) void {
        allocator.free(self.body);
        self.program.deinit();
        freeFunctionValueRedirections(allocator, self.redirections);
        self.* = undefined;
    }
};

fn freeFunctionValueRedirections(allocator: std.mem.Allocator, redirections: []const ir.Redirection) void {
    for (redirections) |redirection| {
        if (redirection.io_number) |word| freeFunctionValueWord(allocator, word);
        if (redirection.target) |word| freeFunctionValueWord(allocator, word);
        if (redirection.here_doc) |text| allocator.free(text);
    }
    allocator.free(redirections);
}

fn freeFunctionValueWord(allocator: std.mem.Allocator, word: ir.WordRef) void {
    allocator.free(word.raw);
    allocator.free(word.text);
}

pub const BackgroundJob = struct {
    id: usize,
    pid: i64,
    pgrp: ?i64 = null,
    command: []const u8,
    child: std.process.Child,
    state: JobState = .running,
    status: ExitStatus = 0,
    stop_signal: ?u8 = null,
    termination_signal: ?u8 = null,
    saved_termios: ?std.posix.termios = null,
    notified_state: ?JobState = null,
};

pub const JobState = enum {
    running,
    stopped,
    done,
};

const PromptAsyncEntry = struct {
    output: []u8,
    updated_ms: u64 = 0,
    inflight: bool = false,
};

const PromptAsyncSchedule = struct {
    output: []u8,
    should_spawn: bool,
};

const EventHook = struct {
    function: []const u8,
};

const IntervalHook = struct {
    name: []const u8,
    function: []const u8,
    interval_ms: u64,
    last_run_ms: u64 = 0,
};

const PromptAsyncRefresh = struct {
    allocator: std.mem.Allocator,
    owner: *Executor,
    cache_key: []const u8,
    script: []const u8,
    io: std.Io,
    executor: Executor,
    thread: std.Thread = undefined,
    done: std.atomic.Value(bool) = .init(false),

    fn run(self: *PromptAsyncRefresh) void {
        defer self.done.store(true, .release);
        var result = self.executor.executeScriptSlice(self.script, .{
            .io = self.io,
            .allow_external = true,
            .external_stdio = .capture,
            .suppress_errexit = true,
            .arg_zero = self.executor.arg_zero,
        }) catch {
            self.owner.finishPromptAsyncRefreshFailed(self.cache_key);
            return;
        };
        defer result.deinit();
        self.owner.finishPromptAsyncRefresh(self.cache_key, result.stdout, self.io) catch {
            self.owner.finishPromptAsyncRefreshFailed(self.cache_key);
            return;
        };
        if (self.owner.prompt_repaint_handler) |handler| handler.request(handler.context);
    }

    fn deinit(self: *PromptAsyncRefresh) void {
        self.executor.deinit();
        self.allocator.free(self.cache_key);
        self.allocator.free(self.script);
        self.* = undefined;
    }
};

pub const ArrayValue = struct {
    values: std.ArrayList([]const u8) = .empty,

    pub fn deinit(self: *ArrayValue, allocator: std.mem.Allocator) void {
        for (self.values.items) |value| allocator.free(value);
        self.values.deinit(allocator);
        self.* = undefined;
    }
};

pub const Executor = struct {
    allocator: std.mem.Allocator,
    env: std.StringHashMapUnmanaged([]const u8) = .empty,
    exported: std.StringHashMapUnmanaged(void) = .empty,
    readonly: std.StringHashMapUnmanaged(void) = .empty,
    arrays: std.StringHashMapUnmanaged(ArrayValue) = .empty,
    functions: std.StringHashMapUnmanaged(FunctionValue) = .empty,
    aliases: std.StringHashMapUnmanaged([]const u8) = .empty,
    command_hash: std.StringHashMapUnmanaged([]const u8) = .empty,
    abbreviations: std.StringHashMapUnmanaged([]const u8) = .empty,
    traps: std.StringHashMapUnmanaged([]const u8) = .empty,
    trap_signal_actions: std.ArrayList(TrapSignalAction) = .empty,
    ignored_trap_signals_at_entry: u64 = 0,
    event_hooks: std.StringHashMapUnmanaged(std.ArrayList(EventHook)) = .empty,
    interval_hooks: std.ArrayList(IntervalHook) = .empty,
    pending_variable_hooks: std.ArrayList([]const u8) = .empty,
    completion_rules: std.ArrayList(completion.Rule) = .empty,
    completion_generation: u64 = 0,
    completion_provider_diagnostics: std.ArrayList(CompletionProviderDiagnostic) = .empty,
    loaded_completion_scripts: std.StringHashMapUnmanaged(void) = .empty,
    loaded_completion_companions: std.StringHashMapUnmanaged(void) = .empty,
    background_jobs: std.ArrayList(BackgroundJob) = .empty,
    pending_job_notifications: std.ArrayList([]const u8) = .empty,
    next_job_id: usize = 1,
    current_job_id: ?usize = null,
    previous_job_id: ?usize = null,
    open_fds: std.AutoHashMapUnmanaged(std.posix.fd_t, void) = .empty,
    shell_options: ShellOptions = .{},
    global_positionals: PositionalParams = .{},
    call_frames: std.ArrayList(CallFrame) = .empty,
    function_depth: usize = 0,
    source_depth: usize = 0,
    pending_return: ?ExitStatus = null,
    loop_depth: usize = 0,
    pending_loop_control: ?LoopControl = null,
    pending_exit: ?ExitStatus = null,
    execution_depth: usize = 0,
    hook_depth: usize = 0,
    running_exit_trap: bool = false,
    warned_stopped_jobs_on_exit: bool = false,
    arg_zero: []const u8 = "rush",
    last_status_text: [3]u8 = .{ '0', 0, 0 },
    last_status_text_len: usize = 1,
    lineno_text: [32]u8 = .{ '1', 0 } ++ .{0} ** 30,
    lineno_text_len: usize = 1,
    last_command_duration_text: [32]u8 = .{ '0', 0 } ++ .{0} ** 30,
    last_command_duration_text_len: usize = 1,
    pid_text: [32]u8 = undefined,
    pid_text_len: usize = 0,
    last_background_pid_text: [32]u8 = undefined,
    last_background_pid_text_len: usize = 0,
    prompt_builder: ?PromptBuilder = null,
    prompt_refresh_interval_ms: ?u64 = null,
    prompt_repaint_handler: ?PromptRepaintHandler = null,
    prompt_async_mutex: std.atomic.Mutex = .unlocked,
    prompt_async_entries: std.StringHashMapUnmanaged(PromptAsyncEntry) = .empty,
    prompt_async_refreshes: std.ArrayList(*PromptAsyncRefresh) = .empty,
    prompt_async_owner: ?*Executor = null,
    completion_builder: ?CompletionBuilder = null,
    completion_context: ?CompletionEvalContext = null,
    last_completion_context: ?CompletionEvalContext = null,
    command_history: ?CommandHistory = null,
    suppress_next_interactive_history_append: bool = false,
    getopts_offset: usize = 1,
    getopts_last_optind: usize = 1,
    parameter_error: expand.ParameterError = .{},
    arithmetic_error: expand.ArithmeticError = .{},
    had_expansion_error: bool = false,
    pending_command_abort: bool = false,
    suppress_special_builtin_properties: bool = false,
    command_substitution_stderr: std.ArrayList(u8) = .empty,
    command_substitution_status: ?ExitStatus = null,
    script_stdin: ?[]const u8 = null,
    script_stdin_offset: usize = 0,
    script_stdin_file: ?std.Io.File = null,

    pub fn init(allocator: std.mem.Allocator) Executor {
        var executor: Executor = .{ .allocator = allocator, .ignored_trap_signals_at_entry = ignoredTrapSignalsAtEntry() };
        executor.setLastStatus(0);
        executor.setPidText();
        return executor;
    }

    const PromptRepaintHandler = struct {
        context: *anyopaque,
        request: *const fn (*anyopaque) void,
    };

    pub fn setPromptRepaintHandler(self: *Executor, context: *anyopaque, request: *const fn (*anyopaque) void) void {
        self.prompt_repaint_handler = .{ .context = context, .request = request };
    }

    pub fn promptRefreshIntervalMs(self: Executor) ?u64 {
        return self.prompt_refresh_interval_ms;
    }

    pub fn setCommandHistory(self: *Executor, history: CommandHistory) void {
        self.command_history = history;
    }

    pub fn consumeSuppressNextInteractiveHistoryAppend(self: *Executor) bool {
        const suppress = self.suppress_next_interactive_history_append;
        self.suppress_next_interactive_history_append = false;
        return suppress;
    }

    pub fn waitForPromptAsyncRefreshes(self: *Executor) void {
        self.reapPromptAsyncRefreshes(true);
    }

    pub fn promptIntervalWaitMs(self: Executor, io: std.Io) ?u64 {
        if (self.interval_hooks.items.len == 0) return null;
        const now = nowMs(io);
        var wait_ms: ?u64 = null;
        for (self.interval_hooks.items) |hook| {
            const due_at = hook.last_run_ms +| hook.interval_ms;
            const remaining = if (due_at <= now) 0 else due_at - now;
            wait_ms = if (wait_ms) |current| @min(current, remaining) else remaining;
        }
        return wait_ms;
    }

    pub fn runPromptEventHooks(self: *Executor, io: std.Io, event: []const u8, args: []const []const u8) !void {
        try self.runEventHooks(io, event, args);
    }

    pub fn runDuePromptIntervals(self: *Executor, io: std.Io) !void {
        const now = nowMs(io);
        for (self.interval_hooks.items) |*hook| {
            if (hook.last_run_ms != 0 and now -| hook.last_run_ms < hook.interval_ms) continue;
            hook.last_run_ms = now;
            try self.runHookFunction(io, hook.function, &.{hook.name});
        }
    }

    pub fn runPendingVariableHooks(self: *Executor, io: std.Io) !void {
        var pending = self.pending_variable_hooks;
        self.pending_variable_hooks = .empty;
        defer {
            for (pending.items) |name| self.allocator.free(name);
            pending.deinit(self.allocator);
        }
        for (pending.items) |name| try self.runEventHooks(io, "variable", &.{name});
    }

    fn queueVariableHook(self: *Executor, name: []const u8) void {
        if (self.hook_depth != 0) return;
        if (!self.event_hooks.contains("variable")) return;
        self.pending_variable_hooks.append(self.allocator, self.allocator.dupe(u8, name) catch return) catch return;
    }

    fn addEventHook(self: *Executor, event: []const u8, function: []const u8) !void {
        const owned_event = try self.allocator.dupe(u8, event);
        errdefer self.allocator.free(owned_event);
        const owned_function = try self.allocator.dupe(u8, function);
        errdefer self.allocator.free(owned_function);
        const result = try self.event_hooks.getOrPut(self.allocator, owned_event);
        if (result.found_existing) {
            self.allocator.free(owned_event);
        } else {
            result.value_ptr.* = .empty;
        }
        try result.value_ptr.append(self.allocator, .{ .function = owned_function });
    }

    fn addIntervalHook(self: *Executor, name: []const u8, interval_ms: u64, function: []const u8) !void {
        for (self.interval_hooks.items) |*hook| {
            if (std.mem.eql(u8, hook.name, name)) {
                self.allocator.free(hook.function);
                hook.function = try self.allocator.dupe(u8, function);
                hook.interval_ms = interval_ms;
                hook.last_run_ms = 0;
                return;
            }
        }
        const owned_name = try self.allocator.dupe(u8, name);
        errdefer self.allocator.free(owned_name);
        const owned_function = try self.allocator.dupe(u8, function);
        errdefer self.allocator.free(owned_function);
        try self.interval_hooks.append(self.allocator, .{
            .name = owned_name,
            .function = owned_function,
            .interval_ms = interval_ms,
        });
    }

    fn runEventHooks(self: *Executor, io: std.Io, event: []const u8, args: []const []const u8) !void {
        const hooks = self.event_hooks.get(event) orelse return;
        for (hooks.items) |hook| try self.runHookFunction(io, hook.function, args);
    }

    fn runHookFunction(self: *Executor, io: std.Io, function: []const u8, args: []const []const u8) !void {
        if (self.hook_depth != 0) return;
        if (!self.hasFunction(function)) return;
        const saved_last_status_text = self.last_status_text;
        const saved_last_status_text_len = self.last_status_text_len;
        self.hook_depth += 1;
        defer {
            self.hook_depth -= 1;
            self.last_status_text = saved_last_status_text;
            self.last_status_text_len = saved_last_status_text_len;
        }
        var script: std.ArrayList(u8) = .empty;
        defer script.deinit(self.allocator);
        try appendShellQuoted(self.allocator, &script, function);
        for (args) |arg| {
            try script.append(self.allocator, ' ');
            try appendShellQuoted(self.allocator, &script, arg);
        }
        var result = try self.executeScriptSlice(script.items, .{ .io = io, .allow_external = true, .external_stdio = .capture, .suppress_errexit = true, .arg_zero = self.arg_zero });
        defer result.deinit();
    }

    fn promptAsyncCacheKey(self: *Executor, io: std.Io, key: []const u8) ![]u8 {
        const cwd = try self.logicalCwd(io);
        defer self.allocator.free(cwd);
        return std.fmt.allocPrint(self.allocator, "{s}\x00{s}", .{ cwd, key });
    }

    fn promptAsyncCachedOutputOrSchedule(self: *Executor, source: *Executor, cache_key: []const u8, ttl_ms: u64, script: []const u8, io: std.Io) ![]u8 {
        self.reapPromptAsyncRefreshes(false);
        const now = nowMs(io);
        var new_key: ?[]u8 = try self.allocator.dupe(u8, cache_key);
        defer if (new_key) |key| self.allocator.free(key);
        var new_entry_output: ?[]u8 = try self.allocator.alloc(u8, 0);
        defer if (new_entry_output) |entry_output| self.allocator.free(entry_output);
        var cold_output: ?[]u8 = try self.allocator.alloc(u8, 0);
        defer if (cold_output) |output| self.allocator.free(output);

        const scheduled = blk: {
            lockExecutorMutex(&self.prompt_async_mutex);
            defer self.prompt_async_mutex.unlock();

            const entry_result = try self.prompt_async_entries.getOrPut(self.allocator, cache_key);
            if (entry_result.found_existing) {
                self.allocator.free(new_key.?);
                new_key = null;
                self.allocator.free(new_entry_output.?);
                new_entry_output = null;
                self.allocator.free(cold_output.?);
                cold_output = null;

                const entry = entry_result.value_ptr;
                const output = try self.allocator.dupe(u8, entry.output);
                errdefer self.allocator.free(output);
                const should_spawn = !entry.inflight and (entry.updated_ms == 0 or now -| entry.updated_ms >= ttl_ms);
                if (should_spawn) entry.inflight = true;
                break :blk PromptAsyncSchedule{ .output = output, .should_spawn = should_spawn };
            }

            entry_result.key_ptr.* = new_key.?;
            new_key = null;
            entry_result.value_ptr.* = .{ .output = new_entry_output.?, .inflight = true };
            new_entry_output = null;
            const output = cold_output.?;
            cold_output = null;
            break :blk PromptAsyncSchedule{ .output = output, .should_spawn = true };
        };

        if (scheduled.should_spawn) self.startPromptAsyncRefresh(source, cache_key, script, io) catch |err| {
            lockExecutorMutex(&self.prompt_async_mutex);
            if (self.prompt_async_entries.getPtr(cache_key)) |entry| entry.inflight = false;
            self.prompt_async_mutex.unlock();
            self.allocator.free(scheduled.output);
            return err;
        };

        return scheduled.output;
    }

    fn startPromptAsyncRefresh(self: *Executor, source: *Executor, cache_key: []const u8, script: []const u8, io: std.Io) !void {
        const refresh = try self.allocator.create(PromptAsyncRefresh);
        errdefer self.allocator.destroy(refresh);
        var owned_cache_key: ?[]u8 = try self.allocator.dupe(u8, cache_key);
        errdefer if (owned_cache_key) |key| self.allocator.free(key);
        var owned_script: ?[]u8 = try self.allocator.dupe(u8, script);
        errdefer if (owned_script) |owned| self.allocator.free(owned);
        refresh.* = .{
            .allocator = self.allocator,
            .owner = self,
            .cache_key = owned_cache_key.?,
            .script = owned_script.?,
            .io = io,
            .executor = Executor.init(self.allocator),
        };
        owned_cache_key = null;
        owned_script = null;
        errdefer refresh.deinit();
        try refresh.executor.copyStateFrom(source);
        try self.prompt_async_refreshes.append(self.allocator, refresh);
        errdefer _ = self.prompt_async_refreshes.pop();
        refresh.thread = try std.Thread.spawn(.{}, PromptAsyncRefresh.run, .{refresh});
    }

    fn finishPromptAsyncRefresh(self: *Executor, cache_key: []const u8, output: []const u8, io: std.Io) !void {
        const owned_output = try self.allocator.dupe(u8, output);
        errdefer self.allocator.free(owned_output);
        lockExecutorMutex(&self.prompt_async_mutex);
        defer self.prompt_async_mutex.unlock();
        const entry = self.prompt_async_entries.getPtr(cache_key) orelse return;
        self.allocator.free(entry.output);
        entry.output = owned_output;
        entry.updated_ms = nowMs(io);
        entry.inflight = false;
    }

    fn finishPromptAsyncRefreshFailed(self: *Executor, cache_key: []const u8) void {
        lockExecutorMutex(&self.prompt_async_mutex);
        defer self.prompt_async_mutex.unlock();
        if (self.prompt_async_entries.getPtr(cache_key)) |entry| entry.inflight = false;
    }

    fn reapPromptAsyncRefreshes(self: *Executor, wait: bool) void {
        var index: usize = 0;
        while (index < self.prompt_async_refreshes.items.len) {
            const refresh = self.prompt_async_refreshes.items[index];
            if (!wait and !refresh.done.load(.acquire)) {
                index += 1;
                continue;
            }
            _ = self.prompt_async_refreshes.swapRemove(index);
            refresh.thread.join();
            if (!refresh.done.load(.acquire)) {
                lockExecutorMutex(&self.prompt_async_mutex);
                if (self.prompt_async_entries.getPtr(refresh.cache_key)) |entry| entry.inflight = false;
                self.prompt_async_mutex.unlock();
            }
            refresh.deinit();
            self.allocator.destroy(refresh);
        }
    }

    pub fn importEnvironment(self: *Executor, environ_map: *const std.process.Environ.Map) !void {
        var iter = environ_map.iterator();
        while (iter.next()) |entry| {
            try self.setEnv(entry.key_ptr.*, entry.value_ptr.*);
            try self.setExported(entry.key_ptr.*);
        }
    }

    pub fn initializeShellVariables(self: *Executor, io: std.Io) !void {
        try self.setEnv("IFS", " \t\n");
        try self.setEnv("OPTIND", "1");

        var ppid_buffer: [32]u8 = undefined;
        const ppid = try std.fmt.bufPrint(&ppid_buffer, "{d}", .{std.posix.getppid()});
        try self.setEnv("PPID", ppid);

        if (self.getEnv("PWD")) |pwd| if (self.validLogicalPwd(pwd)) return;
        const cwd = try std.process.currentPathAlloc(io, self.allocator);
        defer self.allocator.free(cwd);
        try self.setEnv("PWD", cwd);
        try self.setExported("PWD");
    }

    fn validLogicalPwd(self: *Executor, pwd: []const u8) bool {
        if (pwd.len == 0 or pwd[0] != '/') return false;
        if (pathHasDotOrDotDotComponent(pwd)) return false;
        return sameExistingFile(self.allocator, pwd, ".") orelse false;
    }

    fn physicalCwd(self: *Executor, io: std.Io) ![]u8 {
        const cwd = try std.process.currentPathAlloc(io, self.allocator);
        defer self.allocator.free(cwd);
        return self.allocator.dupe(u8, cwd);
    }

    fn clearEnvironment(self: *Executor) void {
        var iter = self.env.iterator();
        while (iter.next()) |entry| {
            self.allocator.free(entry.key_ptr.*);
            self.allocator.free(entry.value_ptr.*);
        }
        self.env.clearRetainingCapacity();
        var exported_iter = self.exported.iterator();
        while (exported_iter.next()) |entry| self.allocator.free(entry.key_ptr.*);
        self.exported.clearRetainingCapacity();
        self.clearCommandHash();
    }

    fn clearCommandHash(self: *Executor) void {
        var iter = self.command_hash.iterator();
        while (iter.next()) |entry| {
            self.allocator.free(entry.key_ptr.*);
            self.allocator.free(entry.value_ptr.*);
        }
        self.command_hash.clearRetainingCapacity();
    }

    fn deinitCommandHash(self: *Executor) void {
        self.clearCommandHash();
        self.command_hash.deinit(self.allocator);
    }

    pub fn setLastStatus(self: *Executor, status: ExitStatus) void {
        const text = std.fmt.bufPrint(&self.last_status_text, "{d}", .{status}) catch unreachable;
        self.last_status_text_len = text.len;
    }

    pub fn lastStatus(self: Executor) ExitStatus {
        return std.fmt.parseInt(ExitStatus, self.last_status_text[0..self.last_status_text_len], 10) catch 0;
    }

    fn setCurrentLineNumber(self: *Executor, source: []const u8, offset: usize) void {
        var line: usize = 1;
        var index: usize = 0;
        const end = @min(offset, source.len);
        while (index < end) : (index += 1) {
            if (source[index] == '\n') line += 1;
        }
        const text = std.fmt.bufPrint(&self.lineno_text, "{d}", .{line}) catch unreachable;
        self.lineno_text_len = text.len;
    }

    pub fn setLastCommandDuration(self: *Executor, duration_ms: i64) void {
        const text = std.fmt.bufPrint(&self.last_command_duration_text, "{d}", .{@max(duration_ms, 0)}) catch unreachable;
        self.last_command_duration_text_len = text.len;
    }

    fn setPidText(self: *Executor) void {
        const pid = shellPid();
        const text = std.fmt.bufPrint(&self.pid_text, "{d}", .{pid}) catch unreachable;
        self.pid_text_len = text.len;
    }

    pub fn deinit(self: *Executor) void {
        var iter = self.env.iterator();
        while (iter.next()) |entry| {
            self.allocator.free(entry.key_ptr.*);
            self.allocator.free(entry.value_ptr.*);
        }
        self.env.deinit(self.allocator);
        var exported_iter = self.exported.iterator();
        while (exported_iter.next()) |entry| self.allocator.free(entry.key_ptr.*);
        self.exported.deinit(self.allocator);
        var readonly_iter = self.readonly.iterator();
        while (readonly_iter.next()) |entry| self.allocator.free(entry.key_ptr.*);
        self.readonly.deinit(self.allocator);
        var array_iter = self.arrays.iterator();
        while (array_iter.next()) |entry| {
            self.allocator.free(entry.key_ptr.*);
            entry.value_ptr.deinit(self.allocator);
        }
        self.arrays.deinit(self.allocator);
        var function_iter = self.functions.iterator();
        while (function_iter.next()) |entry| {
            self.allocator.free(entry.key_ptr.*);
            entry.value_ptr.deinit(self.allocator);
        }
        self.functions.deinit(self.allocator);
        var alias_iter = self.aliases.iterator();
        while (alias_iter.next()) |entry| {
            self.allocator.free(entry.key_ptr.*);
            self.allocator.free(entry.value_ptr.*);
        }
        self.aliases.deinit(self.allocator);
        self.deinitCommandHash();
        var abbr_iter = self.abbreviations.iterator();
        while (abbr_iter.next()) |entry| {
            self.allocator.free(entry.key_ptr.*);
            self.allocator.free(entry.value_ptr.*);
        }
        self.abbreviations.deinit(self.allocator);
        var trap_iter = self.traps.iterator();
        while (trap_iter.next()) |entry| {
            self.allocator.free(entry.key_ptr.*);
            self.allocator.free(entry.value_ptr.*);
        }
        self.traps.deinit(self.allocator);
        var hook_iter = self.event_hooks.iterator();
        while (hook_iter.next()) |entry| {
            self.allocator.free(entry.key_ptr.*);
            for (entry.value_ptr.items) |hook| self.allocator.free(hook.function);
            entry.value_ptr.deinit(self.allocator);
        }
        self.event_hooks.deinit(self.allocator);
        for (self.interval_hooks.items) |hook| {
            self.allocator.free(hook.name);
            self.allocator.free(hook.function);
        }
        self.interval_hooks.deinit(self.allocator);
        for (self.pending_variable_hooks.items) |name| self.allocator.free(name);
        self.pending_variable_hooks.deinit(self.allocator);
        for (self.completion_rules.items) |rule| freeCompletionRule(self.allocator, rule);
        self.completion_rules.deinit(self.allocator);
        self.clearCompletionProviderDiagnostics();
        self.completion_provider_diagnostics.deinit(self.allocator);
        var loaded_completion_iter = self.loaded_completion_scripts.iterator();
        while (loaded_completion_iter.next()) |entry| self.allocator.free(entry.key_ptr.*);
        self.loaded_completion_scripts.deinit(self.allocator);
        var loaded_companion_iter = self.loaded_completion_companions.iterator();
        while (loaded_companion_iter.next()) |entry| self.allocator.free(entry.key_ptr.*);
        self.loaded_completion_companions.deinit(self.allocator);
        for (self.background_jobs.items) |job| self.allocator.free(job.command);
        self.background_jobs.deinit(self.allocator);
        for (self.pending_job_notifications.items) |notification| self.allocator.free(notification);
        self.pending_job_notifications.deinit(self.allocator);
        self.parameter_error.clear(self.allocator);
        self.arithmetic_error.clear(self.allocator);
        self.command_substitution_stderr.deinit(self.allocator);
        self.open_fds.deinit(self.allocator);
        if (self.prompt_builder) |*builder| builder.deinit(self.allocator);
        self.waitForPromptAsyncRefreshes();
        self.restoreTrapSignalActions();
        self.trap_signal_actions.deinit(self.allocator);
        var prompt_async_iter = self.prompt_async_entries.iterator();
        while (prompt_async_iter.next()) |entry| {
            self.allocator.free(entry.key_ptr.*);
            self.allocator.free(entry.value_ptr.output);
        }
        self.prompt_async_entries.deinit(self.allocator);
        self.prompt_async_refreshes.deinit(self.allocator);
        if (self.completion_builder) |*builder| builder.deinit(self.allocator);
        self.global_positionals.deinit(self.allocator);
        for (self.call_frames.items) |*frame| frame.deinit(self.allocator);
        self.call_frames.deinit(self.allocator);
        self.* = undefined;
    }

    pub fn hasFunction(self: Executor, name: []const u8) bool {
        return self.functions.contains(name);
    }

    pub fn registerCompletionRule(self: *Executor, rule: completion.Rule) !void {
        var owned_rule: completion.Rule = .{
            .root = try self.allocator.dupe(u8, rule.root),
            .kind = rule.kind,
            .value = if (rule.value) |value| try self.allocator.dupe(u8, value) else null,
            .provider_kind = rule.provider_kind,
            .option = .{
                .long = if (rule.option.long) |long| try self.allocator.dupe(u8, long) else null,
                .short = if (rule.option.short) |short| try self.allocator.dupe(u8, short) else null,
                .argument = if (rule.option.argument) |argument| try self.allocator.dupe(u8, argument) else null,
                .exclusive_group = if (rule.option.exclusive_group) |group| try self.allocator.dupe(u8, group) else null,
                .repeatable = rule.option.repeatable,
                .terminates_options = rule.option.terminates_options,
                .no_space = rule.option.no_space,
                .inherit = rule.option.inherit,
            },
            .argument = .{
                .state = if (rule.argument.state) |state| try self.allocator.dupe(u8, state) else null,
                .index = rule.argument.index,
                .after_state = if (rule.argument.after_state) |state| try self.allocator.dupe(u8, state) else null,
                .after_value = if (rule.argument.after_value) |value| try self.allocator.dupe(u8, value) else null,
                .repeatable = rule.argument.repeatable,
            },
            .value_grammar = rule.value_grammar,
            .description = if (rule.description) |description| try self.allocator.dupe(u8, description) else null,
            .source = .{
                .kind = rule.source.kind,
                .manifest_path = if (rule.source.manifest_path) |path| try self.allocator.dupe(u8, path) else null,
                .manifest_version = rule.source.manifest_version,
                .companion_path = if (rule.source.companion_path) |path| try self.allocator.dupe(u8, path) else null,
            },
        };
        errdefer freeCompletionRule(self.allocator, owned_rule);
        var path: std.ArrayList([]const u8) = .empty;
        errdefer {
            for (path.items) |segment| self.allocator.free(segment);
            path.deinit(self.allocator);
        }
        for (rule.path) |segment| try path.append(self.allocator, try self.allocator.dupe(u8, segment));
        owned_rule.path = try path.toOwnedSlice(self.allocator);
        try self.completion_rules.append(self.allocator, owned_rule);
        self.completion_generation +%= 1;
    }

    pub fn completionGeneration(self: Executor) u64 {
        return self.completion_generation;
    }

    pub fn completionRules(self: Executor) []const completion.Rule {
        return self.completion_rules.items;
    }

    pub fn completionProviderDiagnostics(self: Executor) []const CompletionProviderDiagnostic {
        return self.completion_provider_diagnostics.items;
    }

    fn clearCompletionProviderDiagnostics(self: *Executor) void {
        for (self.completion_provider_diagnostics.items) |diagnostic| {
            self.allocator.free(diagnostic.function);
            self.allocator.free(diagnostic.command);
            if (diagnostic.err) |err| self.allocator.free(err);
            self.allocator.free(diagnostic.stderr);
        }
        self.completion_provider_diagnostics.clearRetainingCapacity();
    }

    fn appendCompletionProviderDiagnostic(self: *Executor, function: []const u8, command: []const u8, status: ?ExitStatus, err: ?anyerror, stderr: []const u8) !void {
        const owned_function = try self.allocator.dupe(u8, function);
        errdefer self.allocator.free(owned_function);
        const owned_command = try self.allocator.dupe(u8, command);
        errdefer self.allocator.free(owned_command);
        const owned_err = if (err) |provider_err| try self.allocator.dupe(u8, @errorName(provider_err)) else null;
        errdefer if (owned_err) |err_name| self.allocator.free(err_name);
        const owned_stderr = try self.allocator.dupe(u8, stderr);
        errdefer self.allocator.free(owned_stderr);
        try self.completion_provider_diagnostics.append(self.allocator, .{
            .function = owned_function,
            .command = owned_command,
            .status = status,
            .err = owned_err,
            .stderr = owned_stderr,
        });
    }

    fn completionCommandKnown(self: Executor, command: []const u8, io: ?std.Io) !bool {
        if (builtinFor(command) != null) return true;
        if (self.functions.get(command) != null) return true;
        if (self.aliases.get(command) != null) return true;
        for (self.completion_rules.items) |rule| {
            if (std.mem.eql(u8, rule.root, command)) return true;
        }
        if (try self.completionCommandInPath(command, io)) return true;
        return false;
    }

    fn completionCommandInPath(self: Executor, command: []const u8, maybe_io: ?std.Io) !bool {
        const io = maybe_io orelse return false;
        if (std.mem.indexOfScalar(u8, command, '/') != null) {
            std.Io.Dir.cwd().access(io, command, .{ .execute = true }) catch return false;
            return true;
        }
        const path_value = self.getEnv("PATH") orelse return false;
        var parts = std.mem.splitScalar(u8, path_value, ':');
        while (parts.next()) |part| {
            const dir = if (part.len == 0) "." else part;
            const candidate = try std.mem.concat(self.allocator, u8, &.{ dir, "/", command });
            defer self.allocator.free(candidate);
            std.Io.Dir.cwd().access(io, candidate, .{ .execute = true }) catch continue;
            return true;
        }
        return false;
    }

    fn loadCompletionScriptForRoot(self: *Executor, root: []const u8, options: ExecuteOptions) !void {
        const io = options.io orelse return;
        if (root.len == 0 or self.loaded_completion_scripts.contains(root)) return;
        const owned_root = try self.allocator.dupe(u8, root);
        errdefer self.allocator.free(owned_root);
        try self.loaded_completion_scripts.put(self.allocator, owned_root, {});
        const file_name = try rootCompletionFileName(self.allocator, root);
        defer self.allocator.free(file_name);
        if (file_name.len == 0) return;

        if (self.getEnv("XDG_DATA_HOME")) |data_home| {
            if (data_home.len != 0) {
                const path = try std.fs.path.join(self.allocator, &.{ data_home, "rush", "completions", file_name });
                defer self.allocator.free(path);
                if (!self.isManifestCompanionCompletionScript(root, path) and try self.sourceCompletionScript(io, path, options, false)) return;
            }
        } else if (self.getEnv("HOME")) |home| {
            if (home.len != 0) {
                const path = try std.fs.path.join(self.allocator, &.{ home, ".local", "share", "rush", "completions", file_name });
                defer self.allocator.free(path);
                if (!self.isManifestCompanionCompletionScript(root, path) and try self.sourceCompletionScript(io, path, options, false)) return;
            }
        }

        const data_dirs = self.getEnv("XDG_DATA_DIRS") orelse "/usr/local/share:/usr/share";
        var dirs = std.mem.splitScalar(u8, data_dirs, ':');
        while (dirs.next()) |dir| {
            if (dir.len == 0) continue;
            const path = try std.fs.path.join(self.allocator, &.{ dir, "rush", "completions", file_name });
            defer self.allocator.free(path);
            if (!self.isManifestCompanionCompletionScript(root, path) and try self.sourceCompletionScript(io, path, options, false)) return;
        }
    }

    fn isManifestCompanionCompletionScript(self: Executor, root: []const u8, path: []const u8) bool {
        for (self.completion_rules.items) |rule| {
            if (rule.source.kind != .manifest) continue;
            if (!std.mem.eql(u8, rule.root, root)) continue;
            if (rule.source.companion_path) |companion_path| {
                if (std.mem.eql(u8, companion_path, path)) return true;
            }
        }
        return false;
    }

    fn rootCompletionFileName(allocator: std.mem.Allocator, root: []const u8) ![]const u8 {
        if (std.mem.indexOfScalar(u8, root, '/') != null or std.mem.indexOfScalar(u8, root, 0) != null) return allocator.alloc(u8, 0);
        return std.fmt.allocPrint(allocator, "{s}.rush", .{root});
    }

    fn sourceCompletionScript(self: *Executor, io: std.Io, path: []const u8, options: ExecuteOptions, provider_only: bool) !bool {
        if (path.len == 0) return false;
        const contents = std.Io.Dir.cwd().readFileAlloc(io, path, self.allocator, .limited(1024 * 1024)) catch |err| switch (err) {
            error.FileNotFound => return false,
            else => return false,
        };
        defer self.allocator.free(contents);
        var source_options = options;
        source_options.allow_external = true;
        source_options.completion_provider_only = provider_only;
        var result = self.executeScriptSlice(contents, source_options) catch return true;
        defer result.deinit();
        return true;
    }

    fn ensureCompletionCompanionLoaded(self: *Executor, io: std.Io, path: []const u8, options: ExecuteOptions) !void {
        if (path.len == 0 or self.loaded_completion_companions.contains(path)) return;
        const owned_path = try self.allocator.dupe(u8, path);
        errdefer self.allocator.free(owned_path);
        try self.loaded_completion_companions.put(self.allocator, owned_path, {});
        _ = try self.sourceCompletionScript(io, path, options, true);
    }

    pub fn lastCompletionContext(self: Executor) ?CompletionEvalContext {
        return self.last_completion_context;
    }

    pub fn collectCompletionsForInput(self: *Executor, source: []const u8, cursor: usize, options: ExecuteOptions) ![]completion.Candidate {
        self.clearCompletionProviderDiagnostics();
        var context = try completionEvalContextForInput(self.allocator, source, cursor);
        const completing_parameter = context.position == .parameter;
        const parameter_context = context;
        if (context.command.len != 0) try self.loadCompletionScriptForRoot(context.command, options);
        var semantic = try self.analyzeCompletionsForInput(source, cursor);
        defer semantic.deinit();
        const command_path = try completionCommandPath(self.allocator, semantic);
        defer self.allocator.free(command_path);

        context.command = semantic.root;
        context.command_path = command_path;
        context.prefix = semantic.prefix;
        context.argument_index = semantic.argument_index;
        context.argument_state = semantic.argument_state;
        context.parsed_options = semantic.parsed_options;
        context.operands = semantic.operands;
        context.options_terminated = semantic.options_terminated;
        context.previous = semantic.previous;
        context.option_value = semantic.option_value;
        context.value_segment = semantic.value_segment;
        context.replace_start = semantic.replace_start;
        context.replace_end = semantic.replace_end;
        context.position = switch (semantic.position) {
            .command => .command,
            .option, .option_value, .subcommand, .redirect_target, .argument => .argument,
        };

        if (completing_parameter) {
            return try self.collectParameterCompletions(parameter_context);
        }

        const candidates = try self.collectCompletionsWithContext(context.command, context, options);
        if (semantic.position == .command) return candidates;

        var builder: CompletionBuilder = .{};
        errdefer builder.deinit(self.allocator);
        for (candidates) |candidate| try builder.appendCandidateIfMissing(self.allocator, candidate);
        try self.appendBuiltinCompletionCandidates(&builder, semantic, options);
        if (semantic.position != .option_value) try self.appendStructuredCompletionCandidates(&builder, semantic);
        try self.appendDynamicStructuredCompletionCandidates(&builder, context, semantic, options);
        try self.appendDefaultCompletionCandidates(&builder, semantic, options);
        self.freeCompletions(candidates);
        const merged = try builder.finish(self.allocator);
        return merged;
    }

    fn collectParameterCompletions(self: *Executor, context: CompletionEvalContext) ![]completion.Candidate {
        var builder: CompletionBuilder = .{};
        errdefer builder.deinit(self.allocator);
        var iter = self.env.iterator();
        while (iter.next()) |entry| {
            if (std.mem.startsWith(u8, entry.key_ptr.*, context.prefix)) {
                try builder.appendCandidate(self.allocator, .{
                    .value = entry.key_ptr.*,
                    .kind = .variable,
                    .replace_start = context.replace_start,
                    .replace_end = context.replace_end,
                    .append_space = false,
                });
            }
        }
        return try builder.finish(self.allocator);
    }

    pub fn analyzeCompletionsForInput(self: *Executor, source: []const u8, cursor: usize) !CompletionSemanticContext {
        const view = try completionInputView(self.allocator, source, cursor);
        var parsed = try parser.parse(self.allocator, view.source, .{ .mode = .interactive, .cursor = view.cursor });
        defer parsed.deinit();
        const parser_context = parser.completionContext(parsed, view.cursor);
        const clamped_cursor = view.cursor;

        var words: std.ArrayList(CompletionWord) = .empty;
        defer words.deinit(self.allocator);
        try appendActiveCompletionWords(self.allocator, &words, parsed, parser_context);

        const prefix = completionContextPrefix(view.source, parser_context);
        const replace_start = view.offset + parser_context.span.start;
        const replace_end = view.offset + @min(parser_context.cursor, parser_context.span.end);

        if (words.items.len == 0) {
            return .{
                .allocator = self.allocator,
                .path = try self.allocator.alloc([]const u8, 0),
                .parsed_options = try self.allocator.alloc(CompletionParsedOption, 0),
                .operands = try self.allocator.alloc(CompletionParsedOperand, 0),
                .prefix = prefix,
                .position = completionPositionForParserContext(parser_context, prefix),
                .replace_start = replace_start,
                .replace_end = replace_end,
                .parser_position = parser_context.kind,
                .parser_source_offset = view.offset,
            };
        }

        const root = words.items[0].token.lexeme(view.source);
        var path: std.ArrayList([]const u8) = .empty;
        errdefer path.deinit(self.allocator);
        var parsed_options: std.ArrayList(CompletionParsedOption) = .empty;
        errdefer parsed_options.deinit(self.allocator);
        var operands: std.ArrayList(CompletionParsedOperand) = .empty;
        errdefer operands.deinit(self.allocator);
        var index: usize = 1;
        var argument_index: usize = 0;
        var previous_argument: []const u8 = "";
        var previous_argument_state: ?[]const u8 = null;
        var previous: []const u8 = "";
        var suspicious: ?parser.Span = null;
        var option_value: ?CompletionOptionValue = null;
        var stop_after_unknown_option = false;
        var options_terminated = false;
        while (index < words.items.len) {
            const token = words.items[index].token;
            const is_current = token.span.start == parser_context.span.start and clamped_cursor <= token.span.end;
            if (is_current or token.span.end > clamped_cursor) break;
            const word = token.lexeme(view.source);
            previous = word;
            if (stop_after_unknown_option and !findCompletionSubcommand(self.completion_rules.items, root, path.items, word)) break;
            stop_after_unknown_option = false;
            if (options_terminated) {
                const operand_state = completionActiveArgumentState(self.completion_rules.items, root, path.items, argument_index, previous_argument_state, previous_argument);
                try operands.append(self.allocator, .{ .value = word, .index = argument_index, .state = operand_state, .after_terminator = true });
                previous_argument_state = operand_state;
                previous_argument = word;
                argument_index += 1;
            } else if (std.mem.eql(u8, word, "--")) {
                options_terminated = true;
            } else if (findCompletionOption(self.completion_rules.items, root, path.items, word)) |matched| {
                try appendParsedCompletionOption(self.allocator, &parsed_options, matched);
                if (matched.takes_value and !matched.attached_value) {
                    if (index + 1 < words.items.len) {
                        const value_token = words.items[index + 1].token;
                        const value_is_current = value_token.span.start == parser_context.span.start and clamped_cursor <= value_token.span.end;
                        if (!value_is_current and value_token.span.end <= clamped_cursor) {
                            index += 1;
                            previous = value_token.lexeme(view.source);
                            setLastParsedCompletionOptionValue(&parsed_options, previous);
                        } else {
                            option_value = .{ .name = matched.name, .spelling = matched.spelling };
                        }
                    } else {
                        option_value = .{ .name = matched.name, .spelling = matched.spelling };
                    }
                }
                if (matched.terminates_options) options_terminated = true;
            } else if (analyzeShortOptionCluster(self.completion_rules.items, root, path.items, word)) |cluster| {
                if (!cluster.valid) {
                    suspicious = token.span;
                    stop_after_unknown_option = true;
                } else if (cluster.takes_next_value) {
                    _ = try appendShortCompletionClusterParsedOptions(self.allocator, &parsed_options, self.completion_rules.items, root, path.items, word);
                    if (shortCompletionClusterTerminatesOptions(self.completion_rules.items, root, path.items, word)) options_terminated = true;
                    if (index + 1 < words.items.len) {
                        const value_token = words.items[index + 1].token;
                        const value_is_current = value_token.span.start == parser_context.span.start and clamped_cursor <= value_token.span.end;
                        if (!value_is_current and value_token.span.end <= clamped_cursor) {
                            index += 1;
                            previous = value_token.lexeme(view.source);
                            setLastParsedCompletionOptionValue(&parsed_options, previous);
                        }
                    }
                } else {
                    _ = try appendShortCompletionClusterParsedOptions(self.allocator, &parsed_options, self.completion_rules.items, root, path.items, word);
                    if (shortCompletionClusterTerminatesOptions(self.completion_rules.items, root, path.items, word)) options_terminated = true;
                }
            } else if (isOptionLike(word)) {
                suspicious = token.span;
                stop_after_unknown_option = true;
            } else if (argument_index == 0 and findCompletionSubcommand(self.completion_rules.items, root, path.items, word)) {
                try path.append(self.allocator, word);
            } else {
                const operand_state = completionActiveArgumentState(self.completion_rules.items, root, path.items, argument_index, previous_argument_state, previous_argument);
                try operands.append(self.allocator, .{ .value = word, .index = argument_index, .state = operand_state, .after_terminator = false });
                previous_argument_state = operand_state;
                previous_argument = word;
                argument_index += 1;
            }
            index += 1;
        }

        const argument_state = completionActiveArgumentState(self.completion_rules.items, root, path.items, argument_index, previous_argument_state, previous_argument);

        var semantic_prefix = prefix;
        var semantic_replace_start = replace_start;
        var value_segment: ?CompletionValueSegment = null;
        if (option_value == null) {
            if (attachedCompletionOptionValue(self.completion_rules.items, root, path.items, semantic_prefix)) |attached| {
                option_value = .{ .name = attached.name, .spelling = attached.spelling };
                semantic_prefix = semantic_prefix[attached.value_offset..];
                semantic_replace_start += attached.value_offset;
            }
        }
        if (option_value) |active_option_value| {
            const grammar = completionValueGrammarForOption(self.completion_rules.items, root, path.items, active_option_value);
            if (!grammar.isEmpty()) {
                const active = activeCompletionValueSegment(semantic_prefix, semantic_replace_start, grammar);
                semantic_prefix = active.prefix;
                semantic_replace_start = active.replace_start;
                value_segment = active.context;
            }
        }
        const position: CompletionSemanticPosition = if (option_value != null)
            .option_value
        else if (parser_context.kind == .redirect_target)
            .redirect_target
        else if (parser_context.kind == .assignment_name)
            .command
        else if (parser_context.kind == .command)
            .command
        else if (options_terminated)
            .argument
        else if (std.mem.startsWith(u8, semantic_prefix, "-"))
            .option
        else if (argument_state == null and (semantic_prefix.len == 0 or path.items.len == 0 or completionContextHasSubcommands(self.completion_rules.items, root, path.items)))
            .subcommand
        else
            .argument;
        const owned_path = try path.toOwnedSlice(self.allocator);
        errdefer self.allocator.free(owned_path);
        const owned_parsed_options = try parsed_options.toOwnedSlice(self.allocator);
        errdefer self.allocator.free(owned_parsed_options);
        const owned_operands = try operands.toOwnedSlice(self.allocator);
        return .{
            .allocator = self.allocator,
            .root = root,
            .path = owned_path,
            .parsed_options = owned_parsed_options,
            .operands = owned_operands,
            .options_terminated = options_terminated,
            .prefix = semantic_prefix,
            .argument_index = argument_index,
            .argument_state = argument_state,
            .previous = previous,
            .position = position,
            .option_value = option_value,
            .value_segment = value_segment,
            .replace_start = semantic_replace_start,
            .replace_end = replace_end,
            .suspicious_start = if (suspicious) |span| view.offset + span.start else null,
            .suspicious_end = if (suspicious) |span| view.offset + span.end else null,
            .parser_position = parser_context.kind,
            .parser_source_offset = view.offset,
        };
    }

    pub fn completionDiagnosticsForInput(self: *Executor, source: []const u8, cursor: usize) ![]CompletionDiagnostic {
        return self.completionDiagnosticsForInputOptions(source, cursor, .{});
    }

    pub fn completionDiagnosticsForInputOptions(self: *Executor, source: []const u8, cursor: usize, options: ExecuteOptions) ![]CompletionDiagnostic {
        var parsed = try parser.parse(self.allocator, source, .{ .mode = .interactive, .cursor = cursor });
        defer parsed.deinit();
        const clamped_cursor = @min(cursor, source.len);

        var words: std.ArrayList(parser.Token) = .empty;
        defer words.deinit(self.allocator);
        for (parsed.tokens, 0..) |token, token_index| {
            if (token.span.start > clamped_cursor) break;
            if (token.kind != .word) continue;
            switch (parser.nodeKindForToken(parsed, token_index) orelse .word) {
                .assignment_word => {},
                .command_word, .word => try words.append(self.allocator, token),
                else => {},
            }
        }
        if (words.items.len == 0) return self.allocator.alloc(CompletionDiagnostic, 0);

        var diagnostics: std.ArrayList(CompletionDiagnostic) = .empty;
        errdefer diagnostics.deinit(self.allocator);

        const root_token = words.items[0];
        const root = root_token.lexeme(source);
        try self.loadCompletionScriptForRoot(root, options);
        if (root_token.span.end < clamped_cursor and !try self.completionCommandKnown(root, options.io)) {
            try diagnostics.append(self.allocator, .{
                .kind = .unknown_command,
                .severity = .err,
                .start = root_token.span.start,
                .end = root_token.span.end,
                .message = "unknown command",
            });
            return diagnostics.toOwnedSlice(self.allocator);
        }

        var path: std.ArrayList([]const u8) = .empty;
        defer path.deinit(self.allocator);
        var parsed_options: std.ArrayList(CompletionParsedOption) = .empty;
        defer parsed_options.deinit(self.allocator);
        var index: usize = 1;
        var options_terminated = false;
        while (index < words.items.len) : (index += 1) {
            const token = words.items[index];
            if (token.span.end > clamped_cursor) break;
            const word = token.lexeme(source);
            const word_complete = token.span.end < clamped_cursor;
            const has_option_rules = completionContextHasOptions(self.completion_rules.items, root, path.items);
            if (options_terminated) {
                continue;
            } else if (std.mem.eql(u8, word, "--")) {
                options_terminated = true;
            } else if (findCompletionOption(self.completion_rules.items, root, path.items, word)) |matched| {
                if (matchedCompletionOptionSuppression(parsed_options.items, matched)) |suppression| {
                    try diagnostics.append(self.allocator, .{
                        .kind = completionDiagnosticKindForOptionSuppression(suppression),
                        .severity = .err,
                        .start = token.span.start,
                        .end = token.span.end,
                        .message = completionDiagnosticMessageForOptionSuppression(suppression),
                    });
                }
                try appendParsedCompletionOption(self.allocator, &parsed_options, matched);
                if (matched.takes_value and !matched.attached_value) {
                    if (index + 1 >= words.items.len or words.items[index + 1].span.start > clamped_cursor) {
                        try diagnostics.append(self.allocator, .{
                            .kind = .missing_option_value,
                            .severity = .warning,
                            .start = token.span.start,
                            .end = token.span.end,
                            .message = "option requires a value",
                        });
                    } else if (words.items[index + 1].span.end <= clamped_cursor) {
                        index += 1;
                    }
                }
                if (matched.terminates_options) options_terminated = true;
            } else if (if (has_option_rules) analyzeShortOptionCluster(self.completion_rules.items, root, path.items, word) else null) |cluster| {
                if (!cluster.valid) {
                    if (word_complete) {
                        try diagnostics.append(self.allocator, .{
                            .kind = .unknown_option,
                            .severity = .err,
                            .start = token.span.start + (cluster.unknown_offset orelse 0),
                            .end = token.span.end,
                            .message = "unknown option",
                        });
                    }
                } else {
                    if (try appendShortCompletionClusterParsedOptions(self.allocator, &parsed_options, self.completion_rules.items, root, path.items, word)) |suppression| {
                        try diagnostics.append(self.allocator, .{
                            .kind = completionDiagnosticKindForOptionSuppression(suppression),
                            .severity = .err,
                            .start = token.span.start,
                            .end = token.span.end,
                            .message = completionDiagnosticMessageForOptionSuppression(suppression),
                        });
                    }
                    if (shortCompletionClusterTerminatesOptions(self.completion_rules.items, root, path.items, word)) options_terminated = true;
                    if (cluster.takes_next_value) {
                        if (index + 1 >= words.items.len or words.items[index + 1].span.start > clamped_cursor) {
                            try diagnostics.append(self.allocator, .{
                                .kind = .missing_option_value,
                                .severity = .warning,
                                .start = token.span.start,
                                .end = token.span.end,
                                .message = "option requires a value",
                            });
                        } else if (words.items[index + 1].span.end <= clamped_cursor) {
                            index += 1;
                        }
                    }
                }
            } else if (isOptionLike(word)) {
                if (has_option_rules and word_complete and !completionOptionPrefixMatches(self.completion_rules.items, root, path.items, word)) {
                    try diagnostics.append(self.allocator, .{
                        .kind = .unknown_option,
                        .severity = .err,
                        .start = token.span.start,
                        .end = token.span.end,
                        .message = "unknown option",
                    });
                }
            } else if (findCompletionSubcommand(self.completion_rules.items, root, path.items, word)) {
                try path.append(self.allocator, word);
            } else if (completionContextHasSubcommands(self.completion_rules.items, root, path.items)) {
                if (word_complete and !completionSubcommandPrefixMatches(self.completion_rules.items, root, path.items, word)) {
                    try diagnostics.append(self.allocator, .{
                        .kind = .unknown_subcommand,
                        .severity = .err,
                        .start = token.span.start,
                        .end = token.span.end,
                        .message = "unknown subcommand",
                    });
                }
                break;
            } else {
                break;
            }
        }

        return diagnostics.toOwnedSlice(self.allocator);
    }

    pub fn collectCompletionsWithContext(self: *Executor, command: []const u8, context: CompletionEvalContext, options: ExecuteOptions) ![]completion.Candidate {
        if (context.position == .command) return self.collectRootCommandCompletions(context, options);
        _ = command;
        return self.allocator.alloc(completion.Candidate, 0);
    }

    fn collectCompletionsFromFunction(self: *Executor, function: []const u8, command: []const u8, context: CompletionEvalContext, options: ExecuteOptions, companion_path: ?[]const u8) ![]completion.Candidate {
        if (self.completion_builder != null) return error.RecursiveCompletion;
        if (companion_path) |path| {
            if (options.io) |io| try self.ensureCompletionCompanionLoaded(io, path, options);
        }
        if (self.functions.get(function) == null) {
            try self.appendCompletionProviderDiagnostic(function, command, null, error.CompletionProviderFunctionNotFound, "");
            return self.allocator.alloc(completion.Candidate, 0);
        }

        var provider = Executor.init(self.allocator);
        defer provider.deinit();
        try provider.copyStateFrom(self);
        defer provider.cleanupCompletionProviderBackgroundJobs(options.io);

        const function_value = provider.functions.getPtr(function) orelse return self.allocator.alloc(completion.Candidate, 0);
        provider.completion_builder = .{};
        provider.completion_context = context;
        try setCompletionContextVariables(&provider, context);
        errdefer {
            if (provider.completion_builder) |*completion_builder| {
                completion_builder.deinit(self.allocator);
                provider.completion_builder = null;
            }
            provider.completion_context = null;
        }

        var argv = [_]ir.WordRef{
            .{ .raw = function, .text = function, .span = .{ .start = 0, .end = 0 } },
            .{ .raw = command, .text = command, .span = .{ .start = 0, .end = 0 } },
        };
        const call: ir.SimpleCommand = .{ .span = .{ .start = 0, .end = 0 }, .assignments = &.{}, .argv = &argv, .redirections = &.{} };
        var completion_options = options;
        completion_options.external_stdio = .capture;
        var result = provider.executeFunctionBody(call, function_value, completion_options) catch |err| {
            provider.completion_builder.?.deinit(self.allocator);
            provider.completion_builder = null;
            provider.completion_context = null;
            switch (err) {
                error.OutOfMemory => return err,
                else => {
                    try self.appendCompletionProviderDiagnostic(function, command, null, err, "");
                    return self.allocator.alloc(completion.Candidate, 0);
                },
            }
        };
        defer result.deinit();

        var builder = provider.completion_builder.?;
        provider.completion_builder = null;
        errdefer builder.deinit(self.allocator);
        const final_context = provider.completion_context orelse context;
        var stored_context = final_context;
        stored_context.parsed_options = &.{};
        stored_context.operands = &.{};
        self.last_completion_context = stored_context;
        provider.completion_context = null;

        if (result.status != 0) {
            builder.deinit(self.allocator);
            try self.appendCompletionProviderDiagnostic(function, command, result.status, null, result.stderr);
            return self.allocator.alloc(completion.Candidate, 0);
        }

        for (builder.candidates.items) |*candidate| {
            if (candidate.replace_start == 0 and candidate.replace_end == 0) {
                candidate.replace_start = final_context.replace_start;
                candidate.replace_end = final_context.replace_end;
            }
        }

        var deduplicated: CompletionBuilder = .{};
        errdefer deduplicated.deinit(self.allocator);
        for (builder.candidates.items) |candidate| try deduplicated.appendCandidateIfMissing(self.allocator, candidate);
        builder.deinit(self.allocator);
        return deduplicated.finish(self.allocator);
    }

    fn cleanupCompletionProviderBackgroundJobs(self: *Executor, io: ?std.Io) void {
        const real_io = io orelse return;
        for (self.background_jobs.items) |*job| {
            if (job.state == .done) continue;
            if (job.pgrp) |pgrp| switch (zig_builtin.os.tag) {
                .windows, .wasi => {},
                else => std.posix.kill(@intCast(-pgrp), .TERM) catch {},
            };
            job.child.kill(real_io);
            job.state = .done;
        }
    }

    fn collectRootCommandCompletions(self: *Executor, context: CompletionEvalContext, options: ExecuteOptions) ![]completion.Candidate {
        self.last_completion_context = context;
        var builder: CompletionBuilder = .{};
        errdefer builder.deinit(self.allocator);
        var seen: std.StringHashMapUnmanaged(void) = .empty;
        defer deinitSeenCompletionNames(self.allocator, &seen);

        var alias_iter = self.aliases.iterator();
        while (alias_iter.next()) |entry| {
            try appendRootCommandCandidate(self.allocator, &builder, &seen, entry.key_ptr.*, .command, "alias", context);
        }

        var function_iter = self.functions.iterator();
        while (function_iter.next()) |entry| {
            try appendRootCommandCandidate(self.allocator, &builder, &seen, entry.key_ptr.*, .function, "function", context);
        }

        for (builtin_names) |name| {
            try appendRootCommandCandidate(self.allocator, &builder, &seen, name, .builtin, "builtin", context);
        }

        if (options.io) |io| {
            const path = self.getEnv("PATH") orelse "";
            var path_iter = std.mem.splitScalar(u8, path, ':');
            while (path_iter.next()) |path_dir| {
                if (path_dir.len == 0) continue;
                var dir = std.Io.Dir.cwd().openDir(io, path_dir, .{ .iterate = true }) catch continue;
                errdefer dir.close(io);
                var iterator = dir.iterate();
                while (iterator.next(io) catch null) |entry| {
                    try appendRootCommandCandidate(self.allocator, &builder, &seen, entry.name, .command, "executable", context);
                }
                dir.close(io);
            }
        }

        return builder.finish(self.allocator);
    }

    fn appendStructuredCompletionCandidates(self: *Executor, builder: *CompletionBuilder, context: CompletionSemanticContext) !void {
        for (self.completion_rules.items) |rule| {
            switch (rule.kind) {
                .dynamic_subcommands, .dynamic_options, .dynamic_argument, .dynamic_option_value => {},
                .subcommand => {
                    if (context.position != .subcommand) continue;
                    if (!completionRuleContextMatches(rule, context.root, context.path)) continue;
                    const value = rule.value orelse continue;
                    try self.appendStructuredCompletionCandidate(builder, value, rule.description, .subcommand, null, context, true);
                },
                .option => {
                    if (context.position != .option and !(context.position == .subcommand and context.prefix.len == 0)) continue;
                    if (context.position == .subcommand and context.prefix.len == 0) {
                        if (!completionRuleContextMatches(rule, context.root, context.path)) continue;
                    } else if (!completionOptionRuleContextAppliesToPath(rule, context.root, context.path)) continue;
                    if (rule.option.long) |long| {
                        if (completionOptionSuppressionForOption(context, rule.option) != null) continue;
                        var spelling_buffer: [256]u8 = undefined;
                        const value = std.fmt.bufPrint(&spelling_buffer, "--{s}", .{long}) catch continue;
                        try self.appendStructuredCompletionCandidate(builder, value, rule.description, .option, rule.option, context, rule.option.argument == null and !rule.option.no_space);
                    }
                    if (rule.option.short) |short| {
                        if (rule.option.long != null and context.prefix.len == 0) continue;
                        if (completionOptionSuppressionForOption(context, rule.option) != null) continue;
                        var spelling_buffer: [32]u8 = undefined;
                        const value = std.fmt.bufPrint(&spelling_buffer, "-{s}", .{short}) catch continue;
                        try self.appendStructuredCompletionCandidate(builder, value, rule.description, .option, rule.option, context, rule.option.argument == null and !rule.option.no_space);
                    }
                },
            }
        }
    }

    fn appendBuiltinCompletionCandidates(self: *Executor, builder: *CompletionBuilder, context: CompletionSemanticContext, options: ExecuteOptions) !void {
        if (context.position == .option_value) {
            if (std.mem.eql(u8, context.root, "set") and context.option_value != null and (std.mem.eql(u8, context.option_value.?.spelling, "-o") or std.mem.eql(u8, context.option_value.?.spelling, "+o"))) {
                try self.appendSetOptionNameCandidates(builder, context);
            }
            return;
        }
        if (std.mem.eql(u8, context.root, "set") and (std.mem.eql(u8, context.previous, "-o") or std.mem.eql(u8, context.previous, "+o"))) {
            try self.appendSetOptionNameCandidates(builder, context);
            return;
        }
        if (context.position == .option or (std.mem.eql(u8, context.root, "set") and std.mem.startsWith(u8, context.prefix, "+"))) {
            try self.appendBuiltinOptionCandidates(builder, context);
        }
        if (context.position != .subcommand and context.position != .argument) return;

        if (std.mem.eql(u8, context.root, "cd")) {
            if (options.io) |io| try appendPathCandidates(self, builder, io, context.prefix, context.replace_start, context.replace_end, null, true, true);
        } else if (std.mem.eql(u8, context.root, ".") or std.mem.eql(u8, context.root, "source")) {
            if (options.io) |io| try appendPathCandidates(self, builder, io, context.prefix, context.replace_start, context.replace_end, null, false, false);
        } else if (std.mem.eql(u8, context.root, "read") or std.mem.eql(u8, context.root, "export") or std.mem.eql(u8, context.root, "readonly")) {
            try self.appendVariableCandidates(builder, context);
        } else if (std.mem.eql(u8, context.root, "unset")) {
            if (builtinCompletionSawWord(context, "-f")) try self.appendFunctionCandidates(builder, context) else try self.appendVariableCandidates(builder, context);
        } else if (std.mem.eql(u8, context.root, "unalias")) {
            try self.appendAliasCandidates(builder, context);
        } else if (std.mem.eql(u8, context.root, "fg") or std.mem.eql(u8, context.root, "bg") or std.mem.eql(u8, context.root, "jobs")) {
            try self.appendJobCandidates(builder, context);
        } else if (std.mem.eql(u8, context.root, "wait")) {
            try self.appendJobPidCandidates(builder, context);
        } else if (std.mem.eql(u8, context.root, "trap")) {
            try self.appendSignalCandidates(builder, context);
        } else if (std.mem.eql(u8, context.root, "command") or std.mem.eql(u8, context.root, "env")) {
            if (!std.mem.endsWith(u8, context.prefix, "=")) try self.appendCommandNameCandidates(builder, context, options);
        } else if (std.mem.eql(u8, context.root, "test") or std.mem.eql(u8, context.root, "[")) {
            try appendStaticValueCandidates(self, builder, context, &test_operators, .plain, false);
        }
    }

    fn appendBuiltinOptionCandidates(self: *Executor, builder: *CompletionBuilder, context: CompletionSemanticContext) !void {
        if (std.mem.eql(u8, context.root, "command")) return appendStaticValueCandidates(self, builder, context, &.{ "-p", "-v", "-V", "--" }, .option, true);
        if (std.mem.eql(u8, context.root, "cd") or std.mem.eql(u8, context.root, "pwd")) return appendStaticValueCandidates(self, builder, context, &.{ "-L", "-P", "--" }, .option, true);
        if (std.mem.eql(u8, context.root, "read")) return appendStaticValueCandidates(self, builder, context, &.{ "-r", "--" }, .option, true);
        if (std.mem.eql(u8, context.root, "export") or std.mem.eql(u8, context.root, "readonly")) return appendStaticValueCandidates(self, builder, context, &.{ "-p", "--" }, .option, true);
        if (std.mem.eql(u8, context.root, "unset")) return appendStaticValueCandidates(self, builder, context, &.{ "-f", "-v", "--" }, .option, true);
        if (std.mem.eql(u8, context.root, "env")) return appendStaticValueCandidates(self, builder, context, &.{ "-i", "--" }, .option, true);
        if (std.mem.eql(u8, context.root, "set")) return appendStaticValueCandidates(self, builder, context, &set_options, .option, true);
        if (std.mem.eql(u8, context.root, "trap")) return appendStaticValueCandidates(self, builder, context, &.{"--"}, .option, true);
        if (std.mem.eql(u8, context.root, "ulimit")) return appendStaticValueCandidates(self, builder, context, &.{ "-H", "-S", "-a", "-c", "-d", "-f", "-n", "-s", "-v", "-t", "--" }, .option, true);
        if (std.mem.eql(u8, context.root, "umask")) return appendStaticValueCandidates(self, builder, context, &.{ "-S", "--" }, .option, true);
        if (std.mem.eql(u8, context.root, "unalias")) return appendStaticValueCandidates(self, builder, context, &.{ "-a", "--" }, .option, true);
        if (std.mem.eql(u8, context.root, "jobs")) return appendStaticValueCandidates(self, builder, context, &.{ "-l", "-p", "--" }, .option, true);
        if (std.mem.eql(u8, context.root, "printf") or std.mem.eql(u8, context.root, "wait")) return appendStaticValueCandidates(self, builder, context, &.{"--"}, .option, true);
    }

    fn appendVariableCandidates(self: *Executor, builder: *CompletionBuilder, context: CompletionSemanticContext) !void {
        var iter = self.env.iterator();
        while (iter.next()) |entry| try appendCompletionValue(self, builder, context, entry.key_ptr.*, .variable, true);
    }

    fn appendFunctionCandidates(self: *Executor, builder: *CompletionBuilder, context: CompletionSemanticContext) !void {
        var iter = self.functions.iterator();
        while (iter.next()) |entry| try appendCompletionValue(self, builder, context, entry.key_ptr.*, .function, true);
    }

    fn appendAliasCandidates(self: *Executor, builder: *CompletionBuilder, context: CompletionSemanticContext) !void {
        var iter = self.aliases.iterator();
        while (iter.next()) |entry| try appendCompletionValue(self, builder, context, entry.key_ptr.*, .command, true);
    }

    fn appendJobCandidates(self: *Executor, builder: *CompletionBuilder, context: CompletionSemanticContext) !void {
        self.refreshBackgroundJobs();
        if (self.current_job_id != null) try appendCompletionValue(self, builder, context, "%+", .plain, true);
        if (self.previous_job_id != null) try appendCompletionValue(self, builder, context, "%-", .plain, true);
        for (self.background_jobs.items) |job| {
            const spec = try std.fmt.allocPrint(self.allocator, "%{d}", .{job.id});
            defer self.allocator.free(spec);
            try appendCompletionValue(self, builder, context, spec, .plain, true);
        }
    }

    fn appendJobPidCandidates(self: *Executor, builder: *CompletionBuilder, context: CompletionSemanticContext) !void {
        self.refreshBackgroundJobs();
        for (self.background_jobs.items) |job| {
            const pid = try std.fmt.allocPrint(self.allocator, "{d}", .{job.pid});
            defer self.allocator.free(pid);
            try appendCompletionValue(self, builder, context, pid, .plain, true);
        }
    }

    fn appendSignalCandidates(self: *Executor, builder: *CompletionBuilder, context: CompletionSemanticContext) !void {
        try appendStaticValueCandidates(self, builder, context, &signal_names, .plain, true);
    }

    fn appendSetOptionNameCandidates(self: *Executor, builder: *CompletionBuilder, context: CompletionSemanticContext) !void {
        try appendStaticValueCandidates(self, builder, context, &set_option_names, .plain, true);
    }

    fn appendCommandNameCandidates(self: *Executor, builder: *CompletionBuilder, context: CompletionSemanticContext, options: ExecuteOptions) !void {
        var seen: std.StringHashMapUnmanaged(void) = .empty;
        defer deinitSeenCompletionNames(self.allocator, &seen);
        for (builtin_names) |name| try appendSeenCommandCandidate(self, builder, &seen, context, name, .builtin, "builtin");
        var function_iter = self.functions.iterator();
        while (function_iter.next()) |entry| try appendSeenCommandCandidate(self, builder, &seen, context, entry.key_ptr.*, .function, "function");
        var alias_iter = self.aliases.iterator();
        while (alias_iter.next()) |entry| try appendSeenCommandCandidate(self, builder, &seen, context, entry.key_ptr.*, .command, "alias");
        if (options.io) |io| try self.appendExecutableCommandCandidates(builder, &seen, context, io);
    }

    fn appendExecutableCommandCandidates(self: *Executor, builder: *CompletionBuilder, seen: *std.StringHashMapUnmanaged(void), context: CompletionSemanticContext, io: std.Io) !void {
        const path = self.getEnv("PATH") orelse return;
        var path_iter = std.mem.splitScalar(u8, path, ':');
        while (path_iter.next()) |path_dir| {
            if (path_dir.len == 0) continue;
            var dir = std.Io.Dir.cwd().openDir(io, path_dir, .{ .iterate = true }) catch continue;
            errdefer dir.close(io);
            var iterator = dir.iterate();
            while (iterator.next(io) catch null) |entry| {
                try appendSeenCommandCandidate(self, builder, seen, context, entry.name, .command, "executable");
            }
            dir.close(io);
        }
    }

    fn appendSeenCommandCandidate(self: *Executor, builder: *CompletionBuilder, seen: *std.StringHashMapUnmanaged(void), context: CompletionSemanticContext, value: []const u8, kind: completion.Kind, description: []const u8) !void {
        if (completion.fuzzyMatchRank(value, context.prefix) == null) return;
        if (seen.contains(value)) return;
        const seen_value = try self.allocator.dupe(u8, value);
        errdefer self.allocator.free(seen_value);
        try seen.put(self.allocator, seen_value, {});
        try builder.appendCandidateIfMissing(self.allocator, .{ .value = value, .kind = kind, .description = description, .replace_start = context.replace_start, .replace_end = context.replace_end });
    }

    fn appendStaticValueCandidates(self: *Executor, builder: *CompletionBuilder, context: CompletionSemanticContext, values: []const []const u8, kind: completion.Kind, append_space: bool) !void {
        for (values) |value| try appendCompletionValue(self, builder, context, value, kind, append_space);
    }

    fn appendCompletionValue(self: *Executor, builder: *CompletionBuilder, context: CompletionSemanticContext, value: []const u8, kind: completion.Kind, append_space: bool) !void {
        if (completion.fuzzyMatchRank(value, context.prefix) == null) return;
        try builder.appendCandidateIfMissing(self.allocator, .{ .value = value, .kind = kind, .replace_start = context.replace_start, .replace_end = context.replace_end, .append_space = append_space });
    }

    fn appendStructuredCompletionCandidate(
        self: *Executor,
        builder: *CompletionBuilder,
        value: []const u8,
        description: ?[]const u8,
        kind: completion.Kind,
        option: ?completion.Option,
        context: CompletionSemanticContext,
        append_space: bool,
    ) !void {
        if (completion.fuzzyMatchRank(value, context.prefix) == null) return;
        try builder.appendCandidateIfMissing(self.allocator, .{
            .value = value,
            .description = description,
            .kind = kind,
            .option = option,
            .replace_start = context.replace_start,
            .replace_end = context.replace_end,
            .append_space = append_space,
        });
    }

    fn appendDynamicStructuredCompletionCandidates(self: *Executor, builder: *CompletionBuilder, context: CompletionEvalContext, semantic: CompletionSemanticContext, options: ExecuteOptions) !void {
        for (self.completion_rules.items) |rule| {
            if (!completionDynamicRuleMatches(rule, semantic)) continue;
            var provider_context = context;
            provider_context.position = switch (rule.kind) {
                .dynamic_argument => .argument,
                .dynamic_subcommands => .argument,
                .dynamic_options => .argument,
                .dynamic_option_value => .argument,
                else => provider_context.position,
            };
            if (rule.kind == .dynamic_argument and !rule.value_grammar.isEmpty()) {
                provider_context = completionEvalContextWithValueGrammar(provider_context, rule.value_grammar);
            }
            switch (rule.provider_kind) {
                .function => {
                    const function = rule.value orelse continue;
                    const candidates = try self.collectCompletionsFromFunction(function, context.command, provider_context, options, rule.source.companion_path);
                    defer self.freeCompletions(candidates);
                    for (candidates) |candidate| {
                        if (completionOptionCandidateSuppression(self.completion_rules.items, semantic, candidate) != null) continue;
                        try builder.appendCandidateIfMissing(self.allocator, candidate);
                    }
                },
                .builtin_files, .builtin_directories, .builtin_executables, .builtin_variables => {
                    try self.appendBuiltinProviderCompletionCandidates(builder, rule.provider_kind, provider_context, options);
                },
            }
        }
    }

    fn appendBuiltinProviderCompletionCandidates(self: *Executor, builder: *CompletionBuilder, provider_kind: completion.ProviderKind, context: CompletionEvalContext, options: ExecuteOptions) !void {
        self.last_completion_context = context;
        switch (provider_kind) {
            .function => {},
            .builtin_files => {
                const io = options.io orelse return;
                try appendPathCandidates(self, builder, io, context.prefix, context.replace_start, context.replace_end, null, false, false);
            },
            .builtin_directories => {
                const io = options.io orelse return;
                try appendPathCandidates(self, builder, io, context.prefix, context.replace_start, context.replace_end, null, true, true);
            },
            .builtin_executables => {
                const io = options.io orelse return;
                var seen: std.StringHashMapUnmanaged(void) = .empty;
                defer deinitSeenCompletionNames(self.allocator, &seen);
                const path = self.getEnv("PATH") orelse return;
                var path_iter = std.mem.splitScalar(u8, path, ':');
                while (path_iter.next()) |path_dir| {
                    if (path_dir.len == 0) continue;
                    var dir = std.Io.Dir.cwd().openDir(io, path_dir, .{ .iterate = true }) catch continue;
                    errdefer dir.close(io);
                    var iterator = dir.iterate();
                    while (iterator.next(io) catch null) |entry| {
                        if (completion.fuzzyMatchRank(entry.name, context.prefix) == null) continue;
                        if (seen.contains(entry.name)) continue;
                        const seen_name = try self.allocator.dupe(u8, entry.name);
                        errdefer self.allocator.free(seen_name);
                        try seen.put(self.allocator, seen_name, {});
                        try builder.appendCandidateIfMissing(self.allocator, .{ .value = entry.name, .kind = .command, .replace_start = context.replace_start, .replace_end = context.replace_end });
                    }
                    dir.close(io);
                }
            },
            .builtin_variables => {
                var iter = self.env.iterator();
                while (iter.next()) |entry| {
                    if (completion.fuzzyMatchRank(entry.key_ptr.*, context.prefix) != null) {
                        try builder.appendCandidateIfMissing(self.allocator, .{ .value = entry.key_ptr.*, .kind = .variable, .replace_start = context.replace_start, .replace_end = context.replace_end });
                    }
                }
            },
        }
    }

    fn appendDefaultCompletionCandidates(self: *Executor, builder: *CompletionBuilder, context: CompletionSemanticContext, options: ExecuteOptions) !void {
        if (builder.candidates.items.len != 0 and context.position != .redirect_target) return;
        const io = options.io orelse return;
        switch (context.position) {
            .redirect_target => try appendPathCandidates(self, builder, io, context.prefix, context.replace_start, context.replace_end, null, false, false),
            .subcommand, .argument => {
                if (std.mem.eql(u8, context.root, "cd")) return;
                if (self.hasExplicitCompletionRuleForContext(context)) return;
                try appendPathCandidates(self, builder, io, context.prefix, context.replace_start, context.replace_end, null, false, false);
            },
            .option_value => {
                if (self.hasExplicitCompletionRuleForContext(context)) return;
                try appendPathCandidates(self, builder, io, context.prefix, context.replace_start, context.replace_end, null, false, false);
            },
            .command, .option => {},
        }
    }

    fn hasExplicitCompletionRuleForContext(self: Executor, context: CompletionSemanticContext) bool {
        for (self.completion_rules.items) |rule| {
            switch (rule.kind) {
                .dynamic_argument => if (completionDynamicRuleMatches(rule, context)) return true,
                .dynamic_option_value => if (context.position == .option_value and completionDynamicRuleMatches(rule, context)) return true,
                .subcommand => if (context.position == .subcommand and completionRuleContextMatches(rule, context.root, context.path)) return true,
                .dynamic_subcommands => if (context.position == .subcommand and completionDynamicRuleMatches(rule, context)) return true,
                .option, .dynamic_options => {},
            }
        }
        return false;
    }

    pub fn freeCompletions(self: *Executor, candidates: []completion.Candidate) void {
        for (candidates) |candidate| {
            self.allocator.free(candidate.value);
            if (candidate.display) |display| self.allocator.free(display);
            if (candidate.insert) |insert| self.allocator.free(insert);
            if (candidate.description) |description| self.allocator.free(description);
            if (candidate.option) |option| {
                if (option.long) |long| self.allocator.free(long);
                if (option.short) |short| self.allocator.free(short);
                if (option.argument) |argument| self.allocator.free(argument);
                if (option.exclusive_group) |group| self.allocator.free(group);
            }
        }
        self.allocator.free(candidates);
    }

    pub fn freeCompletionDiagnostics(self: *Executor, diagnostics: []CompletionDiagnostic) void {
        self.allocator.free(diagnostics);
    }

    pub fn renderPrompt(self: *Executor, options: ExecuteOptions, fallback: []const u8) ![]const u8 {
        if (!self.hasFunction("rush_prompt")) return self.allocator.dupe(u8, fallback);

        if (self.prompt_builder != null) return error.RecursivePrompt;
        const saved_prompt_async_owner = self.prompt_async_owner;
        const saved_last_status_text = self.last_status_text;
        const saved_last_status_text_len = self.last_status_text_len;
        self.prompt_async_owner = self;
        defer {
            self.prompt_async_owner = saved_prompt_async_owner;
            self.last_status_text = saved_last_status_text;
            self.last_status_text_len = saved_last_status_text_len;
        }
        self.prompt_refresh_interval_ms = null;
        self.prompt_builder = .{};
        errdefer {
            self.prompt_builder.?.deinit(self.allocator);
            self.prompt_builder = null;
        }

        var prompt_options = options;
        prompt_options.external_stdio = .capture;
        var result = try self.executeScriptSlice("rush_prompt", prompt_options);
        defer result.deinit();

        var builder = self.prompt_builder.?;
        self.prompt_builder = null;
        defer builder.deinit(self.allocator);
        self.prompt_refresh_interval_ms = builder.refresh_interval_ms;

        if (builder.used) return builder.text.toOwnedSlice(self.allocator);
        return self.allocator.dupe(u8, result.stdout);
    }

    pub fn getEnv(self: Executor, name: []const u8) ?[]const u8 {
        return self.env.get(name);
    }

    fn logicalCwd(self: *Executor, io: std.Io) ![:0]u8 {
        if (self.getEnv("PWD")) |pwd| {
            if (self.validLogicalPwd(pwd)) return self.allocator.dupeZ(u8, pwd);
        }
        return std.process.currentPathAlloc(io, self.allocator);
    }

    pub fn setArrayElement(self: *Executor, name: []const u8, index: usize, value: []const u8) !void {
        if (self.isReadonly(name)) return error.ReadonlyVariable;
        const owned_name = try self.allocator.dupe(u8, name);
        errdefer self.allocator.free(owned_name);
        const result = try self.arrays.getOrPut(self.allocator, owned_name);
        if (result.found_existing) {
            self.allocator.free(owned_name);
        } else {
            result.value_ptr.* = .{};
        }
        const array = result.value_ptr;
        while (array.values.items.len <= index) {
            try array.values.append(self.allocator, try self.allocator.alloc(u8, 0));
        }
        self.allocator.free(array.values.items[index]);
        array.values.items[index] = try self.allocator.dupe(u8, value);
    }

    pub fn getArrayElement(self: Executor, name: []const u8, index: usize) ?[]const u8 {
        const array = self.arrays.get(name) orelse return null;
        if (index >= array.values.items.len) return null;
        return array.values.items[index];
    }

    pub fn unsetArray(self: *Executor, name: []const u8) void {
        self.removeArray(name);
    }

    fn cloneArray(self: *Executor, name: []const u8) !?ArrayValue {
        const array = self.arrays.get(name) orelse return null;
        var clone: ArrayValue = .{};
        errdefer clone.deinit(self.allocator);
        for (array.values.items) |value| {
            try clone.values.append(self.allocator, try self.allocator.dupe(u8, value));
        }
        return clone;
    }

    fn removeArray(self: *Executor, name: []const u8) void {
        if (self.arrays.fetchRemove(name)) |entry| {
            self.allocator.free(entry.key);
            var value = entry.value;
            value.deinit(self.allocator);
        }
    }

    fn restoreArray(self: *Executor, name: []const u8, old_value: ?ArrayValue) void {
        self.removeArray(name);
        if (old_value) |old| {
            var value = old;
            const owned_name = self.allocator.dupe(u8, name) catch {
                value.deinit(self.allocator);
                return;
            };
            self.arrays.put(self.allocator, owned_name, value) catch {
                self.allocator.free(owned_name);
                value.deinit(self.allocator);
                return;
            };
        }
    }

    pub fn unsetEnv(self: *Executor, name: []const u8) void {
        if (self.isReadonly(name)) return;
        self.unsetExported(name);
        if (self.env.fetchRemove(name)) |entry| {
            self.allocator.free(entry.key);
            self.allocator.free(entry.value);
            if (std.mem.eql(u8, name, "PATH")) self.clearCommandHash();
            self.queueVariableHook(name);
        }
    }

    fn isExported(self: Executor, name: []const u8) bool {
        return self.exported.contains(name);
    }

    pub fn setExported(self: *Executor, name: []const u8) !void {
        if (self.exported.contains(name)) return;
        try self.exported.put(self.allocator, try self.allocator.dupe(u8, name), {});
    }

    fn unsetExported(self: *Executor, name: []const u8) void {
        if (self.exported.fetchRemove(name)) |entry| self.allocator.free(entry.key);
    }

    fn restoreExported(self: *Executor, name: []const u8, exported: bool) !void {
        if (exported) try self.setExported(name) else self.unsetExported(name);
    }

    fn unsetFunction(self: *Executor, name: []const u8) void {
        if (self.functions.fetchRemove(name)) |entry| {
            self.allocator.free(entry.key);
            var value = entry.value;
            value.deinit(self.allocator);
        }
    }

    pub fn isReadonly(self: Executor, name: []const u8) bool {
        return self.readonly.contains(name);
    }

    pub fn setReadonly(self: *Executor, name: []const u8) !void {
        if (self.readonly.contains(name)) return;
        try self.readonly.put(self.allocator, try self.allocator.dupe(u8, name), {});
    }

    pub fn setEnv(self: *Executor, name: []const u8, value: []const u8) !void {
        if (self.isReadonly(name)) return error.ReadonlyVariable;
        try self.setEnvInternal(name, value);
    }

    pub fn setRushStateVariable(self: *Executor, name: []const u8, value: []const u8) !void {
        try self.setEnvInternal(name, value);
    }

    fn setEnvInternal(self: *Executor, name: []const u8, value: []const u8) !void {
        const owned_name = try self.allocator.dupe(u8, name);
        errdefer self.allocator.free(owned_name);
        const owned_value = try self.allocator.dupe(u8, value);
        errdefer self.allocator.free(owned_value);

        const result = try self.env.getOrPut(self.allocator, owned_name);
        if (result.found_existing) {
            self.allocator.free(owned_name);
            self.allocator.free(result.key_ptr.*);
            self.allocator.free(result.value_ptr.*);
            result.key_ptr.* = try self.allocator.dupe(u8, name);
            result.value_ptr.* = owned_value;
        } else {
            result.value_ptr.* = owned_value;
        }
        if (std.mem.eql(u8, name, "PATH")) self.clearCommandHash();
        self.queueVariableHook(name);
    }

    fn shouldSkipForNoexec(self: Executor, options: ExecuteOptions) bool {
        return self.shell_options.noexec and !options.interactive;
    }

    pub fn executeProgram(self: *Executor, program: ir.Program, options: ExecuteOptions) anyerror!CommandResult {
        const root_execution = self.execution_depth == 0;
        if (root_execution) self.pending_command_abort = false;
        defer {
            if (root_execution) self.pending_command_abort = false;
        }
        self.execution_depth += 1;
        defer self.execution_depth -= 1;

        var stdout: std.ArrayList(u8) = .empty;
        errdefer stdout.deinit(self.allocator);
        var stderr: std.ArrayList(u8) = .empty;
        errdefer stderr.deinit(self.allocator);
        var last_status: ExitStatus = 0;
        var last_errexit_ignored_status = false;
        var verbose_read_offset: usize = 0;

        if (program.statements.len > 0) {
            for (program.statements, 0..) |statement, statement_index| {
                try checkCanceled(options);
                const next_start = if (statement_index + 1 < program.statements.len) program.statements[statement_index + 1].span.start else program.source.len;
                try self.appendOrWriteVerboseInput(options, &stderr, program.source, &verbose_read_offset, statement.span.start, next_start);
                if (self.shouldSkipForNoexec(options)) break;
                if (shouldSkipPipeline(statement.op_before, last_status)) continue;
                self.setCurrentLineNumber(program.source, statement.span.start);
                var statement_options = options;
                statement_options.verbose_input_echo = false;
                var result = (if (statement.async_after)
                    self.executeAsyncStatement(program, statement, statement_options)
                else
                    self.executeStatementSync(program, statement, statement_options)) catch |err| return self.finishExpansionErrorProgram(root_execution, options, &stdout, &stderr, err);
                defer result.deinit();
                try self.annotateSourcedError(program.source, statement.span.start, options, &result);
                const result_status = try self.appendOrWriteResultStatus(options, &stdout, &stderr, result);
                const result_errexit_ignored_status = result.errexit_ignored_status;
                try self.dispatchPendingSignalTrap(options, &stdout, &stderr);
                last_status = self.pending_exit orelse result_status;
                self.setLastStatus(last_status);
                const negated_pipeline = statement.kind == .pipeline and program.pipelines[statement.index].negated;
                const ignored_status = self.applyErrexit(last_status, options, negated_pipeline or isFollowedByAndOrListOp(program.statements, statement_index), result_errexit_ignored_status);
                result.errexit_ignored_status = ignored_status;
                last_errexit_ignored_status = ignored_status;
                if (self.pending_exit != null or self.pending_return != null or self.pending_loop_control != null or self.pending_command_abort) break;
            }
            return self.finishExecuteProgram(root_execution, options, .{ .allocator = self.allocator, .status = last_status, .stdout = try stdout.toOwnedSlice(self.allocator), .stderr = try stderr.toOwnedSlice(self.allocator), .errexit_ignored_status = last_errexit_ignored_status });
        }

        if (program.pipelines.len > 0) {
            for (program.pipelines, 0..) |pipeline, pipeline_index| {
                try checkCanceled(options);
                const next_start = if (pipeline_index + 1 < program.pipelines.len) program.pipelines[pipeline_index + 1].span.start else program.source.len;
                try self.appendOrWriteVerboseInput(options, &stderr, program.source, &verbose_read_offset, pipeline.span.start, next_start);
                if (self.shouldSkipForNoexec(options)) break;
                if (shouldSkipPipeline(pipeline.op_before, last_status)) continue;
                self.setCurrentLineNumber(program.source, pipeline.span.start);
                var pipeline_options = options;
                pipeline_options.verbose_input_echo = false;
                var result = (if (pipeline.async_after)
                    self.executeAsyncPipeline(program, pipeline, pipeline_options)
                else
                    self.executePipeline(program, pipeline, pipeline_options)) catch |err| return self.finishExpansionErrorProgram(root_execution, options, &stdout, &stderr, err);
                defer result.deinit();
                try self.annotateSourcedError(program.source, pipeline.span.start, options, &result);
                const result_status = try self.appendOrWriteResultStatus(options, &stdout, &stderr, result);
                const result_errexit_ignored_status = result.errexit_ignored_status;
                try self.dispatchPendingSignalTrap(options, &stdout, &stderr);
                last_status = self.pending_exit orelse result_status;
                self.setLastStatus(last_status);
                const ignored_status = self.applyErrexit(last_status, options, pipeline.negated or isPipelineFollowedByAndOrListOp(program.pipelines, pipeline_index), result_errexit_ignored_status);
                result.errexit_ignored_status = ignored_status;
                last_errexit_ignored_status = ignored_status;
                if (self.pending_exit != null or self.pending_return != null or self.pending_loop_control != null or self.pending_command_abort) break;
            }
            return self.finishExecuteProgram(root_execution, options, .{ .allocator = self.allocator, .status = last_status, .stdout = try stdout.toOwnedSlice(self.allocator), .stderr = try stderr.toOwnedSlice(self.allocator), .errexit_ignored_status = last_errexit_ignored_status });
        }

        for (program.commands, 0..) |command, command_index| {
            try checkCanceled(options);
            const next_start = if (command_index + 1 < program.commands.len) program.commands[command_index + 1].span.start else program.source.len;
            try self.appendOrWriteVerboseInput(options, &stderr, program.source, &verbose_read_offset, command.span.start, next_start);
            if (self.shouldSkipForNoexec(options)) break;
            self.setCurrentLineNumber(program.source, command.span.start);
            var command_options = options;
            command_options.verbose_input_echo = false;
            var result = self.executeSimpleCommand(command, command_options) catch |err| return self.finishExpansionErrorProgram(root_execution, options, &stdout, &stderr, err);
            defer result.deinit();
            try self.annotateSourcedError(program.source, command.span.start, options, &result);
            const result_status = try self.appendOrWriteResultStatus(options, &stdout, &stderr, result);
            const result_errexit_ignored_status = result.errexit_ignored_status;
            try self.dispatchPendingSignalTrap(options, &stdout, &stderr);
            last_status = self.pending_exit orelse result_status;
            self.setLastStatus(last_status);
            const ignored_status = self.applyErrexit(last_status, options, false, result_errexit_ignored_status);
            result.errexit_ignored_status = ignored_status;
            last_errexit_ignored_status = ignored_status;
            if (self.pending_exit != null or self.pending_return != null or self.pending_loop_control != null or self.pending_command_abort) break;
        }
        return self.finishExecuteProgram(root_execution, options, .{ .allocator = self.allocator, .status = last_status, .stdout = try stdout.toOwnedSlice(self.allocator), .stderr = try stderr.toOwnedSlice(self.allocator), .errexit_ignored_status = last_errexit_ignored_status });
    }

    fn finishExpansionErrorProgram(self: *Executor, root_execution: bool, options: ExecuteOptions, stdout: *std.ArrayList(u8), stderr: *std.ArrayList(u8), err: anyerror) !CommandResult {
        var failure = switch (err) {
            error.NounsetParameter, error.ParameterExpansionFailed, error.ArithmeticExpansionFailed => try self.expansionErrorResult(err, options),
            else => return err,
        };
        defer failure.deinit();
        try self.appendOrWriteResult(options, stdout, stderr, failure);
        const status = self.pending_exit orelse failure.status;
        self.setLastStatus(status);
        return self.finishExecuteProgram(root_execution, options, .{ .allocator = self.allocator, .status = status, .stdout = try stdout.toOwnedSlice(self.allocator), .stderr = try stderr.toOwnedSlice(self.allocator) });
    }

    fn annotateSourcedError(self: *Executor, source: []const u8, offset: usize, options: ExecuteOptions, result: *CommandResult) !void {
        if (result.status == 0 or result.stderr.len == 0) return;
        const path = options.source_path orelse return;
        const line = sourceLineNumber(source, offset);
        const annotated = try std.fmt.allocPrint(self.allocator, "{s}:{d}: {s}", .{ path, line, result.stderr });
        self.allocator.free(result.stderr);
        result.stderr = annotated;
    }

    pub fn executePendingSignalTrap(self: *Executor, options: ExecuteOptions) !?CommandResult {
        const raw = pending_trap_signal.swap(0, .seq_cst);
        if (raw == 0) return null;
        const name = signalNameFromNumber(raw) orelse return null;
        const action = self.traps.get(name) orelse return null;
        const trap_result = try self.executeScriptSlice(action, options);
        self.setLastStatus(trap_result.status);
        return trap_result;
    }

    fn dispatchPendingSignalTrap(self: *Executor, options: ExecuteOptions, stdout: *std.ArrayList(u8), stderr: *std.ArrayList(u8)) !void {
        var trap_result = (try self.executePendingSignalTrap(options)) orelse return;
        defer trap_result.deinit();
        try stdout.appendSlice(self.allocator, trap_result.stdout);
        try stderr.appendSlice(self.allocator, trap_result.stderr);
    }

    pub fn executeSignalTrap(self: *Executor, name: []const u8, options: ExecuteOptions) !?CommandResult {
        const action = self.traps.get(name) orelse return null;
        return try self.executeScriptSlice(action, options);
    }

    fn finishExecuteProgram(self: *Executor, root_execution: bool, options: ExecuteOptions, result: CommandResult) !CommandResult {
        if (!root_execution or self.running_exit_trap) return result;
        const action = self.traps.get("EXIT") orelse return result;
        var final = result;
        errdefer final.deinit();
        self.running_exit_trap = true;
        defer self.running_exit_trap = false;
        const prior_pending_exit = self.pending_exit;
        self.pending_exit = null;
        var trap_result = self.executeScriptSlice(action, options) catch |err| {
            self.pending_exit = prior_pending_exit;
            return err;
        };
        defer trap_result.deinit();
        const trap_pending_exit = self.pending_exit;
        if (trap_pending_exit == null) self.pending_exit = prior_pending_exit;
        const stdout = try std.mem.concat(self.allocator, u8, &.{ final.stdout, trap_result.stdout });
        errdefer self.allocator.free(stdout);
        const stderr = try std.mem.concat(self.allocator, u8, &.{ final.stderr, trap_result.stderr });
        errdefer self.allocator.free(stderr);
        self.allocator.free(final.stdout);
        self.allocator.free(final.stderr);
        final.stdout = stdout;
        final.stderr = stderr;
        if (trap_pending_exit) |status| final.status = status else if (prior_pending_exit) |status| final.status = status;
        return final;
    }

    fn applyErrexit(self: *Executor, status: ExitStatus, options: ExecuteOptions, suppressed_context: bool, errexit_ignored_status: bool) bool {
        if (!self.shell_options.errexit or status == 0) return false;
        if (options.suppress_errexit or options.ignore_errexit or suppressed_context or errexit_ignored_status) return true;
        self.pending_exit = status;
        return false;
    }

    fn appendOrWriteResultStatus(self: *Executor, options: ExecuteOptions, stdout: *std.ArrayList(u8), stderr: *std.ArrayList(u8), result: CommandResult) !ExitStatus {
        self.appendOrWriteResult(options, stdout, stderr, result) catch |err| {
            if (!isOutputWriteFailure(err)) return err;
            var failure = try self.writeFailureResult(err, false);
            defer failure.deinit();
            try self.appendOrWriteResult(options, stdout, stderr, failure);
            return failure.status;
        };
        return result.status;
    }

    fn appendOrWriteResult(self: *Executor, options: ExecuteOptions, stdout: *std.ArrayList(u8), stderr: *std.ArrayList(u8), result: CommandResult) !void {
        try self.appendOrWriteCommandSubstitutionStderr(options, stderr);
        if (options.external_stdio == .inherit) {
            if (options.io) |io| {
                try writeInheritedResult(io, result);
                return;
            }
        }
        try stdout.appendSlice(self.allocator, result.stdout);
        try stderr.appendSlice(self.allocator, result.stderr);
    }

    fn appendOrWriteVerboseInput(self: *Executor, options: ExecuteOptions, stderr: *std.ArrayList(u8), source: []const u8, read_offset: *usize, statement_start: usize, next_start: usize) !void {
        const read_end = @max(sourceLineReadEnd(source, statement_start), @min(next_start, source.len));
        if (read_end <= read_offset.*) return;
        const bytes = source[read_offset.*..read_end];
        read_offset.* = read_end;
        if (!options.verbose_input_echo or !self.shell_options.verbose) return;
        if (options.external_stdio == .inherit and options.io != null) {
            try rawWriteAll(2, bytes);
        } else {
            try stderr.appendSlice(self.allocator, bytes);
        }
    }

    fn sourceLineReadEnd(source: []const u8, offset: usize) usize {
        var end = @min(offset, source.len);
        while (end < source.len and source[end] != '\n') : (end += 1) {}
        if (end < source.len) end += 1;
        return end;
    }

    fn appendOrWriteCommandSubstitutionStderr(self: *Executor, options: ExecuteOptions, stderr: *std.ArrayList(u8)) !void {
        if (self.command_substitution_stderr.items.len == 0) return;
        if (options.external_stdio == .inherit and options.io != null) {
            try rawWriteAll(2, self.command_substitution_stderr.items);
        } else {
            try stderr.appendSlice(self.allocator, self.command_substitution_stderr.items);
        }
        self.command_substitution_stderr.clearRetainingCapacity();
    }

    fn executeSubshell(self: *Executor, subshell: ir.Subshell, options: ExecuteOptions) !CommandResult {
        var child = Executor.init(self.allocator);
        defer child.deinit();
        try child.copyStateFrom(self);
        try child.resetCaughtTrapsForSubshell();
        const saved_umask = readShellUmask();
        defer restoreShellUmask(saved_umask);
        var owned_stdin: ?[]u8 = null;
        defer if (owned_stdin) |bytes| self.allocator.free(bytes);
        var stdin_file: ?std.Io.File = null;
        defer if (stdin_file) |file| file.close(options.io.?);
        const redirections = try self.expandRedirections(subshell.redirections, options);
        defer self.freeRedirections(redirections);
        const wrapper: ir.SimpleCommand = .{
            .span = subshell.span,
            .assignments = &.{},
            .argv = &.{},
            .redirections = redirections,
        };
        const redirected_stdin = self.applyInputRedirections(wrapper, "", options, &owned_stdin, &stdin_file) catch |err| return self.redirectionErrorResult(wrapper, err, false);
        if (stdin_file) |file| {
            child.script_stdin = null;
            child.script_stdin_offset = 0;
            child.script_stdin_file = file;
        } else if (redirected_stdin.len != 0 or hasInputRedirection(redirections)) {
            child.script_stdin = redirected_stdin;
            child.script_stdin_offset = 0;
            child.script_stdin_file = null;
        }
        if (self.applyRealFdRedirectionsIfNeeded(wrapper, options) catch |err| return self.redirectionErrorResult(wrapper, err, false)) |guard_value| {
            var guard = guard_value;
            defer guard.restore(self, options.io.?);
            if (redirectionsAffectStdin(redirections)) {
                child.script_stdin = null;
                child.script_stdin_offset = 0;
                child.script_stdin_file = std.Io.File.stdin();
            }
            var result = try child.executeScriptSlice(subshell.body, options);
            defer result.deinit();
            writeInheritedResult(options.io.?, result) catch |err| switch (err) {
                error.BadFileDescriptor => return errorResult(self.allocator, 1, "write", "bad file descriptor"),
                error.BrokenPipe, error.NoSpaceLeft, error.InputOutput => return self.writeFailureResult(err, false),
                else => return err,
            };
            return emptyResult(self.allocator, result.status);
        }
        var result = try child.executeScriptSlice(subshell.body, options);
        errdefer result.deinit();
        result.errexit_ignored_status = false;
        return self.applyOutputRedirections(wrapper, result, options, false);
    }

    fn executeBraceGroup(self: *Executor, group: ir.BraceGroup, options: ExecuteOptions) !CommandResult {
        var owned_stdin: ?[]u8 = null;
        defer if (owned_stdin) |bytes| self.allocator.free(bytes);
        var stdin_file: ?std.Io.File = null;
        defer if (stdin_file) |file| file.close(options.io.?);
        const prior_stdin = self.script_stdin;
        const prior_stdin_offset = self.script_stdin_offset;
        const prior_stdin_file = self.script_stdin_file;
        defer {
            self.script_stdin = prior_stdin;
            self.script_stdin_offset = prior_stdin_offset;
            self.script_stdin_file = prior_stdin_file;
        }
        const redirections = try self.expandRedirections(group.redirections, options);
        defer self.freeRedirections(redirections);
        const wrapper: ir.SimpleCommand = .{
            .span = group.span,
            .assignments = &.{},
            .argv = &.{},
            .redirections = redirections,
        };
        const redirected_stdin = self.applyInputRedirections(wrapper, "", options, &owned_stdin, &stdin_file) catch |err| return self.redirectionErrorResult(wrapper, err, false);
        if (stdin_file) |file| {
            self.script_stdin = null;
            self.script_stdin_offset = 0;
            self.script_stdin_file = file;
        } else if (redirected_stdin.len != 0 or hasInputRedirection(redirections)) {
            self.script_stdin = redirected_stdin;
            self.script_stdin_offset = 0;
            self.script_stdin_file = null;
        }
        if (self.applyRealFdRedirectionsIfNeeded(wrapper, options) catch |err| return self.redirectionErrorResult(wrapper, err, false)) |guard_value| {
            var guard = guard_value;
            defer guard.restore(self, options.io.?);
            if (redirectionsAffectStdin(redirections)) {
                self.script_stdin = null;
                self.script_stdin_offset = 0;
                self.script_stdin_file = std.Io.File.stdin();
            }
            var result = try self.executeScriptSlice(group.body, options);
            defer result.deinit();
            writeInheritedResult(options.io.?, result) catch |err| switch (err) {
                error.BadFileDescriptor => return errorResult(self.allocator, 1, "write", "bad file descriptor"),
                error.BrokenPipe, error.NoSpaceLeft, error.InputOutput => return self.writeFailureResult(err, false),
                else => return err,
            };
            return emptyResult(self.allocator, result.status);
        }
        var execution_options = options;
        if (options.external_stdio == .capture_stdout and commandDuplicatesStderrToStdout(redirections)) execution_options.external_stdio = .capture;
        var result = try self.executeScriptSlice(group.body, execution_options);
        errdefer result.deinit();
        return self.applyOutputRedirections(wrapper, result, options, false);
    }

    fn executeBashTestCommand(self: *Executor, command: ir.BashTestCommand, options: ExecuteOptions) !CommandResult {
        const args = try self.expandWords(command.args, options);
        defer self.freeWords(args);
        const matched = evalBashTest(self.allocator, options, args) catch return errorResult(self.allocator, 2, "[[", "invalid expression");
        return emptyResult(self.allocator, if (matched) 0 else 1);
    }

    fn executeFunctionDefinition(self: *Executor, definition: ir.FunctionDefinition) !CommandResult {
        try self.setFunction(definition.name, definition.body, definition.redirections);
        return emptyResult(self.allocator, 0);
    }

    pub fn copyStateFrom(self: *Executor, other: *const Executor) !void {
        self.shell_options = other.shell_options;
        self.getopts_offset = other.getopts_offset;
        self.getopts_last_optind = other.getopts_last_optind;
        self.arg_zero = other.arg_zero;
        self.last_status_text = other.last_status_text;
        self.last_status_text_len = other.last_status_text_len;
        self.lineno_text = other.lineno_text;
        self.lineno_text_len = other.lineno_text_len;
        self.last_command_duration_text = other.last_command_duration_text;
        self.last_command_duration_text_len = other.last_command_duration_text_len;
        self.pid_text = other.pid_text;
        self.pid_text_len = other.pid_text_len;
        self.last_background_pid_text = other.last_background_pid_text;
        self.last_background_pid_text_len = other.last_background_pid_text_len;
        self.prompt_refresh_interval_ms = other.prompt_refresh_interval_ms;
        self.prompt_repaint_handler = other.prompt_repaint_handler;
        self.prompt_async_owner = other.prompt_async_owner orelse @constCast(other);
        self.completion_context = other.completion_context;
        self.last_completion_context = other.last_completion_context;
        self.command_history = other.command_history;
        self.script_stdin = other.script_stdin;
        self.script_stdin_offset = other.script_stdin_offset;
        self.script_stdin_file = other.script_stdin_file;
        var env_iter = other.env.iterator();
        while (env_iter.next()) |entry| try self.setEnv(entry.key_ptr.*, entry.value_ptr.*);
        var exported_iter = other.exported.iterator();
        while (exported_iter.next()) |entry| try self.setExported(entry.key_ptr.*);
        var readonly_iter = other.readonly.iterator();
        while (readonly_iter.next()) |entry| try self.setReadonly(entry.key_ptr.*);
        var open_fd_iter = other.open_fds.iterator();
        while (open_fd_iter.next()) |entry| try self.open_fds.put(self.allocator, entry.key_ptr.*, {});
        var function_iter = other.functions.iterator();
        while (function_iter.next()) |entry| try self.setFunction(entry.key_ptr.*, entry.value_ptr.body, entry.value_ptr.redirections);
        var alias_iter = other.aliases.iterator();
        while (alias_iter.next()) |entry| try self.setAlias(entry.key_ptr.*, entry.value_ptr.*);
        var command_hash_iter = other.command_hash.iterator();
        while (command_hash_iter.next()) |entry| try self.rememberCommandHash(entry.key_ptr.*, entry.value_ptr.*);
        var abbr_iter = other.abbreviations.iterator();
        while (abbr_iter.next()) |entry| try self.setAbbreviation(entry.key_ptr.*, entry.value_ptr.*);
        for (other.completion_rules.items) |rule| try self.registerCompletionRule(rule);
        self.ignored_trap_signals_at_entry = other.ignored_trap_signals_at_entry;
        var trap_iter = other.traps.iterator();
        while (trap_iter.next()) |entry| try self.setTrap(entry.key_ptr.*, entry.value_ptr.*);
        var hook_iter = other.event_hooks.iterator();
        while (hook_iter.next()) |entry| {
            for (entry.value_ptr.items) |hook| try self.addEventHook(entry.key_ptr.*, hook.function);
        }
        for (other.interval_hooks.items) |hook| try self.addIntervalHook(hook.name, hook.interval_ms, hook.function);
        var array_iter = other.arrays.iterator();
        while (array_iter.next()) |entry| {
            for (entry.value_ptr.values.items, 0..) |value, index| {
                try self.setArrayElement(entry.key_ptr.*, index, value);
            }
        }
        try self.global_positionals.set(self.allocator, other.global_positionals.params);
        for (other.call_frames.items) |frame| {
            var copied: CallFrame = .{};
            errdefer copied.deinit(self.allocator);
            try copied.positionals.set(self.allocator, frame.positionals.params);
            try self.call_frames.append(self.allocator, copied);
        }
    }

    fn resetCaughtTrapsForSubshell(self: *Executor) !void {
        var caught: std.ArrayList([]const u8) = .empty;
        defer caught.deinit(self.allocator);

        var trap_iter = self.traps.iterator();
        while (trap_iter.next()) |entry| {
            if (entry.value_ptr.*.len != 0) try caught.append(self.allocator, entry.key_ptr.*);
        }
        for (caught.items) |name| self.clearTrap(name);
    }

    fn isShellFdOpen(self: Executor, fd: std.posix.fd_t) bool {
        return fd <= 2 or self.open_fds.contains(fd);
    }

    // POSIX 2.7.5/2.7.6: [n]<&word and [n]>&word must fail when word names a
    // file descriptor that is not open, for external commands as well as
    // builtins. Redirections are processed left-to-right, so validation must
    // include earlier redirections from this same command.
    fn validateFdDuplicationTargets(self: Executor, redirections: []const ir.Redirection) !void {
        var open_fds: std.AutoHashMapUnmanaged(std.posix.fd_t, void) = .empty;
        defer open_fds.deinit(self.allocator);

        try open_fds.put(self.allocator, 0, {});
        try open_fds.put(self.allocator, 1, {});
        try open_fds.put(self.allocator, 2, {});
        var shell_fd_iter = self.open_fds.iterator();
        while (shell_fd_iter.next()) |entry| try open_fds.put(self.allocator, entry.key_ptr.*, {});

        for (redirections) |redirection| {
            if (redirection.operator == .greater_and or redirection.operator == .less_and) {
                const default_fd: std.posix.fd_t = if (redirection.operator == .less_and) 0 else 1;
                const from_fd = redirectionFd(redirection) orelse default_fd;
                const target = redirection.target orelse continue;
                if (std.mem.eql(u8, target.text, "-")) {
                    _ = open_fds.remove(from_fd);
                    continue;
                }
                const to_fd = parseFd(target.text) orelse continue;
                if (!open_fds.contains(to_fd)) return error.BadFileDescriptor;
                try open_fds.put(self.allocator, from_fd, {});
                continue;
            }
            if (redirectionOpensFd(redirection)) |fd| try open_fds.put(self.allocator, fd, {});
        }
    }

    fn markShellFdOpen(self: *Executor, fd: std.posix.fd_t) !void {
        if (fd <= 2) return;
        try self.open_fds.put(self.allocator, fd, {});
    }

    fn markShellFdClosed(self: *Executor, fd: std.posix.fd_t) void {
        if (fd <= 2) return;
        _ = self.open_fds.remove(fd);
    }

    fn findBackgroundJob(self: *Executor, pid: i64) ?*BackgroundJob {
        for (self.background_jobs.items) |*job| {
            if (job.pid == pid) return job;
        }
        return null;
    }

    fn findBackgroundJobBySpec(self: *Executor, spec: []const u8) ?*BackgroundJob {
        const has_percent = std.mem.startsWith(u8, spec, "%");
        const text = if (has_percent) spec[1..] else spec;
        if (text.len == 0 or std.mem.eql(u8, text, "+") or std.mem.eql(u8, text, "%")) {
            const id = self.current_job_id orelse return null;
            return self.findBackgroundJobById(id);
        }
        if (std.mem.eql(u8, text, "-")) {
            const id = self.previous_job_id orelse return null;
            return self.findBackgroundJobById(id);
        }
        const numeric_id: ?usize = std.fmt.parseUnsigned(usize, text, 10) catch null;
        if (numeric_id) |id| return self.findBackgroundJobById(id);
        if (!has_percent) return null;
        if (std.mem.startsWith(u8, text, "?")) return self.findBackgroundJobBySubstring(text[1..]);
        return self.findBackgroundJobByPrefix(text);
    }

    fn findBackgroundJobById(self: *Executor, id: usize) ?*BackgroundJob {
        for (self.background_jobs.items) |*job| {
            if (job.id == id) return job;
        }
        return null;
    }

    fn findBackgroundJobByPrefix(self: *Executor, prefix: []const u8) ?*BackgroundJob {
        if (prefix.len == 0) return null;
        var match: ?*BackgroundJob = null;
        for (self.background_jobs.items) |*job| {
            if (!std.mem.startsWith(u8, job.command, prefix)) continue;
            if (match != null) return null;
            match = job;
        }
        return match;
    }

    fn findBackgroundJobBySubstring(self: *Executor, needle: []const u8) ?*BackgroundJob {
        if (needle.len == 0) return null;
        var match: ?*BackgroundJob = null;
        for (self.background_jobs.items) |*job| {
            if (std.mem.indexOf(u8, job.command, needle) == null) continue;
            if (match != null) return null;
            match = job;
        }
        return match;
    }

    fn removeBackgroundJobById(self: *Executor, id: usize) void {
        for (self.background_jobs.items, 0..) |job, index| {
            if (job.id != id) continue;
            self.allocator.free(job.command);
            _ = self.background_jobs.orderedRemove(index);
            self.repairCurrentJobsAfterRemoval(id);
            return;
        }
    }

    fn repairCurrentJobsAfterRemoval(self: *Executor, id: usize) void {
        if (self.previous_job_id == id) self.previous_job_id = null;
        if (self.current_job_id == id) {
            self.current_job_id = self.previous_job_id;
            self.previous_job_id = null;
        }
        if (self.current_job_id) |current| {
            if (self.findBackgroundJobById(current) == null) self.current_job_id = null;
        }
        if (self.previous_job_id) |previous| {
            if (self.findBackgroundJobById(previous) == null) self.previous_job_id = null;
        }
    }

    fn currentBackgroundJob(self: *Executor) ?*BackgroundJob {
        const id = self.current_job_id orelse return null;
        return self.findBackgroundJobById(id);
    }

    fn selectCurrentJob(self: *Executor, id: usize) void {
        if (self.current_job_id != null and self.current_job_id.? != id) self.previous_job_id = self.current_job_id;
        self.current_job_id = id;
    }

    fn jobMarker(self: Executor, job: BackgroundJob) u8 {
        if (self.current_job_id == job.id) return '+';
        if (self.previous_job_id == job.id) return '-';
        return ' ';
    }

    fn refreshJobMarkers(self: *Executor) void {
        const old_current = self.current_job_id;
        const old_previous = self.previous_job_id;
        var current_stopped: ?usize = null;
        var previous_stopped: ?usize = null;
        var index = self.background_jobs.items.len;
        while (index > 0) {
            index -= 1;
            const job = self.background_jobs.items[index];
            if (job.state != .stopped) continue;
            if (current_stopped == null) {
                current_stopped = job.id;
            } else {
                previous_stopped = job.id;
                break;
            }
        }

        const current = current_stopped orelse {
            if (self.current_job_id) |id| {
                if (self.findBackgroundJobById(id) == null) self.current_job_id = null;
            }
            if (self.previous_job_id) |id| {
                if (self.findBackgroundJobById(id) == null) self.previous_job_id = null;
            }
            return;
        };
        self.current_job_id = current;
        if (previous_stopped) |previous| {
            self.previous_job_id = previous;
            return;
        }
        if (old_current != null and old_current.? != current and self.findBackgroundJobById(old_current.?) != null) {
            self.previous_job_id = old_current;
            return;
        }
        if (old_previous != null and old_previous.? != current and self.findBackgroundJobById(old_previous.?) != null) {
            self.previous_job_id = old_previous;
            return;
        }
        var fallback_index = self.background_jobs.items.len;
        while (fallback_index > 0) {
            fallback_index -= 1;
            const job = self.background_jobs.items[fallback_index];
            if (job.id == current) continue;
            self.previous_job_id = job.id;
            return;
        }
        self.previous_job_id = null;
    }

    fn refreshBackgroundJobs(self: *Executor) void {
        const flags: c_int = @intCast(std.posix.W.NOHANG | std.posix.W.UNTRACED);
        for (self.background_jobs.items) |*job| {
            if (job.state == .done) continue;
            var status: c_int = 0;
            const pid: std.c.pid_t = @intCast(job.pid);
            const result = std.c.waitpid(pid, &status, flags);
            if (result <= 0 or result != pid) continue;
            const wait_status: u32 = @intCast(status);
            job.status = exitStatusFromWaitStatus(wait_status);
            job.stop_signal = null;
            job.termination_signal = null;
            if (std.posix.W.IFSTOPPED(wait_status)) {
                job.state = .stopped;
                job.stop_signal = signalStatusNumber(std.posix.W.STOPSIG(wait_status));
            } else {
                job.state = .done;
                if (std.posix.W.IFSIGNALED(wait_status)) job.termination_signal = signalStatusNumber(std.posix.W.TERMSIG(wait_status));
            }
            if (job.state == .stopped) saveJobTerminalModes(job);
            self.queueJobNotification(job) catch {};
        }
    }

    fn hasStoppedBackgroundJobs(self: Executor) bool {
        for (self.background_jobs.items) |job| {
            if (job.state == .stopped) return true;
        }
        return false;
    }

    pub fn shouldWarnBeforeExitWithStoppedJobs(self: *Executor) bool {
        self.refreshBackgroundJobs();
        if (!self.hasStoppedBackgroundJobs()) {
            self.warned_stopped_jobs_on_exit = false;
            return false;
        }
        if (self.warned_stopped_jobs_on_exit) return false;
        self.warned_stopped_jobs_on_exit = true;
        return true;
    }

    fn queueJobNotification(self: *Executor, job: *BackgroundJob) !void {
        if (job.notified_state == job.state) return;
        const state = switch (job.state) {
            .running => return,
            .stopped => "Stopped",
            .done => "Done",
        };
        const notification = try std.fmt.allocPrint(self.allocator, "[{d}] {s} {s}\n", .{ job.id, state, job.command });
        errdefer self.allocator.free(notification);
        try self.pending_job_notifications.append(self.allocator, notification);
        job.notified_state = job.state;
    }

    pub fn drainJobNotifications(self: *Executor) ![]const u8 {
        self.refreshBackgroundJobs();
        var output: std.ArrayList(u8) = .empty;
        errdefer output.deinit(self.allocator);
        for (self.pending_job_notifications.items) |notification| {
            try output.appendSlice(self.allocator, notification);
            self.allocator.free(notification);
        }
        self.pending_job_notifications.clearRetainingCapacity();
        return output.toOwnedSlice(self.allocator);
    }

    pub fn wantsImmediateJobNotificationPoll(self: Executor) bool {
        if (!self.shell_options.notify) return false;
        if (self.pending_job_notifications.items.len != 0) return true;
        for (self.background_jobs.items) |job| {
            if (job.state != .done or job.notified_state != job.state) return true;
        }
        return false;
    }

    fn monitorProcessGroupsEnabled(self: Executor) bool {
        return self.shell_options.monitor;
    }

    pub fn expandAliasesForScript(self: *Executor, script: []const u8) ![]const u8 {
        return self.expandAliasesForScriptWithFeatures(script, .{});
    }

    pub fn expandAliasesForScriptWithFeatures(self: *Executor, script: []const u8, features: compat.Features) ![]const u8 {
        return parser.expandAliases(self.allocator, script, .{
            .features = features,
            .context = self,
            .lookup = lookupAliasForParser,
        });
    }

    fn setAlias(self: *Executor, name: []const u8, value: []const u8) !void {
        const owned_name = try self.allocator.dupe(u8, name);
        errdefer self.allocator.free(owned_name);
        const owned_value = try self.allocator.dupe(u8, value);
        errdefer self.allocator.free(owned_value);
        const result = try self.aliases.getOrPut(self.allocator, owned_name);
        if (result.found_existing) {
            self.allocator.free(owned_name);
            self.allocator.free(result.value_ptr.*);
            result.value_ptr.* = owned_value;
        } else {
            result.value_ptr.* = owned_value;
        }
    }

    fn unsetAlias(self: *Executor, name: []const u8) bool {
        if (self.aliases.fetchRemove(name)) |entry| {
            self.allocator.free(entry.key);
            self.allocator.free(entry.value);
            return true;
        }
        return false;
    }

    pub fn viCommandAlias(self: *Executor, allocator: std.mem.Allocator, letter: u21) !?[]const u8 {
        if (!((letter >= 'A' and letter <= 'Z') or (letter >= 'a' and letter <= 'z'))) return null;
        var name: [2]u8 = .{ '_', @intCast(letter) };
        const value = self.aliases.get(&name) orelse return null;
        const copy = try allocator.dupe(u8, value);
        return copy;
    }

    fn setAbbreviation(self: *Executor, name: []const u8, value: []const u8) !void {
        const owned_name = try self.allocator.dupe(u8, name);
        errdefer self.allocator.free(owned_name);
        const owned_value = try self.allocator.dupe(u8, value);
        errdefer self.allocator.free(owned_value);
        const result = try self.abbreviations.getOrPut(self.allocator, owned_name);
        if (result.found_existing) {
            self.allocator.free(owned_name);
            self.allocator.free(result.value_ptr.*);
            result.value_ptr.* = owned_value;
        } else {
            result.value_ptr.* = owned_value;
        }
    }

    fn unsetAbbreviation(self: *Executor, name: []const u8) bool {
        if (self.abbreviations.fetchRemove(name)) |entry| {
            self.allocator.free(entry.key);
            self.allocator.free(entry.value);
            return true;
        }
        return false;
    }

    pub fn expandAbbreviationForInput(self: *Executor, allocator: std.mem.Allocator, source: []const u8, cursor: usize, append_space: bool) !?completion.Edit {
        const span = try commandAbbreviationSpan(allocator, source, cursor) orelse return null;
        const name = source[span.start..span.end];
        const value = self.abbreviations.get(name) orelse return null;
        return .{
            .replace_start = span.start,
            .replace_end = span.end,
            .replacement = try allocator.dupe(u8, value),
            .append_space = append_space,
        };
    }

    pub fn expandViPathnamePattern(self: *Executor, allocator: std.mem.Allocator, io: std.Io, word: []const u8) !expand.ExpansionPattern {
        var substitution_context: CommandSubstitutionContext = .{ .executor = self, .options = .{ .io = io } };
        var option_flags_buffer: [shell_option_flags_max]u8 = undefined;
        const option_flags = shellOptionFlags(self.shell_options, &option_flags_buffer);
        return expand.expandWordPattern(allocator, word, .{
            .env = self.envLookup(),
            .env_set = self.envSet(),
            .arrays = self.arrayLookup(),
            .io = io,
            .command_substitution = commandSubstitution(&substitution_context),
            .positionals = self.currentPositionals().params,
            .option_flags = option_flags,
            .nounset = self.shell_options.nounset,
            .parameter_error = &self.parameter_error,
            .arithmetic_error = &self.arithmetic_error,
        });
    }

    pub fn expandViPathnamePatterns(self: *Executor, allocator: std.mem.Allocator, io: std.Io, word: []const u8) !expand.ExpansionPatterns {
        var substitution_context: CommandSubstitutionContext = .{ .executor = self, .options = .{ .io = io } };
        var option_flags_buffer: [shell_option_flags_max]u8 = undefined;
        const option_flags = shellOptionFlags(self.shell_options, &option_flags_buffer);
        return expand.expandWordPatterns(allocator, word, .{
            .env = self.envLookup(),
            .env_set = self.envSet(),
            .arrays = self.arrayLookup(),
            .io = io,
            .command_substitution = commandSubstitution(&substitution_context),
            .positionals = self.currentPositionals().params,
            .option_flags = option_flags,
            .nounset = self.shell_options.nounset,
            .parameter_error = &self.parameter_error,
            .arithmetic_error = &self.arithmetic_error,
        });
    }

    fn setFunction(self: *Executor, name: []const u8, body: []const u8, redirections: []const ir.Redirection) !void {
        const owned_name = try self.allocator.dupe(u8, name);
        errdefer self.allocator.free(owned_name);
        const owned_body = try self.allocator.dupe(u8, body);
        errdefer self.allocator.free(owned_body);
        const owned_redirections = try self.cloneRedirections(redirections);
        errdefer self.freeRedirections(owned_redirections);
        var parsed = try parser.parse(self.allocator, owned_body, .{});
        defer parsed.deinit();
        var program = try ir.lowerSimpleCommands(self.allocator, parsed);
        errdefer program.deinit();
        const result = try self.functions.getOrPut(self.allocator, owned_name);
        if (result.found_existing) {
            self.allocator.free(owned_name);
            result.value_ptr.deinit(self.allocator);
        }
        result.value_ptr.* = .{ .body = owned_body, .program = program, .redirections = owned_redirections };
    }

    fn cloneRedirections(self: *Executor, redirections: []const ir.Redirection) ![]ir.Redirection {
        const cloned = try self.allocator.alloc(ir.Redirection, redirections.len);
        errdefer self.allocator.free(cloned);
        var initialized: usize = 0;
        errdefer {
            for (cloned[0..initialized]) |redirection| self.freeRedirection(redirection);
            self.allocator.free(cloned);
        }
        for (redirections, 0..) |redirection, index| {
            cloned[index] = .{
                .span = redirection.span,
                .io_number = if (redirection.io_number) |word| try self.cloneWord(word) else null,
                .operator = redirection.operator,
                .target = if (redirection.target) |word| try self.cloneWord(word) else null,
                .here_doc = if (redirection.here_doc) |text| try self.allocator.dupe(u8, text) else null,
                .here_doc_quoted = redirection.here_doc_quoted,
            };
            initialized += 1;
        }
        return cloned;
    }

    fn cloneWord(self: *Executor, word: ir.WordRef) !ir.WordRef {
        const raw = try self.allocator.dupe(u8, word.raw);
        errdefer self.allocator.free(raw);
        const text = try self.allocator.dupe(u8, word.text);
        errdefer self.allocator.free(text);
        return .{ .span = word.span, .raw = raw, .text = text };
    }

    fn setTrap(self: *Executor, name: []const u8, action: []const u8) !void {
        const owned_name = try self.allocator.dupe(u8, name);
        errdefer self.allocator.free(owned_name);
        const owned_action = try self.allocator.dupe(u8, action);
        errdefer self.allocator.free(owned_action);

        const signal = signalFromTrapName(name);
        const installed_signal = if (signal) |value| try self.ensureTrapSignalInstalled(value) else false;
        errdefer if (installed_signal) self.restoreTrapSignal(signal.?);

        const result = try self.traps.getOrPut(self.allocator, owned_name);
        if (result.found_existing) {
            self.allocator.free(owned_name);
            self.allocator.free(result.value_ptr.*);
            result.value_ptr.* = owned_action;
        } else {
            result.value_ptr.* = owned_action;
        }
    }

    fn clearTrap(self: *Executor, name: []const u8) void {
        if (self.traps.fetchRemove(name)) |entry| {
            if (signalFromTrapName(name)) |signal| self.restoreTrapSignal(signal);
            self.allocator.free(entry.key);
            self.allocator.free(entry.value);
        }
    }

    fn ignoredTrapSignalAtEntry(self: Executor, name: []const u8) bool {
        const signal = signalFromTrapName(name) orelse return false;
        return self.ignored_trap_signals_at_entry & signalBit(signal) != 0;
    }

    fn ensureTrapSignalInstalled(self: *Executor, signal: std.posix.SIG) !bool {
        if (self.trapSignalActionIndex(signal) != null) return false;
        const previous = installTrapSignal(signal);
        errdefer std.posix.sigaction(signal, &previous, null);
        try self.trap_signal_actions.append(self.allocator, .{ .signal = signal, .previous = previous });
        return true;
    }

    fn trapSignalActionIndex(self: Executor, signal: std.posix.SIG) ?usize {
        for (self.trap_signal_actions.items, 0..) |action, index| {
            if (action.signal == signal) return index;
        }
        return null;
    }

    fn restoreTrapSignal(self: *Executor, signal: std.posix.SIG) void {
        const index = self.trapSignalActionIndex(signal) orelse return;
        const action = self.trap_signal_actions.swapRemove(index);
        std.posix.sigaction(action.signal, &action.previous, null);
    }

    fn restoreTrapSignalActions(self: *Executor) void {
        while (self.trap_signal_actions.items.len != 0) {
            const action = self.trap_signal_actions.pop().?;
            std.posix.sigaction(action.signal, &action.previous, null);
        }
    }

    fn executeCaseCommand(self: *Executor, command: ir.CaseCommand, options: ExecuteOptions) !CommandResult {
        var owned_stdin: ?[]u8 = null;
        defer if (owned_stdin) |bytes| self.allocator.free(bytes);
        var stdin_file: ?std.Io.File = null;
        defer if (stdin_file) |file| file.close(options.io.?);
        const prior_stdin = self.script_stdin;
        const prior_stdin_offset = self.script_stdin_offset;
        const prior_stdin_file = self.script_stdin_file;
        defer {
            self.script_stdin = prior_stdin;
            self.script_stdin_offset = prior_stdin_offset;
            self.script_stdin_file = prior_stdin_file;
        }
        const redirected_stdin = self.applyCompoundInputRedirections(command.span, command.redirections, options, &owned_stdin, &stdin_file) catch |err| return self.compoundRedirectionErrorResult(command.span, command.redirections, err, false);
        if (stdin_file) |file| {
            self.script_stdin = null;
            self.script_stdin_offset = 0;
            self.script_stdin_file = file;
        } else if (redirected_stdin) |stdin| {
            self.script_stdin = stdin;
            self.script_stdin_offset = 0;
            self.script_stdin_file = null;
        }
        var real_redirections: []ir.Redirection = &.{};
        if (options.external_stdio == .inherit and command.redirections.len != 0) real_redirections = try self.expandRedirections(command.redirections, options);
        defer if (real_redirections.len != 0) self.freeRedirections(real_redirections);
        const wrapper: ir.SimpleCommand = .{
            .span = command.span,
            .assignments = &.{},
            .argv = &.{},
            .redirections = real_redirections,
        };
        var real_redirection_guard: ?FdRedirectionGuard = if (real_redirections.len != 0)
            self.applyRealFdRedirectionsIfNeeded(wrapper, options) catch |err| return self.redirectionErrorResult(wrapper, err, false)
        else
            null;
        defer if (real_redirection_guard) |*guard| guard.restore(self, options.io.?);
        if (real_redirection_guard != null and redirectionsAffectStdin(real_redirections)) {
            self.script_stdin = null;
            self.script_stdin_offset = 0;
            self.script_stdin_file = std.Io.File.stdin();
        }
        var execution_options = options;
        if (command.redirections.len != 0 and real_redirection_guard == null) execution_options.external_stdio = .capture;

        const subject_words = try self.expandWords(&.{command.word}, execution_options);
        defer self.freeWords(subject_words);
        const subject = if (subject_words.len == 0) "" else subject_words[0].text;

        for (command.arms) |arm| {
            for (arm.patterns) |word| {
                var pattern = try self.expandCasePattern(word, execution_options);
                defer pattern.deinit(self.allocator);
                if (shellCasePatternMatches(pattern, subject)) {
                    var result = try self.executeScriptSlice(arm.body, execution_options);
                    if (real_redirection_guard != null) {
                        defer result.deinit();
                        writeInheritedResult(options.io.?, result) catch |err| switch (err) {
                            error.BadFileDescriptor => return errorResult(self.allocator, 1, "write", "bad file descriptor"),
                            error.BrokenPipe, error.NoSpaceLeft, error.InputOutput => return self.writeFailureResult(err, false),
                            else => return err,
                        };
                        return emptyResult(self.allocator, result.status);
                    }
                    return self.applyCompoundOutputRedirections(command.span, command.redirections, result, options);
                }
            }
        }

        var result = try emptyResult(self.allocator, 0);
        if (real_redirection_guard != null) {
            defer result.deinit();
            writeInheritedResult(options.io.?, result) catch |err| switch (err) {
                error.BadFileDescriptor => return errorResult(self.allocator, 1, "write", "bad file descriptor"),
                error.BrokenPipe, error.NoSpaceLeft, error.InputOutput => return self.writeFailureResult(err, false),
                else => return err,
            };
            return emptyResult(self.allocator, result.status);
        }
        return self.applyCompoundOutputRedirections(command.span, command.redirections, result, options);
    }

    /// Assigns the for-loop variable. A readonly target is a variable
    /// assignment error, so the diagnostic is recorded and the
    /// non-interactive shell stops (POSIX XCU 2.8.1). Returns false when the
    /// loop must stop.
    fn setForLoopVariable(self: *Executor, name: []const u8, value: []const u8, stderr: *std.ArrayList(u8), status: *ExitStatus) !bool {
        self.setEnv(name, value) catch |err| switch (err) {
            error.ReadonlyVariable => {
                try stderr.print(self.allocator, "{s}: readonly variable\n", .{name});
                self.pending_exit = 2;
                status.* = 2;
                return false;
            },
            else => return err,
        };
        return true;
    }

    fn executeForCommand(self: *Executor, command: ir.ForCommand, options: ExecuteOptions) !CommandResult {
        self.loop_depth += 1;
        defer self.loop_depth -= 1;
        var owned_stdin: ?[]u8 = null;
        defer if (owned_stdin) |bytes| self.allocator.free(bytes);
        var stdin_file: ?std.Io.File = null;
        defer if (stdin_file) |file| file.close(options.io.?);
        const prior_stdin = self.script_stdin;
        const prior_stdin_offset = self.script_stdin_offset;
        const prior_stdin_file = self.script_stdin_file;
        defer {
            self.script_stdin = prior_stdin;
            self.script_stdin_offset = prior_stdin_offset;
            self.script_stdin_file = prior_stdin_file;
        }
        const redirected_stdin = self.applyCompoundInputRedirections(command.span, command.redirections, options, &owned_stdin, &stdin_file) catch |err| return self.compoundRedirectionErrorResult(command.span, command.redirections, err, false);
        if (stdin_file) |file| {
            self.script_stdin = null;
            self.script_stdin_offset = 0;
            self.script_stdin_file = file;
        } else if (redirected_stdin) |stdin| {
            self.script_stdin = stdin;
            self.script_stdin_offset = 0;
            self.script_stdin_file = null;
        }
        var real_redirections: []ir.Redirection = &.{};
        if (options.external_stdio == .inherit and command.redirections.len != 0) real_redirections = try self.expandRedirections(command.redirections, options);
        defer if (real_redirections.len != 0) self.freeRedirections(real_redirections);
        const wrapper: ir.SimpleCommand = .{
            .span = command.span,
            .assignments = &.{},
            .argv = &.{},
            .redirections = real_redirections,
        };
        var real_redirection_guard: ?FdRedirectionGuard = if (real_redirections.len != 0)
            self.applyRealFdRedirectionsIfNeeded(wrapper, options) catch |err| return self.redirectionErrorResult(wrapper, err, false)
        else
            null;
        defer if (real_redirection_guard) |*guard| guard.restore(self, options.io.?);
        if (real_redirection_guard != null and redirectionsAffectStdin(real_redirections)) {
            self.script_stdin = null;
            self.script_stdin_offset = 0;
            self.script_stdin_file = std.Io.File.stdin();
        }
        var execution_options = options;
        if (command.redirections.len != 0 and real_redirection_guard == null) execution_options.external_stdio = .capture;
        const expanded_words = if (command.use_positionals) &[_]ir.WordRef{} else try self.expandArgv(command.words, options);
        defer if (!command.use_positionals) self.freeWords(expanded_words);

        var stdout: std.ArrayList(u8) = .empty;
        errdefer stdout.deinit(self.allocator);
        var stderr: std.ArrayList(u8) = .empty;
        errdefer stderr.deinit(self.allocator);
        var status: ExitStatus = 0;
        var status_errexit_ignored = false;

        if (command.use_positionals) {
            for (self.currentPositionals().params) |param| {
                if (!try self.setForLoopVariable(command.name, param, &stderr, &status)) break;
                var body = try self.executeScriptSlice(command.body, execution_options);
                defer body.deinit();
                try stdout.appendSlice(self.allocator, body.stdout);
                try stderr.appendSlice(self.allocator, body.stderr);
                status = body.status;
                status_errexit_ignored = body.errexit_ignored_status;
                if (self.shouldSkipForNoexec(execution_options)) break;
                if (self.pending_exit != null or self.pending_command_abort) break;
                if (self.pending_return != null) break;
                if (self.consumeLoopControl()) |control| switch (control) {
                    .break_loop => break,
                    .continue_loop => continue,
                };
            }
        } else {
            for (expanded_words) |word| {
                if (!try self.setForLoopVariable(command.name, word.text, &stderr, &status)) break;
                var body = try self.executeScriptSlice(command.body, execution_options);
                defer body.deinit();
                try stdout.appendSlice(self.allocator, body.stdout);
                try stderr.appendSlice(self.allocator, body.stderr);
                status = body.status;
                status_errexit_ignored = body.errexit_ignored_status;
                if (self.shouldSkipForNoexec(execution_options)) break;
                if (self.pending_exit != null or self.pending_command_abort) break;
                if (self.pending_return != null) break;
                if (self.consumeLoopControl()) |control| switch (control) {
                    .break_loop => break,
                    .continue_loop => continue,
                };
            }
        }

        const result: CommandResult = .{
            .allocator = self.allocator,
            .status = status,
            .stdout = try stdout.toOwnedSlice(self.allocator),
            .stderr = try stderr.toOwnedSlice(self.allocator),
            .errexit_ignored_status = status_errexit_ignored,
        };
        if (real_redirection_guard != null) {
            var owned_result = result;
            defer owned_result.deinit();
            writeInheritedResult(options.io.?, owned_result) catch |err| switch (err) {
                error.BadFileDescriptor => return errorResult(self.allocator, 1, "write", "bad file descriptor"),
                error.BrokenPipe, error.NoSpaceLeft, error.InputOutput => return self.writeFailureResult(err, false),
                else => return err,
            };
            return emptyResult(self.allocator, owned_result.status);
        }
        return self.applyCompoundOutputRedirections(command.span, command.redirections, result, options);
    }

    fn executeLoopCommand(self: *Executor, command: ir.LoopCommand, options: ExecuteOptions) !CommandResult {
        self.loop_depth += 1;
        defer self.loop_depth -= 1;
        var owned_stdin: ?[]u8 = null;
        defer if (owned_stdin) |bytes| self.allocator.free(bytes);
        var stdin_file: ?std.Io.File = null;
        defer if (stdin_file) |file| file.close(options.io.?);
        const prior_stdin = self.script_stdin;
        const prior_stdin_offset = self.script_stdin_offset;
        const prior_stdin_file = self.script_stdin_file;
        defer {
            self.script_stdin = prior_stdin;
            self.script_stdin_offset = prior_stdin_offset;
            self.script_stdin_file = prior_stdin_file;
        }
        const redirected_stdin = self.applyCompoundInputRedirections(command.span, command.redirections, options, &owned_stdin, &stdin_file) catch |err| return self.compoundRedirectionErrorResult(command.span, command.redirections, err, false);
        if (stdin_file) |file| {
            self.script_stdin = null;
            self.script_stdin_offset = 0;
            self.script_stdin_file = file;
        } else if (redirected_stdin) |stdin| {
            self.script_stdin = stdin;
            self.script_stdin_offset = 0;
            self.script_stdin_file = null;
        }
        var real_redirections: []ir.Redirection = &.{};
        if (options.external_stdio == .inherit and command.redirections.len != 0) real_redirections = try self.expandRedirections(command.redirections, options);
        defer if (real_redirections.len != 0) self.freeRedirections(real_redirections);
        const wrapper: ir.SimpleCommand = .{
            .span = command.span,
            .assignments = &.{},
            .argv = &.{},
            .redirections = real_redirections,
        };
        var real_redirection_guard: ?FdRedirectionGuard = if (real_redirections.len != 0)
            self.applyRealFdRedirectionsIfNeeded(wrapper, options) catch |err| return self.redirectionErrorResult(wrapper, err, false)
        else
            null;
        defer if (real_redirection_guard) |*guard| guard.restore(self, options.io.?);
        if (real_redirection_guard != null and redirectionsAffectStdin(real_redirections)) {
            self.script_stdin = null;
            self.script_stdin_offset = 0;
            self.script_stdin_file = std.Io.File.stdin();
        }
        var execution_options = options;
        if (command.redirections.len != 0 and real_redirection_guard == null) execution_options.external_stdio = .capture;
        var stdout: std.ArrayList(u8) = .empty;
        errdefer stdout.deinit(self.allocator);
        var stderr: std.ArrayList(u8) = .empty;
        errdefer stderr.deinit(self.allocator);
        var status: ExitStatus = 0;
        var status_errexit_ignored = false;

        while (true) {
            var condition_options = execution_options;
            condition_options.suppress_errexit = true;
            var condition = try self.executeScriptSlice(command.condition, condition_options);
            defer condition.deinit();
            try stdout.appendSlice(self.allocator, condition.stdout);
            try stderr.appendSlice(self.allocator, condition.stderr);
            if (self.shouldSkipForNoexec(condition_options)) break;
            if (self.pending_exit != null or self.pending_command_abort) break;
            if (self.pending_return != null) break;

            const run_body = switch (command.kind) {
                .while_loop => condition.status == 0,
                .until_loop => condition.status != 0,
            };
            if (!run_body) break;

            var body = try self.executeScriptSlice(command.body, execution_options);
            defer body.deinit();
            try stdout.appendSlice(self.allocator, body.stdout);
            try stderr.appendSlice(self.allocator, body.stderr);
            status = body.status;
            status_errexit_ignored = body.errexit_ignored_status;
            if (self.shouldSkipForNoexec(execution_options)) break;
            if (self.pending_exit != null or self.pending_command_abort) break;
            if (self.pending_return != null) break;
            if (self.consumeLoopControl()) |control| switch (control) {
                .break_loop => break,
                .continue_loop => continue,
            };
        }

        const result: CommandResult = .{
            .allocator = self.allocator,
            .status = status,
            .stdout = try stdout.toOwnedSlice(self.allocator),
            .stderr = try stderr.toOwnedSlice(self.allocator),
            .errexit_ignored_status = status_errexit_ignored,
        };
        if (real_redirection_guard != null) {
            var owned_result = result;
            defer owned_result.deinit();
            writeInheritedResult(options.io.?, owned_result) catch |err| switch (err) {
                error.BadFileDescriptor => return errorResult(self.allocator, 1, "write", "bad file descriptor"),
                error.BrokenPipe, error.NoSpaceLeft, error.InputOutput => return self.writeFailureResult(err, false),
                else => return err,
            };
            return emptyResult(self.allocator, owned_result.status);
        }
        return self.applyCompoundOutputRedirections(command.span, command.redirections, result, options);
    }

    fn applyCompoundInputRedirections(self: *Executor, span: parser.Span, redirections: []const ir.Redirection, options: ExecuteOptions, owned_stdin: *?[]u8, stdin_file: *?std.Io.File) !?[]const u8 {
        if (redirections.len == 0) return null;
        if (!hasInputRedirection(redirections)) return null;
        const expanded_redirections = try self.expandRedirections(redirections, options);
        defer self.freeRedirections(expanded_redirections);
        const wrapper: ir.SimpleCommand = .{
            .span = span,
            .assignments = &.{},
            .argv = &.{},
            .redirections = expanded_redirections,
        };
        return try self.applyInputRedirections(wrapper, "", options, owned_stdin, stdin_file);
    }

    fn applyCompoundOutputRedirections(self: *Executor, span: parser.Span, redirections: []const ir.Redirection, result: CommandResult, options: ExecuteOptions) !CommandResult {
        if (redirections.len == 0) return result;
        var owned_result = result;
        const expanded_redirections = self.expandRedirections(redirections, options) catch |err| {
            owned_result.deinit();
            return err;
        };
        defer self.freeRedirections(expanded_redirections);
        const wrapper: ir.SimpleCommand = .{
            .span = span,
            .assignments = &.{},
            .argv = &.{},
            .redirections = expanded_redirections,
        };
        return self.applyOutputRedirections(wrapper, owned_result, options, false);
    }

    fn hasInputRedirection(redirections: []const ir.Redirection) bool {
        for (redirections) |redirection| {
            if (isHereDocRedirection(redirection) or isStdinFileRedirection(redirection)) return true;
        }
        return false;
    }

    fn redirectionsAffectStdin(redirections: []const ir.Redirection) bool {
        for (redirections) |redirection| {
            if (redirectionAffectsStdin(redirection)) return true;
        }
        return false;
    }

    fn redirectionAffectsStdin(redirection: ir.Redirection) bool {
        const default_fd: std.posix.fd_t = switch (redirection.operator) {
            .less, .less_great, .dless, .dless_dash, .less_and => 0,
            .greater, .dgreat, .clobber, .greater_and => 1,
            else => return false,
        };
        return (redirectionFd(redirection) orelse default_fd) == 0;
    }

    const ScriptStdinGuard = struct {
        executor: *Executor,
        prior_stdin: ?[]const u8,
        prior_stdin_offset: usize,
        prior_stdin_file: ?std.Io.File,
        prior_pipeline_stdin: PipelineStageStdin,

        fn restore(self: ScriptStdinGuard) void {
            self.executor.script_stdin = self.prior_stdin;
            self.executor.script_stdin_offset = self.prior_stdin_offset;
            self.executor.script_stdin_file = self.prior_stdin_file;
            pipeline_stage_stdin = self.prior_pipeline_stdin;
        }
    };

    fn pushScriptStdin(self: *Executor, stdin: []const u8, stdin_file: ?std.Io.File, force_bytes: bool) ?ScriptStdinGuard {
        if (stdin_file == null and stdin.len == 0 and !force_bytes) return null;
        const guard: ScriptStdinGuard = .{
            .executor = self,
            .prior_stdin = self.script_stdin,
            .prior_stdin_offset = self.script_stdin_offset,
            .prior_stdin_file = self.script_stdin_file,
            .prior_pipeline_stdin = pipeline_stage_stdin,
        };
        self.script_stdin = if (stdin_file == null) stdin else null;
        self.script_stdin_offset = 0;
        self.script_stdin_file = stdin_file;
        pipeline_stage_stdin = .{};
        return guard;
    }

    fn consumeLoopControl(self: *Executor) ?LoopControlKind {
        const control = self.pending_loop_control orelse return null;
        if (control.levels <= 1) {
            self.pending_loop_control = null;
            return control.kind;
        }
        self.pending_loop_control = .{ .kind = control.kind, .levels = control.levels - 1 };
        return .break_loop;
    }

    fn executeIfCommand(self: *Executor, command: ir.IfCommand, options: ExecuteOptions) !CommandResult {
        var owned_stdin: ?[]u8 = null;
        defer if (owned_stdin) |bytes| self.allocator.free(bytes);
        var stdin_file: ?std.Io.File = null;
        defer if (stdin_file) |file| file.close(options.io.?);
        const prior_stdin = self.script_stdin;
        const prior_stdin_offset = self.script_stdin_offset;
        const prior_stdin_file = self.script_stdin_file;
        defer {
            self.script_stdin = prior_stdin;
            self.script_stdin_offset = prior_stdin_offset;
            self.script_stdin_file = prior_stdin_file;
        }
        const redirected_stdin = self.applyCompoundInputRedirections(command.span, command.redirections, options, &owned_stdin, &stdin_file) catch |err| return self.compoundRedirectionErrorResult(command.span, command.redirections, err, false);
        if (stdin_file) |file| {
            self.script_stdin = null;
            self.script_stdin_offset = 0;
            self.script_stdin_file = file;
        } else if (redirected_stdin) |stdin| {
            self.script_stdin = stdin;
            self.script_stdin_offset = 0;
            self.script_stdin_file = null;
        }
        var real_redirections: []ir.Redirection = &.{};
        if (options.external_stdio == .inherit and command.redirections.len != 0) real_redirections = try self.expandRedirections(command.redirections, options);
        defer if (real_redirections.len != 0) self.freeRedirections(real_redirections);
        const wrapper: ir.SimpleCommand = .{
            .span = command.span,
            .assignments = &.{},
            .argv = &.{},
            .redirections = real_redirections,
        };
        var real_redirection_guard: ?FdRedirectionGuard = if (real_redirections.len != 0)
            self.applyRealFdRedirectionsIfNeeded(wrapper, options) catch |err| return self.redirectionErrorResult(wrapper, err, false)
        else
            null;
        defer if (real_redirection_guard) |*guard| guard.restore(self, options.io.?);
        if (real_redirection_guard != null and redirectionsAffectStdin(real_redirections)) {
            self.script_stdin = null;
            self.script_stdin_offset = 0;
            self.script_stdin_file = std.Io.File.stdin();
        }
        var execution_options = options;
        if (command.redirections.len != 0 and real_redirection_guard == null) execution_options.external_stdio = .capture;
        var stdout: std.ArrayList(u8) = .empty;
        errdefer stdout.deinit(self.allocator);
        var stderr: std.ArrayList(u8) = .empty;
        errdefer stderr.deinit(self.allocator);

        var condition_options = execution_options;
        condition_options.suppress_errexit = true;
        var condition = try self.executeScriptSlice(command.condition, condition_options);
        defer condition.deinit();
        try stdout.appendSlice(self.allocator, condition.stdout);
        try stderr.appendSlice(self.allocator, condition.stderr);

        var status: ExitStatus = 0;
        var status_errexit_ignored = false;
        if (self.pending_exit != null or self.pending_command_abort or self.pending_return != null) {
            status = condition.status;
            status_errexit_ignored = condition.errexit_ignored_status;
        } else if (condition.status == 0) {
            var body = try self.executeScriptSlice(command.then_body, execution_options);
            defer body.deinit();
            try stdout.appendSlice(self.allocator, body.stdout);
            try stderr.appendSlice(self.allocator, body.stderr);
            status = body.status;
            status_errexit_ignored = body.errexit_ignored_status;
        } else if (command.else_body) |else_body| {
            var body = try self.executeElseBody(else_body, execution_options);
            defer body.deinit();
            try stdout.appendSlice(self.allocator, body.stdout);
            try stderr.appendSlice(self.allocator, body.stderr);
            status = body.status;
            status_errexit_ignored = body.errexit_ignored_status;
        } else {
            status = 0;
        }

        const result: CommandResult = .{
            .allocator = self.allocator,
            .status = status,
            .stdout = try stdout.toOwnedSlice(self.allocator),
            .stderr = try stderr.toOwnedSlice(self.allocator),
            .errexit_ignored_status = status_errexit_ignored,
        };
        if (real_redirection_guard != null) {
            var owned_result = result;
            defer owned_result.deinit();
            writeInheritedResult(options.io.?, owned_result) catch |err| switch (err) {
                error.BadFileDescriptor => return errorResult(self.allocator, 1, "write", "bad file descriptor"),
                error.BrokenPipe, error.NoSpaceLeft, error.InputOutput => return self.writeFailureResult(err, false),
                else => return err,
            };
            return emptyResult(self.allocator, owned_result.status);
        }
        return self.applyCompoundOutputRedirections(command.span, command.redirections, result, options);
    }

    fn executeElseBody(self: *Executor, else_body: []const u8, options: ExecuteOptions) !CommandResult {
        const trimmed = trimLeftShellSeparators(else_body);
        if (std.mem.startsWith(u8, trimmed, "elif")) {
            const rest = trimLeftShellWhitespace(trimmed[4..]);
            const script = try std.fmt.allocPrint(self.allocator, "if {s} fi", .{rest});
            defer self.allocator.free(script);
            return self.executeScriptSlice(script, options);
        }
        return self.executeScriptSlice(else_body, options);
    }

    fn trimLeftShellSeparators(text: []const u8) []const u8 {
        var index: usize = 0;
        while (index < text.len and (text[index] == ' ' or text[index] == '\t' or text[index] == '\r' or text[index] == '\n' or text[index] == ';')) : (index += 1) {}
        return text[index..];
    }

    fn trimLeftShellWhitespace(text: []const u8) []const u8 {
        var index: usize = 0;
        while (index < text.len and (text[index] == ' ' or text[index] == '\t' or text[index] == '\r' or text[index] == '\n')) : (index += 1) {}
        return text[index..];
    }

    pub fn executeScriptSlice(self: *Executor, script: []const u8, options: ExecuteOptions) anyerror!CommandResult {
        const trimmed = std.mem.trim(u8, script, " \t\r\n;");
        if (trimmed.len == 0) return emptyResult(self.allocator, 0);
        const source = std.mem.trimStart(u8, script, " \t\r\n;");
        if (options.alias_timing_chunks and containsAliasTimingCommandToken(source)) {
            if (try self.aliasTimingChunkProgram(source, options)) |chunk_program| {
                var program = chunk_program;
                defer program.deinit();
                return self.executeScriptChunks(source, program, options);
            }
        }
        const aliased = try self.expandAliasesForScriptWithFeatures(source, options.features);
        defer self.allocator.free(aliased);
        var parsed = try parser.parse(self.allocator, aliased, .{ .features = options.features });
        defer parsed.deinit();
        if (parsed.diagnostics.len != 0) return error.ParseError;
        var program = try ir.lowerSimpleCommands(self.allocator, parsed);
        defer program.deinit();
        if (self.shouldSkipForNoexec(options)) return emptyResult(self.allocator, 0);
        var result = try self.executeProgram(program, options);
        errdefer result.deinit();
        return result;
    }

    fn aliasTimingChunkProgram(self: *Executor, script: []const u8, options: ExecuteOptions) !?ir.Program {
        var parsed = try parser.parse(self.allocator, script, .{ .features = options.features });
        defer parsed.deinit();
        if (parsed.diagnostics.len != 0) return null;
        var program = try ir.lowerSimpleCommands(self.allocator, parsed);
        errdefer program.deinit();
        if (!canExecuteAsAliasTimingChunks(program)) {
            program.deinit();
            return null;
        }
        return program;
    }

    fn executeScriptChunks(self: *Executor, script: []const u8, program: ir.Program, options: ExecuteOptions) anyerror!CommandResult {
        const root_execution = self.execution_depth == 0;
        if (root_execution) self.pending_command_abort = false;
        defer {
            if (root_execution) self.pending_command_abort = false;
        }
        self.execution_depth += 1;
        defer self.execution_depth -= 1;

        var stdout: std.ArrayList(u8) = .empty;
        errdefer stdout.deinit(self.allocator);
        var stderr: std.ArrayList(u8) = .empty;
        errdefer stderr.deinit(self.allocator);
        var last_status: ExitStatus = 0;
        var last_errexit_ignored_status = false;
        var verbose_read_offset: usize = 0;
        var statement_index: usize = 0;
        execute_chunks: while (statement_index < program.statements.len) {
            const start = program.statements[statement_index].span.start;
            // Alias definitions become visible only after the next input line is
            // read; keep same-line statements in one parse with the prior alias table.
            var end_statement_index = lastStatementOnReadLine(script, program, statement_index);
            while (true) {
                const end = if (end_statement_index + 1 < program.statements.len) program.statements[end_statement_index + 1].span.start else script.len;
                if (try self.scriptSliceParsesWithCurrentAliases(script[start..end], options.features)) {
                    try self.appendOrWriteVerboseInput(options, &stderr, script, &verbose_read_offset, start, end);
                    if (self.shouldSkipForNoexec(options)) break :execute_chunks;
                    var statement_options = options;
                    statement_options.verbose_input_echo = false;
                    statement_options.alias_timing_chunks = false;
                    var result = try self.executeScriptSlice(script[start..end], statement_options);
                    defer result.deinit();
                    last_status = try self.appendOrWriteResultStatus(options, &stdout, &stderr, result);
                    last_errexit_ignored_status = result.errexit_ignored_status;
                    statement_index = end_statement_index + 1;
                    if (self.pending_exit != null or self.pending_return != null or self.pending_loop_control != null or self.pending_command_abort) break :execute_chunks;
                    continue :execute_chunks;
                }
                if (end_statement_index + 1 >= program.statements.len) return error.ParseError;
                end_statement_index += 1;
                end_statement_index = lastStatementOnReadLine(script, program, end_statement_index);
            }
        }
        var result: CommandResult = .{ .allocator = self.allocator, .status = last_status, .stdout = try stdout.toOwnedSlice(self.allocator), .stderr = try stderr.toOwnedSlice(self.allocator), .errexit_ignored_status = last_errexit_ignored_status };
        errdefer result.deinit();
        return self.finishExecuteProgram(root_execution, options, result);
    }

    fn scriptSliceParsesWithCurrentAliases(self: *Executor, script: []const u8, features: compat.Features) !bool {
        const aliased = try self.expandAliasesForScriptWithFeatures(script, features);
        defer self.allocator.free(aliased);
        var parsed = try parser.parse(self.allocator, aliased, .{ .features = features });
        defer parsed.deinit();
        return parsed.diagnostics.len == 0;
    }

    fn executeStatementSync(self: *Executor, program: ir.Program, statement: ir.Statement, options: ExecuteOptions) !CommandResult {
        return switch (statement.kind) {
            .pipeline => try self.executePipeline(program, program.pipelines[statement.index], options),
            .if_command => try self.executeIfCommand(program.if_commands[statement.index], options),
            .loop_command => try self.executeLoopCommand(program.loop_commands[statement.index], options),
            .for_command => try self.executeForCommand(program.for_commands[statement.index], options),
            .case_command => try self.executeCaseCommand(program.case_commands[statement.index], options),
            .function_definition => try self.executeFunctionDefinition(program.function_definitions[statement.index]),
            .bash_test_command => try self.executeBashTestCommand(program.bash_test_commands[statement.index], options),
            .brace_group => try self.executeBraceGroup(program.brace_groups[statement.index], options),
            .subshell => try self.executeSubshell(program.subshells[statement.index], options),
        };
    }

    fn executeAsyncStatement(self: *Executor, program: ir.Program, statement: ir.Statement, options: ExecuteOptions) !CommandResult {
        if (statement.kind == .pipeline) return self.executeAsyncPipeline(program, program.pipelines[statement.index], options);
        if (options.io == null) return self.executeAsyncStatementFallback(program, statement, options);
        const command_text = statementText(program, statement);
        const forked = self.forkAsyncJob(command_text, options, .{ .statement = statement }, program) catch |err| switch (err) {
            error.Unsupported => return self.executeAsyncStatementFallback(program, statement, options),
            else => return err,
        };
        return forked;
    }

    fn executeAsyncStatementFallback(self: *Executor, program: ir.Program, statement: ir.Statement, options: ExecuteOptions) !CommandResult {
        var result = try self.executeStatementSync(program, statement, options);
        result.status = 0;
        return result;
    }

    fn executeAsyncPipeline(self: *Executor, program: ir.Program, pipeline: ir.Pipeline, options: ExecuteOptions) !CommandResult {
        if (pipeline.command_indexes.len != 1 or !options.allow_external or options.io == null) return self.executeAsyncPipelineFallback(program, pipeline, options);
        const command = program.commands[pipeline.command_indexes[0]];
        if (command.argv.len == 0 or builtinForName(self.*, command.argv[0].text) != null or self.functions.get(command.argv[0].text) != null) return self.executeAsyncPipelineFallback(program, pipeline, options);
        if (commandNameNeedsRuntimeExpansion(command)) return self.executeAsyncPipelineFallback(program, pipeline, options);
        const expanded = try self.expandSimpleCommand(command, options);
        defer self.freeExpandedCommand(expanded);
        if (expanded.argv.len == 0) return emptyResult(self.allocator, 0);
        return self.executeExternalAsync(expanded, options.io.?, options) catch |err| switch (err) {
            error.BadFileDescriptor, error.FileNotFound, error.IsDir, error.PathAlreadyExists => return self.asyncRedirectionErrorResult(expanded, err),
            else => return err,
        };
    }

    fn executeAsyncPipelineFallback(self: *Executor, program: ir.Program, pipeline: ir.Pipeline, options: ExecuteOptions) !CommandResult {
        if (options.io == null) {
            var result = try self.executePipeline(program, pipeline, options);
            result.status = 0;
            return result;
        }
        return self.forkAsyncJob(pipelineText(program, pipeline), options, .{ .pipeline = pipeline }, program) catch |err| switch (err) {
            error.Unsupported => {
                var result = try self.executePipeline(program, pipeline, options);
                result.status = 0;
                return result;
            },
            else => return err,
        };
    }

    const AsyncJobKind = union(enum) {
        statement: ir.Statement,
        pipeline: ir.Pipeline,
    };

    fn forkAsyncJob(self: *Executor, command_text: []const u8, options: ExecuteOptions, kind: AsyncJobKind, program: ir.Program) !CommandResult {
        const io = options.io orelse return error.Unsupported;
        const use_monitor_pgrp = self.monitorProcessGroupsEnabled();
        const use_cancel_pgrp = completionCancelProcessGroup(options);
        const use_process_pgrp = use_monitor_pgrp or use_cancel_pgrp;
        const pid = try forkProcess();
        if (pid == 0) {
            if (use_process_pgrp) processSetPgrp(0, 0) catch exitForkedChild(2);
            self.resetCaughtTrapsForSubshell() catch exitForkedChild(2);
            resetInteractiveJobSignalHandlers();
            var child_options = options;
            child_options.foreground_terminal = false;
            if (!use_monitor_pgrp) installDevNullStdin(io) catch exitForkedChild(2);
            var status: ExitStatus = 2;
            var child_result = switch (kind) {
                .statement => |statement| self.executeStatementSync(program, statement, child_options),
                .pipeline => |pipeline| self.executePipeline(program, pipeline, child_options),
            } catch null;
            if (child_result) |*result| {
                status = result.status;
                if (child_options.external_stdio == .inherit) writeInheritedResult(io, result.*) catch {};
                result.deinit();
            }
            exitForkedChild(status);
        }

        if (use_process_pgrp) {
            processSetPgrp(pid, pid) catch |err| switch (err) {
                error.ProcessAlreadyExec, error.ProcessNotFound => {},
                else => return err,
            };
        }

        _ = registerCancelableChild(options, childFromPid(pid), use_process_pgrp);
        const numeric_pid: i64 = @intCast(pid);
        self.setLastBackgroundPid(numeric_pid);
        const owned_command = try self.allocator.dupe(u8, std.mem.trim(u8, command_text, " \t\r\n;&"));
        errdefer self.allocator.free(owned_command);
        try self.background_jobs.append(self.allocator, .{
            .id = self.next_job_id,
            .pid = numeric_pid,
            .pgrp = if (use_process_pgrp) numeric_pid else null,
            .command = owned_command,
            .child = childFromPid(pid),
        });
        self.selectCurrentJob(self.next_job_id);
        self.next_job_id += 1;
        return emptyResult(self.allocator, 0);
    }

    fn executePipeline(self: *Executor, program: ir.Program, pipeline: ir.Pipeline, options: ExecuteOptions) anyerror!CommandResult {
        var pipeline_options = options;
        if (pipeline.negated) pipeline_options.ignore_errexit = true;
        if (self.shouldSkipForNoexec(pipeline_options)) return emptyResult(self.allocator, 0);
        if (self.canExecuteRealPipeline(program, pipeline, pipeline_options)) {
            const io = pipeline_options.io orelse return error.MissingIoForExternalCommand;
            return self.executeRealPipeline(program, pipeline, pipeline_options, io);
        }
        if (pipeline.stage_spans.len != pipeline.command_indexes.len) return self.executeSpanPipeline(program, pipeline, pipeline_options);

        var last = try emptyResult(self.allocator, 0);
        var stdin = try self.allocator.alloc(u8, 0);
        defer self.allocator.free(stdin);
        const statuses = try self.allocator.alloc(ExitStatus, pipeline.command_indexes.len);
        defer self.allocator.free(statuses);
        var statuses_len: usize = 0;

        for (pipeline.command_indexes, 0..) |command_index, index| {
            if (self.shouldSkipForNoexec(pipeline_options)) break;
            last.deinit();
            const is_last = index + 1 == pipeline.command_indexes.len;
            last = try self.executeSimplePipelineStage(program.commands[command_index], stdin, pipeline_options, is_last, index > 0);
            statuses[index] = last.status;
            statuses_len = index + 1;
            if (self.shouldSkipForNoexec(pipeline_options)) break;

            if (index + 1 < pipeline.command_indexes.len) {
                self.allocator.free(stdin);
                stdin = try self.allocator.dupe(u8, last.stdout);
            }
        }

        last.status = self.pipelineStatus(pipeline, statuses[0..statuses_len]);
        return last;
    }

    fn executeSpanPipeline(self: *Executor, program: ir.Program, pipeline: ir.Pipeline, options: ExecuteOptions) anyerror!CommandResult {
        var last = try emptyResult(self.allocator, 0);
        var stdin = try self.allocator.alloc(u8, 0);
        defer self.allocator.free(stdin);
        const statuses = try self.allocator.alloc(ExitStatus, pipeline.stage_spans.len);
        defer self.allocator.free(statuses);
        var statuses_len: usize = 0;

        for (pipeline.stage_spans, 0..) |stage_span, index| {
            if (self.shouldSkipForNoexec(options)) break;
            last.deinit();
            const is_last = index + 1 == pipeline.stage_spans.len;
            last = try self.executePipelineStageSpan(program.source[stage_span.start..stage_span.end], stdin, options, is_last);
            statuses[index] = last.status;
            statuses_len = index + 1;
            if (self.shouldSkipForNoexec(options)) break;

            if (index + 1 < pipeline.stage_spans.len) {
                self.allocator.free(stdin);
                stdin = try self.allocator.dupe(u8, last.stdout);
            }
        }

        last.status = self.pipelineStatus(pipeline, statuses[0..statuses_len]);
        return last;
    }

    fn executeSimplePipelineStage(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions, is_last: bool, has_pipe_input: bool) !CommandResult {
        if (is_last) {
            return if (has_pipe_input)
                self.executeSimpleCommandWithPipelineInput(command, stdin, options)
            else
                self.executeSimpleCommandWithInput(command, stdin, options);
        }

        var child = Executor.init(self.allocator);
        defer child.deinit();
        try child.copyStateFrom(self);
        try child.resetCaughtTrapsForSubshell();

        var guard = try self.savePipelineSubshellProcessState(options);
        defer guard.restore();

        return if (has_pipe_input)
            child.executeSimpleCommandWithPipelineInput(command, stdin, options)
        else
            child.executeSimpleCommandWithInput(command, stdin, options);
    }

    fn executePipelineStageSpan(self: *Executor, source: []const u8, stdin: []const u8, options: ExecuteOptions, is_last: bool) !CommandResult {
        if (is_last) return self.executePipelineStageSpanInCurrentShell(source, stdin, options);

        var child = Executor.init(self.allocator);
        defer child.deinit();
        try child.copyStateFrom(self);
        try child.resetCaughtTrapsForSubshell();

        var guard = try self.savePipelineSubshellProcessState(options);
        defer guard.restore();

        return child.executePipelineStageSpanInCurrentShell(source, stdin, options);
    }

    const PipelineSubshellProcessState = struct {
        allocator: std.mem.Allocator,
        io: ?std.Io,
        cwd: ?[:0]u8,
        umask: u16,

        fn restore(self: *PipelineSubshellProcessState) void {
            if (self.cwd) |cwd| {
                if (self.io) |io| std.process.setCurrentPath(io, cwd) catch {};
                self.allocator.free(cwd);
                self.cwd = null;
            }
            restoreShellUmask(self.umask);
        }
    };

    fn savePipelineSubshellProcessState(self: *Executor, options: ExecuteOptions) !PipelineSubshellProcessState {
        const cwd = if (options.io) |io| try std.process.currentPathAlloc(io, self.allocator) else null;
        errdefer if (cwd) |path| self.allocator.free(path);
        return .{
            .allocator = self.allocator,
            .io = options.io,
            .cwd = cwd,
            .umask = readShellUmask(),
        };
    }

    fn executePipelineStageSpanInCurrentShell(self: *Executor, source: []const u8, stdin: []const u8, options: ExecuteOptions) !CommandResult {
        const prior_stdin = self.script_stdin;
        const prior_stdin_offset = self.script_stdin_offset;
        const prior_stdin_file = self.script_stdin_file;
        defer {
            self.script_stdin = prior_stdin;
            self.script_stdin_offset = prior_stdin_offset;
            self.script_stdin_file = prior_stdin_file;
        }
        self.script_stdin = stdin;
        self.script_stdin_offset = 0;
        self.script_stdin_file = null;

        var stage_options = options;
        stage_options.external_stdio = .capture;
        return self.executeScriptSlice(source, stage_options);
    }

    fn pipelineHasRedirections(program: ir.Program, pipeline: ir.Pipeline) bool {
        for (pipeline.command_indexes) |command_index| {
            if (program.commands[command_index].redirections.len != 0) return true;
        }
        return false;
    }

    fn pipelineStatus(self: Executor, pipeline: ir.Pipeline, statuses: []const ExitStatus) ExitStatus {
        const status: ExitStatus = blk: {
            if (statuses.len == 0) break :blk 0;
            if (!self.shell_options.pipefail) break :blk statuses[statuses.len - 1];
            var index = statuses.len;
            while (index > 0) {
                index -= 1;
                if (statuses[index] != 0) break :blk statuses[index];
            }
            break :blk 0;
        };
        return if (pipeline.negated) (if (status == 0) 1 else 0) else status;
    }

    fn canExecuteRealPipeline(self: Executor, program: ir.Program, pipeline: ir.Pipeline, options: ExecuteOptions) bool {
        if (self.completion_builder != null or self.completion_context != null) return false;
        if (pipeline.stage_spans.len != pipeline.command_indexes.len) return false;
        if (!options.allow_external or options.io == null or pipeline.command_indexes.len < 2) return false;
        for (pipeline.command_indexes) |command_index| {
            const command = program.commands[command_index];
            if (command.argv.len == 0) return false;
            // The real-pipe path chooses external vs. mixed execution before
            // per-stage expansion, so dynamic command names must use the
            // normal path where expanded names get function/builtin lookup.
            if (commandNameNeedsRuntimeExpansion(command)) return false;
        }
        return true;
    }

    fn commandNameNeedsRuntimeExpansion(command: ir.SimpleCommand) bool {
        std.debug.assert(command.argv.len != 0);
        const name = command.argv[0];
        return !std.mem.eql(u8, name.raw, name.text);
    }

    fn executeRealPipeline(self: *Executor, program: ir.Program, pipeline: ir.Pipeline, options: ExecuteOptions, io: std.Io) !CommandResult {
        var has_builtin = false;
        for (pipeline.command_indexes) |command_index| {
            const command = program.commands[command_index];
            if (builtinForName(self.*, command.argv[0].text) != null or self.functions.get(command.argv[0].text) != null) {
                has_builtin = true;
                break;
            }
        }
        if (!has_builtin and !pipelineHasRedirections(program, pipeline)) return self.executeExternalPipeline(program, pipeline, options, io);
        return self.executeMixedPipeline(program, pipeline, options, io);
    }

    const PipelinePipe = struct {
        read: ?std.Io.File,
        write: ?std.Io.File,

        fn close(self: *PipelinePipe, io: std.Io) void {
            if (self.read) |file| file.close(io);
            if (self.write) |file| file.close(io);
            self.* = .{ .read = null, .write = null };
        }
    };

    fn movePipelineReservedFdHandles(redirections: []const ir.Redirection, pipes: []PipelinePipe, capture_stdout: *PipelinePipe, capture_stderr: *PipelinePipe, io: std.Io) !void {
        for (redirections) |redirection| {
            const fd = redirectionChildFd(redirection) orelse continue;
            if (fd <= 2) continue;
            for (pipes) |*pipe| try movePipelinePipeFdHandle(pipe, io, fd);
            try movePipelinePipeFdHandle(capture_stdout, io, fd);
            try movePipelinePipeFdHandle(capture_stderr, io, fd);
        }
    }

    fn redirectionChildFd(redirection: ir.Redirection) ?std.posix.fd_t {
        if (redirectionOpensFd(redirection)) |fd| return fd;
        return switch (redirection.operator) {
            .less_and => redirectionFd(redirection) orelse 0,
            .greater_and => redirectionFd(redirection) orelse 1,
            else => null,
        };
    }

    fn movePipelinePipeFdHandle(pipe: *PipelinePipe, io: std.Io, fd: std.posix.fd_t) !void {
        try movePipelineStageFileHandle(&pipe.read, io, fd);
        try movePipelineStageFileHandle(&pipe.write, io, fd);
    }

    const BuiltinPipelineContext = struct {
        executor: *Executor,
        command: ir.SimpleCommand,
        options: ExecuteOptions,
        io: std.Io,
        stdin_file: ?std.Io.File,
        stdout_file: ?std.Io.File,
        stderr_file: ?std.Io.File,
        stdout_sink_id: ?usize,
        stderr_sink_id: ?usize,
        stage_index: usize,
        stage_stdio: ExternalStdio = .capture,
        status: ExitStatus = 0,
        err: ?anyerror = null,
    };

    fn executeMixedPipeline(self: *Executor, program: ir.Program, pipeline: ir.Pipeline, options: ExecuteOptions, io: std.Io) !CommandResult {
        const foreground_terminal = try prepareForegroundTerminal(options.interactive and options.foreground_terminal and options.external_stdio == .inherit);
        if (foreground_terminal) |terminal| return self.executeForegroundMixedPipeline(program, pipeline, options, io, terminal);

        // Mixed pipelines run builtin/function stages on shell threads in the
        // parent only when no foreground terminal handoff is active. Interactive
        // inherited-stdio jobs with a controlling terminal fork through
        // executeForegroundMixedPipeline first so the shell-implemented stages
        // live in the foreground job's process group before tcsetpgrp.
        const pipe_count = pipeline.command_indexes.len - 1;
        const pipes = try self.allocator.alloc(PipelinePipe, pipe_count);
        defer self.allocator.free(pipes);
        for (pipes) |*pipe| pipe.* = try makePipelinePipe(io);
        defer for (pipes) |*pipe| pipe.close(io);

        var capture_stdout = try makePipelinePipe(io);
        defer capture_stdout.close(io);
        var capture_stderr = try makePipelinePipe(io);
        defer capture_stderr.close(io);

        const children = try self.allocator.alloc(std.process.Child, pipeline.command_indexes.len);
        defer self.allocator.free(children);
        const child_stage_indexes = try self.allocator.alloc(usize, pipeline.command_indexes.len);
        defer self.allocator.free(child_stage_indexes);
        const cancel_pids = try self.allocator.alloc(?i32, pipeline.command_indexes.len);
        defer self.allocator.free(cancel_pids);
        @memset(cancel_pids, null);
        defer for (cancel_pids) |pid| unregisterCancelableChild(options, pid);
        var spawned: usize = 0;
        errdefer for (children[0..spawned]) |*child| child.kill(io);

        var threads: std.ArrayList(std.Thread) = .empty;
        defer threads.deinit(self.allocator);
        var contexts: std.ArrayList(*BuiltinPipelineContext) = .empty;
        defer contexts.deinit(self.allocator);
        errdefer {
            for (contexts.items) |context| self.allocator.destroy(context);
        }
        const StageFailure = struct { index: usize, diagnostic: []u8 };
        var stage_failures: std.ArrayList(StageFailure) = .empty;
        defer {
            for (stage_failures.items) |failure| self.allocator.free(failure.diagnostic);
            stage_failures.deinit(self.allocator);
        }

        for (pipeline.command_indexes, 0..) |command_index, index| {
            try checkCanceled(options);
            const command = program.commands[command_index];
            const is_last = index + 1 == pipeline.command_indexes.len;
            const is_builtin_stage = builtinForName(self.*, command.argv[0].text) != null or self.functions.get(command.argv[0].text) != null;
            // With inherited stdio the last stage writes to the shell's own
            // stdout and stderr like other shells, so output streams and the
            // stage sees a tty; capture only when the shell consumes it.
            const inherit_output = options.external_stdio == .inherit;
            var stdin_file: ?std.Io.File = if (index == 0) null else takeRead(&pipes[index - 1]);
            var stdout_file: ?std.Io.File = if (!is_last) takeWrite(&pipes[index]) else if (inherit_output) try dupStdioFile(1) else takeWrite(&capture_stdout);
            var stderr_file: ?std.Io.File = if (!is_last) null else if (inherit_output) try dupStdioFile(2) else takeWrite(&capture_stderr);
            var next_sink_id: usize = 1;
            var stdout_sink_id: ?usize = if (stdout_file != null) takeNextSinkId(&next_sink_id) else null;
            var stderr_sink_id: ?usize = if (stderr_file != null) takeNextSinkId(&next_sink_id) else null;
            var stdout_closed = false;
            var stderr_closed = false;
            var inherited_redirections = if (is_builtin_stage) null else try FdRedirectionGuard.init(self.allocator, io);
            defer if (inherited_redirections) |*guard| guard.restore(self, io);
            if (!is_builtin_stage) try movePipelineReservedFdHandles(command.redirections, pipes, &capture_stdout, &capture_stderr, io);
            self.applyPipelineStageRedirections(io, command, options, &stdin_file, &stdout_file, &stderr_file, &stdout_sink_id, &stderr_sink_id, &next_sink_id, &stdout_closed, &stderr_closed, if (inherited_redirections) |*guard| guard else null) catch |err| {
                // A redirection error fails this stage with a diagnostic
                // while the other pipeline stages still run (POSIX 2.8.1
                // treats it as a utility redirection error).
                const diagnostic = (try self.redirectionFailureDiagnostic(command, err)) orelse return err;
                errdefer self.allocator.free(diagnostic);
                if (stdin_file) |file| file.close(io);
                if (stdout_file) |file| file.close(io);
                if (stderr_file) |file| file.close(io);
                try stage_failures.append(self.allocator, .{ .index = index, .diagnostic = diagnostic });
                continue;
            };
            const command_without_redirs: ir.SimpleCommand = .{
                .span = command.span,
                .assignments = command.assignments,
                .argv = command.argv,
                .redirections = &.{},
            };

            if (is_builtin_stage) {
                const context = try self.allocator.create(BuiltinPipelineContext);
                errdefer self.allocator.destroy(context);
                context.* = .{
                    .executor = self,
                    .command = command_without_redirs,
                    .options = options,
                    .io = io,
                    .stdin_file = stdin_file,
                    .stdout_file = stdout_file,
                    .stderr_file = stderr_file,
                    .stdout_sink_id = stdout_sink_id,
                    .stderr_sink_id = stderr_sink_id,
                    .stage_index = index,
                    // The last interactive stage lets nested externals write
                    // to the terminal directly so they see a tty, unless a
                    // redirection retargeted the stage's output.
                    .stage_stdio = if (is_last and inherit_output and command.redirections.len == 0) .inherit_output else .capture,
                };
                if (is_last) {
                    const thread = try std.Thread.spawn(.{}, runBuiltinPipelineStage, .{context});
                    try threads.append(self.allocator, thread);
                    try contexts.append(self.allocator, context);
                } else {
                    children[spawned] = try forkBuiltinPipelineStage(context);
                    cancel_pids[spawned] = registerCancelableChild(options, children[spawned], false);
                    child_stage_indexes[spawned] = index;
                    spawned += 1;
                    if (stdin_file) |file| file.close(io);
                    if (stdout_file) |file| file.close(io);
                    if (stderr_file) |file| file.close(io);
                    self.allocator.destroy(context);
                }
            } else {
                const argv = try argvForCommand(self.allocator, command_without_redirs);
                defer self.allocator.free(argv);
                const resolved_executable = self.resolveExternalArgv0(command_without_redirs, io, options) catch |err| switch (err) {
                    error.CommandNotFound => {
                        if (stdin_file) |file| file.close(io);
                        if (stdout_file) |file| file.close(io);
                        if (stderr_file) |file| file.close(io);
                        for (pipes) |*pipe| pipe.close(io);
                        capture_stdout.close(io);
                        capture_stderr.close(io);
                        return self.pipelineSpawnFailureResult(io, command.argv[0].text, children[0..spawned], &threads, contexts.items, 127, "command not found");
                    },
                    error.AccessDenied, error.PermissionDenied => {
                        if (stdin_file) |file| file.close(io);
                        if (stdout_file) |file| file.close(io);
                        if (stderr_file) |file| file.close(io);
                        for (pipes) |*pipe| pipe.close(io);
                        capture_stdout.close(io);
                        capture_stderr.close(io);
                        return self.pipelineSpawnFailureResult(io, command.argv[0].text, children[0..spawned], &threads, contexts.items, 126, "permission denied");
                    },
                    else => return err,
                };
                defer if (resolved_executable) |executable| self.allocator.free(executable);
                if (resolved_executable) |executable| argv[0] = executable;
                var child_env = try self.buildProcessEnv(command.assignments);
                defer child_env.deinit();
                const child_pgid = cancellableExternalPgid(options, null);
                children[spawned] = self.spawnExternalCommand(io, .{
                    .argv = argv,
                    .environ_map = &child_env,
                    .stdin = if (stdin_file) |file| .{ .file = file } else .ignore,
                    .stdout = if (stdout_closed) .close else if (stdout_file) |file| .{ .file = file } else .ignore,
                    .stderr = if (stderr_closed) .close else if (stderr_file) |file| .{ .file = file } else .inherit,
                    .pgid = child_pgid,
                }) catch |err| switch (err) {
                    error.FileNotFound => {
                        if (stdin_file) |file| file.close(io);
                        if (stdout_file) |file| file.close(io);
                        if (stderr_file) |file| file.close(io);
                        for (pipes) |*pipe| pipe.close(io);
                        capture_stdout.close(io);
                        capture_stderr.close(io);
                        return self.pipelineSpawnFailureResult(io, command.argv[0].text, children[0..spawned], &threads, contexts.items, 127, "command not found");
                    },
                    error.AccessDenied, error.PermissionDenied, error.IsDir => {
                        if (stdin_file) |file| file.close(io);
                        if (stdout_file) |file| file.close(io);
                        if (stderr_file) |file| file.close(io);
                        for (pipes) |*pipe| pipe.close(io);
                        capture_stdout.close(io);
                        capture_stderr.close(io);
                        return self.pipelineSpawnFailureResult(io, command.argv[0].text, children[0..spawned], &threads, contexts.items, 126, "permission denied");
                    },
                    else => return err,
                };
                const spawned_index = spawned;
                errdefer children[spawned_index].kill(io);
                try movePipelineStageHandlesFromGuard(inherited_redirections.?, &stdin_file, &stdout_file, &stderr_file, io);
                inherited_redirections.?.restore(self, io);
                cancel_pids[spawned] = registerCancelableChild(options, children[spawned], child_pgid != null);
                child_stage_indexes[spawned] = index;
                spawned += 1;
                if (stdin_file) |file| file.close(io);
                if (stdout_file) |file| file.close(io);
                if (stderr_file) |file| file.close(io);
            }
        }

        for (pipes) |*pipe| pipe.close(io);
        if (capture_stdout.write) |file| file.close(io);
        capture_stdout.write = null;
        if (capture_stderr.write) |file| file.close(io);
        capture_stderr.write = null;

        var multi_reader_buffer: std.Io.File.MultiReader.Buffer(2) = undefined;
        var multi_reader: std.Io.File.MultiReader = undefined;
        multi_reader.init(self.allocator, io, multi_reader_buffer.toStreams(), &.{ capture_stdout.read.?, capture_stderr.read.? });
        defer multi_reader.deinit();

        while (multi_reader.fill(64, .none)) |_| {} else |err| switch (err) {
            error.EndOfStream => {},
            else => |e| return e,
        }
        try multi_reader.checkAnyError();

        const statuses = try self.allocator.alloc(ExitStatus, pipeline.command_indexes.len);
        defer self.allocator.free(statuses);
        @memset(statuses, 0);
        for (children[0..spawned], child_stage_indexes[0..spawned]) |*child, stage_index| {
            const term = try child.wait(io);
            statuses[stage_index] = exitStatusFromTerm(term);
        }
        for (threads.items) |thread| thread.join();
        for (contexts.items) |context| {
            if (context.err) |err| {
                for (contexts.items) |owned_context| self.allocator.destroy(owned_context);
                contexts.clearRetainingCapacity();
                return err;
            }
            statuses[context.stage_index] = context.status;
        }
        for (contexts.items) |context| self.allocator.destroy(context);
        contexts.clearRetainingCapacity();

        var stderr_output = try multi_reader.toOwnedSlice(1);
        errdefer self.allocator.free(stderr_output);
        for (stage_failures.items) |failure| {
            statuses[failure.index] = 2;
            const combined = try std.mem.concat(self.allocator, u8, &.{ failure.diagnostic, stderr_output });
            self.allocator.free(stderr_output);
            stderr_output = combined;
        }

        return .{
            .allocator = self.allocator,
            .status = self.pipelineStatus(pipeline, statuses),
            .stdout = try multi_reader.toOwnedSlice(0),
            .stderr = stderr_output,
        };
    }

    fn executeForegroundMixedPipeline(self: *Executor, program: ir.Program, pipeline: ir.Pipeline, options: ExecuteOptions, io: std.Io, terminal: ForegroundTerminal) !CommandResult {
        const pid = try forkProcess();
        if (pid == 0) {
            processSetPgrp(0, 0) catch exitForkedChild(2);
            resetInteractiveJobSignalHandlers();
            var child_options = options;
            child_options.foreground_terminal = false;
            var status: ExitStatus = 2;
            var child_result = self.executeMixedPipeline(program, pipeline, child_options, io) catch null;
            if (child_result) |*result| {
                status = result.status;
                if (child_options.external_stdio == .inherit) writeInheritedResult(io, result.*) catch {};
                result.deinit();
            }
            exitForkedChild(status);
        }

        var child = childFromPid(pid);
        var kill_child_on_error = true;
        errdefer if (kill_child_on_error) child.kill(io);

        processSetPgrp(pid, pid) catch |err| switch (err) {
            error.ProcessAlreadyExec, error.ProcessNotFound => {},
            else => return err,
        };

        const cancel_pid = registerCancelableChild(options, child, true);
        defer unregisterCancelableChild(options, cancel_pid);
        defer restoreForegroundTerminal(terminal);
        try giveTerminalToForegroundPgrp(pid, terminal);

        const wait_status = try waitForegroundProcess(pid);
        const status = exitStatusFromWaitStatus(wait_status);
        if (std.posix.W.IFSTOPPED(wait_status)) {
            const command = try self.allocator.dupe(u8, std.mem.trim(u8, pipelineText(program, pipeline), " \t\r\n;&"));
            errdefer self.allocator.free(command);
            try self.background_jobs.append(self.allocator, .{
                .id = self.next_job_id,
                .pid = @intCast(pid),
                .pgrp = @intCast(pid),
                .command = command,
                .child = child,
                .state = .stopped,
                .status = status,
                .stop_signal = signalStatusNumber(std.posix.W.STOPSIG(wait_status)),
            });
            const job = &self.background_jobs.items[self.background_jobs.items.len - 1];
            saveJobTerminalModes(job);
            self.queueJobNotification(job) catch {};
            self.selectCurrentJob(self.next_job_id);
            self.next_job_id += 1;
            kill_child_on_error = false;
        } else {
            child.id = null;
            kill_child_on_error = false;
        }
        return emptyResult(self.allocator, status);
    }

    fn redirectionFailureDiagnostic(self: *Executor, command: ir.SimpleCommand, err: anyerror) !?[]u8 {
        const name, const message = switch (err) {
            error.BadFileDescriptor => .{ badFdTargetName(command), "bad file descriptor" },
            error.FileNotFound => .{ redirectionTargetName(command), "no such file or directory" },
            error.IsDir => .{ redirectionTargetName(command), "is a directory" },
            error.PathAlreadyExists => .{ noclobberTargetName(command), "cannot overwrite existing file" },
            else => return null,
        };
        return try std.fmt.allocPrint(self.allocator, "{s}: {s}\n", .{ name, message });
    }

    fn asyncRedirectionErrorResult(self: *Executor, command: ir.SimpleCommand, err: anyerror) !CommandResult {
        const diagnostic = (try self.redirectionFailureDiagnostic(command, err)) orelse return err;
        errdefer self.allocator.free(diagnostic);
        return .{
            .allocator = self.allocator,
            .status = 0,
            .stdout = try self.allocator.alloc(u8, 0),
            .stderr = diagnostic,
        };
    }

    fn pipelineSpawnFailureResult(self: *Executor, io: std.Io, name: []const u8, children: []std.process.Child, threads: *std.ArrayList(std.Thread), contexts: []const *BuiltinPipelineContext, status: ExitStatus, message: []const u8) !CommandResult {
        for (children) |*child| child.kill(io);
        for (threads.items) |thread| thread.join();
        for (contexts) |context| self.allocator.destroy(context);
        threads.clearRetainingCapacity();
        return errorResult(self.allocator, status, name, message);
    }

    fn applyPipelineStageRedirections(
        self: *Executor,
        io: std.Io,
        command: ir.SimpleCommand,
        options: ExecuteOptions,
        stdin_file: *?std.Io.File,
        stdout_file: *?std.Io.File,
        stderr_file: *?std.Io.File,
        stdout_sink_id: *?usize,
        stderr_sink_id: *?usize,
        next_sink_id: *usize,
        stdout_closed: *bool,
        stderr_closed: *bool,
        inherited_redirections: ?*FdRedirectionGuard,
    ) !void {
        const redirections = try self.expandRedirections(command.redirections, options);
        defer self.freeRedirections(redirections);
        try self.validateFdDuplicationTargets(redirections);

        var input_fds: std.AutoHashMapUnmanaged(std.posix.fd_t, std.Io.File) = .empty;
        defer {
            var iter = input_fds.valueIterator();
            while (iter.next()) |file| file.close(io);
            input_fds.deinit(self.allocator);
        }

        for (redirections) |redirection| {
            if (redirection.operator == .dless or redirection.operator == .dless_dash) {
                const fd = redirectionFd(redirection) orelse 0;
                if (fd > 2) if (inherited_redirections) |guard| {
                    var inherited_file = try fileFromBytes(io, redirection.here_doc orelse "");
                    var close_inherited_file = true;
                    errdefer if (close_inherited_file) inherited_file.close(io);
                    const guard_owns_file = try self.applyPipelineInheritedFile(&input_fds, stdin_file, stdout_file, stderr_file, guard, io, fd, inherited_file);
                    if (guard_owns_file) {
                        close_inherited_file = false;
                    } else {
                        inherited_file.close(io);
                        close_inherited_file = false;
                    }
                };
                const file = try fileFromBytes(io, redirection.here_doc orelse "");
                if (fd == 0) {
                    if (stdin_file.*) |old| old.close(io);
                    stdin_file.* = file;
                } else {
                    try self.putPipelineInputFd(&input_fds, io, fd, file);
                }
                continue;
            }
            if (redirection.operator == .less or redirection.operator == .less_great) {
                const target = redirection.target orelse continue;
                const fd = redirectionFd(redirection) orelse 0;
                if (fd > 2) if (inherited_redirections) |guard| {
                    var inherited_file = if (redirection.operator == .less_great)
                        try openReadWriteRedirectionFile(io, target.text)
                    else
                        try std.Io.Dir.cwd().openFile(io, target.text, .{});
                    var close_inherited_file = true;
                    errdefer if (close_inherited_file) inherited_file.close(io);
                    const guard_owns_file = try self.applyPipelineInheritedFile(&input_fds, stdin_file, stdout_file, stderr_file, guard, io, fd, inherited_file);
                    if (guard_owns_file) {
                        close_inherited_file = false;
                    } else {
                        inherited_file.close(io);
                        close_inherited_file = false;
                    }
                };
                const file = if (redirection.operator == .less_great)
                    try openReadWriteRedirectionFile(io, target.text)
                else
                    try std.Io.Dir.cwd().openFile(io, target.text, .{});
                if (fd == 0) {
                    if (stdin_file.*) |old| old.close(io);
                    stdin_file.* = file;
                } else {
                    try self.putPipelineInputFd(&input_fds, io, fd, file);
                }
                continue;
            }
            if (redirection.operator == .less_and) {
                const from_fd = redirectionFd(redirection) orelse 0;
                const target = redirection.target orelse continue;
                if (std.mem.eql(u8, target.text, "-")) {
                    if (from_fd > 2) if (inherited_redirections) |guard| try self.closePipelineInheritedFd(&input_fds, stdin_file, stdout_file, stderr_file, guard, io, from_fd);
                    if (from_fd == 0) {
                        if (stdin_file.*) |file| file.close(io);
                        stdin_file.* = null;
                    } else if (input_fds.fetchRemove(from_fd)) |entry| {
                        entry.value.close(io);
                    }
                    continue;
                }
                const to_fd = parseFd(target.text) orelse continue;
                const file = try self.pipelineInputSourceFile(&input_fds, stdin_file.*, stdout_file.*, stderr_file.*, to_fd);
                if (from_fd == 0) {
                    if (stdin_file.*) |old| old.close(io);
                    stdin_file.* = file;
                } else {
                    if (from_fd > 2) if (inherited_redirections) |guard| {
                        var close_file = true;
                        errdefer if (close_file) file.close(io);
                        const guard_owns_file = try self.applyPipelineInheritedFile(&input_fds, stdin_file, stdout_file, stderr_file, guard, io, from_fd, file);
                        if (guard_owns_file) close_file = false;
                        const stored_file = try dupFileExcept(file, from_fd);
                        if (!guard_owns_file) {
                            file.close(io);
                            close_file = false;
                        }
                        try self.putPipelineInputFd(&input_fds, io, from_fd, stored_file);
                    } else {
                        try self.putPipelineInputFd(&input_fds, io, from_fd, file);
                    };
                }
                continue;
            }
            if (isFileOutputRedirection(redirection)) {
                const target = redirection.target orelse continue;
                const fd = redirectionFd(redirection) orelse 1;
                if (fd > 2) if (inherited_redirections) |guard| {
                    var inherited_file = try openOutputRedirectionFile(io, target.text, redirection.operator, self.shell_options.noclobber);
                    var close_inherited_file = true;
                    errdefer if (close_inherited_file) inherited_file.close(io);
                    const guard_owns_file = try self.applyPipelineInheritedFile(&input_fds, stdin_file, stdout_file, stderr_file, guard, io, fd, inherited_file);
                    if (guard_owns_file) {
                        close_inherited_file = false;
                    } else {
                        inherited_file.close(io);
                        close_inherited_file = false;
                    }
                    continue;
                };
                const file = try openOutputRedirectionFile(io, target.text, redirection.operator, self.shell_options.noclobber);
                switch (fd) {
                    1 => {
                        if (stdout_file.*) |old| old.close(io);
                        stdout_file.* = file;
                        stdout_sink_id.* = takeNextSinkId(next_sink_id);
                        stdout_closed.* = false;
                    },
                    2 => {
                        if (stderr_file.*) |old| old.close(io);
                        stderr_file.* = file;
                        stderr_sink_id.* = takeNextSinkId(next_sink_id);
                        stderr_closed.* = false;
                    },
                    else => try self.putPipelineInputFd(&input_fds, io, fd, file),
                }
                continue;
            }
            if (redirection.operator == .greater_and) {
                const from_fd = redirectionFd(redirection) orelse 1;
                const target = redirection.target orelse continue;
                if (std.mem.eql(u8, target.text, "-")) {
                    if (from_fd > 2) if (inherited_redirections) |guard| try self.closePipelineInheritedFd(&input_fds, stdin_file, stdout_file, stderr_file, guard, io, from_fd);
                    switch (from_fd) {
                        0 => {
                            if (stdin_file.*) |file| file.close(io);
                            stdin_file.* = null;
                        },
                        1 => {
                            if (stdout_file.*) |file| file.close(io);
                            stdout_file.* = null;
                            stdout_sink_id.* = null;
                            stdout_closed.* = true;
                        },
                        2 => {
                            if (stderr_file.*) |file| file.close(io);
                            stderr_file.* = null;
                            stderr_sink_id.* = null;
                            stderr_closed.* = true;
                        },
                        else => if (input_fds.fetchRemove(from_fd)) |entry| entry.value.close(io),
                    }
                    continue;
                }

                const to_fd = parseFd(target.text) orelse continue;
                const source_sink_id = switch (to_fd) {
                    1 => stdout_sink_id.*,
                    2 => stderr_sink_id.*,
                    else => null,
                } orelse takeNextSinkId(next_sink_id);
                const file = try self.pipelineInputSourceFile(&input_fds, stdin_file.*, stdout_file.*, stderr_file.*, to_fd);
                switch (from_fd) {
                    0 => {
                        if (stdin_file.*) |old| old.close(io);
                        stdin_file.* = file;
                    },
                    1 => {
                        if (stdout_file.*) |old| old.close(io);
                        stdout_file.* = file;
                        stdout_sink_id.* = source_sink_id;
                        stdout_closed.* = false;
                    },
                    2 => {
                        if (stderr_file.*) |old| old.close(io);
                        stderr_file.* = file;
                        stderr_sink_id.* = source_sink_id;
                        stderr_closed.* = false;
                    },
                    else => {
                        if (from_fd > 2) if (inherited_redirections) |guard| {
                            var close_file = true;
                            errdefer if (close_file) file.close(io);
                            const guard_owns_file = try self.applyPipelineInheritedFile(&input_fds, stdin_file, stdout_file, stderr_file, guard, io, from_fd, file);
                            if (!guard_owns_file) file.close(io);
                            close_file = false;
                        } else {
                            try self.putPipelineInputFd(&input_fds, io, from_fd, file);
                        };
                    },
                }
            }
        }
    }

    fn applyPipelineInheritedFile(
        self: *Executor,
        input_fds: *std.AutoHashMapUnmanaged(std.posix.fd_t, std.Io.File),
        stdin_file: *?std.Io.File,
        stdout_file: *?std.Io.File,
        stderr_file: *?std.Io.File,
        guard: *FdRedirectionGuard,
        io: std.Io,
        fd: std.posix.fd_t,
        file: std.Io.File,
    ) !bool {
        try movePipelineStageFdHandles(input_fds, stdin_file, stdout_file, stderr_file, io, fd);
        if (input_fds.fetchRemove(fd)) |entry| entry.value.close(io);
        try guard.saveFd(self, fd);
        if (file.handle == fd) {
            const duplicate = try rawDup(file.handle);
            defer closeRawFd(io, duplicate);
            try rawDup2(duplicate, fd);
            try self.markShellFdOpen(fd);
            return true;
        }
        try rawDup2(file.handle, fd);
        try self.markShellFdOpen(fd);
        return false;
    }

    fn closePipelineInheritedFd(
        self: *Executor,
        input_fds: *std.AutoHashMapUnmanaged(std.posix.fd_t, std.Io.File),
        stdin_file: *?std.Io.File,
        stdout_file: *?std.Io.File,
        stderr_file: *?std.Io.File,
        guard: *FdRedirectionGuard,
        io: std.Io,
        fd: std.posix.fd_t,
    ) !void {
        try movePipelineStageFdHandles(input_fds, stdin_file, stdout_file, stderr_file, io, fd);
        try guard.saveFd(self, fd);
        closeRawFd(io, fd);
        self.markShellFdClosed(fd);
    }

    fn movePipelineStageFdHandles(
        input_fds: *std.AutoHashMapUnmanaged(std.posix.fd_t, std.Io.File),
        stdin_file: *?std.Io.File,
        stdout_file: *?std.Io.File,
        stderr_file: *?std.Io.File,
        io: std.Io,
        fd: std.posix.fd_t,
    ) !void {
        try movePipelineStageFileHandle(stdin_file, io, fd);
        try movePipelineStageFileHandle(stdout_file, io, fd);
        try movePipelineStageFileHandle(stderr_file, io, fd);
        var iter = input_fds.valueIterator();
        while (iter.next()) |file| {
            if (file.handle != fd) continue;
            const moved = try dupFile(file.*);
            file.close(io);
            file.* = moved;
        }
    }

    fn movePipelineStageFileHandle(file: *?std.Io.File, io: std.Io, fd: std.posix.fd_t) !void {
        if (file.*) |current| {
            if (current.handle != fd) return;
            const moved = try dupFile(current);
            current.close(io);
            file.* = moved;
        }
    }

    fn movePipelineStageHandlesFromGuard(
        guard: FdRedirectionGuard,
        stdin_file: *?std.Io.File,
        stdout_file: *?std.Io.File,
        stderr_file: *?std.Io.File,
        io: std.Io,
    ) !void {
        for (guard.saved.items) |entry| {
            try movePipelineStageFileHandle(stdin_file, io, entry.fd);
            try movePipelineStageFileHandle(stdout_file, io, entry.fd);
            try movePipelineStageFileHandle(stderr_file, io, entry.fd);
        }
    }

    fn moveExternalRedirectionHandles(
        stdin_file: *?std.Io.File,
        stdout_file: *?std.Io.File,
        stderr_file: *?std.Io.File,
        manual_stdout_capture: *?PipelinePipe,
        manual_stderr_capture: *?PipelinePipe,
        io: std.Io,
        fd: std.posix.fd_t,
    ) !void {
        try moveExternalFileHandle(stdin_file, io, fd);
        try moveExternalFileHandle(stdout_file, io, fd);
        try moveExternalFileHandle(stderr_file, io, fd);
        if (manual_stdout_capture.*) |*pipe| try moveExternalPipeFdHandle(pipe, io, fd);
        if (manual_stderr_capture.*) |*pipe| try moveExternalPipeFdHandle(pipe, io, fd);
    }

    fn moveExternalRedirectionHandlesFromGuard(
        guard: FdRedirectionGuard,
        stdin_file: *?std.Io.File,
        stdout_file: *?std.Io.File,
        stderr_file: *?std.Io.File,
        manual_stdout_capture: *?PipelinePipe,
        manual_stderr_capture: *?PipelinePipe,
        io: std.Io,
    ) !void {
        for (guard.saved.items) |entry| {
            try moveExternalRedirectionHandles(stdin_file, stdout_file, stderr_file, manual_stdout_capture, manual_stderr_capture, io, entry.fd);
        }
    }

    fn moveAsyncExternalRedirectionHandlesFromGuard(
        guard: FdRedirectionGuard,
        stdin_file: *?std.Io.File,
        stdout_file: *?std.Io.File,
        stderr_file: *?std.Io.File,
        io: std.Io,
    ) !void {
        for (guard.saved.items) |entry| {
            try moveAsyncExternalRedirectionHandles(stdin_file, stdout_file, stderr_file, io, entry.fd);
        }
    }

    fn moveExternalPipeFdHandle(pipe: *PipelinePipe, io: std.Io, fd: std.posix.fd_t) !void {
        try moveExternalFileHandle(&pipe.read, io, fd);
        try moveExternalFileHandle(&pipe.write, io, fd);
    }

    fn moveExternalFileHandle(file: *?std.Io.File, io: std.Io, fd: std.posix.fd_t) !void {
        if (file.*) |current| {
            if (current.handle != fd) return;
            const moved = try dupFileCloseOnExec(current);
            current.close(io);
            file.* = moved;
        }
    }

    fn duplicateExternalStdioFromFd(
        stdout_file: *?std.Io.File,
        stderr_file: *?std.Io.File,
        io: std.Io,
        from_fd: std.posix.fd_t,
        to_fd: std.posix.fd_t,
    ) !bool {
        if (to_fd <= 2) return false;
        if (from_fd != 1 and from_fd != 2) return false;

        const duplicate: std.Io.File = .{ .handle = try rawDup(to_fd), .flags = .{ .nonblocking = false } };
        errdefer duplicate.close(io);
        switch (from_fd) {
            1 => {
                if (stdout_file.*) |old| old.close(io);
                stdout_file.* = duplicate;
                return true;
            },
            2 => {
                if (stderr_file.*) |old| old.close(io);
                stderr_file.* = duplicate;
                return true;
            },
            else => unreachable,
        }
    }

    fn duplicateExternalStdioFromInheritedTarget(
        stdout_file: *?std.Io.File,
        stderr_file: *?std.Io.File,
        io: std.Io,
        from_fd: std.posix.fd_t,
        to_fd: std.posix.fd_t,
        stdout_closed: bool,
        stderr_closed: bool,
        stdio: ExternalStdio,
    ) !bool {
        if (from_fd == 2 and to_fd == 1 and stdout_file.* == null and !stdout_closed and !externalStdioCapturesStdout(stdio)) {
            if (stderr_file.*) |old| old.close(io);
            stderr_file.* = try dupStdioFile(1);
            return true;
        }
        if (from_fd == 1 and to_fd == 2 and stderr_file.* == null and !stderr_closed and !externalStdioCapturesStderr(stdio)) {
            if (stdout_file.*) |old| old.close(io);
            stdout_file.* = try dupStdioFile(2);
            return true;
        }
        return false;
    }

    fn pipelineInputSourceFile(
        self: Executor,
        input_fds: *const std.AutoHashMapUnmanaged(std.posix.fd_t, std.Io.File),
        stdin_file: ?std.Io.File,
        stdout_file: ?std.Io.File,
        stderr_file: ?std.Io.File,
        fd: std.posix.fd_t,
    ) !std.Io.File {
        if (fd == 0) if (stdin_file) |file| return dupFile(file);
        if (fd == 1) if (stdout_file) |file| return dupFile(file);
        if (fd == 2) if (stderr_file) |file| return dupFile(file);
        if (input_fds.get(fd)) |file| return dupFile(file);
        if (!self.isShellFdOpen(fd)) return error.BadFileDescriptor;
        return .{ .handle = try rawDup(fd), .flags = .{ .nonblocking = false } };
    }

    fn putPipelineInputFd(self: *Executor, input_fds: *std.AutoHashMapUnmanaged(std.posix.fd_t, std.Io.File), io: std.Io, fd: std.posix.fd_t, file: std.Io.File) !void {
        errdefer file.close(io);
        const entry = try input_fds.getOrPut(self.allocator, fd);
        if (entry.found_existing) entry.value_ptr.close(io);
        entry.value_ptr.* = file;
    }

    fn runBuiltinPipelineStage(context: *BuiltinPipelineContext) void {
        runBuiltinPipelineStageFallible(context) catch |err| {
            switch (err) {
                error.BrokenPipe, error.WriteFailed => context.status = 1,
                else => {
                    context.err = err;
                    context.status = 2;
                },
            }
        };
    }

    fn forkBuiltinPipelineStage(context: *BuiltinPipelineContext) !std.process.Child {
        const pid = try forkProcess();
        if (pid == 0) {
            context.executor.resetCaughtTrapsForSubshell() catch exitForkedChild(2);
            runBuiltinPipelineStage(context);
            exitForkedChild(context.status);
        }
        return childFromPid(pid);
    }

    fn runBuiltinPipelineStageFallible(context: *BuiltinPipelineContext) !void {
        defer if (context.stdin_file) |file| file.close(context.io);
        defer if (context.stdout_file) |file| file.close(context.io);
        defer if (context.stderr_file) |file| file.close(context.io);

        // The stage's output must flow into its pipe or redirection target,
        // so externals nested under functions or the command builtin have
        // to be captured rather than inherit the terminal — except for the
        // last interactive stage, where they write to the terminal directly.
        // Routing the pipe input through stage-local stdin lets those nested
        // commands read it in either mode.
        var stage_options = context.options;
        stage_options.external_stdio = context.stage_stdio;
        const stdin_guard = pushPipelineStageStdin(context.stdin_file);
        defer stdin_guard.restore();

        const saved_umask = readShellUmask();
        defer restoreShellUmask(saved_umask);
        var result = try context.executor.executeSimpleCommandWithInput(context.command, "", stage_options);
        defer result.deinit();
        context.status = result.status;
        if (context.stdout_file != null and context.stderr_file != null and context.stdout_sink_id != null and context.stderr_sink_id != null and context.stdout_sink_id.? == context.stderr_sink_id.?) {
            const combined = try std.mem.concat(context.executor.allocator, u8, &.{ result.stdout, result.stderr });
            defer context.executor.allocator.free(combined);
            try writeBytesToFile(context.io, context.stdout_file.?, combined);
            return;
        }
        if (context.stdout_file) |file| try writeBytesToFile(context.io, file, result.stdout);
        if (context.stderr_file) |file| try writeBytesToFile(context.io, file, result.stderr);
    }

    fn takeNextSinkId(next_sink_id: *usize) usize {
        const sink_id = next_sink_id.*;
        next_sink_id.* += 1;
        return sink_id;
    }

    fn takeRead(pipe: *PipelinePipe) ?std.Io.File {
        const file = pipe.read;
        pipe.read = null;
        return file;
    }

    fn takeWrite(pipe: *PipelinePipe) ?std.Io.File {
        const file = pipe.write;
        pipe.write = null;
        return file;
    }

    fn executeExternalPipeline(self: *Executor, program: ir.Program, pipeline: ir.Pipeline, options: ExecuteOptions, io: std.Io) !CommandResult {
        const expanded_commands = try self.allocator.alloc(ir.SimpleCommand, pipeline.command_indexes.len);
        defer self.allocator.free(expanded_commands);
        var expanded_count: usize = 0;
        defer for (expanded_commands[0..expanded_count]) |expanded| self.freeExpandedCommand(expanded);

        var trace_stderr: std.ArrayList(u8) = .empty;
        defer trace_stderr.deinit(self.allocator);

        for (pipeline.command_indexes, 0..) |command_index, index| {
            expanded_commands[index] = try self.expandSimpleCommand(program.commands[command_index], options);
            expanded_count += 1;
            if (self.shell_options.xtrace and (expanded_commands[index].assignments.len != 0 or expanded_commands[index].argv.len != 0)) {
                const trace = try traceLineForCommand(self.allocator, expanded_commands[index]);
                defer self.allocator.free(trace);
                if (options.external_stdio == .inherit) {
                    try rawWriteAll(2, trace);
                } else {
                    try trace_stderr.appendSlice(self.allocator, trace);
                }
            }
        }

        const children = try self.allocator.alloc(std.process.Child, pipeline.command_indexes.len);
        defer self.allocator.free(children);
        const cancel_pids = try self.allocator.alloc(?i32, pipeline.command_indexes.len);
        defer self.allocator.free(cancel_pids);
        @memset(cancel_pids, null);
        defer for (cancel_pids) |pid| unregisterCancelableChild(options, pid);
        var spawned: usize = 0;
        errdefer for (children[0..spawned]) |*child| child.kill(io);

        var previous_stdout: ?std.Io.File = null;
        defer if (previous_stdout) |file| file.close(io);
        const foreground_terminal = try prepareForegroundTerminal(options.foreground_terminal and options.external_stdio == .inherit);
        defer restoreForegroundTerminal(foreground_terminal);
        var pipeline_pgrp: ?std.posix.pid_t = null;

        for (pipeline.command_indexes, 0..) |_, index| {
            try checkCanceled(options);
            const command = expanded_commands[index];
            const argv = try argvForCommand(self.allocator, command);
            defer self.allocator.free(argv);
            const resolved_executable = self.resolveExternalArgv0(command, io, options) catch |err| switch (err) {
                error.CommandNotFound => {
                    const open_stdin = previous_stdout;
                    previous_stdout = null;
                    var failure = try self.externalPipelineSpawnFailureResult(io, command.argv[0].text, children[0..spawned], open_stdin, 127, "command not found");
                    errdefer failure.deinit();
                    if (trace_stderr.items.len != 0) {
                        const stderr = try std.mem.concat(self.allocator, u8, &.{ trace_stderr.items, failure.stderr });
                        self.allocator.free(failure.stderr);
                        failure.stderr = stderr;
                    }
                    return failure;
                },
                error.AccessDenied, error.PermissionDenied => {
                    const open_stdin = previous_stdout;
                    previous_stdout = null;
                    var failure = try self.externalPipelineSpawnFailureResult(io, command.argv[0].text, children[0..spawned], open_stdin, 126, "permission denied");
                    errdefer failure.deinit();
                    if (trace_stderr.items.len != 0) {
                        const stderr = try std.mem.concat(self.allocator, u8, &.{ trace_stderr.items, failure.stderr });
                        self.allocator.free(failure.stderr);
                        failure.stderr = stderr;
                    }
                    return failure;
                },
                else => return err,
            };
            defer if (resolved_executable) |executable| self.allocator.free(executable);
            if (resolved_executable) |executable| argv[0] = executable;
            var child_env = try self.buildProcessEnv(command.assignments);
            defer child_env.deinit();

            // With inherited stdio the last stage owns the shell's stdout
            // and stderr like other shells: output streams to the terminal
            // and the stage sees a tty. Capture only when the shell consumes
            // the output (command substitution, hidden refreshes, tests).
            const inherit_output = options.external_stdio == .inherit;
            const is_last = index + 1 == pipeline.command_indexes.len;
            const requested_pgid: ?std.posix.pid_t = if (foreground_terminal != null) (pipeline_pgrp orelse 0) else null;
            const child_pgid = cancellableExternalPgid(options, requested_pgid);
            children[index] = self.spawnExternalCommand(io, .{
                .argv = argv,
                .environ_map = &child_env,
                .stdin = if (previous_stdout) |file| .{ .file = file } else if (options.external_stdio == .inherit) .inherit else .ignore,
                .stdout = if (is_last and inherit_output) .inherit else .pipe,
                .stderr = if (is_last and !inherit_output) .pipe else .inherit,
                .pgid = child_pgid,
            }) catch |err| switch (err) {
                error.FileNotFound => {
                    const open_stdin = previous_stdout;
                    previous_stdout = null;
                    var failure = try self.externalPipelineSpawnFailureResult(io, command.argv[0].text, children[0..spawned], open_stdin, 127, "command not found");
                    errdefer failure.deinit();
                    if (trace_stderr.items.len != 0) {
                        const stderr = try std.mem.concat(self.allocator, u8, &.{ trace_stderr.items, failure.stderr });
                        self.allocator.free(failure.stderr);
                        failure.stderr = stderr;
                    }
                    return failure;
                },
                error.AccessDenied, error.PermissionDenied, error.IsDir => {
                    const open_stdin = previous_stdout;
                    previous_stdout = null;
                    var failure = try self.externalPipelineSpawnFailureResult(io, command.argv[0].text, children[0..spawned], open_stdin, 126, "permission denied");
                    errdefer failure.deinit();
                    if (trace_stderr.items.len != 0) {
                        const stderr = try std.mem.concat(self.allocator, u8, &.{ trace_stderr.items, failure.stderr });
                        self.allocator.free(failure.stderr);
                        failure.stderr = stderr;
                    }
                    return failure;
                },
                else => return err,
            };
            cancel_pids[index] = registerCancelableChild(options, children[index], child_pgid != null);
            if (pipeline_pgrp == null and foreground_terminal != null) pipeline_pgrp = children[index].id;
            spawned += 1;

            if (previous_stdout) |file| file.close(io);
            previous_stdout = null;

            if (!is_last) {
                previous_stdout = children[index].stdout.?;
                children[index].stdout = null;
            }
        }

        if (pipeline_pgrp) |pgrp| try giveTerminalToForegroundPgrp(pgrp, foreground_terminal);

        var stdout_bytes: []u8 = try self.allocator.alloc(u8, 0);
        errdefer self.allocator.free(stdout_bytes);
        var stderr_bytes: []u8 = try self.allocator.alloc(u8, 0);
        errdefer self.allocator.free(stderr_bytes);

        const last_child = &children[pipeline.command_indexes.len - 1];
        if (options.external_stdio != .inherit) {
            var multi_reader_buffer: std.Io.File.MultiReader.Buffer(2) = undefined;
            var multi_reader: std.Io.File.MultiReader = undefined;
            multi_reader.init(self.allocator, io, multi_reader_buffer.toStreams(), &.{ last_child.stdout.?, last_child.stderr.? });
            defer multi_reader.deinit();

            while (multi_reader.fill(64, .none)) |_| {} else |err| switch (err) {
                error.EndOfStream => {},
                else => |e| return e,
            }
            try multi_reader.checkAnyError();
            self.allocator.free(stdout_bytes);
            stdout_bytes = try multi_reader.toOwnedSlice(0);
            self.allocator.free(stderr_bytes);
            stderr_bytes = try multi_reader.toOwnedSlice(1);
        }
        if (trace_stderr.items.len != 0) {
            const stderr = try std.mem.concat(self.allocator, u8, &.{ trace_stderr.items, stderr_bytes });
            self.allocator.free(stderr_bytes);
            stderr_bytes = stderr;
        }

        const statuses = try self.allocator.alloc(ExitStatus, spawned);
        defer self.allocator.free(statuses);
        for (children[0..spawned], 0..) |*child, index| {
            const term = try child.wait(io);
            statuses[index] = exitStatusFromTerm(term);
        }

        return .{
            .allocator = self.allocator,
            .status = self.pipelineStatus(pipeline, statuses),
            .stdout = stdout_bytes,
            .stderr = stderr_bytes,
        };
    }

    fn externalPipelineSpawnFailureResult(self: *Executor, io: std.Io, name: []const u8, children: []std.process.Child, previous_stdout: ?std.Io.File, status: ExitStatus, message: []const u8) !CommandResult {
        if (previous_stdout) |file| file.close(io);
        for (children) |*child| child.kill(io);
        return errorResult(self.allocator, status, name, message);
    }

    pub fn executeSimpleCommand(self: *Executor, command: ir.SimpleCommand, options: ExecuteOptions) !CommandResult {
        return self.executeSimpleCommandWithInput(command, "", options);
    }

    fn executeSimpleCommandWithInput(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) anyerror!CommandResult {
        return self.executeSimpleCommandWithInputOptions(command, stdin, options, false);
    }

    fn executeSimpleCommandWithPipelineInput(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) anyerror!CommandResult {
        return self.executeSimpleCommandWithInputOptions(command, stdin, options, true);
    }

    fn executeSimpleCommandWithInputOptions(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions, force_stdin: bool) anyerror!CommandResult {
        const expanded = self.expandSimpleCommand(command, options) catch |err| switch (err) {
            error.NounsetParameter, error.ParameterExpansionFailed, error.ArithmeticExpansionFailed => return self.expansionErrorResult(err, options),
            error.ReadonlyVariable => return self.assignmentErrorResult(),
            else => return err,
        };
        defer self.freeExpandedCommand(expanded);

        var trace: ?[]const u8 = null;
        var trace_written = false;
        if (self.shell_options.xtrace and (expanded.assignments.len != 0 or expanded.argv.len != 0)) {
            trace = try traceLineForCommand(self.allocator, expanded);
            if (options.external_stdio == .inherit and options.io != null) {
                try rawWriteAll(2, trace.?);
                trace_written = true;
            }
        }
        defer if (trace) |bytes| self.allocator.free(bytes);

        var result = try self.executeExpandedSimpleCommandWithInput(expanded, stdin, options, force_stdin);
        errdefer result.deinit();
        if (trace != null and !trace_written) {
            const stderr = try std.mem.concat(self.allocator, u8, &.{ trace.?, result.stderr });
            self.allocator.free(result.stderr);
            result.stderr = stderr;
        }
        return result;
    }

    fn executeExpandedSimpleCommandWithInput(self: *Executor, expanded: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions, force_stdin: bool) anyerror!CommandResult {
        if (isRedirectionOnlyExec(expanded)) {
            self.applyAssignments(expanded.assignments) catch |err| switch (err) {
                error.ReadonlyVariable => return self.assignmentErrorResult(),
                else => return err,
            };
            if (self.applyPermanentRealFdRedirections(expanded, options) catch |err| return self.redirectionErrorResult(expanded, err, true)) {
                return emptyResult(self.allocator, 0);
            }
        }

        var owned_stdin: ?[]u8 = null;
        defer if (owned_stdin) |bytes| self.allocator.free(bytes);
        var stdin_file: ?std.Io.File = null;
        defer if (stdin_file) |file| file.close(options.io.?);
        const input_special_builtin = expanded.argv.len > 0 and specialBuiltinPropertiesApply(options, expanded.argv[0].text);
        const effective_stdin = self.applyInputRedirections(expanded, stdin, options, &owned_stdin, &stdin_file) catch |err| return self.redirectionErrorResult(expanded, err, input_special_builtin);

        if (expanded.argv.len == 0) {
            self.applyAssignments(expanded.assignments) catch |err| switch (err) {
                error.ReadonlyVariable => return self.assignmentErrorResult(),
                else => return err,
            };
            const assignment_status = self.command_substitution_status orelse 0;
            if (self.applyRealFdRedirectionsIfNeeded(expanded, options) catch |err| return self.redirectionErrorResult(expanded, err, false)) |guard_value| {
                var guard = guard_value;
                defer guard.restore(self, options.io.?);
                return emptyResult(self.allocator, assignment_status);
            }
            return try self.applyOutputRedirections(expanded, try emptyResult(self.allocator, assignment_status), options, false);
        }

        if (!options.suppress_functions and self.functions.getPtr(expanded.argv[0].text) != null) {
            const function_value = self.functions.getPtr(expanded.argv[0].text).?;
            var result = try self.executeFunctionBody(expanded, function_value, options);
            errdefer result.deinit();
            if (options.external_stdio == .inherit and expanded.redirections.len != 0) return result;
            return try self.applyOutputRedirections(expanded, result, options, false);
        }

        if (builtinForName(self.*, expanded.argv[0].text)) |builtin| {
            const builtin_name = expanded.argv[0].text;
            const special_builtin = specialBuiltinPropertiesApply(options, builtin_name);
            if (self.applyRealFdRedirectionsIfNeeded(expanded, options) catch |err| return self.redirectionErrorResult(expanded, err, special_builtin)) |guard_value| {
                var guard = guard_value;
                defer guard.restore(self, options.io.?);
                const redirected_stdin_file: ?std.Io.File = if (hasInputRedirection(expanded.redirections)) std.Io.File.stdin() else stdin_file;
                const stdin_guard = self.pushScriptStdin(effective_stdin, redirected_stdin_file, hasInputRedirection(expanded.redirections) or stdin.len != 0 or force_stdin);
                defer if (stdin_guard) |script_guard| script_guard.restore();
                var result = try self.executeBuiltinWithAssignments(builtin, expanded, effective_stdin, options);
                defer result.deinit();
                if (options.interactive and std.mem.eql(u8, builtin_name, "exec") and result.status != 0 and self.pending_exit == null) {
                    guard.commit(options.io.?);
                }
                writeInheritedResult(options.io.?, result) catch |err| switch (err) {
                    error.BadFileDescriptor => return errorResult(self.allocator, 1, "write", "bad file descriptor"),
                    error.BrokenPipe, error.NoSpaceLeft, error.InputOutput => return self.writeFailureResult(err, special_builtin),
                    else => return err,
                };
                return emptyResult(self.allocator, result.status);
            }
            const stdin_guard = self.pushScriptStdin(effective_stdin, stdin_file, hasInputRedirection(expanded.redirections) or stdin.len != 0 or force_stdin);
            defer if (stdin_guard) |script_guard| script_guard.restore();
            return try self.applyOutputRedirections(expanded, try self.executeBuiltinWithAssignments(builtin, expanded, effective_stdin, options), options, special_builtin);
        }

        if (!options.allow_external) {
            return try self.applyOutputRedirections(expanded, try errorResult(self.allocator, 127, expanded.argv[0].text, "command not found"), options, false);
        }

        const io = options.io orelse return error.MissingIoForExternalCommand;
        var synthetic_failure = false;
        const external_stdin = if (stdin.len != 0 or force_stdin or hasInputRedirection(expanded.redirections)) effective_stdin else self.remainingScriptStdin();
        var external_result = self.executeExternal(expanded, io, options, external_stdin) catch |err| switch (err) {
            error.CommandNotFound => blk: {
                synthetic_failure = true;
                break :blk try errorResult(self.allocator, 127, expanded.argv[0].text, "command not found");
            },
            error.AccessDenied, error.PermissionDenied => blk: {
                synthetic_failure = true;
                break :blk try errorResult(self.allocator, 126, expanded.argv[0].text, "permission denied");
            },
            error.BadFileDescriptor, error.FileNotFound, error.IsDir, error.PathAlreadyExists => return self.redirectionErrorResult(expanded, err, false),
            else => return err,
        };
        errdefer external_result.deinit();
        if (synthetic_failure) return try self.applyOutputRedirections(expanded, external_result, options, false);
        return try self.applyExternalPostRedirections(expanded, external_result, options);
    }

    fn compoundRedirectionErrorResult(self: *Executor, span: parser.Span, redirections: []ir.Redirection, err: anyerror, special_builtin: bool) !CommandResult {
        const wrapper: ir.SimpleCommand = .{
            .span = span,
            .assignments = &.{},
            .argv = &.{},
            .redirections = redirections,
        };
        return self.redirectionErrorResult(wrapper, err, special_builtin);
    }

    fn redirectionErrorResult(self: *Executor, command: ir.SimpleCommand, err: anyerror, special_builtin: bool) !CommandResult {
        const result = switch (err) {
            error.PathAlreadyExists => try errorResult(self.allocator, 1, noclobberTargetName(command), "cannot overwrite existing file"),
            error.BadFileDescriptor => try errorResult(self.allocator, 1, badFdTargetName(command), "bad file descriptor"),
            error.FileNotFound => try errorResult(self.allocator, 1, redirectionTargetName(command), "no such file or directory"),
            error.IsDir => try errorResult(self.allocator, 1, redirectionTargetName(command), "is a directory"),
            else => return err,
        };
        if (special_builtin) self.pending_exit = result.status;
        return result;
    }

    fn writeFailureResult(self: *Executor, err: anyerror, special_builtin: bool) !CommandResult {
        const message = writeFailureMessage(err) orelse return err;
        const result = try errorResult(self.allocator, 1, "write", message);
        if (special_builtin) self.pending_exit = result.status;
        return result;
    }

    fn assignmentErrorResult(self: *Executor) !CommandResult {
        self.pending_exit = 2;
        return errorResult(self.allocator, 2, "assignment", "readonly variable");
    }

    fn expansionErrorResult(self: *Executor, err: anyerror, options: ExecuteOptions) !CommandResult {
        self.had_expansion_error = true;
        return switch (err) {
            error.NounsetParameter => blk: {
                self.markExpansionErrorConsequence(options, 1);
                break :blk errorResult(self.allocator, 1, "parameter", "unset parameter");
            },
            error.ParameterExpansionFailed => self.parameterExpansionErrorResult(options),
            error.ArithmeticExpansionFailed => self.arithmeticExpansionErrorResult(options),
            else => err,
        };
    }

    fn markExpansionErrorConsequence(self: *Executor, options: ExecuteOptions, status: ExitStatus) void {
        if (options.interactive and !options.force_noninteractive_error_consequences) {
            self.pending_command_abort = true;
        } else {
            self.pending_exit = status;
        }
    }

    fn parameterExpansionErrorResult(self: *Executor, options: ExecuteOptions) !CommandResult {
        if (self.parameter_error.name.len == 0) return errorResult(self.allocator, 1, "parameter", "expansion failed");
        const name = self.parameter_error.name;
        const message = if (self.parameter_error.message.len != 0) self.parameter_error.message else "parameter null or not set";
        self.markExpansionErrorConsequence(options, 1);
        errdefer self.parameter_error.clear(self.allocator);
        const result = try errorResult(self.allocator, 1, name, message);
        self.parameter_error.clear(self.allocator);
        return result;
    }

    fn arithmeticExpansionErrorResult(self: *Executor, options: ExecuteOptions) !CommandResult {
        const message = if (self.arithmetic_error.message.len != 0) self.arithmetic_error.message else "invalid arithmetic expression";
        self.markExpansionErrorConsequence(options, 1);
        errdefer self.arithmetic_error.clear(self.allocator);
        const result = try errorResult(self.allocator, 1, "arithmetic", message);
        self.arithmetic_error.clear(self.allocator);
        return result;
    }

    fn executeBuiltinWithAssignments(self: *Executor, builtin: BuiltinFn, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
        if (specialBuiltinPropertiesApply(options, command.argv[0].text)) {
            self.applyAssignments(command.assignments) catch |err| switch (err) {
                error.ReadonlyVariable => return self.assignmentErrorResult(),
                else => return err,
            };
            return self.runBuiltin(builtin, command, stdin, options);
        }
        var assignment_scope = self.pushTemporaryAssignments(command.assignments) catch |err| switch (err) {
            error.ReadonlyVariable => return self.assignmentErrorResult(),
            else => return err,
        };
        defer assignment_scope.restore();
        return self.runBuiltin(builtin, command, stdin, options);
    }

    // Builtins that assign variables (read, getopts, cd, ...) diagnose a
    // readonly target as a utility error: the builtin fails but, unlike a
    // variable assignment error, a non-special builtin does not stop the
    // shell (POSIX XCU 2.8.1).
    fn runBuiltin(self: *Executor, builtin: BuiltinFn, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
        const previous_suppression = self.suppress_special_builtin_properties;
        self.suppress_special_builtin_properties = previous_suppression or (options.suppress_special_builtin_properties and isSpecialBuiltin(command.argv[0].text));
        defer self.suppress_special_builtin_properties = previous_suppression;
        return builtin(self, command, stdin, options) catch |err| switch (err) {
            error.ReadonlyVariable => blk: {
                if (specialBuiltinPropertiesApply(options, command.argv[0].text)) self.pending_exit = 2;
                break :blk try errorResult(self.allocator, 2, command.argv[0].text, "readonly variable");
            },
            else => err,
        };
    }

    fn executeFunctionBody(self: *Executor, command: ir.SimpleCommand, function_value: *const FunctionValue, options: ExecuteOptions) anyerror!CommandResult {
        var assignment_scope = self.pushTemporaryAssignments(command.assignments) catch |err| switch (err) {
            error.ReadonlyVariable => return self.assignmentErrorResult(),
            else => return err,
        };
        defer assignment_scope.restore();
        var owned_stdin: ?[]u8 = null;
        defer if (owned_stdin) |bytes| self.allocator.free(bytes);
        var stdin_file: ?std.Io.File = null;
        defer if (stdin_file) |file| file.close(options.io.?);
        var pipeline_stdin_guard: ?PipelineStageStdinGuard = null;
        defer if (pipeline_stdin_guard) |guard| guard.restore();
        const prior_stdin = self.script_stdin;
        const prior_stdin_offset = self.script_stdin_offset;
        const prior_stdin_file = self.script_stdin_file;
        defer {
            self.script_stdin = prior_stdin;
            self.script_stdin_offset = prior_stdin_offset;
            self.script_stdin_file = prior_stdin_file;
        }
        const call_stdin = self.applyInputRedirections(command, "", options, &owned_stdin, &stdin_file) catch |err| return self.redirectionErrorResult(command, err, false);
        if (stdin_file) |file| {
            if (pipeline_stdin_guard == null) pipeline_stdin_guard = suspendPipelineStageStdin();
            self.script_stdin = null;
            self.script_stdin_offset = 0;
            self.script_stdin_file = file;
        } else if (call_stdin.len != 0 or hasInputRedirection(command.redirections)) {
            if (pipeline_stdin_guard == null) pipeline_stdin_guard = suspendPipelineStageStdin();
            self.script_stdin = call_stdin;
            self.script_stdin_offset = 0;
            self.script_stdin_file = null;
        }
        var real_call_guard: ?FdRedirectionGuard = if (options.external_stdio == .inherit and command.redirections.len != 0)
            self.applyRealFdRedirectionsIfNeeded(command, options) catch |err| return self.redirectionErrorResult(command, err, false)
        else
            null;
        defer if (real_call_guard) |*guard| guard.restore(self, options.io.?);
        if (real_call_guard != null and redirectionsAffectStdin(command.redirections)) {
            if (pipeline_stdin_guard == null) pipeline_stdin_guard = suspendPipelineStageStdin();
            self.script_stdin = null;
            self.script_stdin_offset = 0;
            self.script_stdin_file = std.Io.File.stdin();
        }
        const redirected_stdin = self.applyCompoundInputRedirections(command.span, function_value.redirections, options, &owned_stdin, &stdin_file) catch |err| return self.compoundRedirectionErrorResult(command.span, function_value.redirections, err, false);
        if (stdin_file) |file| {
            if (pipeline_stdin_guard == null) pipeline_stdin_guard = suspendPipelineStageStdin();
            self.script_stdin = null;
            self.script_stdin_offset = 0;
            self.script_stdin_file = file;
        } else if (redirected_stdin) |stdin| {
            if (pipeline_stdin_guard == null) pipeline_stdin_guard = suspendPipelineStageStdin();
            self.script_stdin = stdin;
            self.script_stdin_offset = 0;
            self.script_stdin_file = null;
        }
        var real_definition_redirections: []ir.Redirection = &.{};
        if (options.external_stdio == .inherit and function_value.redirections.len != 0) real_definition_redirections = try self.expandRedirections(function_value.redirections, options);
        defer if (real_definition_redirections.len != 0) self.freeRedirections(real_definition_redirections);
        const definition_wrapper: ir.SimpleCommand = .{
            .span = command.span,
            .assignments = &.{},
            .argv = &.{},
            .redirections = real_definition_redirections,
        };
        var real_definition_guard: ?FdRedirectionGuard = if (real_definition_redirections.len != 0)
            self.applyRealFdRedirectionsIfNeeded(definition_wrapper, options) catch |err| return self.redirectionErrorResult(definition_wrapper, err, false)
        else
            null;
        defer if (real_definition_guard) |*guard| guard.restore(self, options.io.?);
        if (real_definition_guard != null and redirectionsAffectStdin(real_definition_redirections)) {
            if (pipeline_stdin_guard == null) pipeline_stdin_guard = suspendPipelineStageStdin();
            self.script_stdin = null;
            self.script_stdin_offset = 0;
            self.script_stdin_file = std.Io.File.stdin();
        }
        var execution_options = options;
        if (function_value.redirections.len != 0 and real_definition_guard == null) execution_options.external_stdio = .capture;
        try self.pushCallFrame(command.argv[1..]);
        defer self.popCallFrame();
        self.function_depth += 1;
        defer self.function_depth -= 1;
        var result = try self.executeProgram(function_value.program, execution_options);
        errdefer result.deinit();
        result.errexit_ignored_status = false;
        if (self.pending_return) |status| {
            self.pending_return = null;
            result.status = status;
        }
        if (real_definition_guard != null) {
            writeInheritedResult(options.io.?, result) catch |err| switch (err) {
                error.BadFileDescriptor => return errorResult(self.allocator, 1, "write", "bad file descriptor"),
                error.BrokenPipe, error.NoSpaceLeft, error.InputOutput => return self.writeFailureResult(err, false),
                else => return err,
            };
            const status = result.status;
            result.deinit();
            return emptyResult(self.allocator, status);
        }
        if (real_call_guard != null) {
            writeInheritedResult(options.io.?, result) catch |err| switch (err) {
                error.BadFileDescriptor => return errorResult(self.allocator, 1, "write", "bad file descriptor"),
                error.BrokenPipe, error.NoSpaceLeft, error.InputOutput => return self.writeFailureResult(err, false),
                else => return err,
            };
            const status = result.status;
            result.deinit();
            return emptyResult(self.allocator, status);
        }
        return self.applyCompoundOutputRedirections(command.span, function_value.redirections, result, options);
    }

    fn expandSimpleCommand(self: *Executor, command: ir.SimpleCommand, options: ExecuteOptions) !ir.SimpleCommand {
        self.command_substitution_status = null;
        const assignments = try self.expandAssignmentWords(command.assignments, options);
        errdefer self.freeWords(assignments);
        const argv = if (isDeclarationUtilityInvocation(command.argv))
            try self.expandDeclarationArgv(command.argv, options)
        else
            try self.expandArgv(command.argv, options);
        errdefer self.freeWords(argv);
        const redirections = try self.expandRedirections(command.redirections, options);
        errdefer self.freeRedirections(redirections);

        return .{
            .span = command.span,
            .assignments = assignments,
            .argv = argv,
            .redirections = redirections,
        };
    }

    fn expandArgv(self: *Executor, words: []const ir.WordRef, options: ExecuteOptions) ![]ir.WordRef {
        var expanded: std.ArrayList(ir.WordRef) = .empty;
        errdefer {
            for (expanded.items) |word| self.freeWord(word);
            expanded.deinit(self.allocator);
        }

        for (words) |word| {
            try self.appendExpandedArgvWord(&expanded, word, options);
        }

        return expanded.toOwnedSlice(self.allocator);
    }

    fn expandDeclarationArgv(self: *Executor, words: []const ir.WordRef, options: ExecuteOptions) ![]ir.WordRef {
        var expanded: std.ArrayList(ir.WordRef) = .empty;
        errdefer {
            for (expanded.items) |word| self.freeWord(word);
            expanded.deinit(self.allocator);
        }

        for (words, 0..) |word, index| {
            if (index != 0 and isDeclarationAssignmentWord(word.raw)) {
                const expanded_word = try self.expandAssignmentWord(word, options);
                errdefer self.freeWord(expanded_word);
                try expanded.append(self.allocator, expanded_word);
            } else {
                try self.appendExpandedArgvWord(&expanded, word, options);
            }
        }

        return expanded.toOwnedSlice(self.allocator);
    }

    fn appendExpandedArgvWord(self: *Executor, expanded: *std.ArrayList(ir.WordRef), word: ir.WordRef, options: ExecuteOptions) !void {
        var substitution_context: CommandSubstitutionContext = .{ .executor = self, .options = options };
        const positionals: []const []const u8 = self.currentPositionals().params;
        var option_flags_buffer: [shell_option_flags_max]u8 = undefined;
        const option_flags = shellOptionFlags(self.shell_options, &option_flags_buffer);
        var fields = try expand.expandWord(self.allocator, word.raw, .{ .env = self.envLookup(), .env_set = self.envSet(), .arrays = self.arrayLookup(), .io = options.io, .features = options.features, .command_substitution = commandSubstitution(&substitution_context), .positionals = positionals, .option_flags = option_flags, .pathname_expansion = !self.shell_options.noglob, .nounset = self.shell_options.nounset, .parameter_error = &self.parameter_error, .arithmetic_error = &self.arithmetic_error });
        defer fields.deinit();
        for (fields.fields) |field| {
            const raw = try self.allocator.dupe(u8, word.raw);
            errdefer self.allocator.free(raw);
            const text = try self.allocator.dupe(u8, field);
            errdefer self.allocator.free(text);
            try expanded.append(self.allocator, .{ .span = word.span, .raw = raw, .text = text });
        }
    }

    fn isDeclarationUtilityInvocation(words: []const ir.WordRef) bool {
        return declarationUtilityIndex(words) != null;
    }

    fn declarationUtilityIndex(words: []const ir.WordRef) ?usize {
        if (words.len == 0) return null;
        if (isDeclarationUtilityName(words[0].raw)) return 0;
        if (!std.mem.eql(u8, words[0].raw, "command")) return null;

        var index: usize = 0;
        while (index < words.len and std.mem.eql(u8, words[index].raw, "command")) {
            index += 1;
            while (index < words.len and words[index].raw.len > 1 and words[index].raw[0] == '-') {
                const option = words[index].raw;
                index += 1;
                if (std.mem.eql(u8, option, "--")) break;
                for (option[1..]) |flag| switch (flag) {
                    'p' => {},
                    'v', 'V' => return null,
                    else => return null,
                };
            }
        }

        return if (index < words.len and isDeclarationUtilityName(words[index].raw)) index else null;
    }

    fn isDeclarationUtilityName(name: []const u8) bool {
        return std.mem.eql(u8, name, "export") or std.mem.eql(u8, name, "readonly");
    }

    fn isDeclarationAssignmentWord(raw: []const u8) bool {
        const equals = std.mem.indexOfScalar(u8, raw, '=') orelse return false;
        return isShellName(raw[0..equals]);
    }

    fn expandWords(self: *Executor, words: []const ir.WordRef, options: ExecuteOptions) ![]ir.WordRef {
        const expanded = try self.allocator.alloc(ir.WordRef, words.len);
        errdefer self.allocator.free(expanded);
        var initialized: usize = 0;
        errdefer for (expanded[0..initialized]) |word| self.freeWord(word);

        for (words, 0..) |word, index| {
            expanded[index] = try self.expandWord(word, options);
            initialized += 1;
        }
        return expanded;
    }

    fn expandAssignmentWords(self: *Executor, words: []const ir.WordRef, options: ExecuteOptions) ![]ir.WordRef {
        const expanded = try self.allocator.alloc(ir.WordRef, words.len);
        errdefer self.allocator.free(expanded);
        var initialized: usize = 0;
        errdefer for (expanded[0..initialized]) |word| self.freeWord(word);

        var scope = AssignmentExpansionScope.init(self);
        defer scope.restore();

        for (words, 0..) |word, index| {
            expanded[index] = try self.expandAssignmentWord(word, options);
            initialized += 1;
            try scope.apply(expanded[index]);
        }
        return expanded;
    }

    fn expandRedirections(self: *Executor, redirections: []const ir.Redirection, options: ExecuteOptions) ![]ir.Redirection {
        const expanded = try self.allocator.alloc(ir.Redirection, redirections.len);
        errdefer self.allocator.free(expanded);
        var initialized: usize = 0;
        errdefer for (expanded[0..initialized]) |redirection| self.freeRedirection(redirection);

        for (redirections, 0..) |redirection, index| {
            // Expand into locals with cleanup so a failing later field does
            // not leak the earlier ones; only complete elements are counted
            // in `initialized`.
            const io_number = if (redirection.io_number) |word| try self.expandWord(word, options) else null;
            errdefer if (io_number) |word| self.freeWord(word);
            const target = if (redirection.target) |word| try self.expandWord(word, options) else null;
            errdefer if (target) |word| self.freeWord(word);
            const here_doc = if (redirection.here_doc) |text| try self.expandHereDoc(text, redirection.here_doc_quoted, options) else null;
            expanded[index] = .{
                .span = redirection.span,
                .io_number = io_number,
                .operator = redirection.operator,
                .target = target,
                .here_doc = here_doc,
                .here_doc_quoted = redirection.here_doc_quoted,
            };
            initialized += 1;
        }
        return expanded;
    }

    fn expandHereDoc(self: *Executor, text: []const u8, quoted: bool, options: ExecuteOptions) ![]const u8 {
        if (quoted) return self.allocator.dupe(u8, text);
        var substitution_context: CommandSubstitutionContext = .{ .executor = self, .options = options };
        var option_flags_buffer: [shell_option_flags_max]u8 = undefined;
        const option_flags = shellOptionFlags(self.shell_options, &option_flags_buffer);
        return expand.expandHereDocBody(self.allocator, text, .{ .env = self.envLookup(), .env_set = self.envSet(), .arrays = self.arrayLookup(), .features = options.features, .command_substitution = commandSubstitution(&substitution_context), .nounset = self.shell_options.nounset, .parameter_error = &self.parameter_error, .arithmetic_error = &self.arithmetic_error, .positionals = self.currentPositionals().params, .option_flags = option_flags });
    }

    pub fn expandParametersScalar(self: *Executor, allocator: std.mem.Allocator, raw: []const u8, options: ExecuteOptions) ![]const u8 {
        var substitution_context: CommandSubstitutionContext = .{ .executor = self, .options = options };
        var option_flags_buffer: [shell_option_flags_max]u8 = undefined;
        const option_flags = shellOptionFlags(self.shell_options, &option_flags_buffer);
        return expand.expandParametersScalar(allocator, raw, .{ .env = self.envLookup(), .env_set = self.envSet(), .arrays = self.arrayLookup(), .features = options.features, .command_substitution = commandSubstitution(&substitution_context), .positionals = self.currentPositionals().params, .option_flags = option_flags, .nounset = self.shell_options.nounset, .parameter_error = &self.parameter_error, .arithmetic_error = &self.arithmetic_error });
    }

    fn expandWord(self: *Executor, word: ir.WordRef, options: ExecuteOptions) !ir.WordRef {
        const raw = try self.allocator.dupe(u8, word.raw);
        errdefer self.allocator.free(raw);
        var substitution_context: CommandSubstitutionContext = .{ .executor = self, .options = options };
        var option_flags_buffer: [shell_option_flags_max]u8 = undefined;
        const option_flags = shellOptionFlags(self.shell_options, &option_flags_buffer);
        const text = try expand.expandWordScalar(self.allocator, word.raw, .{ .env = self.envLookup(), .env_set = self.envSet(), .arrays = self.arrayLookup(), .features = options.features, .command_substitution = commandSubstitution(&substitution_context), .positionals = self.currentPositionals().params, .option_flags = option_flags, .nounset = self.shell_options.nounset, .parameter_error = &self.parameter_error, .arithmetic_error = &self.arithmetic_error });
        return .{ .span = word.span, .raw = raw, .text = text };
    }

    fn expandCasePattern(self: *Executor, word: ir.WordRef, options: ExecuteOptions) !CasePattern {
        var parts = try expand.parseWordParts(self.allocator, word.raw);
        defer parts.deinit();

        var text: std.ArrayList(u8) = .empty;
        errdefer text.deinit(self.allocator);
        var special: std.ArrayList(bool) = .empty;
        errdefer special.deinit(self.allocator);

        var substitution_context: CommandSubstitutionContext = .{ .executor = self, .options = options };
        var option_flags_buffer: [shell_option_flags_max]u8 = undefined;
        const option_flags = shellOptionFlags(self.shell_options, &option_flags_buffer);
        const expansion_options: expand.Options = .{ .env = self.envLookup(), .env_set = self.envSet(), .arrays = self.arrayLookup(), .features = options.features, .command_substitution = commandSubstitution(&substitution_context), .positionals = self.currentPositionals().params, .option_flags = option_flags, .nounset = self.shell_options.nounset, .parameter_error = &self.parameter_error, .arithmetic_error = &self.arithmetic_error };

        for (parts.parts) |part| {
            const rendered = try expand.expandWordScalar(self.allocator, part.source(parts.raw), expansion_options);
            defer self.allocator.free(rendered);
            const meta_active = switch (part.kind) {
                .unquoted, .parameter, .arithmetic, .command_substitution => true,
                .single_quoted, .dollar_single_quoted, .double_quoted, .escaped => false,
            };
            try appendCasePatternPart(self.allocator, &text, &special, rendered, meta_active);
        }

        return .{ .text = try text.toOwnedSlice(self.allocator), .special = try special.toOwnedSlice(self.allocator) };
    }

    fn expandAssignmentWord(self: *Executor, word: ir.WordRef, options: ExecuteOptions) !ir.WordRef {
        const raw = try self.allocator.dupe(u8, word.raw);
        errdefer self.allocator.free(raw);
        var substitution_context: CommandSubstitutionContext = .{ .executor = self, .options = options };
        var option_flags_buffer: [shell_option_flags_max]u8 = undefined;
        const option_flags = shellOptionFlags(self.shell_options, &option_flags_buffer);
        const text = try expand.expandAssignmentWordScalar(self.allocator, word.raw, .{ .env = self.envLookup(), .env_set = self.envSet(), .arrays = self.arrayLookup(), .features = options.features, .command_substitution = commandSubstitution(&substitution_context), .positionals = self.currentPositionals().params, .option_flags = option_flags, .nounset = self.shell_options.nounset, .parameter_error = &self.parameter_error, .arithmetic_error = &self.arithmetic_error });
        return .{ .span = word.span, .raw = raw, .text = text };
    }

    fn findExecutableInPath(self: *Executor, io: std.Io, name: []const u8) !?[]const u8 {
        return self.findExecutableInPathValue(io, name, self.getEnv("PATH") orelse return null);
    }

    fn findExecutableInDefaultPath(self: *Executor, io: std.Io, name: []const u8) !?[]const u8 {
        return self.findExecutableInPathValue(io, name, "/bin:/usr/bin");
    }

    fn findExecutableInPathValue(self: *Executor, io: std.Io, name: []const u8, path_value: []const u8) !?[]const u8 {
        if (std.mem.indexOfScalar(u8, name, '/') != null) return self.executableReplacementPath(io, name) catch |err| switch (err) {
            error.CommandNotFound, error.AccessDenied => return null,
            else => return err,
        };
        var parts = std.mem.splitScalar(u8, path_value, ':');
        while (parts.next()) |part| {
            const dir = if (part.len == 0) "." else part;
            const candidate = try std.mem.concat(self.allocator, u8, &.{ dir, "/", name });
            errdefer self.allocator.free(candidate);
            std.Io.Dir.cwd().access(io, candidate, .{ .execute = true }) catch |err| switch (err) {
                error.FileNotFound, error.AccessDenied, error.PermissionDenied => {
                    self.allocator.free(candidate);
                    continue;
                },
                else => return err,
            };
            return candidate;
        }
        return null;
    }

    fn commandHashEligible(command: ir.SimpleCommand, use_default_path: bool) bool {
        if (use_default_path) return false;
        if (command.argv.len == 0) return false;
        if (std.mem.indexOfScalar(u8, command.argv[0].text, '/') != null) return false;
        for (command.assignments) |assignment| {
            const parsed = envAssignment(assignment.text) orelse continue;
            if (std.mem.eql(u8, parsed.name, "PATH")) return false;
        }
        return true;
    }

    fn rememberCommandHash(self: *Executor, name: []const u8, path: []const u8) !void {
        if (self.command_hash.fetchRemove(name)) |entry| {
            self.allocator.free(entry.key);
            self.allocator.free(entry.value);
        }
        const owned_name = try self.allocator.dupe(u8, name);
        errdefer self.allocator.free(owned_name);
        const owned_path = try self.allocator.dupe(u8, path);
        errdefer self.allocator.free(owned_path);
        try self.command_hash.put(self.allocator, owned_name, owned_path);
    }

    fn findReplacementExecutable(self: *Executor, io: std.Io, command: ir.SimpleCommand, use_default_path: bool) ![]const u8 {
        const name = command.argv[0].text;
        if (std.mem.indexOfScalar(u8, name, '/') != null) return self.executableReplacementPath(io, name);
        const cacheable = commandHashEligible(command, use_default_path);
        if (cacheable) if (self.command_hash.get(name)) |path| return self.allocator.dupe(u8, path);
        const path_value = if (use_default_path) "/bin:/usr/bin" else self.commandLookupPath(command) orelse return error.CommandNotFound;
        const executable = try self.findReplacementExecutableInPathValue(io, name, path_value);
        errdefer self.allocator.free(executable);
        if (cacheable) try self.rememberCommandHash(name, executable);
        return executable;
    }

    fn commandLookupPath(self: Executor, command: ir.SimpleCommand) ?[]const u8 {
        var path_value: ?[]const u8 = null;
        for (command.assignments) |assignment| {
            const parsed = envAssignment(assignment.text) orelse continue;
            if (std.mem.eql(u8, parsed.name, "PATH")) path_value = parsed.value;
        }
        return path_value orelse self.getEnv("PATH") orelse "/bin:/usr/bin";
    }

    fn findReplacementExecutableInPathValue(self: *Executor, io: std.Io, name: []const u8, path_value: []const u8) ![]const u8 {
        var permission_denied = false;
        var parts = std.mem.splitScalar(u8, path_value, ':');
        while (parts.next()) |part| {
            const dir = if (part.len == 0) "." else part;
            const candidate = try std.mem.concat(self.allocator, u8, &.{ dir, "/", name });
            errdefer self.allocator.free(candidate);
            std.Io.Dir.cwd().access(io, candidate, .{ .execute = true }) catch |err| switch (err) {
                error.FileNotFound => {
                    self.allocator.free(candidate);
                    continue;
                },
                error.AccessDenied, error.PermissionDenied => {
                    permission_denied = true;
                    self.allocator.free(candidate);
                    continue;
                },
                else => return err,
            };
            return candidate;
        }

        if (permission_denied) return error.AccessDenied;
        return error.CommandNotFound;
    }

    fn executableReplacementPath(self: *Executor, io: std.Io, path: []const u8) ![]const u8 {
        std.Io.Dir.cwd().access(io, path, .{ .execute = true }) catch |err| switch (err) {
            error.FileNotFound => return error.CommandNotFound,
            error.AccessDenied, error.PermissionDenied => return error.AccessDenied,
            else => return err,
        };
        return self.allocator.dupe(u8, path);
    }

    fn readSourceFile(self: *Executor, io: std.Io, name: []const u8, posix_dot: bool) ![]const u8 {
        if (std.mem.indexOfScalar(u8, name, '/') != null) {
            return std.Io.Dir.cwd().readFileAlloc(io, name, self.allocator, .unlimited);
        }

        if (self.getEnv("PATH")) |path_value| {
            var parts = std.mem.splitScalar(u8, path_value, ':');
            while (parts.next()) |dir| {
                const prefix = if (dir.len == 0) "." else dir;
                const candidate = try std.fmt.allocPrint(self.allocator, "{s}/{s}", .{ prefix, name });
                defer self.allocator.free(candidate);
                return std.Io.Dir.cwd().readFileAlloc(io, candidate, self.allocator, .unlimited) catch |err| switch (err) {
                    error.FileNotFound => continue,
                    else => |e| return e,
                };
            }
        }

        if (posix_dot) return error.FileNotFound;
        return std.Io.Dir.cwd().readFileAlloc(io, name, self.allocator, .unlimited);
    }

    fn pushCallFrame(self: *Executor, args: []const ir.WordRef) !void {
        var values = try self.allocator.alloc([]const u8, args.len);
        defer self.allocator.free(values);
        for (args, 0..) |arg, index| values[index] = arg.text;
        var frame: CallFrame = .{};
        errdefer frame.deinit(self.allocator);
        try frame.positionals.set(self.allocator, values);
        try self.call_frames.append(self.allocator, frame);
    }

    fn popCallFrame(self: *Executor) void {
        var frame = self.call_frames.pop().?;
        frame.deinit(self.allocator);
    }

    fn currentCallFrame(self: Executor) ?CallFrame {
        if (self.call_frames.items.len == 0) return null;
        return self.call_frames.items[self.call_frames.items.len - 1];
    }

    fn currentCallFramePtr(self: *Executor) ?*CallFrame {
        if (self.call_frames.items.len == 0) return null;
        return &self.call_frames.items[self.call_frames.items.len - 1];
    }

    fn currentPositionals(self: Executor) PositionalParams {
        if (self.currentCallFrame()) |frame| return frame.positionals;
        return self.global_positionals;
    }

    fn currentPositionalsPtr(self: *Executor) *PositionalParams {
        if (self.currentCallFramePtr()) |frame| return &frame.positionals;
        return &self.global_positionals;
    }

    const CommandSubstitutionContext = struct {
        executor: *Executor,
        options: ExecuteOptions,
    };

    fn commandSubstitution(context: *CommandSubstitutionContext) expand.CommandSubstitution {
        return .{ .context = context, .runFn = runCommandSubstitution };
    }

    fn runCommandSubstitution(context: ?*anyopaque, allocator: std.mem.Allocator, script: []const u8) ![]const u8 {
        const substitution_context: *CommandSubstitutionContext = @ptrCast(@alignCast(context.?));
        var sub_options = substitution_context.options;
        sub_options.external_stdio = .capture_stdout;
        sub_options.force_noninteractive_error_consequences = true;
        var child = Executor.init(substitution_context.executor.allocator);
        defer child.deinit();
        try child.copyStateFrom(substitution_context.executor);
        try child.resetCaughtTrapsForSubshell();
        const saved_umask = readShellUmask();
        defer restoreShellUmask(saved_umask);
        if (substitution_context.executor.remainingScriptStdin()) |stdin| {
            child.script_stdin = stdin;
            child.script_stdin_offset = 0;
            child.script_stdin_file = null;
        } else if (substitution_context.executor.remainingScriptStdinFile()) |file| {
            child.script_stdin = null;
            child.script_stdin_offset = 0;
            child.script_stdin_file = file;
        }
        if (substitution_context.executor.completion_builder != null) child.completion_builder = .{};
        if (substitution_context.executor.prompt_builder != null) child.prompt_builder = .{};
        child.pending_exit = null;
        var result = try child.executeScriptSlice(script, sub_options);
        defer result.deinit();
        substitution_context.executor.command_substitution_status = result.status;
        if (child.had_expansion_error) {
            substitution_context.executor.had_expansion_error = true;
            try substitution_context.executor.command_substitution_stderr.appendSlice(substitution_context.executor.allocator, result.stderr);
        }
        return allocator.dupe(u8, result.stdout);
    }

    fn envSet(self: *Executor) expand.EnvSet {
        return .{ .context = self, .setFn = setEnvCallback };
    }

    fn envLookup(self: *Executor) expand.EnvLookup {
        return .{ .context = self, .lookupFn = lookupEnv };
    }

    fn arrayLookup(self: *Executor) expand.ArrayLookup {
        return .{ .context = self, .lookupFn = lookupArray };
    }

    fn setEnvCallback(context: ?*anyopaque, name: []const u8, value: []const u8) !void {
        const self: *Executor = @ptrCast(@alignCast(context.?));
        try self.setEnv(name, value);
    }

    fn lookupEnv(context: ?*const anyopaque, name: []const u8) ?[]const u8 {
        const self: *const Executor = @ptrCast(@alignCast(context.?));
        if (std.mem.eql(u8, name, "?")) return self.last_status_text[0..self.last_status_text_len];
        if (std.mem.eql(u8, name, "$")) return self.pid_text[0..self.pid_text_len];
        if (std.mem.eql(u8, name, "!")) return self.last_background_pid_text[0..self.last_background_pid_text_len];
        if (std.mem.eql(u8, name, "LINENO")) return self.lineno_text[0..self.lineno_text_len];
        if (std.mem.eql(u8, name, "0")) return self.arg_zero;
        const positionals = self.currentPositionals();
        if (std.mem.eql(u8, name, "#")) return positionals.count;
        if (std.mem.eql(u8, name, "@") or std.mem.eql(u8, name, "*")) return positionals.joined;
        if (name.len == 1 and std.ascii.isDigit(name[0]) and name[0] != '0') {
            const index = name[0] - '1';
            if (index < positionals.params.len) return positionals.params[index];
            return null;
        }
        return self.getEnv(name);
    }

    fn lookupArray(context: ?*const anyopaque, name: []const u8, index: usize) ?[]const u8 {
        const self: *const Executor = @ptrCast(@alignCast(context.?));
        return self.getArrayElement(name, index);
    }

    fn freeExpandedCommand(self: *Executor, command: ir.SimpleCommand) void {
        self.freeWords(command.assignments);
        self.freeWords(command.argv);
        self.freeRedirections(command.redirections);
    }

    fn freeWords(self: *Executor, words: []const ir.WordRef) void {
        for (words) |word| self.freeWord(word);
        self.allocator.free(words);
    }

    fn freeRedirections(self: *Executor, redirections: []const ir.Redirection) void {
        for (redirections) |redirection| self.freeRedirection(redirection);
        self.allocator.free(redirections);
    }

    fn freeRedirection(self: *Executor, redirection: ir.Redirection) void {
        if (redirection.io_number) |word| self.freeWord(word);
        if (redirection.target) |word| self.freeWord(word);
        if (redirection.here_doc) |text| self.allocator.free(text);
    }

    fn freeWord(self: *Executor, word: ir.WordRef) void {
        self.allocator.free(word.raw);
        self.allocator.free(word.text);
    }

    const SavedAssignment = struct {
        name: []const u8,
        old_value: ?[]const u8,
        old_exported: bool = false,
    };

    const SavedArrayAssignment = struct {
        name: []const u8,
        old_value: ?ArrayValue,
    };

    const AssignmentExpansionScope = struct {
        executor: *Executor,
        saved: std.ArrayList(SavedAssignment) = .empty,
        saved_arrays: std.ArrayList(SavedArrayAssignment) = .empty,

        fn init(executor: *Executor) AssignmentExpansionScope {
            return .{ .executor = executor };
        }

        fn apply(self: *AssignmentExpansionScope, assignment: ir.WordRef) !void {
            if (try self.executor.indexedArrayAssignment(assignment.text)) |array_assignment| {
                var old_value = try self.executor.cloneArray(array_assignment.name);
                errdefer if (old_value) |*value| value.deinit(self.executor.allocator);
                const owned_name = try self.executor.allocator.dupe(u8, array_assignment.name);
                errdefer self.executor.allocator.free(owned_name);
                try self.saved_arrays.append(self.executor.allocator, .{ .name = owned_name, .old_value = old_value });
                errdefer _ = self.saved_arrays.pop();
                try self.executor.setArrayElement(array_assignment.name, array_assignment.index, array_assignment.value);
                return;
            }

            const equals = std.mem.indexOfScalar(u8, assignment.text, '=') orelse return;
            const name = assignment.text[0..equals];
            const old_value = if (self.executor.getEnv(name)) |value| try self.executor.allocator.dupe(u8, value) else null;
            errdefer if (old_value) |value| self.executor.allocator.free(value);
            const owned_name = try self.executor.allocator.dupe(u8, name);
            errdefer self.executor.allocator.free(owned_name);
            try self.saved.append(self.executor.allocator, .{ .name = owned_name, .old_value = old_value, .old_exported = self.executor.isExported(name) });
            errdefer _ = self.saved.pop();
            try self.executor.setEnv(name, assignment.text[equals + 1 ..]);
        }

        fn restore(self: *AssignmentExpansionScope) void {
            var index = self.saved.items.len;
            while (index > 0) {
                index -= 1;
                const entry = self.saved.items[index];
                if (entry.old_value) |value| {
                    self.executor.setEnv(entry.name, value) catch {};
                    self.executor.allocator.free(value);
                } else {
                    self.executor.unsetEnv(entry.name);
                }
                self.executor.restoreExported(entry.name, entry.old_exported) catch {};
                self.executor.allocator.free(entry.name);
            }
            self.saved.deinit(self.executor.allocator);

            var array_index = self.saved_arrays.items.len;
            while (array_index > 0) {
                array_index -= 1;
                const entry = self.saved_arrays.items[array_index];
                self.executor.restoreArray(entry.name, entry.old_value);
                self.executor.allocator.free(entry.name);
            }
            self.saved_arrays.deinit(self.executor.allocator);
            self.* = undefined;
        }
    };

    const AssignmentScope = struct {
        executor: *Executor,
        saved: []SavedAssignment,
        saved_arrays: []SavedArrayAssignment,

        fn restore(self: *AssignmentScope) void {
            var index = self.saved.len;
            while (index > 0) {
                index -= 1;
                const entry = self.saved[index];
                if (entry.old_value) |value| {
                    self.executor.setEnv(entry.name, value) catch {};
                    self.executor.allocator.free(value);
                } else {
                    self.executor.unsetEnv(entry.name);
                }
                self.executor.restoreExported(entry.name, entry.old_exported) catch {};
                self.executor.allocator.free(entry.name);
            }
            self.executor.allocator.free(self.saved);

            var array_index = self.saved_arrays.len;
            while (array_index > 0) {
                array_index -= 1;
                const entry = self.saved_arrays[array_index];
                self.executor.restoreArray(entry.name, entry.old_value);
                self.executor.allocator.free(entry.name);
            }
            self.executor.allocator.free(self.saved_arrays);
            self.* = undefined;
        }
    };

    fn pushTemporaryAssignments(self: *Executor, assignments: []const ir.WordRef) !AssignmentScope {
        var saved: std.ArrayList(SavedAssignment) = .empty;
        var saved_arrays: std.ArrayList(SavedArrayAssignment) = .empty;
        errdefer {
            for (saved.items) |entry| {
                self.allocator.free(entry.name);
                if (entry.old_value) |value| self.allocator.free(value);
            }
            saved.deinit(self.allocator);
            for (saved_arrays.items) |entry| {
                self.allocator.free(entry.name);
                if (entry.old_value) |old| {
                    var value = old;
                    value.deinit(self.allocator);
                }
            }
            saved_arrays.deinit(self.allocator);
        }

        for (assignments) |assignment| {
            if (try self.indexedArrayAssignment(assignment.text)) |array_assignment| {
                var old_value = try self.cloneArray(array_assignment.name);
                errdefer if (old_value) |*value| value.deinit(self.allocator);
                var owned_name: ?[]u8 = try self.allocator.dupe(u8, array_assignment.name);
                errdefer if (owned_name) |name| self.allocator.free(name);
                try saved_arrays.append(self.allocator, .{ .name = owned_name.?, .old_value = old_value });
                owned_name = null;
                old_value = null;
                try self.setArrayElement(array_assignment.name, array_assignment.index, array_assignment.value);
                continue;
            }

            const equals = std.mem.indexOfScalar(u8, assignment.text, '=') orelse continue;
            const name = assignment.text[0..equals];
            var old_value = if (self.getEnv(name)) |value| try self.allocator.dupe(u8, value) else null;
            errdefer if (old_value) |value| self.allocator.free(value);
            var owned_name: ?[]u8 = try self.allocator.dupe(u8, name);
            errdefer if (owned_name) |owned| self.allocator.free(owned);
            try saved.append(self.allocator, .{ .name = owned_name.?, .old_value = old_value, .old_exported = self.isExported(name) });
            owned_name = null;
            old_value = null;
            try self.setEnv(name, assignment.text[equals + 1 ..]);
            try self.setExported(name);
        }

        const owned_saved = try saved.toOwnedSlice(self.allocator);
        errdefer {
            for (owned_saved) |entry| {
                self.allocator.free(entry.name);
                if (entry.old_value) |value| self.allocator.free(value);
            }
            self.allocator.free(owned_saved);
        }
        return .{ .executor = self, .saved = owned_saved, .saved_arrays = try saved_arrays.toOwnedSlice(self.allocator) };
    }

    fn applyAssignments(self: *Executor, assignments: []const ir.WordRef) !void {
        for (assignments) |assignment| {
            if (try self.indexedArrayAssignment(assignment.text)) |array_assignment| {
                try self.setArrayElement(array_assignment.name, array_assignment.index, array_assignment.value);
                continue;
            }

            const equals = std.mem.indexOfScalar(u8, assignment.text, '=') orelse continue;
            const name = assignment.text[0..equals];
            try self.setEnv(name, assignment.text[equals + 1 ..]);
            if (self.shell_options.allexport) try self.setExported(name);
        }
    }

    fn indexedArrayAssignment(self: *Executor, text: []const u8) !?IndexedArrayAssignment {
        const syntax = indexedArrayAssignmentSyntax(text) orelse return null;
        const value = expand.evalArithmetic(syntax.index_text, self.envLookup(), self.envSet()) catch |err| return self.arraySubscriptExpansionFailed(syntax.index_text, err);
        const index = std.math.cast(usize, value) orelse return self.arraySubscriptExpansionFailed(syntax.index_text, error.InvalidArithmetic);
        return .{ .name = syntax.name, .index = index, .value = syntax.value };
    }

    fn arraySubscriptExpansionFailed(self: *Executor, index_text: []const u8, err: anyerror) anyerror {
        const message = switch (err) {
            error.InvalidArithmetic => "invalid arithmetic expression",
            error.DivisionByZero => "division by zero",
            error.Overflow => "arithmetic overflow",
            else => return err,
        };

        const expression = try self.allocator.dupe(u8, index_text);
        errdefer self.allocator.free(expression);
        const owned_message = try self.allocator.dupe(u8, message);
        self.arithmetic_error.clear(self.allocator);
        self.arithmetic_error.expression = expression;
        self.arithmetic_error.message = owned_message;
        return error.ArithmeticExpansionFailed;
    }

    fn buildProcessEnv(self: *Executor, assignments: []const ir.WordRef) !std.process.Environ.Map {
        var map = std.process.Environ.Map.init(self.allocator);
        errdefer map.deinit();
        var iter = self.exported.iterator();
        while (iter.next()) |entry| {
            if (self.env.get(entry.key_ptr.*)) |value| try map.put(entry.key_ptr.*, value);
        }
        for (assignments) |assignment| {
            if (indexedArrayAssignmentSyntax(assignment.text) != null) continue;
            const equals = std.mem.indexOfScalar(u8, assignment.text, '=') orelse continue;
            try map.put(assignment.text[0..equals], assignment.text[equals + 1 ..]);
        }
        return map;
    }

    fn applyRealFdRedirectionsIfNeeded(self: *Executor, command: ir.SimpleCommand, options: ExecuteOptions) !?FdRedirectionGuard {
        if (options.external_stdio != .inherit or command.redirections.len == 0) return null;
        const io = options.io orelse return null;
        var guard = try FdRedirectionGuard.init(self.allocator, io);
        errdefer guard.restore(self, io);
        for (command.redirections) |redirection| {
            try guard.apply(self, io, redirection);
        }
        return guard;
    }

    fn applyPermanentRealFdRedirections(self: *Executor, command: ir.SimpleCommand, options: ExecuteOptions) !bool {
        if (options.external_stdio != .inherit or command.redirections.len == 0) return false;
        const io = options.io orelse return false;
        var guard = try FdRedirectionGuard.init(self.allocator, io);
        errdefer guard.restore(self, io);
        for (command.redirections) |redirection| try guard.apply(self, io, redirection);
        guard.commit(io);
        return true;
    }

    fn applyInputRedirections(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions, owned_stdin: *?[]u8, stdin_file: *?std.Io.File) ![]const u8 {
        var current = stdin;
        for (command.redirections) |redirection| {
            if (isHereDocRedirection(redirection)) {
                if (stdin_file.*) |file| {
                    file.close(options.io orelse return error.MissingIoForRedirection);
                    stdin_file.* = null;
                }
                if (owned_stdin.*) |bytes| {
                    self.allocator.free(bytes);
                    owned_stdin.* = null;
                }
                owned_stdin.* = try self.allocator.dupe(u8, redirection.here_doc orelse "");
                current = owned_stdin.*.?;
                continue;
            }
            if (!isStdinFileRedirection(redirection)) continue;
            const io = options.io orelse return error.MissingIoForRedirection;
            const target = redirection.target orelse continue;
            if (owned_stdin.*) |bytes| {
                self.allocator.free(bytes);
                owned_stdin.* = null;
            }
            if (stdin_file.*) |file| file.close(io);
            stdin_file.* = if (redirection.operator == .less_great)
                try openReadWriteRedirectionFile(io, target.text)
            else
                try std.Io.Dir.cwd().openFile(io, target.text, .{});
            current = "";
        }
        return current;
    }

    const OutputSink = union(enum) {
        stdout,
        stderr,
        file: FileOutputSink,
    };

    const FileOutputSink = struct {
        redirection: ir.Redirection,
        id: usize,
    };

    fn applyOutputRedirections(self: *Executor, command: ir.SimpleCommand, result: CommandResult, options: ExecuteOptions, special_exit: bool) !CommandResult {
        var redirected = result;
        errdefer redirected.deinit();

        self.validateFdDuplicationTargets(command.redirections) catch |err| switch (err) {
            error.BadFileDescriptor => {
                redirected.deinit();
                const failure = try errorResult(self.allocator, 1, badFdTargetName(command), "bad file descriptor");
                if (special_exit) self.pending_exit = failure.status;
                return failure;
            },
            else => return err,
        };

        var stdout_sink: OutputSink = .stdout;
        var stderr_sink: OutputSink = .stderr;
        var next_file_id: usize = 1;

        for (command.redirections) |redirection| {
            if (isFileOutputRedirection(redirection)) {
                const fd = redirectionFd(redirection) orelse 1;
                if (fd != 1 and fd != 2) continue;
                self.validateOutputRedirection(redirection, options) catch |err| switch (err) {
                    error.PathAlreadyExists => {
                        redirected.deinit();
                        const failure = try errorResult(self.allocator, 1, targetName(redirection), "cannot overwrite existing file");
                        if (special_exit) self.pending_exit = failure.status;
                        return failure;
                    },
                    error.FileNotFound => {
                        redirected.deinit();
                        const failure = try errorResult(self.allocator, 1, targetName(redirection), "no such file or directory");
                        if (special_exit) self.pending_exit = failure.status;
                        return failure;
                    },
                    error.IsDir => {
                        redirected.deinit();
                        const failure = try errorResult(self.allocator, 1, targetName(redirection), "is a directory");
                        if (special_exit) self.pending_exit = failure.status;
                        return failure;
                    },
                    else => return err,
                };
                const sink: OutputSink = .{ .file = .{ .redirection = redirection, .id = next_file_id } };
                next_file_id += 1;
                if (fd == 1) stdout_sink = sink else stderr_sink = sink;
                continue;
            }

            if (redirection.operator == .greater_and) {
                const from_fd = redirectionFd(redirection) orelse 1;
                const target = redirection.target orelse continue;
                const to_fd = parseFd(target.text) orelse continue;
                if ((from_fd == 1 or from_fd == 2) and (to_fd == 1 or to_fd == 2)) {
                    const copied = if (to_fd == 1) stdout_sink else stderr_sink;
                    if (from_fd == 1) stdout_sink = copied else stderr_sink = copied;
                }
            }
        }

        const original_stdout = redirected.stdout;
        const original_stderr = redirected.stderr;
        var original_streams_active = true;
        defer if (original_streams_active) {
            self.allocator.free(original_stdout);
            self.allocator.free(original_stderr);
        };
        redirected.stdout = try self.allocator.alloc(u8, 0);
        errdefer self.allocator.free(redirected.stdout);
        redirected.stderr = try self.allocator.alloc(u8, 0);
        errdefer self.allocator.free(redirected.stderr);

        if (sameFileSink(stdout_sink, stderr_sink)) {
            const file_sink = stdout_sink.file;
            const combined = if (redirected.stderr_before_stdout)
                try std.mem.concat(self.allocator, u8, &.{ original_stderr, original_stdout })
            else
                try std.mem.concat(self.allocator, u8, &.{ original_stdout, original_stderr });
            defer self.allocator.free(combined);
            self.writeRedirectedBytes(combined, file_sink.redirection, options) catch |err| {
                if (!isOutputWriteFailure(err)) return err;
                redirected.deinit();
                return self.writeFailureResult(err, special_exit);
            };
        } else if (sameCapturedSink(stdout_sink, stderr_sink)) {
            const first = if (redirected.stderr_before_stdout) original_stderr else original_stdout;
            const second = if (redirected.stderr_before_stdout) original_stdout else original_stderr;
            self.routeCapturedStream(&redirected.stdout, &redirected.stderr, first, stdout_sink, options) catch |err| {
                if (!isOutputWriteFailure(err)) return err;
                redirected.deinit();
                return self.writeFailureResult(err, special_exit);
            };
            self.routeCapturedStream(&redirected.stdout, &redirected.stderr, second, stdout_sink, options) catch |err| {
                if (!isOutputWriteFailure(err)) return err;
                redirected.deinit();
                return self.writeFailureResult(err, special_exit);
            };
        } else {
            self.routeCapturedStream(&redirected.stdout, &redirected.stderr, original_stdout, stdout_sink, options) catch |err| {
                if (!isOutputWriteFailure(err)) return err;
                redirected.deinit();
                return self.writeFailureResult(err, special_exit);
            };
            self.routeCapturedStream(&redirected.stdout, &redirected.stderr, original_stderr, stderr_sink, options) catch |err| {
                if (!isOutputWriteFailure(err)) return err;
                redirected.deinit();
                return self.writeFailureResult(err, special_exit);
            };
        }

        self.allocator.free(original_stdout);
        self.allocator.free(original_stderr);
        original_streams_active = false;
        return redirected;
    }

    fn sameFileSink(left: OutputSink, right: OutputSink) bool {
        if (left != .file or right != .file) return false;
        return left.file.id == right.file.id;
    }

    fn sameCapturedSink(left: OutputSink, right: OutputSink) bool {
        return (left == .stdout and right == .stdout) or (left == .stderr and right == .stderr);
    }

    fn routeCapturedStream(self: *Executor, stdout: *[]u8, stderr: *[]u8, bytes: []const u8, sink: OutputSink, options: ExecuteOptions) !void {
        switch (sink) {
            .stdout => try appendOwnedBytes(self.allocator, stdout, bytes),
            .stderr => try appendOwnedBytes(self.allocator, stderr, bytes),
            .file => |file_sink| try self.writeRedirectedBytes(bytes, file_sink.redirection, options),
        }
    }

    fn appendOwnedBytes(allocator: std.mem.Allocator, target: *[]u8, bytes: []const u8) !void {
        const old_len = target.len;
        target.* = try allocator.realloc(target.*, old_len + bytes.len);
        @memcpy(target.*[old_len..], bytes);
    }

    fn validateOutputRedirection(self: *Executor, redirection: ir.Redirection, options: ExecuteOptions) !void {
        const io = options.io orelse return error.MissingIoForRedirection;
        const target = redirection.target orelse return;
        var file = try openOutputRedirectionFile(io, target.text, redirection.operator, self.shell_options.noclobber);
        file.close(io);
    }

    fn writeRedirectedBytes(self: *Executor, bytes: []const u8, redirection: ir.Redirection, options: ExecuteOptions) !void {
        const io = options.io orelse return error.MissingIoForRedirection;
        const target = redirection.target orelse return;
        var file = try openOutputRedirectionFile(io, target.text, redirection.operator, self.shell_options.noclobber);
        defer file.close(io);
        var buffer: [4096]u8 = undefined;
        var writer = file.writer(io, &buffer);
        if (redirection.operator == .dgreat) {
            try writer.seekTo(try file.length(io));
        }
        try writer.interface.writeAll(bytes);
        try writer.interface.flush();
    }

    fn applyExternalPostRedirections(self: *Executor, command: ir.SimpleCommand, result: CommandResult, options: ExecuteOptions) !CommandResult {
        _ = options;
        var redirected = result;
        errdefer redirected.deinit();
        for (command.redirections) |redirection| {
            if (redirection.operator == .greater_and) {
                try self.applyDescriptorDuplication(&redirected, redirection);
            }
        }
        return redirected;
    }

    fn applyDescriptorDuplication(self: *Executor, result: *CommandResult, redirection: ir.Redirection) !void {
        const from_fd = redirectionFd(redirection) orelse 1;
        const target = redirection.target orelse return;
        const to_fd = parseFd(target.text) orelse return;

        if (from_fd == 2 and to_fd == 1) {
            const combined = try self.allocator.alloc(u8, result.stdout.len + result.stderr.len);
            @memcpy(combined[0..result.stdout.len], result.stdout);
            @memcpy(combined[result.stdout.len..], result.stderr);
            self.allocator.free(result.stdout);
            self.allocator.free(result.stderr);
            result.stdout = combined;
            result.stderr = try self.allocator.alloc(u8, 0);
        } else if (from_fd == 1 and to_fd == 2) {
            const combined = try self.allocator.alloc(u8, result.stderr.len + result.stdout.len);
            @memcpy(combined[0..result.stderr.len], result.stderr);
            @memcpy(combined[result.stderr.len..], result.stdout);
            self.allocator.free(result.stdout);
            self.allocator.free(result.stderr);
            result.stdout = try self.allocator.alloc(u8, 0);
            result.stderr = combined;
        }
    }

    fn replaceWithExternal(self: *Executor, command: ir.SimpleCommand, io: std.Io, options: ExecuteOptions) !CommandResult {
        const executable = self.findReplacementExecutable(io, command, options.default_path_lookup) catch |err| switch (err) {
            error.CommandNotFound => return errorResult(self.allocator, 127, command.argv[0].text, "command not found"),
            error.AccessDenied, error.PermissionDenied => return errorResult(self.allocator, 126, command.argv[0].text, "permission denied"),
            else => return err,
        };
        defer self.allocator.free(executable);

        var child_env = try self.buildProcessEnv(command.assignments);
        defer child_env.deinit();
        var argv_storage: std.ArrayList([:0]u8) = .empty;
        defer {
            for (argv_storage.items) |arg| self.allocator.free(arg);
            argv_storage.deinit(self.allocator);
        }
        const argv_ptrs = try self.allocator.alloc(?[*:0]const u8, command.argv.len + 1);
        defer self.allocator.free(argv_ptrs);
        for (command.argv, 0..) |word, index| {
            const arg = try self.allocator.dupeZ(u8, word.text);
            errdefer self.allocator.free(arg);
            try argv_storage.append(self.allocator, arg);
            argv_ptrs[index] = arg.ptr;
        }
        argv_ptrs[command.argv.len] = null;

        var env_storage: std.ArrayList([:0]u8) = .empty;
        defer {
            for (env_storage.items) |entry| self.allocator.free(entry);
            env_storage.deinit(self.allocator);
        }
        const keys = child_env.keys();
        const values = child_env.values();
        const env_ptrs = try self.allocator.alloc(?[*:0]const u8, keys.len + 1);
        defer self.allocator.free(env_ptrs);
        for (keys, values, 0..) |key, value, index| {
            const printed = try std.fmt.allocPrint(self.allocator, "{s}={s}", .{ key, value });
            defer self.allocator.free(printed);
            const entry = try self.allocator.dupeZ(u8, printed);
            errdefer self.allocator.free(entry);
            try env_storage.append(self.allocator, entry);
            env_ptrs[index] = entry.ptr;
        }
        env_ptrs[keys.len] = null;

        const path = try self.allocator.dupeZ(u8, executable);
        defer self.allocator.free(path);
        execve(path.ptr, @ptrCast(argv_ptrs.ptr), @ptrCast(env_ptrs.ptr)) catch |err| switch (err) {
            error.InvalidExe => {
                const shell_path = try self.allocator.dupeZ(u8, posix_shell_path);
                defer self.allocator.free(shell_path);
                const fallback_argv_ptrs = try self.allocator.alloc(?[*:0]const u8, command.argv.len + 2);
                defer self.allocator.free(fallback_argv_ptrs);
                fallback_argv_ptrs[0] = shell_path.ptr;
                fallback_argv_ptrs[1] = path.ptr;
                for (argv_ptrs[1..command.argv.len], 0..) |arg, index| fallback_argv_ptrs[index + 2] = arg;
                fallback_argv_ptrs[command.argv.len + 1] = null;
                execve(shell_path.ptr, @ptrCast(fallback_argv_ptrs.ptr), @ptrCast(env_ptrs.ptr)) catch |fallback_err| switch (fallback_err) {
                    error.AccessDenied, error.PermissionDenied => return errorResult(self.allocator, 126, command.argv[0].text, "permission denied"),
                    error.FileNotFound => return errorResult(self.allocator, 127, command.argv[0].text, "command not found"),
                    else => return fallback_err,
                };
            },
            error.AccessDenied, error.PermissionDenied => return errorResult(self.allocator, 126, command.argv[0].text, "permission denied"),
            error.FileNotFound => return errorResult(self.allocator, 127, command.argv[0].text, "command not found"),
            else => return err,
        };
        unreachable;
    }

    fn setLastBackgroundPid(self: *Executor, pid: i64) void {
        const text = std.fmt.bufPrint(&self.last_background_pid_text, "{d}", .{pid}) catch return;
        self.last_background_pid_text_len = text.len;
    }

    fn executeExternalAsync(self: *Executor, command: ir.SimpleCommand, io: std.Io, options: ExecuteOptions) !CommandResult {
        const argv = try argvForCommand(self.allocator, command);
        defer self.allocator.free(argv);
        const resolved_executable = self.resolveExternalArgv0(command, io, options) catch |err| switch (err) {
            error.CommandNotFound => return errorResult(self.allocator, 127, command.argv[0].text, "command not found"),
            error.AccessDenied, error.PermissionDenied => return errorResult(self.allocator, 126, command.argv[0].text, "permission denied"),
            else => return err,
        };
        defer if (resolved_executable) |executable| self.allocator.free(executable);
        if (resolved_executable) |executable| argv[0] = executable;

        var stdin_file: ?std.Io.File = null;
        defer if (stdin_file) |file| file.close(io);
        var stdout_file: ?std.Io.File = null;
        defer if (stdout_file) |file| file.close(io);
        var stderr_file: ?std.Io.File = null;
        defer if (stderr_file) |file| file.close(io);
        var stdin_closed = false;
        var stdout_closed = false;
        var stderr_closed = false;
        var inherited_redirections = try FdRedirectionGuard.init(self.allocator, io);
        defer inherited_redirections.restore(self, io);
        if (!self.monitorProcessGroupsEnabled()) {
            stdin_file = try openDevNullRead(io);
        }

        // The diagnostic is reported but the async command itself still
        // yields status 0, matching the status of a successful spawn.
        self.validateFdDuplicationTargets(command.redirections) catch |err| switch (err) {
            error.BadFileDescriptor => return errorResult(self.allocator, 0, badFdTargetName(command), "bad file descriptor"),
            else => return err,
        };
        for (command.redirections) |redirection| {
            if (redirection.operator == .less_and) {
                const from_fd = redirectionFd(redirection) orelse 0;
                if (from_fd > 2) {
                    try self.applyAsyncExternalNonStdioDuplication(&stdin_file, &stdout_file, &stderr_file, &inherited_redirections, io, redirection, from_fd);
                    continue;
                }
            }
            if (isInputFdRedirection(redirection)) {
                const fd = redirectionFd(redirection) orelse 0;
                if (fd == 0) {
                    try self.applyAsyncExternalStdinRedirection(&stdin_file, &stdout_file, &stderr_file, io, redirection, &stdin_closed);
                    continue;
                }
                if (fd > 2) try moveAsyncExternalRedirectionHandles(&stdin_file, &stdout_file, &stderr_file, io, fd);
                try inherited_redirections.apply(self, io, redirection);
                continue;
            }
            if (isFileOutputRedirection(redirection)) {
                const target = redirection.target orelse continue;
                const fd = redirectionFd(redirection) orelse 1;
                if (fd > 2) {
                    try moveAsyncExternalRedirectionHandles(&stdin_file, &stdout_file, &stderr_file, io, fd);
                    try inherited_redirections.apply(self, io, redirection);
                    continue;
                }
                var file = try openOutputRedirectionFile(io, target.text, redirection.operator, self.shell_options.noclobber);
                switch (fd) {
                    1 => {
                        if (stdout_file) |old| old.close(io);
                        stdout_file = file;
                        stdout_closed = false;
                    },
                    2 => {
                        if (stderr_file) |old| old.close(io);
                        stderr_file = file;
                        stderr_closed = false;
                    },
                    else => file.close(io),
                }
                continue;
            }
            if (redirection.operator == .greater_and) {
                const from_fd = redirectionFd(redirection) orelse 1;
                const target = redirection.target orelse continue;
                if (from_fd > 2) {
                    try self.applyAsyncExternalNonStdioDuplication(&stdin_file, &stdout_file, &stderr_file, &inherited_redirections, io, redirection, from_fd);
                    continue;
                }
                if (std.mem.eql(u8, target.text, "-")) {
                    if (from_fd == 1) {
                        if (stdout_file) |old| old.close(io);
                        stdout_file = null;
                        stdout_closed = true;
                    } else if (from_fd == 2) {
                        if (stderr_file) |old| old.close(io);
                        stderr_file = null;
                        stderr_closed = true;
                    }
                    continue;
                }
                const to_fd = parseFd(target.text) orelse continue;
                switch (from_fd) {
                    1 => stdout_closed = false,
                    2 => stderr_closed = false,
                    else => {},
                }
                if (try duplicateExternalStdioFromFd(&stdout_file, &stderr_file, io, from_fd, to_fd)) continue;
                if (try duplicateExternalStdioFromInheritedTarget(&stdout_file, &stderr_file, io, from_fd, to_fd, stdout_closed, stderr_closed, options.external_stdio)) continue;
                if (from_fd == 2 and to_fd == 1 and stdout_file != null) {
                    if (stderr_file) |old| old.close(io);
                    const duped = try rawDup(stdout_file.?.handle);
                    stderr_file = .{ .handle = duped, .flags = stdout_file.?.flags };
                } else if (from_fd == 1 and to_fd == 2 and stderr_file != null) {
                    if (stdout_file) |old| old.close(io);
                    const duped = try rawDup(stderr_file.?.handle);
                    stdout_file = .{ .handle = duped, .flags = stderr_file.?.flags };
                }
            }
        }

        var child_env = try self.buildProcessEnv(command.assignments);
        defer child_env.deinit();
        const use_monitor_pgrp = self.monitorProcessGroupsEnabled();
        const use_cancel_pgrp = completionCancelProcessGroup(options);
        const use_process_pgrp = use_monitor_pgrp or use_cancel_pgrp;
        var child = self.spawnExternalCommand(io, .{
            .argv = argv,
            .environ_map = &child_env,
            .stdin = if (stdin_closed) .close else if (stdin_file) |file| .{ .file = file } else if (options.external_stdio == .inherit) .inherit else .close,
            .stdout = if (stdout_closed) .close else if (stdout_file) |file| .{ .file = file } else if (options.external_stdio == .inherit) .inherit else .ignore,
            .stderr = if (stderr_closed) .close else if (stderr_file) |file| .{ .file = file } else if (options.external_stdio == .inherit) .inherit else .ignore,
            .pgid = if (use_process_pgrp) 0 else null,
        }) catch |err| switch (err) {
            error.FileNotFound => return errorResult(self.allocator, 127, command.argv[0].text, "command not found"),
            error.AccessDenied, error.PermissionDenied, error.IsDir => return errorResult(self.allocator, 126, command.argv[0].text, "permission denied"),
            else => return err,
        };
        errdefer child.kill(io);
        try moveAsyncExternalRedirectionHandlesFromGuard(inherited_redirections, &stdin_file, &stdout_file, &stderr_file, io);
        inherited_redirections.restore(self, io);
        if (stdin_file) |file| {
            file.close(io);
            stdin_file = null;
        }
        if (stdout_file) |file| {
            file.close(io);
            stdout_file = null;
        }
        if (stderr_file) |file| {
            file.close(io);
            stderr_file = null;
        }
        _ = registerCancelableChild(options, child, use_process_pgrp);
        if (child.id) |pid| {
            const numeric_pid: i64 = @intCast(pid);
            self.setLastBackgroundPid(numeric_pid);
            const argv_text = try argvForCommand(self.allocator, command);
            defer self.allocator.free(argv_text);
            const command_text = try joinParams(self.allocator, argv_text);
            errdefer self.allocator.free(command_text);
            try self.background_jobs.append(self.allocator, .{ .id = self.next_job_id, .pid = numeric_pid, .pgrp = if (use_process_pgrp) numeric_pid else null, .command = command_text, .child = child });
            self.selectCurrentJob(self.next_job_id);
            self.next_job_id += 1;
        }
        return emptyResult(self.allocator, 0);
    }

    fn applyAsyncExternalStdinRedirection(
        self: Executor,
        stdin_file: *?std.Io.File,
        stdout_file: *?std.Io.File,
        stderr_file: *?std.Io.File,
        io: std.Io,
        redirection: ir.Redirection,
        stdin_closed: *bool,
    ) !void {
        if (redirection.operator == .dless or redirection.operator == .dless_dash) {
            const file = try fileFromBytes(io, redirection.here_doc orelse "");
            if (stdin_file.*) |old| old.close(io);
            stdin_file.* = file;
            stdin_closed.* = false;
            return;
        }
        if (redirection.operator == .less or redirection.operator == .less_great) {
            const target = redirection.target orelse return;
            const file = if (redirection.operator == .less_great)
                try openReadWriteRedirectionFile(io, target.text)
            else
                try std.Io.Dir.cwd().openFile(io, target.text, .{});
            if (stdin_file.*) |old| old.close(io);
            stdin_file.* = file;
            stdin_closed.* = false;
            return;
        }
        if (redirection.operator == .less_and) {
            const target = redirection.target orelse return;
            if (std.mem.eql(u8, target.text, "-")) {
                if (stdin_file.*) |file| file.close(io);
                stdin_file.* = null;
                stdin_closed.* = true;
                return;
            }
            const to_fd = parseFd(target.text) orelse return;
            const file = try self.asyncExternalSourceFile(stdin_file.*, stdout_file.*, stderr_file.*, to_fd);
            if (stdin_file.*) |old| old.close(io);
            stdin_file.* = file;
            stdin_closed.* = false;
        }
    }

    fn applyAsyncExternalNonStdioDuplication(
        self: *Executor,
        stdin_file: *?std.Io.File,
        stdout_file: *?std.Io.File,
        stderr_file: *?std.Io.File,
        inherited_redirections: *FdRedirectionGuard,
        io: std.Io,
        redirection: ir.Redirection,
        from_fd: std.posix.fd_t,
    ) !void {
        try moveAsyncExternalRedirectionHandles(stdin_file, stdout_file, stderr_file, io, from_fd);

        const target = redirection.target orelse return;
        if (std.mem.eql(u8, target.text, "-")) {
            try inherited_redirections.apply(self, io, redirection);
            return;
        }

        const to_fd = parseFd(target.text) orelse return;
        const source_file: ?std.Io.File = switch (to_fd) {
            0 => stdin_file.*,
            1 => stdout_file.*,
            2 => stderr_file.*,
            else => null,
        };
        if (source_file) |file| {
            try self.applyExternalInheritedFile(inherited_redirections, from_fd, file);
        } else {
            try inherited_redirections.apply(self, io, redirection);
        }
    }

    fn asyncExternalSourceFile(self: Executor, stdin_file: ?std.Io.File, stdout_file: ?std.Io.File, stderr_file: ?std.Io.File, fd: std.posix.fd_t) !std.Io.File {
        if (fd == 0) if (stdin_file) |file| return dupFile(file);
        if (fd == 1) if (stdout_file) |file| return dupFile(file);
        if (fd == 2) if (stderr_file) |file| return dupFile(file);
        if (!self.isShellFdOpen(fd)) return error.BadFileDescriptor;
        return .{ .handle = try rawDup(fd), .flags = .{ .nonblocking = false } };
    }

    fn moveAsyncExternalRedirectionHandles(stdin_file: *?std.Io.File, stdout_file: *?std.Io.File, stderr_file: *?std.Io.File, io: std.Io, fd: std.posix.fd_t) !void {
        try moveExternalFileHandle(stdin_file, io, fd);
        try moveExternalFileHandle(stdout_file, io, fd);
        try moveExternalFileHandle(stderr_file, io, fd);
    }

    fn remainingScriptStdin(self: Executor) ?[]const u8 {
        const script_stdin = self.script_stdin orelse return null;
        if (self.script_stdin_offset > script_stdin.len) return null;
        return script_stdin[self.script_stdin_offset..];
    }

    fn remainingScriptStdinFile(self: Executor) ?std.Io.File {
        return self.script_stdin_file;
    }

    fn executeExternal(self: *Executor, command: ir.SimpleCommand, io: std.Io, options: ExecuteOptions, fallback_stdin: ?[]const u8) !CommandResult {
        const argv = try argvForCommand(self.allocator, command);
        defer self.allocator.free(argv);
        const resolved_executable = self.resolveExternalArgv0(command, io, options) catch |err| switch (err) {
            error.CommandNotFound => return error.CommandNotFound,
            else => return err,
        };
        defer if (resolved_executable) |executable| self.allocator.free(executable);
        if (resolved_executable) |executable| argv[0] = executable;

        var stdin_file: ?std.Io.File = null;
        defer if (stdin_file) |file| file.close(io);
        var stdout_file: ?std.Io.File = null;
        defer if (stdout_file) |file| file.close(io);
        var stderr_file: ?std.Io.File = null;
        defer if (stderr_file) |file| file.close(io);
        var stdout_closed = false;
        var stderr_closed = false;
        var inherited_redirections = try FdRedirectionGuard.init(self.allocator, io);
        defer inherited_redirections.restore(self, io);
        var manual_stdout_capture: ?PipelinePipe = null;
        defer if (manual_stdout_capture) |*pipe| pipe.close(io);
        var manual_stderr_capture: ?PipelinePipe = null;
        defer if (manual_stderr_capture) |*pipe| pipe.close(io);
        var stdin_redirected = false;

        try self.validateFdDuplicationTargets(command.redirections);
        for (command.redirections) |redirection| {
            if (redirection.operator == .less_and) {
                const from_fd = redirectionFd(redirection) orelse 0;
                if (from_fd > 2) {
                    try self.applyExternalNonStdioDuplication(&stdin_file, &stdout_file, &stderr_file, &manual_stdout_capture, &manual_stderr_capture, &inherited_redirections, io, redirection, from_fd, options);
                    continue;
                }
            }
            if (isInputFdRedirection(redirection)) {
                const fd = redirectionFd(redirection) orelse 0;
                if (fd > 2) try moveExternalRedirectionHandles(&stdin_file, &stdout_file, &stderr_file, &manual_stdout_capture, &manual_stderr_capture, io, fd);
                try inherited_redirections.apply(self, io, redirection);
                if (fd == 0) stdin_redirected = true;
                continue;
            }
            if (isFileOutputRedirection(redirection)) {
                const target = redirection.target orelse continue;
                const fd = redirectionFd(redirection) orelse 1;
                if (fd > 2) {
                    try moveExternalRedirectionHandles(&stdin_file, &stdout_file, &stderr_file, &manual_stdout_capture, &manual_stderr_capture, io, fd);
                    try inherited_redirections.apply(self, io, redirection);
                    continue;
                }
                var file = try openOutputRedirectionFile(io, target.text, redirection.operator, self.shell_options.noclobber);
                switch (fd) {
                    1 => {
                        if (stdout_file) |old| old.close(io);
                        stdout_file = file;
                        stdout_closed = false;
                    },
                    2 => {
                        if (stderr_file) |old| old.close(io);
                        stderr_file = file;
                        stderr_closed = false;
                    },
                    else => file.close(io),
                }
                continue;
            }
            if (redirection.operator == .greater_and) {
                const from_fd = redirectionFd(redirection) orelse 1;
                const target = redirection.target orelse continue;
                if (from_fd > 2) {
                    try self.applyExternalNonStdioDuplication(&stdin_file, &stdout_file, &stderr_file, &manual_stdout_capture, &manual_stderr_capture, &inherited_redirections, io, redirection, from_fd, options);
                    continue;
                }
                if (std.mem.eql(u8, target.text, "-")) {
                    if (from_fd == 1) {
                        if (stdout_file) |old| old.close(io);
                        stdout_file = null;
                        stdout_closed = true;
                    } else if (from_fd == 2) {
                        if (stderr_file) |old| old.close(io);
                        stderr_file = null;
                        stderr_closed = true;
                    }
                    continue;
                }
                const to_fd = parseFd(target.text) orelse continue;
                switch (from_fd) {
                    1 => stdout_closed = false,
                    2 => stderr_closed = false,
                    else => {},
                }
                if (try duplicateExternalStdioFromFd(&stdout_file, &stderr_file, io, from_fd, to_fd)) continue;
                if (try duplicateExternalStdioFromInheritedTarget(&stdout_file, &stderr_file, io, from_fd, to_fd, stdout_closed, stderr_closed, options.external_stdio)) continue;
                if (from_fd == 2 and to_fd == 1 and stdout_file == null and !stdout_closed and externalStdioCapturesStdout(options.external_stdio) and manual_stdout_capture == null) {
                    manual_stdout_capture = try makePipelinePipe(io);
                } else if (from_fd == 1 and to_fd == 2 and stderr_file == null and !stderr_closed and externalStdioCapturesStderr(options.external_stdio) and manual_stderr_capture == null) {
                    manual_stderr_capture = try makePipelinePipe(io);
                }
                if (from_fd == 2 and to_fd == 1 and stdout_file != null) {
                    if (stderr_file) |old| old.close(io);
                    const duped = try rawDup(stdout_file.?.handle);
                    stderr_file = .{ .handle = duped, .flags = stdout_file.?.flags };
                } else if (from_fd == 2 and to_fd == 1 and manual_stdout_capture != null) {
                    if (stderr_file) |old| old.close(io);
                    const duped = try rawDup(manual_stdout_capture.?.write.?.handle);
                    stderr_file = .{ .handle = duped, .flags = manual_stdout_capture.?.write.?.flags };
                } else if (from_fd == 1 and to_fd == 2 and stderr_file != null) {
                    if (stdout_file) |old| old.close(io);
                    const duped = try rawDup(stderr_file.?.handle);
                    stdout_file = .{ .handle = duped, .flags = stderr_file.?.flags };
                } else if (from_fd == 1 and to_fd == 2 and manual_stderr_capture != null) {
                    if (stdout_file) |old| old.close(io);
                    const duped = try rawDup(manual_stderr_capture.?.write.?.handle);
                    stdout_file = .{ .handle = duped, .flags = manual_stderr_capture.?.write.?.flags };
                }
            }
        }

        if (stdin_file == null and !stdin_redirected and (externalStdinUsesScriptInput(options.external_stdio) or self.remainingScriptStdinFile() != null)) {
            if (fallback_stdin) |stdin| {
                stdin_file = try fileFromBytes(io, stdin);
                if (self.script_stdin) |script_stdin| self.script_stdin_offset = script_stdin.len;
            } else if (pipeline_stage_stdin.active) {
                if (pipeline_stage_stdin.file) |file| stdin_file = try dupFile(file);
            } else if (self.remainingScriptStdinFile()) |file| {
                stdin_file = try dupFile(file);
            }
        }

        var child_env = try self.buildProcessEnv(command.assignments);
        defer child_env.deinit();
        const final_stdout_captured = !stdout_closed and externalStdioCapturesStdout(options.external_stdio) and stdout_file == null;
        const duplicate_stderr_to_stdout = final_stdout_captured and stderr_file == null and commandDuplicatesStderrToStdout(command.redirections);
        const capture_stdout_pipe = final_stdout_captured and manual_stdout_capture == null and !duplicate_stderr_to_stdout;
        const final_stderr_captured = !stderr_closed and stderr_file == null and externalStdioCapturesStderr(options.external_stdio);
        const capture_stderr_pipe = final_stderr_captured and manual_stderr_capture == null and !duplicate_stderr_to_stdout;
        var merged_capture: ?PipelinePipe = if (duplicate_stderr_to_stdout and manual_stdout_capture == null) try makePipelinePipe(io) else null;
        defer if (merged_capture) |*pipe| pipe.close(io);
        const merged_stderr_write: ?std.Io.File = if (merged_capture) |pipe| .{ .handle = try rawDup(pipe.write.?.handle), .flags = pipe.write.?.flags } else null;
        const foreground_terminal = try prepareForegroundTerminal(options.foreground_terminal and options.external_stdio == .inherit and stdin_file == null and !stdin_redirected);
        try checkCanceled(options);

        // Interactive command substitutions still need the shell's tty on
        // stdin; only stdout is captured.
        const inherit_stdin = externalStdioInheritsStdin(options.external_stdio) or
            (options.interactive and options.external_stdio == .capture_stdout);
        const child_pgid = cancellableExternalPgid(options, if (foreground_terminal != null) 0 else null);
        var child = self.spawnExternalCommand(io, .{
            .argv = argv,
            .environ_map = &child_env,
            .stdin = if (stdin_redirected) .inherit else if (stdin_file) |file| .{ .file = file } else if (inherit_stdin) .inherit else .close,
            .stdout = if (stdout_closed) .close else if (stdout_file) |file| .{ .file = file } else if (merged_capture) |pipe| .{ .file = pipe.write.? } else if (manual_stdout_capture) |pipe| .{ .file = pipe.write.? } else if (capture_stdout_pipe) .pipe else .inherit,
            .stderr = if (stderr_closed) .close else if (stderr_file) |file| .{ .file = file } else if (merged_stderr_write) |file| .{ .file = file } else if (duplicate_stderr_to_stdout) .{ .file = manual_stdout_capture.?.write.? } else if (manual_stderr_capture) |pipe| .{ .file = pipe.write.? } else if (capture_stderr_pipe) .pipe else .inherit,
            .pgid = child_pgid,
        }) catch |err| switch (err) {
            error.FileNotFound => return error.CommandNotFound,
            error.AccessDenied, error.PermissionDenied, error.IsDir => return error.AccessDenied,
            else => return err,
        };
        errdefer child.kill(io);
        try moveExternalRedirectionHandlesFromGuard(inherited_redirections, &stdin_file, &stdout_file, &stderr_file, &manual_stdout_capture, &manual_stderr_capture, io);
        inherited_redirections.restore(self, io);
        if (stdin_file) |file| {
            file.close(io);
            stdin_file = null;
        }
        if (stdout_file) |file| {
            file.close(io);
            stdout_file = null;
        }
        if (stderr_file) |file| {
            file.close(io);
            stderr_file = null;
        }
        const cancel_pid = registerCancelableChild(options, child, child_pgid != null);
        defer unregisterCancelableChild(options, cancel_pid);
        defer child.kill(io);
        if (merged_capture) |*pipe| {
            pipe.write.?.close(io);
            pipe.write = null;
        }
        if (manual_stdout_capture) |*pipe| {
            pipe.write.?.close(io);
            pipe.write = null;
        }
        if (manual_stderr_capture) |*pipe| {
            pipe.write.?.close(io);
            pipe.write = null;
        }
        if (merged_stderr_write) |file| file.close(io);
        defer if (capture_stdout_pipe) if (child.stdout) |file| file.close(io);
        defer if (capture_stderr_pipe) if (child.stderr) |file| file.close(io);
        try giveTerminalToForegroundChild(&child, foreground_terminal);
        defer restoreForegroundTerminal(foreground_terminal);

        var stdout: []u8 = try self.allocator.alloc(u8, 0);
        errdefer self.allocator.free(stdout);
        var stderr: []u8 = try self.allocator.alloc(u8, 0);
        errdefer self.allocator.free(stderr);

        const stdout_read_file: ?std.Io.File = if (capture_stdout_pipe) child.stdout.? else if (merged_capture) |pipe| pipe.read.? else if (manual_stdout_capture) |pipe| pipe.read.? else null;
        const stderr_read_file: ?std.Io.File = if (capture_stderr_pipe) child.stderr.? else if (manual_stderr_capture) |pipe| pipe.read.? else null;
        if (stdout_read_file != null and stderr_read_file != null) {
            var multi_reader_buffer: std.Io.File.MultiReader.Buffer(2) = undefined;
            var multi_reader: std.Io.File.MultiReader = undefined;
            multi_reader.init(self.allocator, io, multi_reader_buffer.toStreams(), &.{ stdout_read_file.?, stderr_read_file.? });
            defer multi_reader.deinit();
            while (multi_reader.fill(64, .none)) |_| {} else |err| switch (err) {
                error.EndOfStream => {},
                else => |e| return e,
            }
            try multi_reader.checkAnyError();
            self.allocator.free(stdout);
            self.allocator.free(stderr);
            stdout = try multi_reader.toOwnedSlice(0);
            stderr = try multi_reader.toOwnedSlice(1);
            if (capture_stdout_pipe) {
                child.stdout.?.close(io);
                child.stdout = null;
            }
            if (capture_stderr_pipe) {
                child.stderr.?.close(io);
                child.stderr = null;
            }
        } else if (stdout_read_file) |file| {
            var reader_buffer: [4096]u8 = undefined;
            var reader = file.reader(io, &reader_buffer);
            const captured = try reader.interface.allocRemaining(self.allocator, .unlimited);
            self.allocator.free(stdout);
            stdout = captured;
            if (capture_stdout_pipe) {
                child.stdout.?.close(io);
                child.stdout = null;
            }
        } else if (stderr_read_file) |file| {
            var reader_buffer: [4096]u8 = undefined;
            var reader = file.reader(io, &reader_buffer);
            const captured = try reader.interface.allocRemaining(self.allocator, .unlimited);
            self.allocator.free(stderr);
            stderr = captured;
            if (capture_stderr_pipe) {
                child.stderr.?.close(io);
                child.stderr = null;
            }
        }

        const term = try child.wait(io);
        return .{
            .allocator = self.allocator,
            .status = exitStatusFromTerm(term),
            .stdout = stdout,
            .stderr = stderr,
        };
    }

    fn applyExternalNonStdioDuplication(
        self: *Executor,
        stdin_file: *?std.Io.File,
        stdout_file: *?std.Io.File,
        stderr_file: *?std.Io.File,
        manual_stdout_capture: *?PipelinePipe,
        manual_stderr_capture: *?PipelinePipe,
        inherited_redirections: *FdRedirectionGuard,
        io: std.Io,
        redirection: ir.Redirection,
        from_fd: std.posix.fd_t,
        options: ExecuteOptions,
    ) !void {
        const target = redirection.target orelse return;
        if (std.mem.eql(u8, target.text, "-")) {
            try moveExternalRedirectionHandles(stdin_file, stdout_file, stderr_file, manual_stdout_capture, manual_stderr_capture, io, from_fd);
            try inherited_redirections.apply(self, io, redirection);
            return;
        }

        const to_fd = parseFd(target.text) orelse return;
        if (to_fd == 1 and stdout_file.* == null and externalStdioCapturesStdout(options.external_stdio) and manual_stdout_capture.* == null) {
            manual_stdout_capture.* = try makePipelinePipe(io);
        }
        if (to_fd == 2 and stderr_file.* == null and externalStdioCapturesStderr(options.external_stdio) and manual_stderr_capture.* == null) {
            manual_stderr_capture.* = try makePipelinePipe(io);
        }

        try moveExternalRedirectionHandles(stdin_file, stdout_file, stderr_file, manual_stdout_capture, manual_stderr_capture, io, from_fd);
        const source_file: ?std.Io.File = if (to_fd == 1)
            if (stdout_file.*) |file| file else if (manual_stdout_capture.*) |pipe| pipe.write.? else null
        else if (to_fd == 2)
            if (stderr_file.*) |file| file else if (manual_stderr_capture.*) |pipe| pipe.write.? else null
        else
            null;
        if (source_file) |file| {
            try self.applyExternalInheritedFile(inherited_redirections, from_fd, file);
        } else {
            try inherited_redirections.apply(self, io, redirection);
        }
    }

    fn applyExternalInheritedFile(self: *Executor, inherited_redirections: *FdRedirectionGuard, fd: std.posix.fd_t, file: std.Io.File) !void {
        try inherited_redirections.saveFd(self, fd);
        try installRedirectionFile(file, fd);
        try self.markShellFdOpen(fd);
    }

    fn spawnExternalCommand(self: *Executor, io: std.Io, spawn_options: ExternalSpawnOptions) !std.process.Child {
        return std.process.spawn(io, .{
            .argv = spawn_options.argv,
            .environ_map = spawn_options.environ_map,
            .stdin = spawn_options.stdin,
            .stdout = spawn_options.stdout,
            .stderr = spawn_options.stderr,
            .pgid = spawn_options.pgid,
        }) catch |err| switch (err) {
            error.InvalidExe => return self.spawnExternalShellFallback(io, spawn_options),
            else => return err,
        };
    }

    fn spawnExternalShellFallback(self: *Executor, io: std.Io, spawn_options: ExternalSpawnOptions) !std.process.Child {
        const fallback_argv = try self.shellFallbackArgv(spawn_options.argv);
        defer self.allocator.free(fallback_argv);
        return std.process.spawn(io, .{
            .argv = fallback_argv,
            .environ_map = spawn_options.environ_map,
            .stdin = spawn_options.stdin,
            .stdout = spawn_options.stdout,
            .stderr = spawn_options.stderr,
            .pgid = spawn_options.pgid,
        });
    }

    fn shellFallbackArgv(self: *Executor, argv: []const []const u8) ![]const []const u8 {
        std.debug.assert(argv.len > 0);
        const fallback_argv = try self.allocator.alloc([]const u8, argv.len + 1);
        fallback_argv[0] = posix_shell_path;
        fallback_argv[1] = argv[0];
        @memcpy(fallback_argv[2..], argv[1..]);
        return fallback_argv;
    }

    fn resolveExternalArgv0(self: *Executor, command: ir.SimpleCommand, io: std.Io, options: ExecuteOptions) !?[]const u8 {
        const executable = try self.findReplacementExecutable(io, command, options.default_path_lookup);
        return @as(?[]const u8, executable);
    }
};

const ExecveError = error{ FileNotFound, AccessDenied, PermissionDenied, InvalidExe, ExecFailed, Unsupported };

fn execve(path: [*:0]const u8, argv: [*:null]const ?[*:0]const u8, envp: [*:null]const ?[*:0]const u8) ExecveError!void {
    if (zig_builtin.os.tag == .windows or zig_builtin.os.tag == .wasi) return error.Unsupported;
    if (zig_builtin.link_libc) {
        const rc = std.c.execve(path, argv, envp);
        return switch (std.c.errno(rc)) {
            .SUCCESS => unreachable,
            .NOENT, .NOTDIR => error.FileNotFound,
            .ACCES, .PERM => error.AccessDenied,
            .NOEXEC => error.InvalidExe,
            else => error.ExecFailed,
        };
    }
    if (zig_builtin.os.tag == .linux) {
        const rc = std.os.linux.execve(path, argv, envp);
        return switch (std.os.linux.errno(rc)) {
            .SUCCESS => unreachable,
            .NOENT, .NOTDIR => error.FileNotFound,
            .ACCES, .PERM => error.AccessDenied,
            .NOEXEC => error.InvalidExe,
            else => error.ExecFailed,
        };
    }
    return error.Unsupported;
}

fn shellPid() i64 {
    if (zig_builtin.os.tag == .linux and !zig_builtin.link_libc) return @intCast(std.os.linux.getpid());
    return @intCast(std.c.getpid());
}

fn shellUmask(mask: u16) u16 {
    if (zig_builtin.os.tag == .linux and !zig_builtin.link_libc) {
        return @intCast(std.os.linux.syscall1(.umask, mask));
    }
    return @intCast(std.c.umask(mask));
}

fn readShellUmask() u16 {
    const mask = shellUmask(0);
    _ = shellUmask(mask);
    return mask;
}

fn restoreShellUmask(mask: u16) void {
    _ = shellUmask(mask);
}

const FdRedirectionGuard = struct {
    const SavedFd = struct {
        fd: std.posix.fd_t,
        saved: ?std.posix.fd_t,
    };

    allocator: std.mem.Allocator,
    saved: std.ArrayList(SavedFd) = .empty,
    active: bool = true,

    fn init(allocator: std.mem.Allocator, io: std.Io) !FdRedirectionGuard {
        _ = io;
        return .{ .allocator = allocator };
    }

    fn saveFd(self: *FdRedirectionGuard, executor: *Executor, fd: std.posix.fd_t) !void {
        for (self.saved.items) |entry| if (entry.fd == fd) return;
        const should_save = fd <= 2 or executor.isShellFdOpen(fd);
        const saved_fd = if (should_save) rawDup(fd) catch |err| switch (err) {
            error.BadFileDescriptor => null,
            else => return err,
        } else null;
        try self.saved.append(self.allocator, .{ .fd = fd, .saved = saved_fd });
    }

    fn apply(self: *FdRedirectionGuard, executor: *Executor, io: std.Io, redirection: ir.Redirection) !void {
        if (redirection.operator == .dless or redirection.operator == .dless_dash) {
            const fd = redirectionFd(redirection) orelse 0;
            try self.saveFd(executor, fd);
            var file = try fileFromBytes(io, redirection.here_doc orelse "");
            defer if (file.handle != fd) file.close(io);
            try installRedirectionFile(file, fd);
            try executor.markShellFdOpen(fd);
            return;
        }
        if (redirection.operator == .less or redirection.operator == .less_great) {
            const target = redirection.target orelse return;
            const fd = redirectionFd(redirection) orelse 0;
            try self.saveFd(executor, fd);
            var file = if (redirection.operator == .less_great)
                try openReadWriteRedirectionFile(io, target.text)
            else
                try std.Io.Dir.cwd().openFile(io, target.text, .{});
            defer if (file.handle != fd) file.close(io);
            try installRedirectionFile(file, fd);
            try executor.markShellFdOpen(fd);
            return;
        }
        if (isFileOutputRedirection(redirection)) {
            const target = redirection.target orelse return;
            const fd = redirectionFd(redirection) orelse 1;
            try self.saveFd(executor, fd);
            var file = try openOutputRedirectionFile(io, target.text, redirection.operator, executor.shell_options.noclobber);
            defer if (file.handle != fd) file.close(io);
            try installRedirectionFile(file, fd);
            try executor.markShellFdOpen(fd);
            return;
        }
        if (redirection.operator == .greater_and or redirection.operator == .less_and) {
            const default_fd: std.posix.fd_t = if (redirection.operator == .less_and) 0 else 1;
            const from_fd = redirectionFd(redirection) orelse default_fd;
            const target = redirection.target orelse return;
            try self.saveFd(executor, from_fd);
            if (std.mem.eql(u8, target.text, "-")) {
                closeRawFd(io, from_fd);
                executor.markShellFdClosed(from_fd);
                return;
            }
            const to_fd = parseFd(target.text) orelse return;
            if (!executor.isShellFdOpen(to_fd)) return error.BadFileDescriptor;
            try rawDup2(to_fd, from_fd);
            try executor.markShellFdOpen(from_fd);
            return;
        }
    }

    fn commit(self: *FdRedirectionGuard, io: std.Io) void {
        if (!self.active) return;
        for (self.saved.items) |entry| {
            if (entry.saved) |saved_fd| closeRawFd(io, saved_fd);
        }
        self.saved.deinit(self.allocator);
        self.active = false;
    }

    fn restore(self: *FdRedirectionGuard, executor: *Executor, io: std.Io) void {
        if (!self.active) return;
        var index = self.saved.items.len;
        while (index > 0) {
            index -= 1;
            const entry = self.saved.items[index];
            if (entry.saved) |saved_fd| {
                rawDup2(saved_fd, entry.fd) catch {};
                closeRawFd(io, saved_fd);
            } else {
                closeRawFd(io, entry.fd);
                executor.markShellFdClosed(entry.fd);
            }
        }
        self.saved.deinit(self.allocator);
        self.active = false;
    }
};

fn writeInheritedResult(io: std.Io, result: CommandResult) !void {
    _ = io;
    if (result.stderr_before_stdout) {
        try rawWriteAll(2, result.stderr);
        try rawWriteAll(1, result.stdout);
        return;
    }
    try rawWriteAll(1, result.stdout);
    try rawWriteAll(2, result.stderr);
}

fn rawWriteAll(fd: std.posix.fd_t, bytes: []const u8) !void {
    var remaining = bytes;
    while (remaining.len != 0) {
        const written = try rawWrite(fd, remaining);
        remaining = remaining[written..];
    }
}

fn rawWrite(fd: std.posix.fd_t, bytes: []const u8) !usize {
    if (zig_builtin.os.tag == .linux and !zig_builtin.link_libc) {
        const rc = std.os.linux.write(fd, bytes.ptr, bytes.len);
        switch (std.os.linux.errno(rc)) {
            .SUCCESS => return rc,
            .BADF => return error.BadFileDescriptor,
            .INTR => return rawWrite(fd, bytes),
            .IO => return error.InputOutput,
            .NOSPC => return error.NoSpaceLeft,
            .PIPE => return error.BrokenPipe,
            else => return error.Unexpected,
        }
    }
    while (true) {
        const rc = std.c.write(fd, bytes.ptr, bytes.len);
        switch (std.c.errno(rc)) {
            .SUCCESS => return @intCast(rc),
            .BADF => return error.BadFileDescriptor,
            .INTR => continue,
            .IO => return error.InputOutput,
            .NOSPC => return error.NoSpaceLeft,
            .PIPE => return error.BrokenPipe,
            else => return error.Unexpected,
        }
    }
}

fn isOutputWriteFailure(err: anyerror) bool {
    return writeFailureMessage(err) != null;
}

fn writeFailureMessage(err: anyerror) ?[]const u8 {
    return switch (err) {
        error.BrokenPipe => "broken pipe",
        error.NoSpaceLeft => "no space left on device",
        error.InputOutput => "input/output error",
        error.WriteFailed => "write failed",
        else => null,
    };
}

fn rawDup(fd: std.posix.fd_t) !std.posix.fd_t {
    if (zig_builtin.os.tag == .linux and !zig_builtin.link_libc) {
        const rc = std.os.linux.dup(fd);
        switch (std.os.linux.errno(rc)) {
            .SUCCESS => return @intCast(rc),
            .BADF => return error.BadFileDescriptor,
            .MFILE => return error.ProcessFdQuotaExceeded,
            else => return error.Unexpected,
        }
    }
    while (true) {
        const rc = std.c.dup(fd);
        switch (std.c.errno(rc)) {
            .SUCCESS => return @intCast(rc),
            .BADF => return error.BadFileDescriptor,
            .INTR => continue,
            .MFILE => return error.ProcessFdQuotaExceeded,
            else => return error.Unexpected,
        }
    }
}

fn rawDup2(old_fd: std.posix.fd_t, new_fd: std.posix.fd_t) !void {
    if (old_fd == new_fd) return;
    if (zig_builtin.os.tag == .linux and !zig_builtin.link_libc) {
        const rc = std.os.linux.dup2(old_fd, new_fd);
        switch (std.os.linux.errno(rc)) {
            .SUCCESS => return,
            .BADF => return error.BadFileDescriptor,
            .BUSY => return error.FileBusy,
            .INTR => return rawDup2(old_fd, new_fd),
            .MFILE => return error.ProcessFdQuotaExceeded,
            else => return error.Unexpected,
        }
    }
    while (true) {
        const rc = std.c.dup2(old_fd, new_fd);
        switch (std.c.errno(rc)) {
            .SUCCESS => return,
            .BADF => return error.BadFileDescriptor,
            .INTR => continue,
            .MFILE => return error.ProcessFdQuotaExceeded,
            else => return error.Unexpected,
        }
    }
}

fn makePipelinePipe(io: std.Io) !Executor.PipelinePipe {
    const builtin = @import("builtin");
    return switch (builtin.os.tag) {
        .linux => blk: {
            var fds: [2]i32 = undefined;
            const rc = std.os.linux.pipe2(&fds, .{ .CLOEXEC = true });
            switch (std.os.linux.errno(rc)) {
                .SUCCESS => {},
                .MFILE => return error.ProcessFdQuotaExceeded,
                .NFILE => return error.SystemFdQuotaExceeded,
                else => return error.Unexpected,
            }
            break :blk filesFromPipeFds(fds);
        },
        .macos, .freebsd, .openbsd, .netbsd, .dragonfly, .illumos => blk: {
            var fds: [2]std.c.fd_t = undefined;
            const rc = std.c.pipe(&fds);
            switch (std.c.errno(rc)) {
                .SUCCESS => {},
                .MFILE => return error.ProcessFdQuotaExceeded,
                .NFILE => return error.SystemFdQuotaExceeded,
                else => return error.Unexpected,
            }
            errdefer {
                closeRawFd(io, fds[0]);
                closeRawFd(io, fds[1]);
            }
            try setCloseOnExec(fds[0]);
            try setCloseOnExec(fds[1]);
            break :blk filesFromPipeFds(.{ fds[0], fds[1] });
        },
        else => error.Unsupported,
    };
}

fn closeRawFd(io: std.Io, fd: std.posix.fd_t) void {
    _ = io;
    rawClose(fd) catch {};
}

fn rawClose(fd: std.posix.fd_t) !void {
    if (zig_builtin.os.tag == .linux and !zig_builtin.link_libc) {
        const rc = std.os.linux.close(fd);
        switch (std.os.linux.errno(rc)) {
            .SUCCESS, .BADF => return,
            .INTR => return rawClose(fd),
            else => return error.Unexpected,
        }
    }
    while (true) {
        const rc = std.c.close(fd);
        switch (std.c.errno(rc)) {
            .SUCCESS, .BADF => return,
            .INTR => continue,
            else => return error.Unexpected,
        }
    }
}

fn forkProcess() !std.posix.pid_t {
    if (comptime zig_builtin.link_libc) {
        while (true) {
            const rc = std.c.fork();
            switch (std.c.errno(rc)) {
                .SUCCESS => return @intCast(rc),
                .INTR => continue,
                .AGAIN, .NOMEM => return error.SystemResources,
                else => return error.Unexpected,
            }
        }
    }
    if (comptime zig_builtin.os.tag == .linux) {
        const rc = std.os.linux.fork();
        switch (std.os.linux.errno(rc)) {
            .SUCCESS => return @intCast(rc),
            .AGAIN, .NOMEM => return error.SystemResources,
            else => return error.Unexpected,
        }
    }
    return error.Unsupported;
}

fn exitForkedChild(status: ExitStatus) noreturn {
    if (comptime zig_builtin.link_libc) std.c._exit(status);
    if (comptime zig_builtin.os.tag == .linux) std.os.linux.exit(status);
    unreachable;
}

fn childFromPid(pid: std.posix.pid_t) std.process.Child {
    return .{
        .id = pid,
        .thread_handle = {},
        .stdin = null,
        .stdout = null,
        .stderr = null,
        .request_resource_usage_statistics = false,
    };
}

fn statementText(program: ir.Program, statement: ir.Statement) []const u8 {
    return switch (statement.kind) {
        .pipeline => pipelineText(program, program.pipelines[statement.index]),
        .if_command => spanText(program.source, program.if_commands[statement.index].span),
        .loop_command => spanText(program.source, program.loop_commands[statement.index].span),
        .for_command => spanText(program.source, program.for_commands[statement.index].span),
        .case_command => spanText(program.source, program.case_commands[statement.index].span),
        .function_definition => spanText(program.source, program.function_definitions[statement.index].span),
        .bash_test_command => spanText(program.source, program.bash_test_commands[statement.index].span),
        .brace_group => spanText(program.source, program.brace_groups[statement.index].span),
        .subshell => spanText(program.source, program.subshells[statement.index].span),
    };
}

fn pipelineText(program: ir.Program, pipeline: ir.Pipeline) []const u8 {
    return spanText(program.source, pipeline.span);
}

fn spanText(source: []const u8, span: parser.Span) []const u8 {
    return source[@min(span.start, source.len)..@min(span.end, source.len)];
}

fn sourceLineNumber(source: []const u8, offset: usize) usize {
    var line: usize = 1;
    for (source[0..@min(offset, source.len)]) |byte| {
        if (byte == '\n') line += 1;
    }
    return line;
}

fn setCloseOnExec(fd: std.posix.fd_t) !void {
    const rc = std.c.fcntl(fd, @as(c_int, std.c.F.SETFD), @as(c_int, std.c.FD_CLOEXEC));
    switch (std.c.errno(rc)) {
        .SUCCESS => {},
        .BADF => return error.FileDescriptorNotASocket,
        .INVAL => return error.Unexpected,
        else => return error.Unexpected,
    }
}

fn filesFromPipeFds(fds: [2]std.posix.fd_t) Executor.PipelinePipe {
    return .{
        .read = .{ .handle = fds[0], .flags = .{ .nonblocking = false } },
        .write = .{ .handle = fds[1], .flags = .{ .nonblocking = false } },
    };
}

fn dupFile(file: std.Io.File) !std.Io.File {
    return .{ .handle = try rawDup(file.handle), .flags = file.flags };
}

fn dupFileCloseOnExec(file: std.Io.File) !std.Io.File {
    const duplicate = try dupFile(file);
    errdefer rawClose(duplicate.handle) catch {};
    try setCloseOnExec(duplicate.handle);
    return duplicate;
}

fn dupFileExcept(file: std.Io.File, excluded_fd: std.posix.fd_t) !std.Io.File {
    const first = try rawDup(file.handle);
    if (first != excluded_fd) return .{ .handle = first, .flags = file.flags };
    const second = rawDup(first) catch |err| {
        rawClose(first) catch {};
        return err;
    };
    rawClose(first) catch {};
    return .{ .handle = second, .flags = file.flags };
}

fn openDevNullRead(io: std.Io) !std.Io.File {
    var file = try std.Io.Dir.cwd().openFile(io, "/dev/null", .{});
    if (file.handle > 2) return file;

    const duplicate = try rawDup(file.handle);
    const flags = file.flags;
    file.close(io);
    return .{ .handle = duplicate, .flags = flags };
}

fn installDevNullStdin(io: std.Io) !void {
    var file = try openDevNullRead(io);
    defer file.close(io);
    try installRedirectionFile(file, 0);
}

fn installRedirectionFile(file: std.Io.File, fd: std.posix.fd_t) !void {
    if (file.handle == fd) {
        const duplicate = try rawDup(file.handle);
        defer rawClose(duplicate) catch {};
        try rawDup2(duplicate, fd);
        return;
    }
    try rawDup2(file.handle, fd);
}

/// Duplicates one of the shell's own stdio descriptors so a pipeline
/// stage can write to it and close it independently.
fn dupStdioFile(fd: std.posix.fd_t) !std.Io.File {
    return .{ .handle = try rawDup(fd), .flags = .{ .nonblocking = false } };
}

extern "c" fn tcgetpgrp(fd: std.c.fd_t) std.c.pid_t;
extern "c" fn tcsetpgrp(fd: std.c.fd_t, pgrp: std.c.pid_t) c_int;
extern "c" fn getpgid(pid: std.c.pid_t) std.c.pid_t;

const ForegroundTerminal = struct {
    tty_fd: std.posix.fd_t,
    previous_pgrp: std.posix.pid_t,
};

fn processSetPgrp(pid: std.posix.pid_t, pgrp: std.posix.pid_t) !void {
    if (zig_builtin.link_libc) {
        while (true) {
            const rc = std.c.setpgid(pid, pgrp);
            switch (std.c.errno(rc)) {
                .SUCCESS => return,
                .INTR => continue,
                .ACCES => return error.ProcessAlreadyExec,
                .INVAL => return error.InvalidProcessGroupId,
                .PERM => return error.PermissionDenied,
                .SRCH => return error.ProcessNotFound,
                else => return error.Unexpected,
            }
        }
    }
    if (zig_builtin.os.tag == .linux) {
        const rc = std.os.linux.setpgid(pid, pgrp);
        switch (std.os.linux.errno(rc)) {
            .SUCCESS => return,
            .ACCES => return error.ProcessAlreadyExec,
            .INVAL => return error.InvalidProcessGroupId,
            .PERM => return error.PermissionDenied,
            .SRCH => return error.ProcessNotFound,
            else => return error.Unexpected,
        }
    }
    return error.Unsupported;
}

fn processGetPgrp(pid: std.posix.pid_t) !std.posix.pid_t {
    if (zig_builtin.link_libc) {
        while (true) {
            const rc = getpgid(pid);
            switch (std.c.errno(rc)) {
                .SUCCESS => return @intCast(rc),
                .INTR => continue,
                .INVAL => return error.InvalidProcessId,
                .PERM => return error.PermissionDenied,
                .SRCH => return error.ProcessNotFound,
                else => return error.Unexpected,
            }
        }
    }
    if (zig_builtin.os.tag == .linux) {
        const rc = std.os.linux.getpgid(pid);
        switch (std.os.linux.errno(rc)) {
            .SUCCESS => return @intCast(rc),
            .INVAL => return error.InvalidProcessId,
            .PERM => return error.PermissionDenied,
            .SRCH => return error.ProcessNotFound,
            else => return error.Unexpected,
        }
    }
    return error.Unsupported;
}

fn terminalGetPgrp(fd: std.posix.fd_t) !std.posix.pid_t {
    if (zig_builtin.link_libc) {
        while (true) {
            const rc = tcgetpgrp(fd);
            switch (std.c.errno(rc)) {
                .SUCCESS => return @intCast(rc),
                .BADF, .INVAL => unreachable,
                .INTR => continue,
                .NOTTY => return error.NotATerminal,
                else => return error.Unexpected,
            }
        }
    }
    return std.posix.tcgetpgrp(fd);
}

fn terminalSetPgrp(fd: std.posix.fd_t, pgrp: std.posix.pid_t) !void {
    if (zig_builtin.link_libc) {
        while (true) {
            const rc = tcsetpgrp(fd, pgrp);
            switch (std.c.errno(rc)) {
                .SUCCESS => return,
                .BADF, .INVAL => unreachable,
                .INTR => continue,
                .NOTTY => return error.NotATerminal,
                .PERM => return error.NotAPgrpMember,
                else => return error.Unexpected,
            }
        }
    }
    return std.posix.tcsetpgrp(fd, pgrp);
}

fn prepareForegroundTerminal(enabled: bool) !?ForegroundTerminal {
    if (!enabled) return null;
    const tty_fd = std.Io.File.stdin().handle;
    const previous_pgrp = terminalGetPgrp(tty_fd) catch |err| switch (err) {
        error.NotATerminal => return null,
        else => return err,
    };
    return .{ .tty_fd = tty_fd, .previous_pgrp = previous_pgrp };
}

fn waitForegroundProcess(pid: std.posix.pid_t) !u32 {
    if (zig_builtin.link_libc) {
        while (true) {
            var status: c_int = 0;
            const rc = std.c.waitpid(pid, &status, @intCast(std.posix.W.UNTRACED));
            switch (std.c.errno(rc)) {
                .SUCCESS => return @bitCast(status),
                .INTR => continue,
                .CHILD => return error.ProcessNotFound,
                else => return error.Unexpected,
            }
        }
    }
    if (zig_builtin.os.tag == .linux) {
        while (true) {
            var status: u32 = 0;
            const rc = std.os.linux.waitpid(pid, &status, std.posix.W.UNTRACED);
            switch (std.os.linux.errno(rc)) {
                .SUCCESS => return status,
                .INTR => continue,
                .CHILD => return error.ProcessNotFound,
                else => return error.Unexpected,
            }
        }
    }
    return error.Unsupported;
}

fn giveTerminalToForegroundChild(child: *std.process.Child, terminal: ?ForegroundTerminal) !void {
    const child_pgrp = child.id orelse return;
    return giveTerminalToForegroundPgrp(child_pgrp, terminal);
}

fn giveTerminalToForegroundPgrp(pgrp: std.posix.pid_t, terminal: ?ForegroundTerminal) !void {
    const active = terminal orelse return;
    var sigttou = ignoreSignal(.TTOU);
    defer sigttou.restore();
    terminalSetPgrp(active.tty_fd, pgrp) catch |err| switch (err) {
        error.NotATerminal, error.NotAPgrpMember => return,
        else => return err,
    };
}

fn restoreForegroundTerminal(terminal: ?ForegroundTerminal) void {
    const active = terminal orelse return;
    var sigttou = ignoreSignal(.TTOU);
    defer sigttou.restore();
    terminalSetPgrp(active.tty_fd, active.previous_pgrp) catch {};
}

fn trapSignalHandler(signal: std.posix.SIG) callconv(.c) void {
    pending_trap_signal.store(@intCast(@intFromEnum(signal)), .seq_cst);
    const fd = trap_signal_wake_fd.load(.acquire);
    if (fd != -1) _ = std.c.write(fd, "t", 1);
}

pub fn setTrapSignalWakeFd(fd: std.posix.fd_t) void {
    trap_signal_wake_fd.store(fd, .release);
}

pub fn clearTrapSignalWakeFd(fd: std.posix.fd_t) void {
    if (trap_signal_wake_fd.load(.acquire) == fd) trap_signal_wake_fd.store(-1, .release);
}

fn testTermSignalHandler(signal: std.posix.SIG) callconv(.c) void {
    if (signal == .TERM) _ = test_term_signal_count.fetchAdd(1, .seq_cst);
}

fn expectTestTermSignalHandlerInstalled() !void {
    var current: std.posix.Sigaction = undefined;
    std.posix.sigaction(.TERM, null, &current);
    try std.testing.expect(current.handler.handler != null);
    try std.testing.expect(current.handler.handler.? == testTermSignalHandler);
}

fn installTrapSignal(signal: std.posix.SIG) std.posix.Sigaction {
    const action: std.posix.Sigaction = .{
        .handler = .{ .handler = trapSignalHandler },
        .mask = std.posix.sigemptyset(),
        .flags = 0,
    };
    var previous: std.posix.Sigaction = undefined;
    std.posix.sigaction(signal, &action, &previous);
    return previous;
}

fn signalFromTrapName(name: []const u8) ?std.posix.SIG {
    if (std.mem.eql(u8, name, "HUP")) return .HUP;
    if (std.mem.eql(u8, name, "INT")) return .INT;
    if (std.mem.eql(u8, name, "QUIT")) return .QUIT;
    if (std.mem.eql(u8, name, "TERM")) return .TERM;
    if (std.mem.eql(u8, name, "USR1")) return .USR1;
    if (std.mem.eql(u8, name, "USR2")) return .USR2;
    return null;
}

fn signalNameFromNumber(raw: u8) ?[]const u8 {
    inline for (.{ "HUP", "INT", "QUIT", "TERM", "USR1", "USR2" }) |name| {
        const signal = signalFromTrapName(name).?;
        if (raw == @intFromEnum(signal)) return name;
    }
    return null;
}

fn ignoredTrapSignalsAtEntry() u64 {
    var mask: u64 = 0;
    for (supported_trap_signals) |signal| {
        var current: std.posix.Sigaction = undefined;
        std.posix.sigaction(signal, null, &current);
        if (current.handler.handler == std.posix.SIG.IGN) mask |= signalBit(signal);
    }
    return mask;
}

fn signalBit(signal: std.posix.SIG) u64 {
    const raw = @intFromEnum(signal);
    return if (raw < 64) @as(u64, 1) << @intCast(raw) else 0;
}

const SignalActionGuard = struct {
    signal: std.posix.SIG,
    previous: std.posix.Sigaction,

    fn restore(self: *SignalActionGuard) void {
        std.posix.sigaction(self.signal, &self.previous, null);
    }
};

fn ignoreSignal(signal: std.posix.SIG) SignalActionGuard {
    const ignored: std.posix.Sigaction = .{
        .handler = .{ .handler = std.posix.SIG.IGN },
        .mask = std.posix.sigemptyset(),
        .flags = 0,
    };
    var previous: std.posix.Sigaction = undefined;
    std.posix.sigaction(signal, &ignored, &previous);
    return .{ .signal = signal, .previous = previous };
}

pub fn resetInteractiveJobSignalHandlers() void {
    defaultSignal(.INT);
    defaultSignal(.QUIT);
    defaultSignal(.TERM);
}

fn defaultSignal(signal: std.posix.SIG) void {
    const action: std.posix.Sigaction = .{
        .handler = .{ .handler = std.posix.SIG.DFL },
        .mask = std.posix.sigemptyset(),
        .flags = 0,
    };
    std.posix.sigaction(signal, &action, null);
}

fn fileFromBytes(io: std.Io, bytes: []const u8) !std.Io.File {
    var name_buffer: [128]u8 = undefined;
    var attempts: usize = 0;
    const Counter = struct {
        var value: std.atomic.Value(u64) = .init(0);
    };
    while (attempts < 32) : (attempts += 1) {
        const suffix = Counter.value.fetchAdd(1, .monotonic);
        const name = try std.fmt.bufPrint(&name_buffer, ".rush-heredoc-{d}-{d}.tmp", .{ shellPid(), suffix });
        var write_file = std.Io.Dir.cwd().createFile(io, name, .{ .truncate = false, .exclusive = true }) catch |err| switch (err) {
            error.PathAlreadyExists => continue,
            else => return err,
        };
        defer write_file.close(io);
        errdefer std.Io.Dir.cwd().deleteFile(io, name) catch {};
        try writeBytesToFile(io, write_file, bytes);
        const read_file = try std.Io.Dir.cwd().openFile(io, name, .{});
        std.Io.Dir.cwd().deleteFile(io, name) catch {};
        return read_file;
    }
    return error.PathAlreadyExists;
}

fn writeBytesToFile(io: std.Io, file: std.Io.File, bytes: []const u8) !void {
    var buffer: [4096]u8 = undefined;
    var writer = file.writer(io, &buffer);
    try writer.interface.writeAll(bytes);
    try writer.interface.flush();
}

fn openReadWriteRedirectionFile(io: std.Io, target: []const u8) !std.Io.File {
    const builtin = @import("builtin");
    return switch (builtin.os.tag) {
        .windows, .wasi => std.Io.Dir.cwd().createFile(io, target, .{ .truncate = false }),
        else => blk: {
            const fd = try std.posix.openat(std.Io.Dir.cwd().handle, target, .{
                .ACCMODE = .RDWR,
                .CREAT = true,
                .CLOEXEC = true,
            }, 0o666);
            break :blk .{ .handle = fd, .flags = .{ .nonblocking = false } };
        },
    };
}

fn openOutputRedirectionFile(io: std.Io, target: []const u8, operator: parser.TokenKind, noclobber: bool) !std.Io.File {
    return switch (operator) {
        .dgreat => openAppendRedirectionFile(io, target),
        .clobber => std.Io.Dir.cwd().createFile(io, target, .{ .truncate = true }),
        .greater => if (noclobber)
            std.Io.Dir.cwd().createFile(io, target, .{ .truncate = false, .exclusive = true })
        else
            std.Io.Dir.cwd().createFile(io, target, .{ .truncate = true }),
        else => unreachable,
    };
}

fn openAppendRedirectionFile(io: std.Io, target: []const u8) !std.Io.File {
    const builtin = @import("builtin");
    return switch (builtin.os.tag) {
        .windows, .wasi => std.Io.Dir.cwd().createFile(io, target, .{ .truncate = false }),
        else => blk: {
            const fd = try std.posix.openat(std.Io.Dir.cwd().handle, target, .{
                .ACCMODE = .WRONLY,
                .CREAT = true,
                .APPEND = true,
                .CLOEXEC = true,
            }, 0o666);
            break :blk .{ .handle = fd, .flags = .{ .nonblocking = false } };
        },
    };
}

fn traceLineForCommand(allocator: std.mem.Allocator, command: ir.SimpleCommand) ![]const u8 {
    var line: std.ArrayList(u8) = .empty;
    errdefer line.deinit(allocator);
    try line.appendSlice(allocator, "+");
    for (command.assignments) |assignment| {
        try line.append(allocator, ' ');
        try line.appendSlice(allocator, assignment.text);
    }
    for (command.argv) |arg| {
        try line.append(allocator, ' ');
        try line.appendSlice(allocator, arg.text);
    }
    try line.append(allocator, '\n');
    return line.toOwnedSlice(allocator);
}

fn simpleCommandFromArgs(command: ir.SimpleCommand, start: usize) ir.SimpleCommand {
    return .{
        .span = command.span,
        .assignments = command.assignments,
        .argv = command.argv[start..],
        .redirections = &.{},
    };
}

/// A nested command built from already-expanded words. Builtins like
/// command and exec receive expanded argv but re-execute it through the
/// normal path, which expands again from each word's raw text; that
/// double-expands "$@" and re-runs command substitutions. Quoting the
/// expanded text as the raw word makes re-expansion the identity.
const PreExpandedCommand = struct {
    allocator: std.mem.Allocator,
    assignments: []ir.WordRef,
    argv: []ir.WordRef,

    fn command(self: PreExpandedCommand, span: parser.Span) ir.SimpleCommand {
        return .{
            .span = span,
            .assignments = self.assignments,
            .argv = self.argv,
            .redirections = &.{},
        };
    }

    fn deinit(self: *PreExpandedCommand) void {
        for (self.assignments) |word| {
            self.allocator.free(word.raw);
            self.allocator.free(word.text);
        }
        self.allocator.free(self.assignments);
        for (self.argv) |word| {
            self.allocator.free(word.raw);
            self.allocator.free(word.text);
        }
        self.allocator.free(self.argv);
        self.* = undefined;
    }
};

fn quotedWordFromExpanded(allocator: std.mem.Allocator, word: ir.WordRef, value_start: usize) !ir.WordRef {
    std.debug.assert(value_start <= word.text.len);
    var raw: std.ArrayList(u8) = .empty;
    errdefer raw.deinit(allocator);
    try raw.appendSlice(allocator, word.text[0..value_start]);
    try appendShellQuoted(allocator, &raw, word.text[value_start..]);
    const text = try allocator.dupe(u8, word.text);
    errdefer allocator.free(text);
    return .{ .span = word.span, .raw = try raw.toOwnedSlice(allocator), .text = text };
}

fn preExpandedCommandFromArgs(allocator: std.mem.Allocator, command: ir.SimpleCommand, start: usize) !PreExpandedCommand {
    var assignments: std.ArrayList(ir.WordRef) = .empty;
    var argv: std.ArrayList(ir.WordRef) = .empty;
    errdefer {
        for (assignments.items) |word| {
            allocator.free(word.raw);
            allocator.free(word.text);
        }
        assignments.deinit(allocator);
        for (argv.items) |word| {
            allocator.free(word.raw);
            allocator.free(word.text);
        }
        argv.deinit(allocator);
    }
    for (command.assignments) |word| {
        // Keep "name=" literal so the word still parses as an assignment;
        // only the expanded value needs quoting.
        const value_start = if (std.mem.indexOfScalar(u8, word.text, '=')) |eq| eq + 1 else word.text.len;
        try assignments.append(allocator, try quotedWordFromExpanded(allocator, word, value_start));
    }
    for (command.argv[start..]) |word| {
        try argv.append(allocator, try quotedWordFromExpanded(allocator, word, 0));
    }
    return .{
        .allocator = allocator,
        .assignments = try assignments.toOwnedSlice(allocator),
        .argv = try argv.toOwnedSlice(allocator),
    };
}

fn stdoutLine(allocator: std.mem.Allocator, text: []const u8, status: ExitStatus) !CommandResult {
    const stdout = try std.fmt.allocPrint(allocator, "{s}\n", .{text});
    errdefer allocator.free(stdout);
    return .{ .allocator = allocator, .status = status, .stdout = stdout, .stderr = try allocator.alloc(u8, 0) };
}

fn stdoutLineFmt(allocator: std.mem.Allocator, comptime fmt: []const u8, args: anytype, status: ExitStatus) !CommandResult {
    const text = try std.fmt.allocPrint(allocator, fmt ++ "\n", args);
    errdefer allocator.free(text);
    return .{ .allocator = allocator, .status = status, .stdout = text, .stderr = try allocator.alloc(u8, 0) };
}

fn argvForCommand(allocator: std.mem.Allocator, command: ir.SimpleCommand) ![][]const u8 {
    const argv = try allocator.alloc([]const u8, command.argv.len);
    for (command.argv, 0..) |word, index| {
        argv[index] = word.text;
    }
    return argv;
}

fn lookupAliasForParser(context: *anyopaque, name: []const u8) ?[]const u8 {
    const self: *Executor = @ptrCast(@alignCast(context));
    return self.aliases.get(name);
}

fn containsAliasTimingCommandToken(script: []const u8) bool {
    var index: usize = 0;
    while (index < script.len) {
        const start = index;
        while (index < script.len and !isAliasWordBoundary(script[index])) : (index += 1) {}
        const word = script[start..index];
        if (std.mem.eql(u8, word, "alias")) return true;
        if (std.mem.eql(u8, word, "eval")) return true;
        if (std.mem.eql(u8, word, ".")) return true;
        if (index < script.len) index += 1;
    }
    return false;
}

fn canExecuteAsAliasTimingChunks(program: ir.Program) bool {
    if (program.statements.len < 2) return false;
    var previous_end: usize = 0;
    for (program.statements, 0..) |statement, index| {
        if (statement.op_before != .sequence or statement.async_after) return false;
        if (index != 0 and statement.span.start < previous_end) return false;
        previous_end = statement.span.end;
    }
    return true;
}

fn lastStatementOnReadLine(script: []const u8, program: ir.Program, first_statement_index: usize) usize {
    std.debug.assert(first_statement_index < program.statements.len);
    const start = program.statements[first_statement_index].span.start;
    const line_end = if (std.mem.findScalar(u8, script[start..], '\n')) |offset| start + offset else script.len;
    var index = first_statement_index;
    while (index + 1 < program.statements.len and program.statements[index + 1].span.start < line_end) : (index += 1) {}
    return index;
}

fn isAliasWordBoundary(byte: u8) bool {
    return byte == ' ' or byte == '\t' or byte == '\r' or byte == '\n' or byte == ';' or byte == '&' or byte == '|' or byte == '(' or byte == ')' or byte == '<' or byte == '>';
}

fn commandAbbreviationSpan(allocator: std.mem.Allocator, source: []const u8, cursor: usize) !?parser.Span {
    const clamped_cursor = @min(cursor, source.len);
    var parsed = try parser.parse(allocator, source, .{ .mode = .interactive, .cursor = clamped_cursor });
    defer parsed.deinit();
    const highlights = try parser.syntaxHighlights(allocator, parsed);
    defer allocator.free(highlights);
    var selected: ?parser.Span = null;
    for (highlights) |highlight| {
        if (highlight.kind != .command) continue;
        if (clamped_cursor < highlight.span.end) return null;
        selected = highlight.span;
    }
    return selected;
}

fn shouldSkipPipeline(op: ir.ListOp, previous_status: ExitStatus) bool {
    return switch (op) {
        .sequence => false,
        .and_if => previous_status != 0,
        .or_if => previous_status == 0,
    };
}

fn isAndOrListOp(op: ir.ListOp) bool {
    return op == .and_if or op == .or_if;
}

fn isFollowedByAndOrListOp(statements: []const ir.Statement, index: usize) bool {
    return index + 1 < statements.len and isAndOrListOp(statements[index + 1].op_before);
}

fn isPipelineFollowedByAndOrListOp(pipelines: []const ir.Pipeline, index: usize) bool {
    return index + 1 < pipelines.len and isAndOrListOp(pipelines[index + 1].op_before);
}

const BuiltinFn = *const fn (*Executor, ir.SimpleCommand, []const u8, ExecuteOptions) anyerror!CommandResult;

fn isSpecialBuiltin(name: []const u8) bool {
    return std.mem.eql(u8, name, ":") or
        std.mem.eql(u8, name, ".") or
        std.mem.eql(u8, name, "break") or
        std.mem.eql(u8, name, "continue") or
        std.mem.eql(u8, name, "eval") or
        std.mem.eql(u8, name, "exec") or
        std.mem.eql(u8, name, "exit") or
        std.mem.eql(u8, name, "export") or
        std.mem.eql(u8, name, "readonly") or
        std.mem.eql(u8, name, "return") or
        std.mem.eql(u8, name, "set") or
        std.mem.eql(u8, name, "shift") or
        std.mem.eql(u8, name, "times") or
        std.mem.eql(u8, name, "trap") or
        std.mem.eql(u8, name, "unset");
}

fn specialBuiltinPropertiesApply(options: ExecuteOptions, name: []const u8) bool {
    return isSpecialBuiltin(name) and !options.suppress_special_builtin_properties;
}

fn setSpecialBuiltinErrorConsequence(self: *Executor, status: ExitStatus) void {
    if (!self.suppress_special_builtin_properties) self.pending_exit = status;
}

fn builtinForName(self: Executor, name: []const u8) ?BuiltinFn {
    if (std.mem.eql(u8, name, "prompt")) return builtinPrompt;
    if (self.prompt_builder != null) {
        if (std.mem.eql(u8, name, "prompt_pwd")) return builtinPromptPwd;
        if (std.mem.eql(u8, name, "prompt_duration")) return builtinPromptDuration;
        if (std.mem.eql(u8, name, "prompt_async")) return builtinPromptAsync;
        if (std.mem.eql(u8, name, "prompt_time")) return builtinPromptTime;
    }
    if (self.completion_builder != null) {
        if (std.mem.eql(u8, name, "completion")) return builtinCompletion;
    }
    return builtinFor(name);
}

fn builtinFor(name: []const u8) ?BuiltinFn {
    if (std.mem.eql(u8, name, ".")) return builtinSource;
    if (std.mem.eql(u8, name, ":")) return builtinTrue;
    if (std.mem.eql(u8, name, "abbr")) return builtinAbbr;
    if (std.mem.eql(u8, name, "alias")) return builtinAlias;
    if (std.mem.eql(u8, name, "bg")) return builtinBg;
    if (std.mem.eql(u8, name, "break")) return builtinBreak;
    if (std.mem.eql(u8, name, "color")) return builtinColor;
    if (std.mem.eql(u8, name, "true")) return builtinTrue;
    if (std.mem.eql(u8, name, "false")) return builtinFalse;
    if (std.mem.eql(u8, name, "echo")) return builtinEcho;
    if (std.mem.eql(u8, name, "command")) return builtinCommand;
    if (std.mem.eql(u8, name, "complete")) return builtinComplete;
    if (std.mem.eql(u8, name, "continue")) return builtinContinue;
    if (std.mem.eql(u8, name, "cd")) return builtinCd;
    if (std.mem.eql(u8, name, "printf")) return builtinPrintf;
    if (std.mem.eql(u8, name, "pwd")) return builtinPwd;
    if (std.mem.eql(u8, name, "read")) return builtinRead;
    if (std.mem.eql(u8, name, "readonly")) return builtinReadonly;
    if (std.mem.eql(u8, name, "return")) return builtinReturn;
    if (std.mem.eql(u8, name, "shift")) return builtinShift;
    if (std.mem.eql(u8, name, "export")) return builtinExport;
    if (std.mem.eql(u8, name, "event")) return builtinEvent;
    if (std.mem.eql(u8, name, "getopts")) return builtinGetopts;
    if (std.mem.eql(u8, name, "hash")) return builtinHash;
    if (std.mem.eql(u8, name, "fc")) return builtinFc;
    if (std.mem.eql(u8, name, "fg")) return builtinFg;
    if (std.mem.eql(u8, name, "jobs")) return builtinJobs;
    if (std.mem.eql(u8, name, "kill")) return builtinKill;
    if (std.mem.eql(u8, name, "interval")) return builtinInterval;
    if (std.mem.eql(u8, name, "unset")) return builtinUnset;
    if (std.mem.eql(u8, name, "env")) return builtinEnv;
    if (std.mem.eql(u8, name, "eval")) return builtinEval;
    if (std.mem.eql(u8, name, "exec")) return builtinExec;
    if (std.mem.eql(u8, name, "exit")) return builtinExit;
    if (std.mem.eql(u8, name, "set")) return builtinSet;
    if (std.mem.eql(u8, name, "source")) return builtinSource;
    if (std.mem.eql(u8, name, "test")) return builtinTest;
    if (std.mem.eql(u8, name, "times")) return builtinTimes;
    if (std.mem.eql(u8, name, "trap")) return builtinTrap;
    if (std.mem.eql(u8, name, "type")) return builtinType;
    if (std.mem.eql(u8, name, "ulimit")) return builtinUlimit;
    if (std.mem.eql(u8, name, "umask")) return builtinUmask;
    if (std.mem.eql(u8, name, "unalias")) return builtinUnalias;
    if (std.mem.eql(u8, name, "wait")) return builtinWait;
    if (std.mem.eql(u8, name, "[")) return builtinTest;
    return null;
}

fn builtinSource(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    const io = options.io orelse return error.MissingIoForBuiltin;
    if (command.argv.len < 2) return sourceUsageError(self, command.argv[0].text, 2, "missing file operand");
    if (command.argv.len > 2) return sourceUsageError(self, command.argv[0].text, 2, "arguments are not implemented yet");
    const posix_dot = std.mem.eql(u8, command.argv[0].text, ".");
    const contents = self.readSourceFile(io, command.argv[1].text, posix_dot) catch |err| switch (err) {
        error.FileNotFound => return sourceUsageError(self, command.argv[0].text, 1, "file not found"),
        error.AccessDenied, error.PermissionDenied => {
            const message = try std.fmt.allocPrint(self.allocator, "{s}: permission denied", .{command.argv[1].text});
            defer self.allocator.free(message);
            return sourceUsageError(self, command.argv[0].text, 1, message);
        },
        else => |e| return e,
    };
    defer self.allocator.free(contents);
    var source_options = options;
    source_options.source_path = command.argv[1].text;
    source_options.verbose_input_echo = true;
    self.source_depth += 1;
    defer self.source_depth -= 1;
    var result = self.executeScriptSlice(contents, source_options) catch |err| switch (err) {
        error.ParseError => return sourceUsageError(self, command.argv[0].text, 2, "syntax error"),
        else => return err,
    };
    errdefer result.deinit();
    // return inside a dot script stops the script and supplies the dot
    // utility's exit status (POSIX XCU return).
    if (self.pending_return) |status| {
        self.pending_return = null;
        result.status = status;
    }
    return result;
}

fn sourceUsageError(self: *Executor, name: []const u8, status: ExitStatus, message: []const u8) !CommandResult {
    if (std.mem.eql(u8, name, ".")) setSpecialBuiltinErrorConsequence(self, status);
    return errorResult(self.allocator, status, name, message);
}

fn builtinCommand(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    if (command.argv.len == 1) return emptyResult(self.allocator, 0);
    var use_default_path = false;
    var lookup_mode: CommandLookupMode = .none;
    var index: usize = 1;
    while (index < command.argv.len and command.argv[index].text.len > 1 and command.argv[index].text[0] == '-') {
        const option = command.argv[index].text;
        index += 1;
        if (std.mem.eql(u8, option, "--")) break;
        for (option[1..]) |flag| switch (flag) {
            'p' => use_default_path = true,
            'v' => lookup_mode = .terse,
            'V' => lookup_mode = .verbose,
            else => return errorResult(self.allocator, 2, "command", "unsupported option"),
        };
        if (std.mem.indexOfScalar(u8, option[1..], 'V') != null) {
            lookup_mode = .verbose;
        }
    }
    if (lookup_mode != .none) {
        if (index >= command.argv.len) return errorResult(self.allocator, 2, "command", "missing command name");
        return commandLookupMany(self, options, command.argv[index..], use_default_path, lookup_mode);
    }
    if (index >= command.argv.len) return emptyResult(self.allocator, 0);
    var pre_expanded = try preExpandedCommandFromArgs(self.allocator, command, index);
    defer pre_expanded.deinit();
    var nested_options = options;
    nested_options.suppress_functions = true;
    nested_options.suppress_special_builtin_properties = true;
    if (use_default_path) nested_options.default_path_lookup = true;
    return self.executeSimpleCommandWithInput(pre_expanded.command(command.span), stdin, nested_options);
}

fn builtinType(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    var index: usize = 1;
    var option_terminated = false;
    if (index < command.argv.len and std.mem.eql(u8, command.argv[index].text, "--")) {
        option_terminated = true;
        index += 1;
    }
    if (index >= command.argv.len) return errorResult(self.allocator, 2, "type", "missing operand");
    if (!option_terminated and std.mem.startsWith(u8, command.argv[index].text, "-") and !std.mem.eql(u8, command.argv[index].text, "-")) return errorResult(self.allocator, 2, "type", "unsupported option");
    return commandLookupMany(self, options, command.argv[index..], false, .verbose);
}

fn builtinHash(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    var reset = false;
    var index: usize = 1;
    while (index < command.argv.len and command.argv[index].text.len > 1 and command.argv[index].text[0] == '-') {
        const option = command.argv[index].text;
        index += 1;
        if (std.mem.eql(u8, option, "--")) break;
        for (option[1..]) |flag| switch (flag) {
            'r' => reset = true,
            else => return errorResult(self.allocator, 2, "hash", "unsupported option"),
        };
    }

    if (reset) self.clearCommandHash();
    if (index >= command.argv.len) return printCommandHash(self);

    const io = options.io orelse return error.MissingIoForBuiltin;
    var stderr: std.ArrayList(u8) = .empty;
    errdefer stderr.deinit(self.allocator);

    var status: ExitStatus = 0;
    for (command.argv[index..]) |arg| {
        const name = arg.text;
        if (self.functions.get(name) != null or builtinForName(self.*, name) != null) continue;
        if (std.mem.indexOfScalar(u8, name, '/') != null) continue;
        const found = try self.findExecutableInPath(io, name);
        if (found) |path| {
            defer self.allocator.free(path);
            try self.rememberCommandHash(name, path);
            continue;
        }
        status = 1;
        const diagnostic = try std.fmt.allocPrint(self.allocator, "hash: {s}: not found\n", .{name});
        defer self.allocator.free(diagnostic);
        try stderr.appendSlice(self.allocator, diagnostic);
    }

    return .{
        .allocator = self.allocator,
        .status = status,
        .stdout = try self.allocator.alloc(u8, 0),
        .stderr = try stderr.toOwnedSlice(self.allocator),
    };
}

fn printCommandHash(self: *Executor) !CommandResult {
    var names: std.ArrayList([]const u8) = .empty;
    defer names.deinit(self.allocator);

    var iter = self.command_hash.iterator();
    while (iter.next()) |entry| try names.append(self.allocator, entry.key_ptr.*);
    std.mem.sort([]const u8, names.items, {}, lessThanString);

    var stdout: std.ArrayList(u8) = .empty;
    errdefer stdout.deinit(self.allocator);
    for (names.items) |name| {
        try stdout.appendSlice(self.allocator, self.command_hash.get(name).?);
        try stdout.append(self.allocator, '\n');
    }

    return .{
        .allocator = self.allocator,
        .status = 0,
        .stdout = try stdout.toOwnedSlice(self.allocator),
        .stderr = try self.allocator.alloc(u8, 0),
    };
}

const FcOptions = struct {
    list: bool = false,
    no_numbers: bool = false,
    reverse: bool = false,
    substitute: bool = false,
    editor: ?[]const u8 = null,
    first_operand: usize,
};

const FcReferenceError = error{
    EmptyHistory,
    InvalidReference,
    UnresolvedReference,
};

const FcOptionError = error{
    MissingEditor,
    UnsupportedOption,
};

fn builtinFc(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    self.suppress_next_interactive_history_append = true;

    const parsed = parseFcOptions(command) catch |err| return fcOptionErrorResult(self, err);
    if (parsed.list and parsed.substitute) return errorResult(self.allocator, 2, "fc", "conflicting options");
    if (parsed.list and parsed.editor != null) return errorResult(self.allocator, 2, "fc", "-e is not valid with -l");

    const history = self.command_history orelse return errorResult(self.allocator, 1, "fc", "history is not available");
    const entries = try history.list(history.context, self.allocator);
    defer freeHistoryEntries(self.allocator, entries);
    if (entries.len == 0) return errorResult(self.allocator, 1, "fc", "no history");
    std.mem.sort(HistoryEntry, entries, {}, lessThanHistoryEntryNumber);

    if (parsed.list) return builtinFcList(self, command, entries, parsed);
    if (parsed.substitute) return builtinFcSubstitute(self, command, entries, parsed, options);
    return builtinFcEdit(self, command, entries, parsed, options);
}

fn parseFcOptions(command: ir.SimpleCommand) FcOptionError!FcOptions {
    var parsed: FcOptions = .{ .first_operand = 1 };
    var index: usize = 1;
    while (index < command.argv.len) {
        const arg = command.argv[index].text;
        if (std.mem.eql(u8, arg, "--")) {
            index += 1;
            break;
        }
        if (arg.len < 2 or arg[0] != '-' or fcLooksLikeRelativeReference(arg)) break;
        index += 1;
        var flag_index: usize = 1;
        while (flag_index < arg.len) : (flag_index += 1) {
            switch (arg[flag_index]) {
                'l' => parsed.list = true,
                'n' => parsed.no_numbers = true,
                'r' => parsed.reverse = true,
                's' => parsed.substitute = true,
                'e' => {
                    if (flag_index + 1 < arg.len) {
                        parsed.editor = arg[flag_index + 1 ..];
                        flag_index = arg.len;
                    } else {
                        if (index >= command.argv.len) return error.MissingEditor;
                        parsed.editor = command.argv[index].text;
                        index += 1;
                    }
                },
                else => return error.UnsupportedOption,
            }
        }
    }
    parsed.first_operand = index;
    return parsed;
}

fn fcOptionErrorResult(self: *Executor, err: FcOptionError) !CommandResult {
    return switch (err) {
        error.MissingEditor => errorResult(self.allocator, 2, "fc", "missing editor"),
        error.UnsupportedOption => errorResult(self.allocator, 2, "fc", "unsupported option"),
    };
}

fn fcLooksLikeRelativeReference(arg: []const u8) bool {
    return arg.len > 1 and arg[0] == '-' and std.ascii.isDigit(arg[1]);
}

fn builtinFcList(self: *Executor, command: ir.SimpleCommand, entries: []HistoryEntry, options: FcOptions) !CommandResult {
    const operands = command.argv[options.first_operand..];
    if (operands.len > 2) return errorResult(self.allocator, 2, "fc", "too many operands");

    const latest = entries[entries.len - 1].number;
    const default_first = @max(entries[0].number, latest - 15);
    const first = resolveFcReference(entries, if (operands.len >= 1) operands[0].text else null, default_first) catch |err| return fcReferenceErrorResult(self, err);
    const last = resolveFcReference(entries, if (operands.len >= 2) operands[1].text else null, latest) catch |err| return fcReferenceErrorResult(self, err);
    return formatFcListing(self.allocator, entries, first, last, options.reverse, options.no_numbers);
}

fn builtinFcSubstitute(self: *Executor, command: ir.SimpleCommand, entries: []HistoryEntry, options: FcOptions, execute_options: ExecuteOptions) !CommandResult {
    var operand_index = options.first_operand;
    var replacement: ?FcReplacement = null;
    if (operand_index < command.argv.len) {
        const operand = command.argv[operand_index].text;
        if (std.mem.indexOfScalar(u8, operand, '=')) |equals| {
            replacement = .{ .old = operand[0..equals], .new = operand[equals + 1 ..] };
            if (replacement.?.old.len == 0) return errorResult(self.allocator, 2, "fc", "empty replacement pattern");
            operand_index += 1;
        }
    }
    if (command.argv.len - operand_index > 1) return errorResult(self.allocator, 2, "fc", "too many operands");

    const latest = entries[entries.len - 1].number;
    const number = resolveFcReference(entries, if (operand_index < command.argv.len) command.argv[operand_index].text else null, latest) catch |err| return fcReferenceErrorResult(self, err);
    const entry = findHistoryEntry(entries, number) orelse return fcReferenceErrorResult(self, error.UnresolvedReference);
    const script = if (replacement) |replace|
        try replaceFirstFcMatch(self.allocator, entry.command, replace.old, replace.new)
    else
        try self.allocator.dupe(u8, entry.command);
    defer self.allocator.free(script);

    return executeFcCommands(self, script, execute_options);
}

const FcReplacement = struct {
    old: []const u8,
    new: []const u8,
};

fn builtinFcEdit(self: *Executor, command: ir.SimpleCommand, entries: []HistoryEntry, options: FcOptions, execute_options: ExecuteOptions) !CommandResult {
    const operands = command.argv[options.first_operand..];
    if (operands.len > 2) return errorResult(self.allocator, 2, "fc", "too many operands");

    const latest = entries[entries.len - 1].number;
    const first = resolveFcReference(entries, if (operands.len >= 1) operands[0].text else null, latest) catch |err| return fcReferenceErrorResult(self, err);
    const last_default = if (operands.len >= 1) first else latest;
    const last = resolveFcReference(entries, if (operands.len >= 2) operands[1].text else null, last_default) catch |err| return fcReferenceErrorResult(self, err);

    var script = try fcRangeScript(self.allocator, entries, first, last, options.reverse);
    defer self.allocator.free(script);

    const editor = options.editor orelse self.getEnv("FCEDIT") orelse self.getEnv("EDITOR") orelse "ed";
    if (!std.mem.eql(u8, editor, "-")) {
        const io = execute_options.io orelse return errorResult(self.allocator, 1, "fc", "editor mode requires io");
        const path = try writeFcEditorTempFile(self, io, script);
        defer self.allocator.free(path);
        defer std.Io.Dir.cwd().deleteFile(io, path) catch {};

        const quoted_path = try singleQuote(self.allocator, path);
        defer self.allocator.free(quoted_path);
        const editor_script = try std.fmt.allocPrint(self.allocator, "{s} {s}", .{ editor, quoted_path });
        defer self.allocator.free(editor_script);

        var editor_options = execute_options;
        editor_options.allow_external = true;
        editor_options.external_stdio = .inherit;
        editor_options.verbose_input_echo = false;
        var editor_result = try self.executeScriptSlice(editor_script, editor_options);
        defer editor_result.deinit();
        if (editor_result.status != 0) {
            return .{
                .allocator = self.allocator,
                .status = editor_result.status,
                .stdout = try self.allocator.dupe(u8, editor_result.stdout),
                .stderr = try self.allocator.dupe(u8, editor_result.stderr),
            };
        }

        const edited = try std.Io.Dir.cwd().readFileAlloc(io, path, self.allocator, .limited(1024 * 1024));
        self.allocator.free(script);
        script = edited;
    }

    return executeFcCommands(self, script, execute_options);
}

fn executeFcCommands(self: *Executor, script: []const u8, options: ExecuteOptions) !CommandResult {
    const history = self.command_history orelse return errorResult(self.allocator, 1, "fc", "history is not available");
    const append = history.append orelse return errorResult(self.allocator, 1, "fc", "history append is not available");
    const io = options.io orelse return errorResult(self.allocator, 1, "fc", "history append requires io");

    var nested_options = options;
    nested_options.verbose_input_echo = false;
    const started_at: i64 = @intCast(nowMs(io) / 1000);
    const started_ms = nowMs(io);
    var result = try self.executeScriptSlice(script, nested_options);
    errdefer result.deinit();
    const duration_ms: i64 = @intCast(nowMs(io) -| started_ms);
    try append(history.context, io, script, result.status, started_at, duration_ms);
    return result;
}

fn resolveFcReference(entries: []const HistoryEntry, maybe_ref: ?[]const u8, default_number: i64) FcReferenceError!i64 {
    if (entries.len == 0) return error.EmptyHistory;
    const ref = maybe_ref orelse return clampHistoryNumber(entries, default_number);
    if (ref.len == 0) return error.InvalidReference;
    if (parseFcNumericReference(ref)) |number| {
        if (number == 0) return error.InvalidReference;
        const absolute = if (number < 0) entries[entries.len - 1].number + 1 + number else number;
        return clampHistoryNumber(entries, absolute);
    } else |_| {
        var index = entries.len;
        while (index > 0) {
            index -= 1;
            if (std.mem.startsWith(u8, entries[index].command, ref)) return entries[index].number;
        }
        return error.UnresolvedReference;
    }
}

fn parseFcNumericReference(ref: []const u8) !i64 {
    var digit_index: usize = 0;
    if (ref[0] == '-' or ref[0] == '+') digit_index = 1;
    if (digit_index == ref.len) return error.InvalidCharacter;
    for (ref[digit_index..]) |byte| if (!std.ascii.isDigit(byte)) return error.InvalidCharacter;
    return std.fmt.parseInt(i64, ref, 10);
}

fn clampHistoryNumber(entries: []const HistoryEntry, number: i64) i64 {
    return @min(@max(number, entries[0].number), entries[entries.len - 1].number);
}

fn fcReferenceErrorResult(self: *Executor, err: FcReferenceError) !CommandResult {
    return switch (err) {
        error.EmptyHistory => errorResult(self.allocator, 1, "fc", "no history"),
        error.InvalidReference => errorResult(self.allocator, 1, "fc", "invalid history reference"),
        error.UnresolvedReference => errorResult(self.allocator, 1, "fc", "history reference not found"),
    };
}

fn formatFcListing(allocator: std.mem.Allocator, entries: []const HistoryEntry, first: i64, last: i64, reverse: bool, no_numbers: bool) !CommandResult {
    var stdout: std.ArrayList(u8) = .empty;
    errdefer stdout.deinit(allocator);

    const low = @min(first, last);
    const high = @max(first, last);
    var ascending = first <= last;
    if (reverse) ascending = !ascending;

    if (ascending) {
        for (entries) |entry| {
            if (entry.number < low or entry.number > high) continue;
            try appendFcListingEntry(allocator, &stdout, entry, no_numbers);
        }
    } else {
        var index = entries.len;
        while (index > 0) {
            index -= 1;
            const entry = entries[index];
            if (entry.number < low or entry.number > high) continue;
            try appendFcListingEntry(allocator, &stdout, entry, no_numbers);
        }
    }

    return .{
        .allocator = allocator,
        .status = 0,
        .stdout = try stdout.toOwnedSlice(allocator),
        .stderr = try allocator.alloc(u8, 0),
    };
}

fn appendFcListingEntry(allocator: std.mem.Allocator, stdout: *std.ArrayList(u8), entry: HistoryEntry, no_numbers: bool) !void {
    const line = if (no_numbers)
        try std.fmt.allocPrint(allocator, "{s}\n", .{entry.command})
    else
        try std.fmt.allocPrint(allocator, "{d}\t{s}\n", .{ entry.number, entry.command });
    defer allocator.free(line);
    try stdout.appendSlice(allocator, line);
}

fn fcRangeScript(allocator: std.mem.Allocator, entries: []const HistoryEntry, first: i64, last: i64, reverse: bool) ![]u8 {
    var script: std.ArrayList(u8) = .empty;
    errdefer script.deinit(allocator);

    const low = @min(first, last);
    const high = @max(first, last);
    var ascending = first <= last;
    if (reverse) ascending = !ascending;

    if (ascending) {
        for (entries) |entry| {
            if (entry.number < low or entry.number > high) continue;
            try appendFcScriptCommand(allocator, &script, entry.command);
        }
    } else {
        var index = entries.len;
        while (index > 0) {
            index -= 1;
            const entry = entries[index];
            if (entry.number < low or entry.number > high) continue;
            try appendFcScriptCommand(allocator, &script, entry.command);
        }
    }

    return script.toOwnedSlice(allocator);
}

fn appendFcScriptCommand(allocator: std.mem.Allocator, script: *std.ArrayList(u8), command: []const u8) !void {
    try script.appendSlice(allocator, command);
    if (command.len == 0 or command[command.len - 1] != '\n') try script.append(allocator, '\n');
}

fn replaceFirstFcMatch(allocator: std.mem.Allocator, command: []const u8, old: []const u8, new: []const u8) ![]u8 {
    const index = std.mem.indexOf(u8, command, old) orelse return allocator.dupe(u8, command);
    var result: std.ArrayList(u8) = .empty;
    errdefer result.deinit(allocator);
    try result.appendSlice(allocator, command[0..index]);
    try result.appendSlice(allocator, new);
    try result.appendSlice(allocator, command[index + old.len ..]);
    return result.toOwnedSlice(allocator);
}

fn writeFcEditorTempFile(self: *Executor, io: std.Io, contents: []const u8) ![]u8 {
    const Counter = struct {
        var value: std.atomic.Value(u64) = .init(0);
    };
    const tmpdir = self.getEnv("TMPDIR") orelse "/tmp";
    var attempts: usize = 0;
    while (attempts < 32) : (attempts += 1) {
        const suffix = Counter.value.fetchAdd(1, .monotonic);
        const path = try std.fmt.allocPrint(self.allocator, "{s}/rush-fc-{d}-{d}.tmp", .{ tmpdir, shellPid(), suffix });
        var file = std.Io.Dir.cwd().createFile(io, path, .{ .truncate = false, .exclusive = true }) catch |err| switch (err) {
            error.PathAlreadyExists => {
                self.allocator.free(path);
                continue;
            },
            else => {
                self.allocator.free(path);
                return err;
            },
        };
        errdefer self.allocator.free(path);
        errdefer std.Io.Dir.cwd().deleteFile(io, path) catch {};
        defer file.close(io);
        try writeBytesToFile(io, file, contents);
        return path;
    }
    return error.PathAlreadyExists;
}

fn findHistoryEntry(entries: []const HistoryEntry, number: i64) ?HistoryEntry {
    for (entries) |entry| if (entry.number == number) return entry;
    return null;
}

fn lessThanHistoryEntryNumber(_: void, lhs: HistoryEntry, rhs: HistoryEntry) bool {
    return lhs.number < rhs.number;
}

fn freeHistoryEntries(allocator: std.mem.Allocator, entries: []HistoryEntry) void {
    for (entries) |entry| allocator.free(entry.command);
    allocator.free(entries);
}

const CommandLookupMode = enum { none, terse, verbose };

fn commandLookupMany(self: *Executor, options: ExecuteOptions, args: []const ir.WordRef, use_default_path: bool, mode: CommandLookupMode) !CommandResult {
    var stdout: std.ArrayList(u8) = .empty;
    errdefer stdout.deinit(self.allocator);

    var stderr: std.ArrayList(u8) = .empty;
    errdefer stderr.deinit(self.allocator);

    var status: ExitStatus = 0;
    for (args) |arg| {
        var result = try commandLookup(self, options, arg.text, use_default_path, mode);
        defer result.deinit();
        try stdout.appendSlice(self.allocator, result.stdout);
        try stderr.appendSlice(self.allocator, result.stderr);
        if (result.status != 0) status = result.status;
    }

    const stdout_slice = try stdout.toOwnedSlice(self.allocator);
    errdefer self.allocator.free(stdout_slice);

    return .{
        .allocator = self.allocator,
        .status = status,
        .stdout = stdout_slice,
        .stderr = try stderr.toOwnedSlice(self.allocator),
    };
}

fn commandLookup(self: *Executor, options: ExecuteOptions, name: []const u8, use_default_path: bool, mode: CommandLookupMode) !CommandResult {
    if (self.aliases.get(name)) |value| {
        if (mode == .terse) {
            const quoted = try singleQuote(self.allocator, value);
            defer self.allocator.free(quoted);
            return stdoutLineFmt(self.allocator, "alias {s}={s}", .{ name, quoted }, 0);
        }
        return stdoutLineFmt(self.allocator, "{s} is an alias for {s}", .{ name, value }, 0);
    }
    if (parser.isAliasReservedWord(name)) {
        return if (mode == .terse)
            stdoutLine(self.allocator, name, 0)
        else
            stdoutLineFmt(self.allocator, "{s} is a shell keyword", .{name}, 0);
    }
    if (self.functions.get(name) != null) {
        return if (mode == .terse)
            stdoutLine(self.allocator, name, 0)
        else
            stdoutLineFmt(self.allocator, "{s} is a function", .{name}, 0);
    }
    if (isSpecialBuiltin(name)) {
        return if (mode == .terse)
            stdoutLine(self.allocator, name, 0)
        else
            stdoutLineFmt(self.allocator, "{s} is a special shell builtin", .{name}, 0);
    }
    if (builtinForName(self.*, name) != null) {
        return if (mode == .terse)
            stdoutLine(self.allocator, name, 0)
        else
            stdoutLineFmt(self.allocator, "{s} is a shell builtin", .{name}, 0);
    }
    if (options.io) |io| {
        const found = if (use_default_path) try self.findExecutableInDefaultPath(io, name) else try self.findExecutableInPath(io, name);
        if (found) |path| {
            defer self.allocator.free(path);
            return if (mode == .terse)
                stdoutLine(self.allocator, path, 0)
            else
                stdoutLineFmt(self.allocator, "{s} is {s}", .{ name, path }, 0);
        }
    }
    // POSIX command: a name that could not be found exits 127; -V also
    // writes a diagnostic while -v stays silent.
    if (mode == .verbose) return errorResult(self.allocator, 127, name, "not found");
    return emptyResult(self.allocator, 127);
}

fn builtinComplete(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    if (options.completion_provider_only) return emptyResult(self.allocator, 0);
    if (command.argv.len < 2) return errorResult(self.allocator, 2, "complete", "missing command name");
    var pattern = try parseCompletionPattern(self.allocator, command.argv[1].text);
    defer pattern.deinit(self.allocator);
    var index: usize = 2;
    var function_name: ?[]const u8 = null;
    var rule: completion.Rule = .{ .root = pattern.root, .path = pattern.path, .kind = .subcommand };
    var rule_set = false;
    while (index < command.argv.len) {
        const option = command.argv[index].text;
        index += 1;
        if (std.mem.eql(u8, option, "--function")) {
            if (index >= command.argv.len) return errorResult(self.allocator, 2, "complete", "missing function name");
            function_name = command.argv[index].text;
            if (rule_set) rule.value = command.argv[index].text;
            index += 1;
        } else if (std.mem.eql(u8, option, "--subcommands")) {
            rule = .{ .root = pattern.root, .path = pattern.path, .kind = .dynamic_subcommands, .value = function_name };
            rule_set = true;
        } else if (std.mem.eql(u8, option, "--options")) {
            rule = .{ .root = pattern.root, .path = pattern.path, .kind = .dynamic_options, .value = function_name };
            rule_set = true;
        } else if (std.mem.eql(u8, option, "--argument")) {
            const argument = rule.argument;
            const value_grammar = rule.value_grammar;
            rule = .{ .root = pattern.root, .path = pattern.path, .kind = .dynamic_argument, .value = function_name };
            rule.argument = argument;
            rule.value_grammar = value_grammar;
            rule_set = true;
        } else if (std.mem.eql(u8, option, "--option-value")) {
            rule = .{ .root = pattern.root, .path = pattern.path, .kind = .dynamic_option_value, .value = function_name };
            rule_set = true;
        } else if (std.mem.eql(u8, option, "--subcommand")) {
            if (index >= command.argv.len) return errorResult(self.allocator, 2, "complete", "missing subcommand name");
            rule = .{ .root = pattern.root, .path = pattern.path, .kind = .subcommand, .value = command.argv[index].text };
            rule_set = true;
            index += 1;
        } else if (std.mem.eql(u8, option, "--option")) {
            rule = .{ .root = pattern.root, .path = pattern.path, .kind = .option };
            rule_set = true;
        } else if (std.mem.eql(u8, option, "--long")) {
            if (index >= command.argv.len) return errorResult(self.allocator, 2, "complete", "missing long option name");
            rule.option.long = command.argv[index].text;
            index += 1;
        } else if (std.mem.eql(u8, option, "--short")) {
            if (index >= command.argv.len) return errorResult(self.allocator, 2, "complete", "missing short option name");
            rule.option.short = command.argv[index].text;
            index += 1;
        } else if (std.mem.eql(u8, option, "--value-name")) {
            if (index >= command.argv.len) return errorResult(self.allocator, 2, "complete", "missing value name");
            rule.option.argument = command.argv[index].text;
            index += 1;
        } else if (std.mem.eql(u8, option, "--exclusive-group")) {
            if (index >= command.argv.len) return errorResult(self.allocator, 2, "complete", "missing exclusive group name");
            rule.option.exclusive_group = command.argv[index].text;
            index += 1;
        } else if (std.mem.eql(u8, option, "--terminates-options")) {
            rule.option.terminates_options = true;
        } else if (std.mem.eql(u8, option, "--index")) {
            if (index >= command.argv.len) return errorResult(self.allocator, 2, "complete", "missing argument index");
            rule.argument.index = std.fmt.parseInt(usize, command.argv[index].text, 10) catch return errorResult(self.allocator, 2, "complete", "invalid argument index");
            index += 1;
        } else if (std.mem.eql(u8, option, "--state")) {
            if (index >= command.argv.len) return errorResult(self.allocator, 2, "complete", "missing argument state");
            rule.argument.state = command.argv[index].text;
            index += 1;
        } else if (std.mem.eql(u8, option, "--after-state")) {
            if (index >= command.argv.len) return errorResult(self.allocator, 2, "complete", "missing previous argument state");
            rule.argument.after_state = command.argv[index].text;
            index += 1;
        } else if (std.mem.eql(u8, option, "--after")) {
            if (index >= command.argv.len) return errorResult(self.allocator, 2, "complete", "missing previous argument value");
            rule.argument.after_value = command.argv[index].text;
            index += 1;
        } else if (std.mem.eql(u8, option, "--repeatable")) {
            if (rule.kind == .option) rule.option.repeatable = true else rule.argument.repeatable = true;
        } else if (std.mem.eql(u8, option, "--list-separator") or std.mem.eql(u8, option, "--value-list-separator")) {
            if (index >= command.argv.len) return errorResult(self.allocator, 2, "complete", "missing list separator");
            rule.value_grammar.list_separator = parseCompletionValueSeparator(command.argv[index].text) orelse return errorResult(self.allocator, 2, "complete", "value separator must be one byte");
            index += 1;
        } else if (std.mem.eql(u8, option, "--key-value-separator") or std.mem.eql(u8, option, "--value-key-value-separator")) {
            if (index >= command.argv.len) return errorResult(self.allocator, 2, "complete", "missing key/value separator");
            rule.value_grammar.key_value_separator = parseCompletionValueSeparator(command.argv[index].text) orelse return errorResult(self.allocator, 2, "complete", "value separator must be one byte");
            index += 1;
        } else if (std.mem.eql(u8, option, "--description")) {
            if (index >= command.argv.len) return errorResult(self.allocator, 2, "complete", "missing description text");
            rule.description = command.argv[index].text;
            index += 1;
        } else if (std.mem.eql(u8, option, "--no-space")) {
            rule.option.no_space = true;
        } else {
            return errorResult(self.allocator, 2, "complete", "unsupported option");
        }
    }
    if (rule_set) {
        if (rule.kind == .option and rule.option.long == null and rule.option.short == null) return errorResult(self.allocator, 2, "complete", "missing option spelling");
        if (rule.kind == .dynamic_option_value and rule.option.long == null and rule.option.short == null) return errorResult(self.allocator, 2, "complete", "missing option spelling");
        if (rule.option.exclusive_group != null and rule.kind != .option) return errorResult(self.allocator, 2, "complete", "exclusive groups require --option");
        if ((rule.option.repeatable or rule.option.terminates_options) and rule.kind != .option) return errorResult(self.allocator, 2, "complete", "option occurrence flags require --option");
        if (rule.argument.hasSelector() and rule.kind != .dynamic_argument) return errorResult(self.allocator, 2, "complete", "argument state options require --argument");
        if ((rule.argument.after_state != null or rule.argument.after_value != null) and rule.argument.state == null) return errorResult(self.allocator, 2, "complete", "argument transitions require --state");
        if (rule.kind == .dynamic_subcommands or rule.kind == .dynamic_options or rule.kind == .dynamic_argument or rule.kind == .dynamic_option_value) {
            if (rule.value == null) return errorResult(self.allocator, 2, "complete", "missing function name");
        }
        try self.registerCompletionRule(rule);
    } else {
        if (function_name != null) return errorResult(self.allocator, 2, "complete", "--function requires --subcommands, --options, --argument, or --option-value");
        return errorResult(self.allocator, 2, "complete", "missing completion rule");
    }
    return emptyResult(self.allocator, 0);
}

fn parseCompletionValueSeparator(separator: []const u8) ?u8 {
    if (separator.len != 1) return null;
    return separator[0];
}

const CompletionPattern = struct {
    root: []const u8,
    path: []const []const u8,

    fn deinit(self: *CompletionPattern, allocator: std.mem.Allocator) void {
        allocator.free(self.root);
        for (self.path) |segment| allocator.free(segment);
        allocator.free(self.path);
        self.* = undefined;
    }
};

fn parseCompletionPattern(allocator: std.mem.Allocator, pattern: []const u8) !CompletionPattern {
    var parsed = try parser.parse(allocator, pattern, .{});
    defer parsed.deinit();
    if (parsed.diagnostics.len != 0) return error.InvalidCompletionPattern;

    var words: std.ArrayList([]const u8) = .empty;
    errdefer {
        for (words.items) |word| allocator.free(word);
        words.deinit(allocator);
    }
    for (parsed.tokens) |token| {
        if (token.kind == .word) try words.append(allocator, try allocator.dupe(u8, token.lexeme(pattern)));
    }
    if (words.items.len == 0) return error.InvalidCompletionPattern;
    const root = words.items[0];
    const path = try allocator.alloc([]const u8, words.items.len - 1);
    @memcpy(path, words.items[1..]);
    words.deinit(allocator);
    return .{ .root = root, .path = path };
}

fn builtinCompletion(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    const builder = if (self.completion_builder) |*builder| builder else return errorResult(self.allocator, 2, "completion", "not completing a command");
    if (command.argv.len < 2) return errorResult(self.allocator, 2, "completion", "missing subcommand");
    const subcommand = command.argv[1].text;
    if (std.mem.eql(u8, subcommand, "prefix")) return completionContextLine(self, subcommand, completionContextValue(self.*, .prefix));
    if (std.mem.eql(u8, subcommand, "command")) return completionContextLine(self, subcommand, completionContextValue(self.*, .command));
    if (std.mem.eql(u8, subcommand, "command-path")) return completionContextLine(self, subcommand, completionContextValue(self.*, .command_path));
    if (std.mem.eql(u8, subcommand, "argument-index")) {
        const context = self.completion_context orelse return errorResult(self.allocator, 2, "completion", "missing completion context");
        const text = try std.fmt.allocPrint(self.allocator, "{d}\n", .{context.argument_index});
        return .{ .allocator = self.allocator, .status = 0, .stdout = text, .stderr = try self.allocator.alloc(u8, 0) };
    }
    if (std.mem.eql(u8, subcommand, "operand-index")) {
        const context = self.completion_context orelse return errorResult(self.allocator, 2, "completion", "missing completion context");
        const text = try std.fmt.allocPrint(self.allocator, "{d}\n", .{context.argument_index});
        return .{ .allocator = self.allocator, .status = 0, .stdout = text, .stderr = try self.allocator.alloc(u8, 0) };
    }
    if (std.mem.eql(u8, subcommand, "argument-state")) {
        const context = self.completion_context orelse return errorResult(self.allocator, 2, "completion", "missing completion context");
        return stdoutLine(self.allocator, context.argument_state orelse "", 0);
    }
    if (std.mem.eql(u8, subcommand, "operand-state")) {
        const context = self.completion_context orelse return errorResult(self.allocator, 2, "completion", "missing completion context");
        return stdoutLine(self.allocator, context.argument_state orelse "", 0);
    }
    if (std.mem.eql(u8, subcommand, "option-present")) return builtinCompletionOptionPresent(self, command);
    if (std.mem.eql(u8, subcommand, "option-values")) return builtinCompletionOptionValues(self, command);
    if (std.mem.eql(u8, subcommand, "operands")) return builtinCompletionOperands(self, command);
    if (std.mem.eql(u8, subcommand, "operand")) return builtinCompletionOperand(self, command);
    if (std.mem.eql(u8, subcommand, "options-terminated")) {
        if (command.argv.len != 2) return errorResult(self.allocator, 2, "completion", "unsupported context option");
        const context = self.completion_context orelse return errorResult(self.allocator, 2, "completion", "missing completion context");
        return stdoutLine(self.allocator, if (context.options_terminated) "true" else "false", 0);
    }
    if (std.mem.eql(u8, subcommand, "previous")) return completionContextLine(self, subcommand, completionContextValue(self.*, .previous));
    if (std.mem.eql(u8, subcommand, "position")) {
        const context = self.completion_context orelse return errorResult(self.allocator, 2, "completion", "missing completion context");
        return stdoutLine(self.allocator, if (context.option_value != null) "option_value" else @tagName(context.position), 0);
    }
    if (std.mem.eql(u8, subcommand, "option-name")) return completionOptionContextLine(self, subcommand, .name);
    if (std.mem.eql(u8, subcommand, "option-spelling")) return completionOptionContextLine(self, subcommand, .spelling);
    if (std.mem.eql(u8, subcommand, "value-segment")) return completionValueSegmentContextLine(self, subcommand, .segment);
    if (std.mem.eql(u8, subcommand, "value-separator")) return completionValueSegmentContextLine(self, subcommand, .separator);
    if (std.mem.eql(u8, subcommand, "value-position")) return completionValueSegmentContextLine(self, subcommand, .position);
    if (std.mem.eql(u8, subcommand, "value-key")) return completionValueSegmentContextLine(self, subcommand, .key);
    if (std.mem.eql(u8, subcommand, "files")) return builtinCompletionFiles(self, builder, command, options, false);
    if (std.mem.eql(u8, subcommand, "directories")) return builtinCompletionFiles(self, builder, command, options, true);
    if (std.mem.eql(u8, subcommand, "executables")) return builtinCompletionExecutables(self, builder, command, options);
    if (std.mem.eql(u8, subcommand, "variables")) return builtinCompletionVariables(self, builder, command);
    if (std.mem.eql(u8, subcommand, "option")) return builtinCompletionOption(self, builder, command);
    if (std.mem.eql(u8, subcommand, "candidates")) return builtinCompletionCandidates(self, builder, command, stdin);
    if (!std.mem.eql(u8, subcommand, "candidate")) return errorResult(self.allocator, 2, "completion", "unsupported subcommand");

    var candidate: completion.Candidate = .{ .value = "", .replace_start = 0, .replace_end = 0 };
    var value_set = false;
    var index: usize = 2;
    while (index < command.argv.len) {
        const arg = command.argv[index].text;
        index += 1;
        if (std.mem.eql(u8, arg, "--display")) {
            if (index >= command.argv.len) return errorResult(self.allocator, 2, "completion", "missing display text");
            candidate.display = command.argv[index].text;
            index += 1;
        } else if (std.mem.eql(u8, arg, "--description")) {
            if (index >= command.argv.len) return errorResult(self.allocator, 2, "completion", "missing description text");
            candidate.description = command.argv[index].text;
            index += 1;
        } else if (std.mem.eql(u8, arg, "--kind")) {
            if (index >= command.argv.len) return errorResult(self.allocator, 2, "completion", "missing kind");
            candidate.kind = parseCompletionKind(command.argv[index].text) orelse return errorResult(self.allocator, 2, "completion", "unsupported kind");
            index += 1;
        } else if (std.mem.eql(u8, arg, "--no-space")) {
            candidate.append_space = false;
        } else if (std.mem.startsWith(u8, arg, "--")) {
            return errorResult(self.allocator, 2, "completion", "unsupported candidate option");
        } else if (!value_set) {
            candidate.value = arg;
            value_set = true;
        } else {
            return errorResult(self.allocator, 2, "completion", "too many arguments");
        }
    }
    if (!value_set) return errorResult(self.allocator, 2, "completion", "missing candidate value");
    try builder.appendCandidate(self.allocator, candidate);
    return emptyResult(self.allocator, 0);
}

const CompletionOptionSelector = struct {
    kind: enum { long, short },
    name: []const u8,
};

fn builtinCompletionOptionPresent(self: *Executor, command: ir.SimpleCommand) !CommandResult {
    const context = self.completion_context orelse return errorResult(self.allocator, 2, "completion", "missing completion context");
    const selector = completionOptionSelectorFromCommand(command, 2) catch |err| return completionOptionSelectorErrorResult(self, err);
    const present = completionParsedOptionMatchesSelector(self.*, context, selector) != null;
    return stdoutLine(self.allocator, if (present) "true" else "false", if (present) 0 else 1);
}

fn builtinCompletionOptionValues(self: *Executor, command: ir.SimpleCommand) !CommandResult {
    const context = self.completion_context orelse return errorResult(self.allocator, 2, "completion", "missing completion context");
    const selector = completionOptionSelectorFromCommand(command, 2) catch |err| return completionOptionSelectorErrorResult(self, err);
    const selector_key = completionOptionSelectorKey(self.*, context, selector);

    var out: std.Io.Writer.Allocating = .init(self.allocator);
    errdefer out.deinit();
    for (context.parsed_options) |option| {
        if (!completionParsedOptionMatchesSelectorKey(option, selector, selector_key)) continue;
        const value = option.value orelse continue;
        try out.writer.print("{s}\n", .{value});
    }
    return .{ .allocator = self.allocator, .status = 0, .stdout = try out.toOwnedSlice(), .stderr = try self.allocator.alloc(u8, 0) };
}

fn builtinCompletionOperands(self: *Executor, command: ir.SimpleCommand) !CommandResult {
    if (command.argv.len != 2) return errorResult(self.allocator, 2, "completion", "unsupported context option");
    const context = self.completion_context orelse return errorResult(self.allocator, 2, "completion", "missing completion context");

    var out: std.Io.Writer.Allocating = .init(self.allocator);
    errdefer out.deinit();
    for (context.operands) |operand| try out.writer.print("{s}\n", .{operand.value});
    return .{ .allocator = self.allocator, .status = 0, .stdout = try out.toOwnedSlice(), .stderr = try self.allocator.alloc(u8, 0) };
}

fn builtinCompletionOperand(self: *Executor, command: ir.SimpleCommand) !CommandResult {
    if (command.argv.len != 3) return errorResult(self.allocator, 2, "completion", "missing operand index");
    const context = self.completion_context orelse return errorResult(self.allocator, 2, "completion", "missing completion context");
    const requested = std.fmt.parseInt(usize, command.argv[2].text, 10) catch return errorResult(self.allocator, 2, "completion", "invalid operand index");
    for (context.operands) |operand| {
        if (operand.index == requested) return stdoutLine(self.allocator, operand.value, 0);
    }
    return stdoutLine(self.allocator, "", 0);
}

fn completionOptionSelectorFromCommand(command: ir.SimpleCommand, start: usize) !CompletionOptionSelector {
    if (command.argv.len != start + 2) return error.InvalidCompletionOptionSelector;
    const flag = command.argv[start].text;
    const name = command.argv[start + 1].text;
    if (name.len == 0) return error.InvalidCompletionOptionSelector;
    if (std.mem.eql(u8, flag, "--long")) return .{ .kind = .long, .name = name };
    if (std.mem.eql(u8, flag, "--short")) return .{ .kind = .short, .name = name };
    return error.InvalidCompletionOptionSelector;
}

fn completionOptionSelectorErrorResult(self: *Executor, err: anyerror) !CommandResult {
    return switch (err) {
        error.InvalidCompletionOptionSelector => errorResult(self.allocator, 2, "completion", "expected --long NAME or --short C"),
        else => err,
    };
}

fn completionParsedOptionMatchesSelector(self: Executor, context: CompletionEvalContext, selector: CompletionOptionSelector) ?CompletionParsedOption {
    const selector_key = completionOptionSelectorKey(self, context, selector);
    for (context.parsed_options) |option| {
        if (completionParsedOptionMatchesSelectorKey(option, selector, selector_key)) return option;
    }
    return null;
}

fn completionParsedOptionMatchesSelectorKey(option: CompletionParsedOption, selector: CompletionOptionSelector, selector_key: []const u8) bool {
    if (std.mem.eql(u8, option.key, selector_key)) return true;
    return switch (selector.kind) {
        .long => std.mem.eql(u8, option.name, selector.name) and std.mem.startsWith(u8, option.spelling, "--"),
        .short => std.mem.eql(u8, option.name, selector.name) and std.mem.startsWith(u8, option.spelling, "-"),
    };
}

fn completionOptionSelectorKey(self: Executor, context: CompletionEvalContext, selector: CompletionOptionSelector) []const u8 {
    for (self.completion_rules.items) |rule| {
        if (rule.kind != .option and rule.kind != .dynamic_option_value) continue;
        if (!std.mem.eql(u8, rule.root, context.command)) continue;
        if (!completionEvalRuleAppliesToPath(rule, context.command_path)) continue;
        switch (selector.kind) {
            .long => if (rule.option.long) |long| if (std.mem.eql(u8, long, selector.name)) return completionOptionKey(rule.option) orelse selector.name,
            .short => if (rule.option.short) |short| if (std.mem.eql(u8, short, selector.name)) return completionOptionKey(rule.option) orelse selector.name,
        }
    }
    return selector.name;
}

fn completionEvalRuleAppliesToPath(rule: completion.Rule, command_path: []const u8) bool {
    if (rule.path.len == 0) return true;
    const path_start = if (std.mem.indexOfScalar(u8, command_path, ' ')) |space| space + 1 else return false;
    var segments = std.mem.splitScalar(u8, command_path[path_start..], ' ');
    for (rule.path) |expected| {
        const actual = segments.next() orelse return false;
        if (!std.mem.eql(u8, expected, actual)) return false;
    }
    return true;
}

fn builtinCompletionCandidates(self: *Executor, builder: *CompletionBuilder, command: ir.SimpleCommand, stdin: []const u8) !CommandResult {
    var candidate: completion.Candidate = .{ .value = "", .replace_start = 0, .replace_end = 0 };
    var index: usize = 2;
    while (index < command.argv.len) {
        const arg = command.argv[index].text;
        index += 1;
        if (std.mem.eql(u8, arg, "--description")) {
            if (index >= command.argv.len) return errorResult(self.allocator, 2, "completion", "missing description text");
            candidate.description = command.argv[index].text;
            index += 1;
        } else if (std.mem.eql(u8, arg, "--kind")) {
            if (index >= command.argv.len) return errorResult(self.allocator, 2, "completion", "missing kind");
            candidate.kind = parseCompletionKind(command.argv[index].text) orelse return errorResult(self.allocator, 2, "completion", "unsupported kind");
            index += 1;
        } else if (std.mem.eql(u8, arg, "--no-space")) {
            candidate.append_space = false;
        } else if (std.mem.startsWith(u8, arg, "--")) {
            return errorResult(self.allocator, 2, "completion", "unsupported candidates option");
        } else {
            return errorResult(self.allocator, 2, "completion", "too many arguments");
        }
    }

    var lines = std.mem.splitScalar(u8, stdin, '\n');
    while (lines.next()) |raw_line| {
        const value = if (std.mem.endsWith(u8, raw_line, "\r")) raw_line[0 .. raw_line.len - 1] else raw_line;
        if (value.len == 0) continue;
        candidate.value = value;
        try builder.appendCandidate(self.allocator, candidate);
    }
    return emptyResult(self.allocator, 0);
}

fn builtinCompletionOption(self: *Executor, builder: *CompletionBuilder, command: ir.SimpleCommand) !CommandResult {
    var option: completion.Option = .{};
    var description: ?[]const u8 = null;
    var index: usize = 2;
    while (index < command.argv.len) {
        const arg = command.argv[index].text;
        index += 1;
        if (std.mem.eql(u8, arg, "--long")) {
            if (index >= command.argv.len) return errorResult(self.allocator, 2, "completion", "missing long option name");
            option.long = command.argv[index].text;
            index += 1;
        } else if (std.mem.eql(u8, arg, "--short")) {
            if (index >= command.argv.len) return errorResult(self.allocator, 2, "completion", "missing short option name");
            option.short = command.argv[index].text;
            index += 1;
        } else if (std.mem.eql(u8, arg, "--argument")) {
            if (index >= command.argv.len) return errorResult(self.allocator, 2, "completion", "missing argument name");
            option.argument = command.argv[index].text;
            index += 1;
        } else if (std.mem.eql(u8, arg, "--exclusive-group")) {
            if (index >= command.argv.len) return errorResult(self.allocator, 2, "completion", "missing exclusive group name");
            option.exclusive_group = command.argv[index].text;
            index += 1;
        } else if (std.mem.eql(u8, arg, "--repeatable")) {
            option.repeatable = true;
        } else if (std.mem.eql(u8, arg, "--terminates-options")) {
            option.terminates_options = true;
        } else if (std.mem.eql(u8, arg, "--description")) {
            if (index >= command.argv.len) return errorResult(self.allocator, 2, "completion", "missing description text");
            description = command.argv[index].text;
            index += 1;
        } else {
            return errorResult(self.allocator, 2, "completion", "unsupported option declaration flag");
        }
    }

    if (option.long == null and option.short == null) return errorResult(self.allocator, 2, "completion", "missing option spelling");
    if (updateCompletionOptionValueContext(self, option)) return emptyResult(self.allocator, 0);
    if (option.long) |long| {
        const value = try std.mem.concat(self.allocator, u8, &.{ "--", long });
        defer self.allocator.free(value);
        try builder.appendCandidate(self.allocator, .{ .value = value, .description = description, .kind = .option, .option = option, .replace_start = 0, .replace_end = 0 });
    }
    if (option.short) |short| {
        const value = try std.mem.concat(self.allocator, u8, &.{ "-", short });
        defer self.allocator.free(value);
        try builder.appendCandidate(self.allocator, .{ .value = value, .description = description, .kind = .option, .option = option, .replace_start = 0, .replace_end = 0 });
    }
    return emptyResult(self.allocator, 0);
}

const CompletionContextField = enum { prefix, command, command_path, previous };

fn setCompletionContextVariables(self: *Executor, context: CompletionEvalContext) !void {
    var argument_index_buffer: [64]u8 = undefined;
    const argument_index = try std.fmt.bufPrint(&argument_index_buffer, "{d}", .{context.argument_index});
    try self.setEnv("rush_completion_prefix", context.prefix);
    try self.setEnv("rush_completion_command", context.command);
    try self.setEnv("rush_completion_command_path", if (context.command_path.len != 0) context.command_path else context.command);
    try self.setEnv("rush_completion_previous", context.previous);
    try self.setEnv("rush_completion_position", if (context.option_value != null) "option_value" else @tagName(context.position));
    try self.setEnv("rush_completion_argument_index", argument_index);
    try self.setEnv("rush_completion_operand_index", argument_index);
    try self.setEnv("rush_completion_argument_state", context.argument_state orelse "");
    try self.setEnv("rush_completion_operand_state", context.argument_state orelse "");
    try self.setEnv("rush_completion_options_terminated", if (context.options_terminated) "true" else "false");
    if (context.option_value) |option_value| {
        try self.setEnv("rush_completion_option_name", option_value.name);
        try self.setEnv("rush_completion_option_spelling", option_value.spelling);
    } else {
        try self.setEnv("rush_completion_option_name", "");
        try self.setEnv("rush_completion_option_spelling", "");
    }
    if (context.value_segment) |segment| {
        var separator_buffer: [1]u8 = undefined;
        const separator = if (segment.activeSeparator()) |value| separator: {
            separator_buffer[0] = value;
            break :separator separator_buffer[0..];
        } else "";
        try self.setEnv("rush_completion_value_segment", segment.segment);
        try self.setEnv("rush_completion_value_separator", separator);
        try self.setEnv("rush_completion_value_position", @tagName(segment.position));
        try self.setEnv("rush_completion_value_key", segment.key);
    } else {
        try self.setEnv("rush_completion_value_segment", "");
        try self.setEnv("rush_completion_value_separator", "");
        try self.setEnv("rush_completion_value_position", "");
        try self.setEnv("rush_completion_value_key", "");
    }
}

fn completionContextValue(self: Executor, field: CompletionContextField) ?[]const u8 {
    const context = self.completion_context orelse return null;
    return switch (field) {
        .prefix => context.prefix,
        .command => context.command,
        .command_path => if (context.command_path.len != 0) context.command_path else context.command,
        .previous => context.previous,
    };
}

fn completionContextLine(self: *Executor, name: []const u8, value: ?[]const u8) !CommandResult {
    _ = name;
    return stdoutLine(self.allocator, value orelse return errorResult(self.allocator, 2, "completion", "missing completion context"), 0);
}

fn completionOptionContextLine(self: *Executor, name: []const u8, field: enum { name, spelling }) !CommandResult {
    _ = name;
    const context = self.completion_context orelse return errorResult(self.allocator, 2, "completion", "missing completion context");
    const option_value = context.option_value orelse return errorResult(self.allocator, 2, "completion", "missing active option");
    return stdoutLine(self.allocator, switch (field) {
        .name => option_value.name,
        .spelling => option_value.spelling,
    }, 0);
}

fn completionValueSegmentContextLine(self: *Executor, name: []const u8, field: enum { segment, separator, position, key }) !CommandResult {
    _ = name;
    const context = self.completion_context orelse return errorResult(self.allocator, 2, "completion", "missing completion context");
    const segment = context.value_segment orelse return errorResult(self.allocator, 2, "completion", "missing active value segment");
    return switch (field) {
        .segment => stdoutLine(self.allocator, segment.segment, 0),
        .separator => if (segment.activeSeparator()) |separator| stdoutLineFmt(self.allocator, "{c}", .{separator}, 0) else stdoutLine(self.allocator, "", 0),
        .position => stdoutLine(self.allocator, @tagName(segment.position), 0),
        .key => stdoutLine(self.allocator, segment.key, 0),
    };
}

fn updateCompletionOptionValueContext(self: *Executor, option: completion.Option) bool {
    if (option.argument == null) return false;
    var context = self.completion_context orelse return false;
    if (context.option_value != null) return true;

    if (option.long) |long| {
        var attached_prefix_buffer: [256]u8 = undefined;
        const attached_prefix = std.fmt.bufPrint(&attached_prefix_buffer, "--{s}=", .{long}) catch return false;
        if (std.mem.startsWith(u8, context.prefix, attached_prefix)) {
            const value_start = context.replace_start + attached_prefix.len;
            const spelling = context.prefix[0 .. attached_prefix.len - 1];
            context.option_value = .{ .name = spelling[2..], .spelling = spelling };
            context.prefix = context.prefix[attached_prefix.len..];
            context.replace_start = value_start;
            self.completion_context = context;
            return true;
        }

        var spelling_buffer: [256]u8 = undefined;
        const spelling = std.fmt.bufPrint(&spelling_buffer, "--{s}", .{long}) catch return false;
        if (std.mem.eql(u8, context.previous, spelling)) {
            context.option_value = .{ .name = context.previous[2..], .spelling = context.previous };
            self.completion_context = context;
            return true;
        }
    }
    if (option.short) |short| {
        var spelling_buffer: [16]u8 = undefined;
        const spelling = std.fmt.bufPrint(&spelling_buffer, "-{s}", .{short}) catch return false;
        if (std.mem.eql(u8, context.previous, spelling)) {
            context.option_value = .{ .name = context.previous[1..], .spelling = context.previous };
            self.completion_context = context;
            return true;
        }
    }
    return false;
}

fn completionPrefixOption(self: *Executor, command: ir.SimpleCommand, start: usize) ![]const u8 {
    var prefix: ?[]const u8 = null;
    var index = start;
    while (index < command.argv.len) {
        const option = command.argv[index].text;
        index += 1;
        if (std.mem.eql(u8, option, "--prefix")) {
            if (index >= command.argv.len) return error.MissingCompletionPrefix;
            prefix = command.argv[index].text;
            index += 1;
        } else {
            return error.UnsupportedCompletionOption;
        }
    }
    if (prefix) |value| return value;
    const context = self.completion_context orelse return "";
    return context.prefix;
}

fn builtinCompletionFiles(self: *Executor, builder: *CompletionBuilder, command: ir.SimpleCommand, options: ExecuteOptions, directories_only: bool) !CommandResult {
    const io = options.io orelse return error.MissingIoForBuiltin;
    var append_slash = false;
    var extension: ?[]const u8 = null;
    var prefix: ?[]const u8 = null;
    var index: usize = 2;
    while (index < command.argv.len) {
        const option = command.argv[index].text;
        index += 1;
        if (std.mem.eql(u8, option, "--prefix")) {
            if (index >= command.argv.len) return errorResult(self.allocator, 2, "completion", "missing prefix");
            prefix = command.argv[index].text;
            index += 1;
        } else if (std.mem.eql(u8, option, "--extension") and !directories_only) {
            if (index >= command.argv.len) return errorResult(self.allocator, 2, "completion", "missing extension");
            extension = command.argv[index].text;
            index += 1;
        } else if (std.mem.eql(u8, option, "--append-slash") and directories_only) {
            append_slash = true;
        } else {
            return errorResult(self.allocator, 2, "completion", "unsupported helper option");
        }
    }
    const effective_prefix = prefix orelse if (self.completion_context) |context| context.prefix else "";
    const replace_start: usize = if (prefix == null) if (self.completion_context) |context| context.replace_start else 0 else 0;
    const replace_end: usize = if (prefix == null) if (self.completion_context) |context| context.replace_end else effective_prefix.len else effective_prefix.len;
    try appendPathCandidates(self, builder, io, effective_prefix, replace_start, replace_end, extension, directories_only, append_slash);
    return emptyResult(self.allocator, 0);
}

fn appendPathCandidates(self: *Executor, builder: *CompletionBuilder, io: std.Io, prefix: []const u8, replace_start: usize, replace_end: usize, extension: ?[]const u8, directories_only: bool, append_slash: bool) !void {
    _ = append_slash;
    const split = try splitCompletionPathPrefix(self.allocator, prefix);
    defer split.deinit(self.allocator);
    const candidate_replace_start = replace_start + split.raw_display_prefix_len;
    var dir = try std.Io.Dir.cwd().openDir(io, split.directory, .{ .iterate = true });
    defer dir.close(io);
    var iterator = dir.iterate();
    while (try iterator.next(io)) |entry| {
        if (entry.name.len == 0) continue;
        if (entry.name[0] == '.' and (split.base.len == 0 or split.base[0] != '.')) continue;
        if (completion.fuzzyMatchRank(entry.name, split.base) == null) continue;
        const is_directory = entry.kind == .directory;
        if (directories_only and !is_directory) continue;
        if (extension) |ext| {
            if (!std.mem.endsWith(u8, entry.name, ext)) continue;
        }
        const value = if (is_directory) value: {
            const slash = if (is_directory) "/" else "";
            break :value try std.mem.concat(self.allocator, u8, &.{ entry.name, slash });
        } else entry.name;
        defer if (value.ptr != entry.name.ptr) self.allocator.free(value);
        try builder.appendCandidate(self.allocator, .{
            .value = value,
            .kind = if (is_directory) .directory else .file,
            .replace_start = candidate_replace_start,
            .replace_end = replace_end,
            .append_space = !is_directory,
        });
    }
}

const CompletionPathPrefix = struct {
    directory: []const u8,
    raw_display_prefix_len: usize,
    base: []const u8,

    fn deinit(self: CompletionPathPrefix, allocator: std.mem.Allocator) void {
        allocator.free(self.directory);
        allocator.free(self.base);
    }
};

fn splitCompletionPathPrefix(allocator: std.mem.Allocator, prefix: []const u8) !CompletionPathPrefix {
    const slash_index = std.mem.lastIndexOfScalar(u8, prefix, '/') orelse {
        const directory = try allocator.dupe(u8, ".");
        errdefer allocator.free(directory);
        const base = try completion.decodeShellWordForCompletion(allocator, prefix);
        return .{ .directory = directory, .raw_display_prefix_len = 0, .base = base };
    };
    const display_prefix = prefix[0 .. slash_index + 1];
    const decoded_directory = if (display_prefix.len == 0) try allocator.dupe(u8, "/") else try completion.decodeShellWordForCompletion(allocator, display_prefix);
    errdefer allocator.free(decoded_directory);
    const base = try completion.decodeShellWordForCompletion(allocator, prefix[slash_index + 1 ..]);
    return .{ .directory = decoded_directory, .raw_display_prefix_len = display_prefix.len, .base = base };
}

fn builtinCompletionVariables(self: *Executor, builder: *CompletionBuilder, command: ir.SimpleCommand) !CommandResult {
    const prefix = completionPrefixOption(self, command, 2) catch |err| switch (err) {
        error.MissingCompletionPrefix => return errorResult(self.allocator, 2, "completion", "missing prefix"),
        error.UnsupportedCompletionOption => return errorResult(self.allocator, 2, "completion", "unsupported helper option"),
        else => |e| return e,
    };
    var iter = self.env.iterator();
    while (iter.next()) |entry| {
        if (completion.fuzzyMatchRank(entry.key_ptr.*, prefix) != null) {
            try builder.appendCandidate(self.allocator, .{ .value = entry.key_ptr.*, .kind = .variable, .replace_start = completionHelperReplaceStart(self.*, prefix), .replace_end = completionHelperReplaceEnd(self.*, prefix) });
        }
    }
    return emptyResult(self.allocator, 0);
}

fn builtinCompletionExecutables(self: *Executor, builder: *CompletionBuilder, command: ir.SimpleCommand, options: ExecuteOptions) !CommandResult {
    const io = options.io orelse return error.MissingIoForBuiltin;
    const prefix = completionPrefixOption(self, command, 2) catch |err| switch (err) {
        error.MissingCompletionPrefix => return errorResult(self.allocator, 2, "completion", "missing prefix"),
        error.UnsupportedCompletionOption => return errorResult(self.allocator, 2, "completion", "unsupported helper option"),
        else => |e| return e,
    };
    const path = self.getEnv("PATH") orelse return emptyResult(self.allocator, 0);
    var path_iter = std.mem.splitScalar(u8, path, ':');
    while (path_iter.next()) |path_dir| {
        if (path_dir.len == 0) continue;
        var dir = std.Io.Dir.cwd().openDir(io, path_dir, .{ .iterate = true }) catch continue;
        errdefer dir.close(io);
        var iterator = dir.iterate();
        while (iterator.next(io) catch null) |entry| {
            if (completion.fuzzyMatchRank(entry.name, prefix) != null) {
                try builder.appendCandidate(self.allocator, .{ .value = entry.name, .kind = .command, .replace_start = completionHelperReplaceStart(self.*, prefix), .replace_end = completionHelperReplaceEnd(self.*, prefix) });
            }
        }
        dir.close(io);
    }
    return emptyResult(self.allocator, 0);
}

fn completionHelperReplaceStart(self: Executor, prefix: []const u8) usize {
    const context = self.completion_context orelse return 0;
    if (!std.mem.eql(u8, context.prefix, prefix)) return 0;
    return context.replace_start;
}

fn completionHelperReplaceEnd(self: Executor, prefix: []const u8) usize {
    const context = self.completion_context orelse return prefix.len;
    if (!std.mem.eql(u8, context.prefix, prefix)) return prefix.len;
    return context.replace_end;
}

fn parseCompletionKind(name: []const u8) ?completion.Kind {
    inline for (@typeInfo(completion.Kind).@"enum".fields) |field| {
        if (std.mem.eql(u8, name, field.name)) return @enumFromInt(field.value);
    }
    return null;
}

pub fn completionEvalContextForInput(allocator: std.mem.Allocator, source: []const u8, cursor: usize) !CompletionEvalContext {
    const view = try completionInputView(allocator, source, cursor);
    var parsed = try parser.parse(allocator, view.source, .{ .mode = .interactive, .cursor = view.cursor });
    defer parsed.deinit();
    const context = parser.completionContext(parsed, view.cursor);
    const prefix = completionContextPrefix(view.source, context);
    const current_token_index = context.token_index;

    var command: []const u8 = "";
    var previous: []const u8 = "";
    var argument_index: usize = 0;
    var words_seen: usize = 0;
    var words: std.ArrayList(CompletionWord) = .empty;
    defer words.deinit(allocator);
    try appendActiveCompletionWords(allocator, &words, parsed, context);
    for (words.items) |word_token| {
        const token = word_token.token;
        const is_current_token = word_token.index == current_token_index and context.cursor <= token.span.end;
        const word = token.lexeme(view.source);
        if (words_seen == 0) {
            command = word;
        } else {
            argument_index = words_seen;
        }
        if (!is_current_token and token.span.end <= context.cursor) previous = word;
        words_seen += 1;
    }

    return .{
        .prefix = prefix,
        .command = command,
        .argument_index = argument_index,
        .previous = previous,
        .position = context.kind,
        .replace_start = view.offset + context.span.start,
        .replace_end = view.offset + @min(context.cursor, context.span.end),
    };
}

const CompletionInputView = struct {
    source: []const u8,
    cursor: usize,
    offset: usize,
};

const CompletionWord = struct {
    index: usize,
    token: parser.Token,
};

const TokenRange = struct {
    start: usize,
    end: usize,
};

fn completionInputView(allocator: std.mem.Allocator, source: []const u8, cursor: usize) !CompletionInputView {
    const clamped_cursor = @min(cursor, source.len);
    if (try commandSubstitutionCompletionValueSpan(allocator, source, clamped_cursor)) |span| {
        return .{
            .source = source[span.start..span.end],
            .cursor = clamped_cursor - span.start,
            .offset = span.start,
        };
    }
    return .{ .source = source, .cursor = clamped_cursor, .offset = 0 };
}

fn commandSubstitutionCompletionValueSpan(allocator: std.mem.Allocator, source: []const u8, cursor: usize) !?parser.Span {
    var best: ?parser.Span = null;
    var index: usize = 0;
    var single = false;
    var double = false;
    while (index < cursor) : (index += 1) {
        const byte = source[index];
        if (byte == '\\' and !single) {
            if (index + 1 < cursor) index += 1;
            continue;
        }
        if (byte == '\'' and !double) {
            single = !single;
            continue;
        }
        if (byte == '"' and !single) {
            double = !double;
            continue;
        }
        if (single or byte != '$' or index + 1 >= source.len or source[index + 1] != '(') continue;
        if (index + 2 < source.len and source[index + 2] == '(') continue;

        const value_start = index + 2;
        if (cursor < value_start) continue;
        if (try parser.commandSubstitutionEnd(allocator, source, source.len, index)) |end| {
            const value_end = end - 1;
            if (cursor <= value_end) best = .init(value_start, value_end);
        } else {
            best = .init(value_start, source.len);
        }
    }
    return best;
}

fn appendActiveCompletionWords(allocator: std.mem.Allocator, words: *std.ArrayList(CompletionWord), parsed: parser.ParseResult, context: parser.CompletionContext) !void {
    const range = activeSimpleCommandTokenRange(parsed, context) orelse return;
    for (range.start..range.end) |index| {
        const token = parsed.tokens[index];
        if (token.span.start > context.cursor) break;
        if (token.kind != .word) continue;
        const node_kind = parser.nodeKindForToken(parsed, index) orelse continue;
        switch (node_kind) {
            .command_word, .word => {},
            .assignment_word, .io_number => continue,
            else => continue,
        }
        if (parser.tokenHasNodeKind(parsed, index, .redirection)) continue;
        try words.append(allocator, .{ .index = index, .token = token });
    }
}

fn activeSimpleCommandTokenRange(parsed: parser.ParseResult, context: parser.CompletionContext) ?TokenRange {
    if (context.token_index) |token_index| {
        if (simpleCommandNodeForToken(parsed, token_index)) |node| {
            return .{ .start = node.token_start, .end = node.token_end };
        }
    }

    var best: ?parser.Node = null;
    for (parsed.nodes) |node| {
        if (node.kind != .simple_command) continue;
        if (!node.span.touches(context.cursor)) continue;
        if (best == null or node.span.len() < best.?.span.len()) best = node;
    }
    if (best) |node| return .{ .start = node.token_start, .end = node.token_end };
    return null;
}

fn simpleCommandNodeForToken(parsed: parser.ParseResult, token_index: usize) ?parser.Node {
    var best: ?parser.Node = null;
    for (parsed.nodes) |node| {
        if (node.kind != .simple_command) continue;
        if (token_index < node.token_start or token_index >= node.token_end) continue;
        if (best == null or node.span.len() < best.?.span.len()) best = node;
    }
    return best;
}

fn completionPositionForParserContext(context: parser.CompletionContext, prefix: []const u8) CompletionSemanticPosition {
    return switch (context.kind) {
        .command, .assignment_name => .command,
        .redirect_target => .redirect_target,
        .argument, .assignment_value, .quoted_string => if (std.mem.startsWith(u8, prefix, "-")) .option else .argument,
        .parameter, .separator => .argument,
    };
}

fn completionContextPrefix(source: []const u8, context: parser.CompletionContext) []const u8 {
    const start = context.span.start;
    const end = @min(context.cursor, context.span.end);
    if (start >= end or end > source.len) return "";
    return source[start..end];
}

fn builtinEval(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    var script: std.ArrayList(u8) = .empty;
    defer script.deinit(self.allocator);
    for (command.argv[1..], 0..) |arg, index| {
        if (index > 0) try script.append(self.allocator, ' ');
        try script.appendSlice(self.allocator, arg.text);
    }
    return self.executeScriptSlice(script.items, options) catch |err| switch (err) {
        error.ParseError => blk: {
            // eval is a special builtin: a syntax error in the constructed
            // command stops the non-interactive shell (POSIX XCU 2.8.1).
            setSpecialBuiltinErrorConsequence(self, 2);
            break :blk try errorResult(self.allocator, 2, "eval", "syntax error");
        },
        else => err,
    };
}

fn builtinExec(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    if (command.argv.len == 1) return emptyResult(self.allocator, 0);
    var pre_expanded = try preExpandedCommandFromArgs(self.allocator, command, 1);
    defer pre_expanded.deinit();
    const nested = pre_expanded.command(command.span);
    if (options.allow_external and options.external_stdio == .inherit and options.io != null and builtinForName(self.*, nested.argv[0].text) == null and self.functions.get(nested.argv[0].text) == null) {
        var result = try self.replaceWithExternal(nested, options.io.?, options);
        errdefer result.deinit();
        if (!options.interactive) self.pending_exit = result.status;
        return result;
    }
    var result = try self.executeSimpleCommandWithInput(nested, stdin, options);
    errdefer result.deinit();
    self.pending_exit = result.status;
    return result;
}

fn builtinExit(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    if (command.argv.len > 2) return exitUsageError(self, "too many arguments");
    const status: ExitStatus = if (command.argv.len == 2) blk: {
        const parsed = std.fmt.parseInt(u64, command.argv[1].text, 10) catch return exitUsageError(self, "numeric argument required");
        break :blk @truncate(parsed);
    } else self.lastStatus();
    if (options.interactive and self.shouldWarnBeforeExitWithStoppedJobs()) {
        const stderr = try self.allocator.dupe(u8, stopped_jobs_exit_warning);
        errdefer self.allocator.free(stderr);
        return .{ .allocator = self.allocator, .status = 0, .stdout = try self.allocator.alloc(u8, 0), .stderr = stderr };
    }
    self.pending_exit = status;
    return emptyResult(self.allocator, status);
}

fn exitUsageError(self: *Executor, message: []const u8) !CommandResult {
    setSpecialBuiltinErrorConsequence(self, 2);
    return errorResult(self.allocator, 2, "exit", message);
}

fn builtinBreak(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    _ = options;
    return setLoopControlBuiltin(self, command, .break_loop, "break");
}

fn builtinContinue(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    _ = options;
    return setLoopControlBuiltin(self, command, .continue_loop, "continue");
}

fn setLoopControlBuiltin(self: *Executor, command: ir.SimpleCommand, kind: LoopControlKind, name: []const u8) !CommandResult {
    if (command.argv.len > 2) return loopControlUsageError(self, name, "too many arguments");
    const levels: usize = if (command.argv.len == 2) blk: {
        const parsed = std.fmt.parseInt(usize, command.argv[1].text, 10) catch return loopControlUsageError(self, name, "numeric argument required");
        if (parsed == 0) return loopControlUsageError(self, name, "loop count must be positive");
        break :blk parsed;
    } else 1;
    // POSIX.1-2024: break/continue outside any enclosing loop exit with
    // status 0 and the shell keeps running; dash and bash agree. Operand
    // errors above still stop the shell like other special builtins.
    if (self.loop_depth == 0) return emptyResult(self.allocator, 0);
    self.pending_loop_control = .{ .kind = kind, .levels = @min(levels, self.loop_depth) };
    return emptyResult(self.allocator, 0);
}

fn loopControlUsageError(self: *Executor, name: []const u8, message: []const u8) !CommandResult {
    setSpecialBuiltinErrorConsequence(self, 2);
    return errorResult(self.allocator, 2, name, message);
}

fn builtinTrue(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = command;
    _ = stdin;
    _ = options;
    return emptyResult(self.allocator, 0);
}

fn builtinFalse(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = command;
    _ = stdin;
    _ = options;
    return emptyResult(self.allocator, 1);
}

fn builtinEcho(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    _ = options;
    var stdout: std.ArrayList(u8) = .empty;
    errdefer stdout.deinit(self.allocator);

    for (command.argv[1..], 0..) |arg, index| {
        if (index > 0) try stdout.append(self.allocator, ' ');
        try stdout.appendSlice(self.allocator, arg.text);
    }
    try stdout.append(self.allocator, '\n');

    return .{
        .allocator = self.allocator,
        .status = 0,
        .stdout = try stdout.toOwnedSlice(self.allocator),
        .stderr = try self.allocator.alloc(u8, 0),
    };
}

fn builtinColor(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    _ = options;
    if (command.argv.len < 2) return errorResult(self.allocator, 2, "color", "missing subcommand");

    const subcommand = command.argv[1].text;
    const rgb: [3]u8 = if (std.mem.eql(u8, subcommand, "dim")) blk: {
        if (command.argv.len != 4) return errorResult(self.allocator, 2, "color", "usage: color dim COLOR PERCENT");
        const color = parseHexColor(command.argv[2].text) orelse return invalidColorResult(self, command.argv[2].text);
        const percent = parseColorPercent(command.argv[3].text) orelse return errorResult(self.allocator, 2, "color", "percent must be between 0 and 100");
        break :blk mixRgb(color, .{ 0, 0, 0 }, percent);
    } else if (std.mem.eql(u8, subcommand, "blend")) blk: {
        if (command.argv.len != 5) return errorResult(self.allocator, 2, "color", "usage: color blend COLOR COLOR PERCENT");
        const first = parseHexColor(command.argv[2].text) orelse return invalidColorResult(self, command.argv[2].text);
        const second = parseHexColor(command.argv[3].text) orelse return invalidColorResult(self, command.argv[3].text);
        const percent = parseColorPercent(command.argv[4].text) orelse return errorResult(self.allocator, 2, "color", "percent must be between 0 and 100");
        break :blk mixRgb(first, second, percent);
    } else return errorResult(self.allocator, 2, "color", "unsupported subcommand");

    const stdout = try std.fmt.allocPrint(self.allocator, "#{x:0>2}{x:0>2}{x:0>2}\n", .{ rgb[0], rgb[1], rgb[2] });
    errdefer self.allocator.free(stdout);
    return .{
        .allocator = self.allocator,
        .status = 0,
        .stdout = stdout,
        .stderr = try self.allocator.alloc(u8, 0),
    };
}

fn invalidColorResult(self: *Executor, color: []const u8) !CommandResult {
    const stderr = try std.fmt.allocPrint(self.allocator, "color: invalid color: {s}\n", .{color});
    errdefer self.allocator.free(stderr);
    return .{
        .allocator = self.allocator,
        .status = 2,
        .stdout = try self.allocator.alloc(u8, 0),
        .stderr = stderr,
    };
}

fn parseHexColor(color: []const u8) ?[3]u8 {
    if (color.len != 7 or color[0] != '#') return null;
    const value = std.fmt.parseUnsigned(u24, color[1..], 16) catch return null;
    return .{ @intCast(value >> 16), @intCast((value >> 8) & 0xff), @intCast(value & 0xff) };
}

fn parseColorPercent(text: []const u8) ?u8 {
    const percent = std.fmt.parseUnsigned(u8, text, 10) catch return null;
    if (percent > 100) return null;
    return percent;
}

fn mixRgb(first: [3]u8, second: [3]u8, percent: u8) [3]u8 {
    return .{
        mixChannel(first[0], second[0], percent),
        mixChannel(first[1], second[1], percent),
        mixChannel(first[2], second[2], percent),
    };
}

fn mixChannel(first: u8, second: u8, percent: u8) u8 {
    const remaining: u16 = 100 - @as(u16, percent);
    const amount: u16 = percent;
    return @intCast((@as(u16, first) * remaining + @as(u16, second) * amount + 50) / 100);
}

fn builtinPrompt(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    _ = options;
    if (command.argv.len < 2) return errorResult(self.allocator, 2, "prompt", "missing subcommand");

    const subcommand = command.argv[1].text;
    if (std.mem.eql(u8, subcommand, "repaint")) {
        if (command.argv.len != 2) return errorResult(self.allocator, 2, "prompt", "too many arguments");
        if (self.prompt_repaint_handler) |handler| {
            handler.request(handler.context);
        }
        return emptyResult(self.allocator, 0);
    }

    const builder = if (self.prompt_builder) |*builder| builder else return errorResult(self.allocator, 2, "prompt", "not rendering a prompt");
    if (std.mem.eql(u8, subcommand, "text")) {
        try appendPromptArgs(self, builder, command.argv[2..]);
        return emptyResult(self.allocator, 0);
    }
    if (std.mem.eql(u8, subcommand, "segment")) {
        var index: usize = 2;
        var style: PromptStyle = .{};
        while (index < command.argv.len and std.mem.startsWith(u8, command.argv[index].text, "--")) {
            const option = command.argv[index].text;
            index += 1;
            if (std.mem.eql(u8, option, "--fg")) {
                if (index >= command.argv.len) return errorResult(self.allocator, 2, "prompt", "missing option value");
                style.fg = parsePromptColor(command.argv[index].text) orelse return errorResult(self.allocator, 2, "prompt", "unsupported foreground color");
                index += 1;
            } else if (std.mem.eql(u8, option, "--bg")) {
                if (index >= command.argv.len) return errorResult(self.allocator, 2, "prompt", "missing option value");
                style.bg = parsePromptColor(command.argv[index].text) orelse return errorResult(self.allocator, 2, "prompt", "unsupported background color");
                index += 1;
            } else if (std.mem.eql(u8, option, "--max-width") or std.mem.eql(u8, option, "--min-width") or std.mem.eql(u8, option, "--truncate")) {
                if (index >= command.argv.len) return errorResult(self.allocator, 2, "prompt", "missing option value");
                index += 1;
            } else if (std.mem.eql(u8, option, "--bold")) {
                style.bold = true;
            } else if (std.mem.eql(u8, option, "--dim")) {
                style.dim = true;
            } else if (std.mem.eql(u8, option, "--italic")) {
                style.italic = true;
            } else if (std.mem.eql(u8, option, "--underline")) {
                style.underline = true;
            } else if (std.mem.eql(u8, option, "--blink")) {
                style.blink = true;
            } else if (std.mem.eql(u8, option, "--reverse")) {
                style.reverse = true;
            } else if (std.mem.eql(u8, option, "--strikethrough")) {
                style.strikethrough = true;
            } else {
                return errorResult(self.allocator, 2, "prompt", "unsupported segment option");
            }
        }
        try builder.appendSegment(self.allocator, style, command.argv[index..]);
        return emptyResult(self.allocator, 0);
    }
    if (std.mem.eql(u8, subcommand, "newline")) {
        try builder.text.append(self.allocator, '\n');
        builder.used = true;
        return emptyResult(self.allocator, 0);
    }
    if (std.mem.eql(u8, subcommand, "refresh")) {
        if (command.argv.len != 4 or !std.mem.eql(u8, command.argv[2].text, "--interval")) return errorResult(self.allocator, 2, "prompt", "usage: refresh --interval MS");
        const interval = std.fmt.parseUnsigned(u64, command.argv[3].text, 10) catch return errorResult(self.allocator, 2, "prompt", "invalid refresh interval");
        if (interval == 0) return errorResult(self.allocator, 2, "prompt", "invalid refresh interval");
        builder.refresh_interval_ms = interval;
        return emptyResult(self.allocator, 0);
    }
    return errorResult(self.allocator, 2, "prompt", "unsupported subcommand");
}

fn appendPromptArgs(self: *Executor, builder: *PromptBuilder, args: []const ir.WordRef) !void {
    try builder.appendText(self.allocator, args);
}

fn joinPromptAsyncCommand(allocator: std.mem.Allocator, args: []const ir.WordRef) ![]u8 {
    var script: std.ArrayList(u8) = .empty;
    errdefer script.deinit(allocator);
    for (args, 0..) |arg, index| {
        if (index > 0) try script.append(allocator, ' ');
        try appendShellQuoted(allocator, &script, arg.text);
    }
    return script.toOwnedSlice(allocator);
}

fn appendShellQuoted(allocator: std.mem.Allocator, out: *std.ArrayList(u8), text: []const u8) !void {
    try out.append(allocator, '\'');
    for (text) |byte| {
        if (byte == '\'') {
            try out.appendSlice(allocator, "'\\''");
        } else {
            try out.append(allocator, byte);
        }
    }
    try out.append(allocator, '\'');
}

fn lockExecutorMutex(mutex: *std.atomic.Mutex) void {
    while (!mutex.tryLock()) std.Thread.yield() catch {};
}

fn nowMs(io: std.Io) u64 {
    const timestamp = std.Io.Timestamp.now(io, .real);
    if (timestamp.nanoseconds <= 0) return 0;
    return @intCast(@divFloor(timestamp.nanoseconds, std.time.ns_per_ms));
}

fn parsePromptColor(name: []const u8) ?vaxis.Color {
    if (std.mem.eql(u8, name, "default")) return .default;
    if (std.mem.eql(u8, name, "black")) return .{ .index = 0 };
    if (std.mem.eql(u8, name, "red")) return .{ .index = 1 };
    if (std.mem.eql(u8, name, "green")) return .{ .index = 2 };
    if (std.mem.eql(u8, name, "yellow")) return .{ .index = 3 };
    if (std.mem.eql(u8, name, "blue")) return .{ .index = 4 };
    if (std.mem.eql(u8, name, "magenta")) return .{ .index = 5 };
    if (std.mem.eql(u8, name, "cyan")) return .{ .index = 6 };
    if (std.mem.eql(u8, name, "white")) return .{ .index = 7 };
    if (std.mem.eql(u8, name, "bright-black")) return .{ .index = 8 };
    if (std.mem.eql(u8, name, "bright-red")) return .{ .index = 9 };
    if (std.mem.eql(u8, name, "bright-green")) return .{ .index = 10 };
    if (std.mem.eql(u8, name, "bright-yellow")) return .{ .index = 11 };
    if (std.mem.eql(u8, name, "bright-blue")) return .{ .index = 12 };
    if (std.mem.eql(u8, name, "bright-magenta")) return .{ .index = 13 };
    if (std.mem.eql(u8, name, "bright-cyan")) return .{ .index = 14 };
    if (std.mem.eql(u8, name, "bright-white")) return .{ .index = 15 };
    if (std.mem.startsWith(u8, name, "index:")) {
        const index = std.fmt.parseUnsigned(u8, name["index:".len..], 10) catch return null;
        return .{ .index = index };
    }
    if (name.len == 7 and name[0] == '#') {
        const value = std.fmt.parseUnsigned(u24, name[1..], 16) catch return null;
        return vaxis.Color.rgbFromUint(value);
    }
    return null;
}

fn builtinPromptPwd(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    const io = options.io orelse return error.MissingIoForBuiltin;

    // Follows the shape of fish's prompt_pwd: --dir-length 0 disables
    // shortening, --full-length-dirs keeps trailing components full.
    var dir_length: usize = 0;
    var full_dirs: usize = 1;
    var index: usize = 1;
    while (index < command.argv.len) : (index += 1) {
        const arg = command.argv[index].text;
        const is_dir_length = std.mem.eql(u8, arg, "-d") or std.mem.eql(u8, arg, "--dir-length");
        const is_full_dirs = std.mem.eql(u8, arg, "-D") or std.mem.eql(u8, arg, "--full-length-dirs");
        if (!is_dir_length and !is_full_dirs) return errorResult(self.allocator, 2, "prompt_pwd", "usage: prompt_pwd [-d N] [-D N]");
        index += 1;
        if (index == command.argv.len) return errorResult(self.allocator, 2, "prompt_pwd", "usage: prompt_pwd [-d N] [-D N]");
        const value = std.fmt.parseUnsigned(usize, command.argv[index].text, 10) catch return errorResult(self.allocator, 2, "prompt_pwd", "invalid number");
        if (is_dir_length) dir_length = value else full_dirs = value;
    }

    const cwd = try self.logicalCwd(io);
    defer self.allocator.free(cwd);
    const display = try homeRelativePath(self.allocator, cwd, self.getEnv("HOME"));
    defer if (display.owned) self.allocator.free(display.text);
    if (dir_length == 0) return stdoutLine(self.allocator, display.text, 0);
    const shortened = try shortenPromptPath(self.allocator, display.text, dir_length, full_dirs);
    defer self.allocator.free(shortened);
    return stdoutLine(self.allocator, shortened, 0);
}

/// Shortens all but the trailing `full_dirs` path components to their
/// first `dir_length` characters, keeping a leading dot (".config" with
/// length 1 becomes ".c"), like fish's prompt_pwd.
fn shortenPromptPath(allocator: std.mem.Allocator, path: []const u8, dir_length: usize, full_dirs: usize) ![]const u8 {
    std.debug.assert(dir_length > 0);
    var component_count: usize = 0;
    {
        var iter = std.mem.splitScalar(u8, path, '/');
        while (iter.next()) |_| component_count += 1;
    }

    var out: std.ArrayList(u8) = .empty;
    errdefer out.deinit(allocator);
    var iter = std.mem.splitScalar(u8, path, '/');
    var index: usize = 0;
    while (iter.next()) |component| : (index += 1) {
        if (index > 0) try out.append(allocator, '/');
        if (index + @min(full_dirs, component_count) >= component_count) {
            try out.appendSlice(allocator, component);
        } else {
            try out.appendSlice(allocator, shortenPathComponent(component, dir_length));
        }
    }
    return out.toOwnedSlice(allocator);
}

fn shortenPathComponent(component: []const u8, dir_length: usize) []const u8 {
    std.debug.assert(dir_length > 0);
    const start: usize = if (std.mem.startsWith(u8, component, ".")) 1 else 0;
    var end = start;
    var count: usize = 0;
    while (end < component.len and count < dir_length) : (count += 1) {
        end += std.unicode.utf8ByteSequenceLength(component[end]) catch 1;
    }
    return component[0..@min(end, component.len)];
}

test "shortenPromptPath shortens components like fish prompt_pwd" {
    const cases = [_]struct { path: []const u8, dir_length: usize, full_dirs: usize, expected: []const u8 }{
        .{ .path = "~/repos/rush2", .dir_length = 1, .full_dirs = 1, .expected = "~/r/rush2" },
        .{ .path = "/usr/local/share", .dir_length = 1, .full_dirs = 1, .expected = "/u/l/share" },
        .{ .path = "/usr/local/share", .dir_length = 2, .full_dirs = 1, .expected = "/us/lo/share" },
        .{ .path = "/usr/local/share", .dir_length = 1, .full_dirs = 2, .expected = "/u/local/share" },
        .{ .path = "/usr/local/share", .dir_length = 1, .full_dirs = 0, .expected = "/u/l/s" },
        .{ .path = "~/.config/rush", .dir_length = 1, .full_dirs = 1, .expected = "~/.c/rush" },
        .{ .path = "~", .dir_length = 1, .full_dirs = 1, .expected = "~" },
        .{ .path = "/", .dir_length = 1, .full_dirs = 1, .expected = "/" },
    };
    for (cases) |case| {
        const shortened = try shortenPromptPath(std.testing.allocator, case.path, case.dir_length, case.full_dirs);
        defer std.testing.allocator.free(shortened);
        try std.testing.expectEqualStrings(case.expected, shortened);
    }
}

fn builtinPromptDuration(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = command;
    _ = stdin;
    _ = options;
    return stdoutLine(self.allocator, self.last_command_duration_text[0..self.last_command_duration_text_len], 0);
}

fn builtinPromptAsync(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    if (self.prompt_builder == null) return errorResult(self.allocator, 2, "prompt_async", "not rendering a prompt");
    if (command.argv.len < 6) return errorResult(self.allocator, 2, "prompt_async", "usage: KEY --ttl MS -- COMMAND...");
    if (!std.mem.eql(u8, command.argv[2].text, "--ttl")) return errorResult(self.allocator, 2, "prompt_async", "usage: KEY --ttl MS -- COMMAND...");
    const ttl_ms = std.fmt.parseUnsigned(u64, command.argv[3].text, 10) catch return errorResult(self.allocator, 2, "prompt_async", "invalid ttl");
    if (!std.mem.eql(u8, command.argv[4].text, "--")) return errorResult(self.allocator, 2, "prompt_async", "usage: KEY --ttl MS -- COMMAND...");
    const io = options.io orelse return error.MissingIoForBuiltin;

    const owner = self.prompt_async_owner orelse self;
    const cache_key = try owner.promptAsyncCacheKey(io, command.argv[1].text);
    defer owner.allocator.free(cache_key);
    const script = try joinPromptAsyncCommand(owner.allocator, command.argv[5..]);
    defer owner.allocator.free(script);

    const output = try owner.promptAsyncCachedOutputOrSchedule(self, cache_key, ttl_ms, script, io);
    defer owner.allocator.free(output);
    return .{
        .allocator = self.allocator,
        .status = self.lastStatus(),
        .stdout = try self.allocator.dupe(u8, output),
        .stderr = try self.allocator.alloc(u8, 0),
    };
}

fn builtinPromptTime(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    if (command.argv.len != 2) return errorResult(self.allocator, 2, "prompt_time", "usage: prompt_time FORMAT");
    const io = options.io orelse return error.MissingIoForBuiltin;

    var local_zone = try zeit.local(self.allocator, io, .{});
    defer local_zone.deinit();
    const now = zeit.instant(.{ .now = io }, &local_zone);
    const time = now.time();

    var stdout: std.Io.Writer.Allocating = .init(self.allocator);
    errdefer stdout.deinit();
    if (std.mem.indexOfScalar(u8, command.argv[1].text, '%') != null) {
        try time.strftime(&stdout.writer, command.argv[1].text);
    } else {
        try time.gofmt(&stdout.writer, command.argv[1].text);
    }
    try stdout.writer.writeByte('\n');
    return .{
        .allocator = self.allocator,
        .status = 0,
        .stdout = try stdout.toOwnedSlice(),
        .stderr = try self.allocator.alloc(u8, 0),
    };
}

fn builtinEvent(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    _ = options;
    if (command.argv.len != 3) return errorResult(self.allocator, 2, "event", "usage: EVENT FUNCTION");
    const event = command.argv[1].text;
    if (!isPromptEventName(event)) return errorResult(self.allocator, 2, "event", "unsupported event");
    const function = command.argv[2].text;
    if (!isShellName(function)) return errorResult(self.allocator, 2, "event", "invalid function name");
    try self.addEventHook(event, function);
    return emptyResult(self.allocator, 0);
}

fn builtinInterval(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    _ = options;
    if (command.argv.len != 5 or !std.mem.eql(u8, command.argv[2].text, "--interval")) return errorResult(self.allocator, 2, "interval", "usage: NAME --interval MS FUNCTION");
    const interval_ms = std.fmt.parseUnsigned(u64, command.argv[3].text, 10) catch return errorResult(self.allocator, 2, "interval", "invalid interval");
    if (interval_ms == 0) return errorResult(self.allocator, 2, "interval", "invalid interval");
    if (!isShellName(command.argv[4].text)) return errorResult(self.allocator, 2, "interval", "invalid function name");
    try self.addIntervalHook(command.argv[1].text, interval_ms, command.argv[4].text);
    return emptyResult(self.allocator, 0);
}

fn isPromptEventName(name: []const u8) bool {
    return std.mem.eql(u8, name, "prompt") or
        std.mem.eql(u8, name, "preexec") or
        std.mem.eql(u8, name, "postexec") or
        std.mem.eql(u8, name, "variable");
}

const PromptPath = struct {
    text: []const u8,
    owned: bool = false,
};

fn homeRelativePath(allocator: std.mem.Allocator, path: []const u8, maybe_home: ?[]const u8) !PromptPath {
    const home = maybe_home orelse return .{ .text = path };
    if (home.len == 0) return .{ .text = path };
    if (std.mem.eql(u8, path, home)) return .{ .text = "~" };
    if (std.mem.startsWith(u8, path, home) and path.len > home.len and path[home.len] == '/') {
        return .{ .text = try std.mem.concat(allocator, u8, &.{ "~", path[home.len..] }), .owned = true };
    }
    return .{ .text = path };
}

fn normalizeLogicalPath(allocator: std.mem.Allocator, base: []const u8, target: []const u8) ![]const u8 {
    const combined = if (target.len > 0 and target[0] == '/')
        try allocator.dupe(u8, target)
    else
        try std.mem.concat(allocator, u8, &.{ base, "/", target });
    defer allocator.free(combined);

    // A pathname beginning with exactly two slashes keeps its
    // implementation-defined // root, while three or more leading slashes
    // collapse to one (POSIX XBD 4.13). dash and bash preserve // the same
    // way.
    const source_root = if (target.len > 0 and target[0] == '/') target else base;
    const double_slash_root = source_root.len >= 2 and source_root[0] == '/' and source_root[1] == '/' and
        (source_root.len == 2 or source_root[2] != '/');

    var parts: std.ArrayList([]const u8) = .empty;
    defer parts.deinit(allocator);
    var iter = std.mem.splitScalar(u8, combined, '/');
    while (iter.next()) |part| {
        if (part.len == 0 or std.mem.eql(u8, part, ".")) continue;
        if (std.mem.eql(u8, part, "..")) {
            if (parts.items.len > 0) _ = parts.pop();
            continue;
        }
        try parts.append(allocator, part);
    }

    if (parts.items.len == 0) return allocator.dupe(u8, if (double_slash_root) "//" else "/");
    var out: std.ArrayList(u8) = .empty;
    errdefer out.deinit(allocator);
    if (double_slash_root) try out.append(allocator, '/');
    for (parts.items) |part| {
        try out.append(allocator, '/');
        try out.appendSlice(allocator, part);
    }
    return out.toOwnedSlice(allocator);
}

fn builtinPrintf(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    _ = options;
    var format_index: usize = 1;
    if (format_index < command.argv.len and std.mem.eql(u8, command.argv[format_index].text, "--")) format_index += 1;
    if (format_index >= command.argv.len) return errorResult(self.allocator, 2, "printf", "missing format operand");

    var stdout: std.ArrayList(u8) = .empty;
    errdefer stdout.deinit(self.allocator);
    var stderr: std.ArrayList(u8) = .empty;
    errdefer stderr.deinit(self.allocator);
    var status: ExitStatus = 0;
    var stderr_before_stdout = false;
    try appendPrintfOutput(self.allocator, &stdout, &stderr, &status, &stderr_before_stdout, command.argv[format_index].text, command.argv[format_index + 1 ..]);
    return .{
        .allocator = self.allocator,
        .status = status,
        .stdout = try stdout.toOwnedSlice(self.allocator),
        .stderr = try stderr.toOwnedSlice(self.allocator),
        .stderr_before_stdout = stderr_before_stdout,
    };
}

fn builtinRead(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    var arg_start: usize = 1;
    const read_options = parseReadOptions(command, &arg_start, options.features) catch |err| switch (err) {
        error.UnsupportedOption => return errorResult(self.allocator, 2, "read", "unsupported option"),
        error.MissingDelimiter => return errorResult(self.allocator, 2, "read", "missing delimiter"),
    };

    const names = command.argv[arg_start..];
    if (names.len == 0) return errorResult(self.allocator, 2, "read", "missing variable name");
    for (names) |name_word| {
        if (!isShellName(name_word.text)) return errorResult(self.allocator, 2, "read", "invalid variable name");
    }

    const read_input = try nextReadInput(self, stdin, read_options, options);
    defer read_input.deinit(self.allocator);
    const status = read_input.status;
    const raw_line = read_input.line;

    const ifs = self.getEnv("IFS") orelse " \t\n";
    var cursor = skipReadIfsWhitespace(raw_line, 0, ifs, !read_options.raw_mode);
    for (names, 0..) |name_word, index| {
        if (index == names.len - 1) {
            const value_end = trimTrailingReadIfsWhitespace(raw_line, raw_line.len, ifs, !read_options.raw_mode);
            const value = if (cursor <= value_end) raw_line[cursor..value_end] else "";
            try setReadValue(self, name_word.text, value, read_options.raw_mode);
            break;
        }
        const field = nextReadField(raw_line, &cursor, ifs, !read_options.raw_mode);
        try setReadValue(self, name_word.text, field, read_options.raw_mode);
    }
    return emptyResult(self.allocator, status);
}

const ReadOptions = struct {
    raw_mode: bool = false,
    delimiter: u8 = '\n',
};

const ReadPrompt = struct {
    active: bool = false,
    text: []const u8 = "",
};

fn parseReadOptions(command: ir.SimpleCommand, arg_start: *usize, features: compat.Features) !ReadOptions {
    var result: ReadOptions = .{};
    while (arg_start.* < command.argv.len) {
        const arg = command.argv[arg_start.*].text;
        if (std.mem.eql(u8, arg, "--")) {
            arg_start.* += 1;
            break;
        }
        if (arg.len < 2 or arg[0] != '-') break;

        var option_index: usize = 1;
        while (option_index < arg.len) {
            switch (arg[option_index]) {
                'r' => {
                    result.raw_mode = true;
                    option_index += 1;
                },
                'd' => {
                    if (!features.isBash()) return error.UnsupportedOption;
                    if (option_index + 1 < arg.len) {
                        result.delimiter = arg[option_index + 1];
                        option_index = arg.len;
                    } else {
                        arg_start.* += 1;
                        if (arg_start.* >= command.argv.len) return error.MissingDelimiter;
                        const delimiter_arg = command.argv[arg_start.*].text;
                        result.delimiter = if (delimiter_arg.len == 0) 0 else delimiter_arg[0];
                        option_index = arg.len;
                    }
                },
                else => return error.UnsupportedOption,
            }
        }
        arg_start.* += 1;
    }
    return result;
}

fn setReadValue(self: *Executor, name: []const u8, raw_value: []const u8, raw_mode: bool) !void {
    if (raw_mode) return self.setEnv(name, raw_value);
    const value = try unescapeReadLine(self.allocator, raw_value);
    defer self.allocator.free(value);
    try self.setEnv(name, value);
}

const ReadInput = struct {
    line: []const u8,
    status: ExitStatus,

    owned: ?[]u8 = null,
    consumed: usize = 0,

    fn deinit(self: ReadInput, allocator: std.mem.Allocator) void {
        if (self.owned) |bytes| allocator.free(bytes);
    }
};

fn nextReadInput(self: *Executor, stdin: []const u8, read_options: ReadOptions, execute_options: ExecuteOptions) !ReadInput {
    if (stdin.len != 0) return try readInputFromSlice(self.allocator, stdin, read_options);
    if (pipeline_stage_stdin.active) {
        if (pipeline_stage_stdin.file) |file| return try readInputFromFile(self, file, read_options, .{});
        return .{ .line = "", .status = 1 };
    }
    if (self.script_stdin_file) |file| return try readInputFromFile(self, file, read_options, readContinuationPrompt(self, file, execute_options));
    const script_stdin = self.script_stdin orelse {
        if (!execute_options.interactive) return .{ .line = "", .status = 1 };
        const file = std.Io.File.stdin();
        return try readInputFromFile(self, file, read_options, readContinuationPrompt(self, file, execute_options));
    };
    if (self.script_stdin_offset >= script_stdin.len) return .{ .line = "", .status = 1 };
    const remaining = script_stdin[self.script_stdin_offset..];
    const input = try readInputFromSlice(self.allocator, remaining, read_options);
    self.script_stdin_offset += input.consumed;
    return input;
}

fn readContinuationPrompt(self: *Executor, file: std.Io.File, options: ExecuteOptions) ReadPrompt {
    if (!options.interactive) return .{};
    const io = options.io orelse return .{};
    if (!(file.isTty(io) catch false)) return .{};
    return .{ .active = true, .text = self.getEnv("PS2") orelse "> " };
}

fn readInputFromFile(self: *Executor, file: std.Io.File, options: ReadOptions, prompt: ReadPrompt) !ReadInput {
    var line: std.ArrayList(u8) = .empty;
    errdefer line.deinit(self.allocator);
    var byte: [1]u8 = undefined;
    const delimiter = options.delimiter;
    while (true) {
        const read_len = try std.posix.read(file.handle, &byte);
        if (read_len == 0) {
            trimReadCarriageReturnInPlace(&line);
            const owned = try line.toOwnedSlice(self.allocator);
            return .{ .line = trimReadCarriageReturn(owned), .status = 1, .owned = owned };
        }
        if (byte[0] == delimiter) {
            trimReadCarriageReturnInPlace(&line);
            if (delimiter == '\n' and !options.raw_mode and readLineContinues(line.items)) {
                line.items.len -= 1;
                if (prompt.active) try rawWriteAll(2, prompt.text);
                continue;
            }
            const owned = try line.toOwnedSlice(self.allocator);
            return .{ .line = owned, .status = 0, .owned = owned };
        }
        try line.append(self.allocator, byte[0]);
    }
}

fn readInputFromSlice(allocator: std.mem.Allocator, stdin: []const u8, options: ReadOptions) !ReadInput {
    var cursor: usize = 0;
    var logical: std.ArrayList(u8) = .empty;
    errdefer logical.deinit(allocator);
    var continued = false;
    while (true) {
        const remaining = stdin[cursor..];
        const delimiter = std.mem.indexOfScalar(u8, remaining, options.delimiter);
        const line_end = delimiter orelse remaining.len;
        const consumed = cursor + @min(line_end + 1, remaining.len);
        const physical_line = trimReadCarriageReturn(remaining[0..line_end]);
        if (options.delimiter == '\n' and delimiter != null and !options.raw_mode and readLineContinues(physical_line)) {
            continued = true;
            try logical.appendSlice(allocator, physical_line[0 .. physical_line.len - 1]);
            cursor = consumed;
            if (cursor >= stdin.len) {
                const owned = try logical.toOwnedSlice(allocator);
                return .{ .line = owned, .status = 1, .owned = owned, .consumed = consumed };
            }
            continue;
        }
        const status: ExitStatus = if (delimiter != null) 0 else 1;
        if (continued) {
            try logical.appendSlice(allocator, physical_line);
            const owned = try logical.toOwnedSlice(allocator);
            return .{ .line = owned, .status = status, .owned = owned, .consumed = consumed };
        }
        return .{ .line = physical_line, .status = status, .consumed = consumed };
    }
}

fn trimReadCarriageReturn(line: []const u8) []const u8 {
    if (line.len > 0 and line[line.len - 1] == '\r') return line[0 .. line.len - 1];
    return line;
}

fn trimReadCarriageReturnInPlace(line: *std.ArrayList(u8)) void {
    if (line.items.len > 0 and line.items[line.items.len - 1] == '\r') line.items.len -= 1;
}

fn readLineContinues(line: []const u8) bool {
    var backslashes: usize = 0;
    var index = line.len;
    while (index > 0 and line[index - 1] == '\\') : (index -= 1) {
        backslashes += 1;
    }
    return backslashes % 2 == 1;
}

const PrintfSpec = struct {
    spec: u8,
    argument: ?usize = null,
    left_adjust: bool = false,
    zero_pad: bool = false,
    sign_plus: bool = false,
    sign_space: bool = false,
    alternate: bool = false,
    width_from_argument: bool = false,
    width: ?usize = null,
    precision_from_argument: bool = false,
    precision: ?usize = null,
};

const PrintfIntegerBase = enum { decimal, octal, lower_hex, upper_hex };

const PrintfArgumentMode = enum { none, numbered, unnumbered };

fn appendPrintfOutput(allocator: std.mem.Allocator, stdout: *std.ArrayList(u8), stderr: *std.ArrayList(u8), status: *ExitStatus, stderr_before_stdout: *bool, format: []const u8, args: []const ir.WordRef) !void {
    const argument_mode = analyzePrintfFormat(format) catch |err| switch (err) {
        error.MixedArguments => {
            try printfDiagnostic(allocator, stderr, status, "invalid format");
            return;
        },
    };

    var arg_index: usize = 0;
    var numbered_base: usize = 0;
    var first_pass = true;
    while (first_pass or switch (argument_mode) {
        .numbered => numbered_base < args.len,
        .none, .unnumbered => arg_index < args.len,
    }) {
        first_pass = false;
        const before = if (argument_mode == .numbered) numbered_base else arg_index;
        var pass_max_numbered_argument: usize = 0;
        var index: usize = 0;
        while (index < format.len) {
            switch (format[index]) {
                '\\' => {
                    index += 1;
                    if (index >= format.len) {
                        try stdout.append(allocator, '\\');
                    } else {
                        _ = try appendEscapedSequence(allocator, stdout, format, &index, .format);
                    }
                },
                '%' => {
                    index += 1;
                    if (index >= format.len) {
                        try printfDiagnostic(allocator, stderr, status, "invalid format");
                        break;
                    }
                    const spec = parsePrintfSpec(format, &index) orelse {
                        try printfDiagnostic(allocator, stderr, status, "invalid format");
                        continue;
                    };
                    if (spec.spec == '%') {
                        if (spec.width_from_argument or spec.precision_from_argument) {
                            try printfDiagnostic(allocator, stderr, status, "invalid format");
                            continue;
                        }
                        try stdout.append(allocator, '%');
                        continue;
                    }
                    const resolved_spec = try resolvePrintfDynamicSpec(allocator, stderr, status, stderr_before_stdout, spec, args, &arg_index);
                    const arg = if (spec.argument) |argument_number| blk: {
                        pass_max_numbered_argument = @max(pass_max_numbered_argument, argument_number);
                        const offset = std.math.add(usize, numbered_base, argument_number - 1) catch {
                            try printfDiagnostic(allocator, stderr, status, "missing argument");
                            return;
                        };
                        if (offset >= args.len) {
                            try printfDiagnostic(allocator, stderr, status, "missing argument");
                            return;
                        }
                        break :blk args[offset].text;
                    } else if (arg_index < args.len) blk: {
                        const value = args[arg_index].text;
                        arg_index += 1;
                        break :blk value;
                    } else "";
                    if (!try appendPrintfConversion(allocator, stdout, stderr, status, stderr_before_stdout, resolved_spec, arg)) return;
                },
                else => {
                    try stdout.append(allocator, format[index]);
                    index += 1;
                },
            }
        }
        if (argument_mode == .numbered) {
            if (pass_max_numbered_argument == 0) break;
            numbered_base = std.math.add(usize, numbered_base, pass_max_numbered_argument) catch {
                try printfDiagnostic(allocator, stderr, status, "missing argument");
                return;
            };
            if (numbered_base == before) break;
        } else if (arg_index == before) break;
    }
}

fn analyzePrintfFormat(format: []const u8) error{MixedArguments}!PrintfArgumentMode {
    var result: PrintfArgumentMode = .none;
    var index: usize = 0;
    while (index < format.len) {
        switch (format[index]) {
            '\\' => {
                index += 1;
                if (index < format.len) index += 1;
            },
            '%' => {
                index += 1;
                if (index >= format.len) return result;
                const spec = parsePrintfSpec(format, &index) orelse return result;
                if (spec.spec == '%') continue;
                if (spec.width_from_argument or spec.precision_from_argument) {
                    if (result == .numbered) return error.MixedArguments;
                    result = .unnumbered;
                }
                if (spec.argument != null) {
                    if (result == .unnumbered) return error.MixedArguments;
                    result = .numbered;
                } else {
                    if (result == .numbered) return error.MixedArguments;
                    result = .unnumbered;
                }
            },
            else => index += 1,
        }
    }
    return result;
}

fn printfDiagnostic(allocator: std.mem.Allocator, stderr: *std.ArrayList(u8), status: *ExitStatus, message: []const u8) !void {
    status.* = 1;
    try stderr.appendSlice(allocator, "printf: ");
    try stderr.appendSlice(allocator, message);
    try stderr.append(allocator, '\n');
}

fn printfNumericDiagnostic(allocator: std.mem.Allocator, stderr: *std.ArrayList(u8), status: *ExitStatus, stderr_before_stdout: *bool) !void {
    stderr_before_stdout.* = true;
    try printfDiagnostic(allocator, stderr, status, "numeric argument required");
}

fn resolvePrintfDynamicSpec(allocator: std.mem.Allocator, stderr: *std.ArrayList(u8), status: *ExitStatus, stderr_before_stdout: *bool, spec: PrintfSpec, args: []const ir.WordRef, arg_index: *usize) !PrintfSpec {
    var result = spec;
    if (result.width_from_argument) {
        const value = try parsePrintfSigned(allocator, stderr, status, stderr_before_stdout, nextPrintfArgument(args, arg_index));
        applyPrintfDynamicWidth(&result, value);
    }
    if (result.precision_from_argument) {
        const value = try parsePrintfSigned(allocator, stderr, status, stderr_before_stdout, nextPrintfArgument(args, arg_index));
        result.precision = if (value < 0) null else printfDynamicMagnitude(value);
    }
    result.width_from_argument = false;
    result.precision_from_argument = false;
    return result;
}

fn nextPrintfArgument(args: []const ir.WordRef, arg_index: *usize) []const u8 {
    if (arg_index.* >= args.len) return "";
    const value = args[arg_index.*].text;
    arg_index.* += 1;
    return value;
}

fn applyPrintfDynamicWidth(spec: *PrintfSpec, value: i64) void {
    if (value < 0) {
        spec.left_adjust = true;
    }
    spec.width = printfDynamicMagnitude(value);
}

fn printfDynamicMagnitude(value: i64) usize {
    const magnitude: u64 = if (value < 0) @as(u64, @intCast(-(value + 1))) + 1 else @intCast(value);
    return std.math.cast(usize, magnitude) orelse std.math.maxInt(usize);
}

fn parsePrintfSpec(format: []const u8, index: *usize) ?PrintfSpec {
    var result: PrintfSpec = .{ .spec = 0 };
    if (index.* < format.len and std.ascii.isDigit(format[index.*])) {
        const start = index.*;
        while (index.* < format.len and std.ascii.isDigit(format[index.*])) : (index.* += 1) {}
        if (index.* < format.len and format[index.*] == '$') {
            const argument_number = std.fmt.parseInt(usize, format[start..index.*], 10) catch return null;
            if (argument_number == 0) return null;
            result.argument = argument_number;
            index.* += 1;
        } else {
            index.* = start;
        }
    }
    while (index.* < format.len) {
        switch (format[index.*]) {
            '-' => result.left_adjust = true,
            '0' => result.zero_pad = true,
            '+' => result.sign_plus = true,
            ' ' => result.sign_space = true,
            '#' => result.alternate = true,
            else => break,
        }
        index.* += 1;
    }
    if (index.* < format.len and format[index.*] == '*') {
        result.width_from_argument = true;
        index.* += 1;
    } else if (index.* < format.len and std.ascii.isDigit(format[index.*])) {
        const start = index.*;
        while (index.* < format.len and std.ascii.isDigit(format[index.*])) : (index.* += 1) {}
        result.width = std.fmt.parseInt(usize, format[start..index.*], 10) catch null;
    }
    if (index.* < format.len and format[index.*] == '.') {
        index.* += 1;
        const start = index.*;
        if (index.* < format.len and format[index.*] == '*') {
            result.precision_from_argument = true;
            index.* += 1;
        } else {
            while (index.* < format.len and std.ascii.isDigit(format[index.*])) : (index.* += 1) {}
            result.precision = if (start == index.*) 0 else std.fmt.parseInt(usize, format[start..index.*], 10) catch 0;
        }
    }
    if (index.* >= format.len) return null;
    result.spec = format[index.*];
    index.* += 1;
    return result;
}

fn appendPrintfConversion(allocator: std.mem.Allocator, stdout: *std.ArrayList(u8), stderr: *std.ArrayList(u8), status: *ExitStatus, stderr_before_stdout: *bool, spec: PrintfSpec, arg: []const u8) !bool {
    if (isPrintfFloatSpec(spec.spec)) {
        try appendPrintfFloatConversion(allocator, stdout, stderr, status, spec, arg);
        return true;
    }

    switch (spec.spec) {
        'd', 'i' => {
            const rendered = try formatPrintfSignedInteger(allocator, spec, try parsePrintfSigned(allocator, stderr, status, stderr_before_stdout, arg));
            defer allocator.free(rendered);
            try stdout.appendSlice(allocator, rendered);
            return true;
        },
        'u' => {
            const rendered = try formatPrintfUnsignedInteger(allocator, spec, try parsePrintfUnsigned(allocator, stderr, status, stderr_before_stdout, arg), .decimal);
            defer allocator.free(rendered);
            try stdout.appendSlice(allocator, rendered);
            return true;
        },
        'o' => {
            const rendered = try formatPrintfUnsignedInteger(allocator, spec, try parsePrintfUnsigned(allocator, stderr, status, stderr_before_stdout, arg), .octal);
            defer allocator.free(rendered);
            try stdout.appendSlice(allocator, rendered);
            return true;
        },
        'x' => {
            const rendered = try formatPrintfUnsignedInteger(allocator, spec, try parsePrintfUnsigned(allocator, stderr, status, stderr_before_stdout, arg), .lower_hex);
            defer allocator.free(rendered);
            try stdout.appendSlice(allocator, rendered);
            return true;
        },
        'X' => {
            const rendered = try formatPrintfUnsignedInteger(allocator, spec, try parsePrintfUnsigned(allocator, stderr, status, stderr_before_stdout, arg), .upper_hex);
            defer allocator.free(rendered);
            try stdout.appendSlice(allocator, rendered);
            return true;
        },
        else => {},
    }

    if (spec.spec == 'b') {
        var escaped: std.ArrayList(u8) = .empty;
        errdefer escaped.deinit(allocator);
        const keep_going = try appendEscapedString(allocator, &escaped, arg);
        const bytes = try escaped.toOwnedSlice(allocator);
        defer allocator.free(bytes);
        try appendPadded(allocator, stdout, truncatePrintfBytes(bytes, spec.precision), spec);
        return keep_going;
    }

    const rendered: []u8 = switch (spec.spec) {
        's' => try formatPrintfString(allocator, arg, spec.precision),
        'c' => try allocator.dupe(u8, if (arg.len == 0) &[_]u8{0} else arg[0..1]),
        else => blk: {
            try printfDiagnostic(allocator, stderr, status, "invalid conversion");
            break :blk try allocator.alloc(u8, 0);
        },
    };
    defer allocator.free(rendered);
    try appendPadded(allocator, stdout, rendered, spec);
    return true;
}

fn formatPrintfString(allocator: std.mem.Allocator, arg: []const u8, precision: ?usize) ![]u8 {
    return allocator.dupe(u8, truncatePrintfBytes(arg, precision));
}

fn truncatePrintfBytes(text: []const u8, precision: ?usize) []const u8 {
    const limit = if (precision) |value| @min(value, text.len) else text.len;
    return text[0..limit];
}

fn formatPrintfSignedInteger(allocator: std.mem.Allocator, spec: PrintfSpec, value: i64) ![]u8 {
    const negative = value < 0;
    const magnitude: u64 = if (negative) @as(u64, @intCast(-(value + 1))) + 1 else @intCast(value);
    return formatPrintfInteger(allocator, spec, magnitude, negative, .decimal);
}

fn formatPrintfUnsignedInteger(allocator: std.mem.Allocator, spec: PrintfSpec, value: u64, base: PrintfIntegerBase) ![]u8 {
    var unsigned_spec = spec;
    unsigned_spec.sign_plus = false;
    unsigned_spec.sign_space = false;
    return formatPrintfInteger(allocator, unsigned_spec, value, false, base);
}

fn formatPrintfInteger(allocator: std.mem.Allocator, spec: PrintfSpec, magnitude: u64, negative: bool, base: PrintfIntegerBase) ![]u8 {
    const raw_digits = try formatPrintfIntegerDigits(allocator, magnitude, base);
    defer allocator.free(raw_digits);

    var digits: []const u8 = raw_digits;
    if (spec.precision == 0 and magnitude == 0) digits = "";

    var precision_zeroes: usize = if (spec.precision) |precision| if (precision > digits.len) precision - digits.len else 0 else 0;
    if (base == .octal and spec.alternate) {
        if (digits.len + precision_zeroes == 0) {
            precision_zeroes = 1;
        } else if ((digits.len == 0 or digits[0] != '0') and precision_zeroes == 0) {
            precision_zeroes = 1;
        }
    }

    var prefix_buffer: [2]u8 = undefined;
    const prefix: []const u8 = switch (base) {
        .decimal => blk: {
            if (negative) {
                prefix_buffer[0] = '-';
                break :blk prefix_buffer[0..1];
            }
            if (spec.sign_plus) {
                prefix_buffer[0] = '+';
                break :blk prefix_buffer[0..1];
            }
            if (spec.sign_space) {
                prefix_buffer[0] = ' ';
                break :blk prefix_buffer[0..1];
            }
            break :blk "";
        },
        .octal => "",
        .lower_hex => if (spec.alternate and magnitude != 0) "0x" else "",
        .upper_hex => if (spec.alternate and magnitude != 0) "0X" else "",
    };

    const unpadded_len = prefix.len + precision_zeroes + digits.len;
    const width = spec.width orelse 0;
    const width_pad = if (width > unpadded_len) width - unpadded_len else 0;
    const use_zero_width_pad = spec.zero_pad and !spec.left_adjust and spec.precision == null;
    const leading_spaces: usize = if (!spec.left_adjust and !use_zero_width_pad) width_pad else 0;
    const width_zeroes: usize = if (use_zero_width_pad) width_pad else 0;
    const trailing_spaces: usize = if (spec.left_adjust) width_pad else 0;

    var out: std.ArrayList(u8) = .empty;
    errdefer out.deinit(allocator);
    try out.appendNTimes(allocator, ' ', leading_spaces);
    try out.appendSlice(allocator, prefix);
    try out.appendNTimes(allocator, '0', width_zeroes + precision_zeroes);
    try out.appendSlice(allocator, digits);
    try out.appendNTimes(allocator, ' ', trailing_spaces);
    return out.toOwnedSlice(allocator);
}

fn formatPrintfIntegerDigits(allocator: std.mem.Allocator, value: u64, base: PrintfIntegerBase) ![]u8 {
    return switch (base) {
        .decimal => std.fmt.allocPrint(allocator, "{d}", .{value}),
        .octal => std.fmt.allocPrint(allocator, "{o}", .{value}),
        .lower_hex => std.fmt.allocPrint(allocator, "{x}", .{value}),
        .upper_hex => std.fmt.allocPrint(allocator, "{X}", .{value}),
    };
}

fn appendPadded(allocator: std.mem.Allocator, stdout: *std.ArrayList(u8), text: []const u8, spec: PrintfSpec) !void {
    const width = spec.width orelse 0;
    const pad_len = if (width > text.len) width - text.len else 0;
    const pad_byte: u8 = if (spec.zero_pad and !spec.left_adjust) '0' else ' ';
    if (!spec.left_adjust) try stdout.appendNTimes(allocator, pad_byte, pad_len);
    try stdout.appendSlice(allocator, text);
    if (spec.left_adjust) try stdout.appendNTimes(allocator, ' ', pad_len);
}

fn isPrintfFloatSpec(spec: u8) bool {
    return switch (spec) {
        'a', 'A', 'e', 'E', 'f', 'F', 'g', 'G' => true,
        else => false,
    };
}

fn appendPrintfFloatConversion(allocator: std.mem.Allocator, stdout: *std.ArrayList(u8), stderr: *std.ArrayList(u8), status: *ExitStatus, spec: PrintfSpec, arg: []const u8) !void {
    const value = try parsePrintfFloat(allocator, stderr, status, arg);

    var format_buffer: [64]u8 = undefined;
    const c_format = printfCFormat(&format_buffer, spec) catch unreachable;

    var stack_buffer: [128]u8 = undefined;
    const stack_len = snprintf(stack_buffer[0..].ptr, stack_buffer.len, c_format.ptr, value);
    if (stack_len < 0) {
        try printfDiagnostic(allocator, stderr, status, "invalid conversion");
        return;
    }
    const needed: usize = @intCast(stack_len);
    if (needed < stack_buffer.len) {
        try stdout.appendSlice(allocator, stack_buffer[0..needed]);
        return;
    }

    const heap_buffer = try allocator.alloc(u8, needed + 1);
    defer allocator.free(heap_buffer);
    const heap_len = snprintf(heap_buffer.ptr, heap_buffer.len, c_format.ptr, value);
    if (heap_len < 0) {
        try printfDiagnostic(allocator, stderr, status, "invalid conversion");
        return;
    }
    try stdout.appendSlice(allocator, heap_buffer[0..@min(@as(usize, @intCast(heap_len)), needed)]);
}

fn printfCFormat(buffer: []u8, spec: PrintfSpec) ![:0]u8 {
    var flags_buffer: [5]u8 = undefined;
    var flags_len: usize = 0;
    if (spec.left_adjust) {
        flags_buffer[flags_len] = '-';
        flags_len += 1;
    }
    if (spec.sign_plus) {
        flags_buffer[flags_len] = '+';
        flags_len += 1;
    }
    if (spec.sign_space) {
        flags_buffer[flags_len] = ' ';
        flags_len += 1;
    }
    if (spec.alternate) {
        flags_buffer[flags_len] = '#';
        flags_len += 1;
    }
    if (spec.zero_pad) {
        flags_buffer[flags_len] = '0';
        flags_len += 1;
    }
    const flags = flags_buffer[0..flags_len];

    if (spec.width) |width| {
        if (spec.precision) |precision| {
            return std.fmt.bufPrintSentinel(buffer, "%{s}{d}.{d}{c}", .{ flags, width, precision, spec.spec }, 0);
        }
        return std.fmt.bufPrintSentinel(buffer, "%{s}{d}{c}", .{ flags, width, spec.spec }, 0);
    }
    if (spec.precision) |precision| {
        return std.fmt.bufPrintSentinel(buffer, "%{s}.{d}{c}", .{ flags, precision, spec.spec }, 0);
    }
    return std.fmt.bufPrintSentinel(buffer, "%{s}{c}", .{ flags, spec.spec }, 0);
}

const PrintfIntegerConstant = struct {
    magnitude: u64,
    negative: bool = false,
    complete: bool = true,
    overflow: bool = false,
};

const PrintfMagnitude = struct {
    value: u64,
    overflow: bool = false,
};

const PrintfSignedValue = struct {
    value: i64,
    overflow: bool = false,
};

const PrintfUnsignedValue = struct {
    value: u64,
    overflow: bool = false,
};

fn parsePrintfSigned(allocator: std.mem.Allocator, stderr: *std.ArrayList(u8), status: *ExitStatus, stderr_before_stdout: *bool, arg: []const u8) !i64 {
    const parsed = parsePrintfIntegerConstant(arg) catch |err| switch (err) {
        error.InvalidCharacter => {
            try printfNumericDiagnostic(allocator, stderr, status, stderr_before_stdout);
            return 0;
        },
        error.Overflow => {
            try printfNumericDiagnostic(allocator, stderr, status, stderr_before_stdout);
            return 0;
        },
    };
    const converted = printfSignedValue(parsed);
    if (!parsed.complete or converted.overflow) try printfNumericDiagnostic(allocator, stderr, status, stderr_before_stdout);
    return converted.value;
}

fn parsePrintfUnsigned(allocator: std.mem.Allocator, stderr: *std.ArrayList(u8), status: *ExitStatus, stderr_before_stdout: *bool, arg: []const u8) !u64 {
    const parsed = parsePrintfIntegerConstant(arg) catch |err| switch (err) {
        error.InvalidCharacter => {
            try printfNumericDiagnostic(allocator, stderr, status, stderr_before_stdout);
            return 0;
        },
        error.Overflow => {
            try printfNumericDiagnostic(allocator, stderr, status, stderr_before_stdout);
            return 0;
        },
    };
    const converted = printfUnsignedValue(parsed);
    if (!parsed.complete or converted.overflow) try printfNumericDiagnostic(allocator, stderr, status, stderr_before_stdout);
    return converted.value;
}

fn printfSignedValue(parsed: PrintfIntegerConstant) PrintfSignedValue {
    if (!parsed.negative) {
        if (parsed.magnitude > std.math.maxInt(i64)) return .{ .value = std.math.maxInt(i64), .overflow = true };
        return .{ .value = @intCast(parsed.magnitude), .overflow = parsed.overflow };
    }
    const max_plus_one = @as(u64, @intCast(std.math.maxInt(i64))) + 1;
    if (parsed.magnitude == max_plus_one) return .{ .value = std.math.minInt(i64), .overflow = parsed.overflow };
    if (parsed.magnitude > max_plus_one) return .{ .value = std.math.minInt(i64), .overflow = true };
    return .{ .value = -@as(i64, @intCast(parsed.magnitude)), .overflow = parsed.overflow };
}

fn printfUnsignedValue(parsed: PrintfIntegerConstant) PrintfUnsignedValue {
    if (!parsed.negative) return .{ .value = parsed.magnitude, .overflow = parsed.overflow };
    if (parsed.overflow) return .{ .value = std.math.maxInt(u64), .overflow = true };
    return .{ .value = (~parsed.magnitude) +% 1 };
}

fn parsePrintfMagnitude(text: []const u8, base: u8) !PrintfMagnitude {
    const value = std.fmt.parseInt(u64, text, base) catch |err| switch (err) {
        error.Overflow => return .{ .value = std.math.maxInt(u64), .overflow = true },
        else => return err,
    };
    return .{ .value = value };
}

fn parsePrintfIntegerConstant(arg: []const u8) !PrintfIntegerConstant {
    if (arg.len == 0) return .{ .magnitude = 0 };
    if (arg[0] == '\'' or arg[0] == '"') return .{ .magnitude = if (arg.len > 1) arg[1] else 0 };

    var cursor: usize = 0;
    var negative = false;
    if (arg[cursor] == '+' or arg[cursor] == '-') {
        negative = arg[cursor] == '-';
        cursor += 1;
    }
    if (cursor >= arg.len or !std.ascii.isDigit(arg[cursor])) return error.InvalidCharacter;

    const digits_start: usize = cursor;
    var base: u8 = 10;
    if (arg[cursor] == '0') {
        base = 8;
        cursor += 1;
        if (cursor < arg.len and (arg[cursor] == 'x' or arg[cursor] == 'X')) {
            base = 16;
            cursor += 1;
            const hex_start = cursor;
            while (cursor < arg.len and std.ascii.isHex(arg[cursor])) : (cursor += 1) {}
            if (cursor == hex_start) return .{ .magnitude = 0, .negative = negative, .complete = false };
            const magnitude = try parsePrintfMagnitude(arg[hex_start..cursor], base);
            return .{
                .magnitude = magnitude.value,
                .negative = negative,
                .complete = cursor == arg.len,
                .overflow = magnitude.overflow,
            };
        }
        while (cursor < arg.len and arg[cursor] >= '0' and arg[cursor] <= '7') : (cursor += 1) {}
    } else {
        while (cursor < arg.len and std.ascii.isDigit(arg[cursor])) : (cursor += 1) {}
    }
    const magnitude = try parsePrintfMagnitude(arg[digits_start..cursor], base);
    return .{
        .magnitude = magnitude.value,
        .negative = negative,
        .complete = cursor == arg.len,
        .overflow = magnitude.overflow,
    };
}

fn parsePrintfFloat(allocator: std.mem.Allocator, stderr: *std.ArrayList(u8), status: *ExitStatus, arg: []const u8) !f64 {
    if (arg.len == 0) return 0;
    return std.fmt.parseFloat(f64, arg) catch {
        try printfDiagnostic(allocator, stderr, status, "numeric argument required");
        return 0;
    };
}

fn appendEscapedString(allocator: std.mem.Allocator, stdout: *std.ArrayList(u8), text: []const u8) !bool {
    var index: usize = 0;
    while (index < text.len) {
        if (text[index] != '\\') {
            try stdout.append(allocator, text[index]);
            index += 1;
            continue;
        }
        index += 1;
        if (index >= text.len) {
            try stdout.append(allocator, '\\');
        } else if (!try appendEscapedSequence(allocator, stdout, text, &index, .percent_b)) {
            return false;
        }
    }
    return true;
}

const PrintfEscapeMode = enum { format, percent_b };

fn appendEscapedSequence(allocator: std.mem.Allocator, stdout: *std.ArrayList(u8), text: []const u8, index: *usize, mode: PrintfEscapeMode) !bool {
    const byte = text[index.*];
    switch (byte) {
        'a' => try stdout.append(allocator, 0x07),
        'b' => try stdout.append(allocator, 0x08),
        'c' => {
            index.* += 1;
            return false;
        },
        'f' => try stdout.append(allocator, 0x0c),
        'n' => try stdout.append(allocator, '\n'),
        'r' => try stdout.append(allocator, '\r'),
        't' => try stdout.append(allocator, '\t'),
        'v' => try stdout.append(allocator, 0x0b),
        '\\' => try stdout.append(allocator, '\\'),
        '0'...'7' => {
            try appendOctalEscape(allocator, stdout, text, index, mode);
            return true;
        },
        else => {
            try stdout.append(allocator, '\\');
            try stdout.append(allocator, byte);
        },
    }
    index.* += 1;
    return true;
}

fn appendOctalEscape(allocator: std.mem.Allocator, stdout: *std.ArrayList(u8), text: []const u8, index: *usize, mode: PrintfEscapeMode) !void {
    var value: u8 = 0;
    var count: usize = 0;
    var cursor = index.*;
    if (mode == .percent_b and cursor < text.len and text[cursor] == '0') cursor += 1;
    while (cursor < text.len and count < 3 and text[cursor] >= '0' and text[cursor] <= '7') : (count += 1) {
        value = value * 8 + (text[cursor] - '0');
        cursor += 1;
    }
    if (count == 0) {
        try stdout.append(allocator, 0);
        index.* += 1;
    } else {
        try stdout.append(allocator, value);
        index.* = cursor;
    }
}

fn isShellName(name: []const u8) bool {
    if (name.len == 0 or !(std.ascii.isAlphabetic(name[0]) or name[0] == '_')) return false;
    for (name[1..]) |byte| {
        if (!(std.ascii.isAlphabetic(byte) or std.ascii.isDigit(byte) or byte == '_')) return false;
    }
    return true;
}

fn isAliasName(name: []const u8) bool {
    if (name.len == 0) return false;
    for (name) |byte| {
        if (!(std.ascii.isAlphabetic(byte) or std.ascii.isDigit(byte) or byte == '!' or byte == '%' or byte == ',' or byte == '-' or byte == '@' or byte == '_')) return false;
    }
    return true;
}

fn unescapeReadLine(allocator: std.mem.Allocator, raw: []const u8) ![]const u8 {
    var out: std.ArrayList(u8) = .empty;
    errdefer out.deinit(allocator);
    var index: usize = 0;
    while (index < raw.len) {
        if (raw[index] == '\\') {
            index += 1;
            if (index >= raw.len) break;
        }
        try out.append(allocator, raw[index]);
        index += 1;
    }
    return out.toOwnedSlice(allocator);
}

fn nextReadField(text: []const u8, cursor: *usize, ifs: []const u8, honor_escapes: bool) []const u8 {
    cursor.* = skipReadIfsWhitespace(text, cursor.*, ifs, honor_escapes);
    if (cursor.* >= text.len) return "";
    if (isReadIfsNonWhitespace(text[cursor.*], ifs)) {
        cursor.* += 1;
        cursor.* = skipReadIfsWhitespace(text, cursor.*, ifs, honor_escapes);
        return "";
    }
    const start = cursor.*;
    while (cursor.* < text.len) {
        if (honor_escapes and text[cursor.*] == '\\' and cursor.* + 1 < text.len) {
            cursor.* += 2;
            continue;
        }
        if (isReadIfs(text[cursor.*], ifs)) break;
        cursor.* += 1;
    }
    const end = cursor.*;
    if (cursor.* < text.len and isReadIfsWhitespace(text[cursor.*], ifs)) {
        const after_whitespace = skipReadIfsWhitespace(text, cursor.*, ifs, honor_escapes);
        if (after_whitespace < text.len and isReadIfsNonWhitespace(text[after_whitespace], ifs)) {
            cursor.* = after_whitespace + 1;
        }
    } else if (cursor.* < text.len and isReadIfsNonWhitespace(text[cursor.*], ifs)) {
        cursor.* += 1;
    }
    cursor.* = skipReadIfsWhitespace(text, cursor.*, ifs, honor_escapes);
    return text[start..end];
}

fn skipReadIfsWhitespace(text: []const u8, start: usize, ifs: []const u8, honor_escapes: bool) usize {
    var index = start;
    while (index < text.len) {
        if (honor_escapes and text[index] == '\\' and index + 1 < text.len) break;
        if (!isReadIfsWhitespace(text[index], ifs)) break;
        index += 1;
    }
    return index;
}

fn trimTrailingReadIfsWhitespace(text: []const u8, end: usize, ifs: []const u8, honor_escapes: bool) usize {
    var index = end;
    while (index > 0 and isReadIfsWhitespace(text[index - 1], ifs) and !(honor_escapes and isEscapedReadByte(text, index - 1))) : (index -= 1) {}
    return index;
}

fn isEscapedReadByte(text: []const u8, index: usize) bool {
    var backslashes: usize = 0;
    var cursor = index;
    while (cursor > 0 and text[cursor - 1] == '\\') : (cursor -= 1) {
        backslashes += 1;
    }
    return backslashes % 2 == 1;
}

fn isReadIfs(byte: u8, ifs: []const u8) bool {
    return std.mem.findScalar(u8, ifs, byte) != null;
}

fn isDefaultReadIfsWhitespace(byte: u8) bool {
    return byte == ' ' or byte == '\t' or byte == '\n';
}

fn isReadIfsWhitespace(byte: u8, ifs: []const u8) bool {
    return isDefaultReadIfsWhitespace(byte) and isReadIfs(byte, ifs);
}

fn isReadIfsNonWhitespace(byte: u8, ifs: []const u8) bool {
    return !isDefaultReadIfsWhitespace(byte) and isReadIfs(byte, ifs);
}

fn builtinCd(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    const io = options.io orelse return error.MissingIoForBuiltin;

    var arg_index: usize = 1;
    var physical = false;
    while (arg_index < command.argv.len) {
        const option = command.argv[arg_index].text;
        if (std.mem.eql(u8, option, "--")) {
            arg_index += 1;
            break;
        } else if (std.mem.eql(u8, option, "-L")) {
            physical = false;
            arg_index += 1;
        } else if (std.mem.eql(u8, option, "-P")) {
            physical = true;
            arg_index += 1;
        } else if (std.mem.startsWith(u8, option, "-") and !std.mem.eql(u8, option, "-")) {
            return errorResult(self.allocator, 2, "cd", "unsupported option");
        } else {
            break;
        }
    }
    if (command.argv.len > arg_index + 1) return errorResult(self.allocator, 2, "cd", "too many arguments");

    const operand = if (arg_index < command.argv.len) command.argv[arg_index].text else self.getEnv("HOME") orelse return errorResult(self.allocator, 1, "cd", "HOME not set");
    const oldpwd_target = std.mem.eql(u8, operand, "-");
    const target = if (oldpwd_target) self.getEnv("OLDPWD") orelse return errorResult(self.allocator, 1, "cd", "OLDPWD not set") else operand;
    const old_pwd = try self.logicalCwd(io);
    defer self.allocator.free(old_pwd);

    const cd_target = try resolveCdTarget(self, io, target);
    defer cd_target.deinit(self.allocator);

    std.process.setCurrentPath(io, cd_target.path) catch |err| {
        const message = try std.fmt.allocPrint(self.allocator, "{s}: {s}", .{ cd_target.path, cdErrorMessage(err) });
        defer self.allocator.free(message);
        return errorResult(self.allocator, 1, "cd", message);
    };
    const new_pwd = if (physical)
        try self.physicalCwd(io)
    else
        try normalizeLogicalPath(self.allocator, old_pwd, cd_target.path);
    errdefer self.allocator.free(new_pwd);
    try self.setEnv("OLDPWD", old_pwd);
    try self.setEnv("PWD", new_pwd);
    try self.setExported("OLDPWD");
    try self.setExported("PWD");
    const stdout = if (oldpwd_target or cd_target.print_path) try std.fmt.allocPrint(self.allocator, "{s}\n", .{new_pwd}) else try self.allocator.alloc(u8, 0);
    errdefer self.allocator.free(stdout);
    self.allocator.free(new_pwd);
    return .{
        .allocator = self.allocator,
        .status = 0,
        .stdout = stdout,
        .stderr = try self.allocator.alloc(u8, 0),
    };
}

fn cdErrorMessage(err: anyerror) []const u8 {
    return switch (err) {
        error.FileNotFound => "no such file or directory",
        error.NotDir => "not a directory",
        error.AccessDenied, error.PermissionDenied => "permission denied",
        error.NameTooLong => "file name too long",
        else => @errorName(err),
    };
}

const CdTarget = struct {
    path: []const u8,
    print_path: bool = false,
    owned: bool = false,

    fn deinit(self: CdTarget, allocator: std.mem.Allocator) void {
        if (self.owned) allocator.free(self.path);
    }
};

fn resolveCdTarget(self: *Executor, io: std.Io, target: []const u8) !CdTarget {
    if (!shouldSearchCdpath(target)) return .{ .path = target };
    const cdpath = self.getEnv("CDPATH") orelse return .{ .path = target };
    var iter = std.mem.splitScalar(u8, cdpath, ':');
    while (iter.next()) |entry| {
        const candidate_owned = entry.len != 0 and !std.mem.eql(u8, entry, ".");
        const candidate = if (candidate_owned)
            try std.mem.concat(self.allocator, u8, &.{ entry, "/", target })
        else
            target;
        errdefer if (candidate_owned) self.allocator.free(candidate);
        var dir = std.Io.Dir.cwd().openDir(io, candidate, .{}) catch {
            if (candidate_owned) self.allocator.free(candidate);
            continue;
        };
        dir.close(io);
        return .{ .path = candidate, .print_path = entry.len != 0, .owned = candidate_owned };
    }
    return .{ .path = target };
}

fn shouldSearchCdpath(target: []const u8) bool {
    if (target.len == 0 or target[0] == '/') return false;
    const end = std.mem.indexOfScalar(u8, target, '/') orelse target.len;
    const first = target[0..end];
    return !std.mem.eql(u8, first, ".") and !std.mem.eql(u8, first, "..");
}

fn pathHasDotOrDotDotComponent(path: []const u8) bool {
    var iter = std.mem.splitScalar(u8, path, '/');
    while (iter.next()) |component| {
        if (std.mem.eql(u8, component, ".") or std.mem.eql(u8, component, "..")) return true;
    }
    return false;
}

fn builtinPwd(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    const io = options.io orelse return error.MissingIoForBuiltin;
    var arg_index: usize = 1;
    var physical = false;
    while (arg_index < command.argv.len) {
        const option = command.argv[arg_index].text;
        if (std.mem.eql(u8, option, "--")) {
            arg_index += 1;
            break;
        } else if (std.mem.eql(u8, option, "-L")) {
            physical = false;
            arg_index += 1;
        } else if (std.mem.eql(u8, option, "-P")) {
            physical = true;
            arg_index += 1;
        } else if (std.mem.startsWith(u8, option, "-")) {
            return errorResult(self.allocator, 2, "pwd", "unsupported option");
        } else {
            break;
        }
    }
    if (arg_index < command.argv.len) return errorResult(self.allocator, 2, "pwd", "too many arguments");

    const cwd = if (physical) try self.physicalCwd(io) else blk: {
        const logical = try self.logicalCwd(io);
        defer self.allocator.free(logical);
        break :blk try self.allocator.dupe(u8, logical);
    };
    defer self.allocator.free(cwd);
    const stdout = try std.fmt.allocPrint(self.allocator, "{s}\n", .{cwd});
    errdefer self.allocator.free(stdout);
    return .{
        .allocator = self.allocator,
        .status = 0,
        .stdout = stdout,
        .stderr = try self.allocator.alloc(u8, 0),
    };
}

fn builtinTrap(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    if (command.argv.len == 1) return listTraps(self);

    var action_index: usize = 1;
    if (std.mem.eql(u8, command.argv[action_index].text, "--")) {
        action_index += 1;
        if (action_index >= command.argv.len) return listTraps(self);
    }
    const action = command.argv[action_index].text;
    if (action_index + 1 >= command.argv.len) return trapError(self, 2, "missing signal");

    for (command.argv[action_index + 1 ..]) |signal_word| {
        const name = try normalizeTrapName(self.allocator, signal_word.text);
        defer self.allocator.free(name);
        if (!validTrapName(name)) {
            const message = try std.fmt.allocPrint(self.allocator, "{s}: invalid signal specification", .{signal_word.text});
            defer self.allocator.free(message);
            return trapError(self, 1, message);
        }
        if (!options.interactive and self.ignoredTrapSignalAtEntry(name)) continue;
        if (std.mem.eql(u8, action, "-")) {
            self.clearTrap(name);
        } else {
            try self.setTrap(name, action);
        }
    }
    return emptyResult(self.allocator, 0);
}

fn trapError(self: *Executor, status: ExitStatus, message: []const u8) !CommandResult {
    setSpecialBuiltinErrorConsequence(self, status);
    return errorResult(self.allocator, status, "trap", message);
}

fn listTraps(self: *Executor) !CommandResult {
    var names: std.ArrayList([]const u8) = .empty;
    defer names.deinit(self.allocator);
    var iter = self.traps.iterator();
    while (iter.next()) |entry| try names.append(self.allocator, entry.key_ptr.*);
    std.mem.sort([]const u8, names.items, {}, lessThanString);

    var stdout: std.ArrayList(u8) = .empty;
    errdefer stdout.deinit(self.allocator);
    for (names.items) |name| {
        const quoted = try singleQuote(self.allocator, self.traps.get(name).?);
        defer self.allocator.free(quoted);
        try stdout.print(self.allocator, "trap -- {s} {s}\n", .{ quoted, name });
    }
    return .{ .allocator = self.allocator, .status = 0, .stdout = try stdout.toOwnedSlice(self.allocator), .stderr = try self.allocator.alloc(u8, 0) };
}

fn normalizeTrapName(allocator: std.mem.Allocator, raw: []const u8) ![]const u8 {
    if (std.mem.eql(u8, raw, "0")) return allocator.dupe(u8, "EXIT");
    if (parseTrapSignalNumber(raw)) |name| return allocator.dupe(u8, name);
    const start: usize = if (std.ascii.startsWithIgnoreCase(raw, "SIG") and raw.len > 3) 3 else 0;
    if (start >= raw.len) return allocator.dupe(u8, raw);
    const name = try allocator.alloc(u8, raw.len - start);
    for (raw[start..], 0..) |byte, index| name[index] = std.ascii.toUpper(byte);
    return name;
}

fn validTrapName(name: []const u8) bool {
    return std.mem.eql(u8, name, "EXIT") or signalFromTrapName(name) != null;
}

fn parseTrapSignalNumber(raw: []const u8) ?[]const u8 {
    if (raw.len == 0) return null;
    for (raw) |byte| if (!std.ascii.isDigit(byte)) return null;
    const number = std.fmt.parseInt(u8, raw, 10) catch return null;
    return signalNameFromNumber(number);
}

fn singleQuote(allocator: std.mem.Allocator, text: []const u8) ![]const u8 {
    var out: std.ArrayList(u8) = .empty;
    errdefer out.deinit(allocator);
    try out.append(allocator, '\'');
    for (text) |byte| {
        if (byte == '\'') {
            try out.appendSlice(allocator, "'\\''");
        } else {
            try out.append(allocator, byte);
        }
    }
    try out.append(allocator, '\'');
    return out.toOwnedSlice(allocator);
}

fn builtinAlias(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    _ = options;
    if (command.argv.len == 1) return listAliases(self, null);

    var stdout: std.ArrayList(u8) = .empty;
    errdefer stdout.deinit(self.allocator);
    for (command.argv[1..]) |arg| {
        if (std.mem.indexOfScalar(u8, arg.text, '=')) |equals| {
            const name = arg.text[0..equals];
            if (!isAliasName(name)) return errorResult(self.allocator, 2, "alias", "invalid alias name");
            try self.setAlias(name, arg.text[equals + 1 ..]);
        } else {
            if (!isAliasName(arg.text)) return errorResult(self.allocator, 2, "alias", "invalid alias name");
            const value = self.aliases.get(arg.text) orelse return errorResult(self.allocator, 1, "alias", "not found");
            const quoted = try singleQuote(self.allocator, value);
            defer self.allocator.free(quoted);
            try stdout.print(self.allocator, "{s}={s}\n", .{ arg.text, quoted });
        }
    }
    return .{ .allocator = self.allocator, .status = 0, .stdout = try stdout.toOwnedSlice(self.allocator), .stderr = try self.allocator.alloc(u8, 0) };
}

fn builtinAbbr(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    _ = options;
    if (command.argv.len == 1 or (command.argv.len == 2 and std.mem.eql(u8, command.argv[1].text, "--list"))) return listAbbreviations(self);
    if (std.mem.eql(u8, command.argv[1].text, "--erase")) {
        if (command.argv.len != 3) return errorResult(self.allocator, 2, "abbr", "usage: abbr --erase NAME");
        if (!isShellName(command.argv[2].text)) return errorResult(self.allocator, 2, "abbr", "invalid abbreviation name");
        if (!self.unsetAbbreviation(command.argv[2].text)) return errorResult(self.allocator, 1, "abbr", "not found");
        return emptyResult(self.allocator, 0);
    }
    if (std.mem.startsWith(u8, command.argv[1].text, "--")) return errorResult(self.allocator, 2, "abbr", "unsupported option");
    if (command.argv.len != 3) return errorResult(self.allocator, 2, "abbr", "usage: abbr NAME EXPANSION");
    if (!isShellName(command.argv[1].text)) return errorResult(self.allocator, 2, "abbr", "invalid abbreviation name");
    try self.setAbbreviation(command.argv[1].text, command.argv[2].text);
    return emptyResult(self.allocator, 0);
}

fn listAbbreviations(self: *Executor) !CommandResult {
    var names: std.ArrayList([]const u8) = .empty;
    defer names.deinit(self.allocator);
    var iter = self.abbreviations.iterator();
    while (iter.next()) |entry| try names.append(self.allocator, entry.key_ptr.*);
    std.mem.sort([]const u8, names.items, {}, lessThanString);

    var stdout: std.ArrayList(u8) = .empty;
    errdefer stdout.deinit(self.allocator);
    for (names.items) |name| {
        const quoted = try singleQuote(self.allocator, self.abbreviations.get(name).?);
        defer self.allocator.free(quoted);
        try stdout.print(self.allocator, "abbr {s} {s}\n", .{ name, quoted });
    }
    return .{ .allocator = self.allocator, .status = 0, .stdout = try stdout.toOwnedSlice(self.allocator), .stderr = try self.allocator.alloc(u8, 0) };
}

fn listAliases(self: *Executor, prefix: ?[]const u8) !CommandResult {
    _ = prefix;
    var names: std.ArrayList([]const u8) = .empty;
    defer names.deinit(self.allocator);
    var iter = self.aliases.iterator();
    while (iter.next()) |entry| try names.append(self.allocator, entry.key_ptr.*);
    std.mem.sort([]const u8, names.items, {}, lessThanString);

    var stdout: std.ArrayList(u8) = .empty;
    errdefer stdout.deinit(self.allocator);
    for (names.items) |name| {
        const quoted = try singleQuote(self.allocator, self.aliases.get(name).?);
        defer self.allocator.free(quoted);
        try stdout.print(self.allocator, "{s}={s}\n", .{ name, quoted });
    }
    return .{ .allocator = self.allocator, .status = 0, .stdout = try stdout.toOwnedSlice(self.allocator), .stderr = try self.allocator.alloc(u8, 0) };
}

fn builtinUnalias(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    _ = options;
    if (command.argv.len == 1) return errorResult(self.allocator, 2, "unalias", "missing operand");
    var index: usize = 1;
    const option_terminated = std.mem.eql(u8, command.argv[index].text, "--");
    if (option_terminated) index += 1;
    if (index >= command.argv.len) return errorResult(self.allocator, 2, "unalias", "missing operand");
    if (!option_terminated and std.mem.startsWith(u8, command.argv[index].text, "-") and !std.mem.eql(u8, command.argv[index].text, "-a")) return errorResult(self.allocator, 2, "unalias", "unsupported option");
    if (!option_terminated and std.mem.eql(u8, command.argv[index].text, "-a")) {
        var iter = self.aliases.iterator();
        while (iter.next()) |entry| {
            self.allocator.free(entry.key_ptr.*);
            self.allocator.free(entry.value_ptr.*);
        }
        self.aliases.clearRetainingCapacity();
        index += 1;
        if (index == command.argv.len) return emptyResult(self.allocator, 0);
    }
    for (command.argv[index..]) |arg| {
        if (!isAliasName(arg.text)) return errorResult(self.allocator, 2, "unalias", "invalid alias name");
        if (!self.unsetAlias(arg.text)) return errorResult(self.allocator, 1, "unalias", "not found");
    }
    return emptyResult(self.allocator, 0);
}

fn builtinGetopts(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    _ = options;
    if (command.argv.len < 3) return errorResult(self.allocator, 2, "getopts", "usage: getopts optstring name [arg ...]");
    const optstring = command.argv[1].text;
    const name = command.argv[2].text;
    if (!isValidGetoptsOptstring(optstring)) return errorResult(self.allocator, 2, "getopts", "invalid optstring");
    if (!isShellName(name)) return errorResult(self.allocator, 2, "getopts", "invalid variable name");

    const arg_count = if (command.argv.len > 3) command.argv.len - 3 else self.currentPositionals().params.len;
    const args = try self.allocator.alloc([]const u8, arg_count);
    defer self.allocator.free(args);
    if (command.argv.len > 3) {
        for (command.argv[3..], 0..) |arg, index| args[index] = arg.text;
    } else {
        const positionals = self.currentPositionals().params;
        for (positionals, 0..) |param, index| args[index] = param;
    }

    var optind = getOptind(self.*);
    if (optind != self.getopts_last_optind) self.getopts_offset = 1;
    self.getopts_last_optind = optind;
    const silent = optstring.len > 0 and optstring[0] == ':';

    if (optind == 0) optind = 1;
    if (optind > args.len) return finishGetoptsEnd(self, name, optind);

    const arg = args[optind - 1];
    if (arg.len < 2 or arg[0] != '-' or std.mem.eql(u8, arg, "-")) return finishGetoptsEnd(self, name, optind);
    if (std.mem.eql(u8, arg, "--")) return finishGetoptsEnd(self, name, optind + 1);

    if (self.getopts_offset >= arg.len) self.getopts_offset = 1;
    const option = arg[self.getopts_offset];
    const next_offset = self.getopts_offset + 1;
    const spec = getoptsSpec(optstring, option);
    if (spec == .invalid) {
        if (next_offset < arg.len) {
            self.getopts_offset = next_offset;
        } else {
            optind += 1;
            self.getopts_offset = 1;
        }
        self.getopts_last_optind = optind;
        try setOptind(self, optind);
        if (silent) {
            const optarg = [_]u8{option};
            try self.setEnv("OPTARG", optarg[0..]);
            try self.setEnv(name, "?");
            return emptyResult(self.allocator, 0);
        }
        try unsetGetoptsOptarg(self);
        try self.setEnv(name, "?");
        const stderr = try std.fmt.allocPrint(self.allocator, "getopts: illegal option -- {c}\n", .{option});
        errdefer self.allocator.free(stderr);
        return .{ .allocator = self.allocator, .status = 0, .stdout = try self.allocator.alloc(u8, 0), .stderr = stderr };
    }

    const name_value = [_]u8{option};
    try self.setEnv(name, name_value[0..]);
    if (spec == .requires_arg) {
        if (next_offset < arg.len) {
            try self.setEnv("OPTARG", arg[next_offset..]);
            optind += 1;
            self.getopts_offset = 1;
        } else if (optind < args.len) {
            try self.setEnv("OPTARG", args[optind]);
            optind += 2;
            self.getopts_offset = 1;
        } else {
            optind += 1;
            self.getopts_offset = 1;
            self.getopts_last_optind = optind;
            try setOptind(self, optind);
            const optarg = [_]u8{option};
            try self.setEnv("OPTARG", optarg[0..]);
            if (silent) {
                try self.setEnv(name, ":");
                return emptyResult(self.allocator, 0);
            }
            try unsetGetoptsOptarg(self);
            try self.setEnv(name, "?");
            const stderr = try std.fmt.allocPrint(self.allocator, "getopts: option requires an argument -- {c}\n", .{option});
            errdefer self.allocator.free(stderr);
            return .{ .allocator = self.allocator, .status = 0, .stdout = try self.allocator.alloc(u8, 0), .stderr = stderr };
        }
    } else {
        try unsetGetoptsOptarg(self);
        if (next_offset < arg.len) {
            self.getopts_offset = next_offset;
        } else {
            optind += 1;
            self.getopts_offset = 1;
        }
    }

    self.getopts_last_optind = optind;
    try setOptind(self, optind);
    return emptyResult(self.allocator, 0);
}

const GetoptsSpec = enum { invalid, no_arg, requires_arg };

fn isValidGetoptsOptstring(optstring: []const u8) bool {
    const start: usize = if (optstring.len > 0 and optstring[0] == ':') 1 else 0;
    var index = start;
    while (index < optstring.len) : (index += 1) {
        switch (optstring[index]) {
            '?' => return false,
            ':' => if (index == start or optstring[index - 1] == ':') return false,
            else => {},
        }
    }
    return true;
}

fn getoptsSpec(optstring: []const u8, option: u8) GetoptsSpec {
    if (option == ':' or option == '?') return .invalid;
    const start: usize = if (optstring.len > 0 and optstring[0] == ':') 1 else 0;
    var index = start;
    while (index < optstring.len) : (index += 1) {
        if (optstring[index] == ':') continue;
        if (optstring[index] != option) continue;
        return if (index + 1 < optstring.len and optstring[index + 1] == ':') .requires_arg else .no_arg;
    }
    return .invalid;
}

fn getOptind(self: Executor) usize {
    const text = self.getEnv("OPTIND") orelse return 1;
    const parsed = std.fmt.parseInt(usize, text, 10) catch return 1;
    return if (parsed == 0) 1 else parsed;
}

fn setOptind(self: *Executor, optind: usize) !void {
    const text = try std.fmt.allocPrint(self.allocator, "{d}", .{optind});
    defer self.allocator.free(text);
    try self.setEnv("OPTIND", text);
}

fn unsetGetoptsOptarg(self: *Executor) !void {
    if (self.isReadonly("OPTARG")) return error.ReadonlyVariable;
    self.unsetEnv("OPTARG");
}

fn finishGetoptsEnd(self: *Executor, name: []const u8, optind: usize) !CommandResult {
    self.getopts_offset = 1;
    self.getopts_last_optind = optind;
    try setOptind(self, optind);
    try self.setEnv(name, "?");
    try unsetGetoptsOptarg(self);
    return emptyResult(self.allocator, 1);
}

fn builtinExport(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    _ = options;
    var index: usize = 1;
    const option_terminated = index < command.argv.len and std.mem.eql(u8, command.argv[index].text, "--");
    if (option_terminated) index += 1;
    if (index >= command.argv.len) return listExported(self);
    if (!option_terminated and std.mem.eql(u8, command.argv[index].text, "-p")) {
        if (command.argv.len != index + 1) return variableBuiltinUsageError(self, "export", "too many arguments");
        return listExported(self);
    }
    if (!option_terminated and std.mem.startsWith(u8, command.argv[index].text, "-") and !std.mem.eql(u8, command.argv[index].text, "-")) return variableBuiltinUsageError(self, "export", "unsupported option");

    for (command.argv[index..]) |arg| {
        const assignment = std.mem.indexOfScalar(u8, arg.text, '=');
        const name = if (assignment) |equals| arg.text[0..equals] else arg.text;
        if (!isShellName(name)) return variableBuiltinUsageError(self, "export", "invalid variable name");
        if (assignment) |equals| {
            if (self.isReadonly(name)) return variableBuiltinUsageError(self, "export", "readonly variable");
            try self.setEnv(name, arg.text[equals + 1 ..]);
        }
        try self.setExported(name);
    }
    return emptyResult(self.allocator, 0);
}

fn listExported(self: *Executor) !CommandResult {
    var names: std.ArrayList([]const u8) = .empty;
    defer names.deinit(self.allocator);
    var iter = self.exported.iterator();
    while (iter.next()) |entry| try names.append(self.allocator, entry.key_ptr.*);
    std.mem.sort([]const u8, names.items, {}, lessThanString);

    var stdout: std.ArrayList(u8) = .empty;
    errdefer stdout.deinit(self.allocator);
    for (names.items) |name| {
        try stdout.appendSlice(self.allocator, "export ");
        try stdout.appendSlice(self.allocator, name);
        if (self.env.get(name)) |value| {
            try stdout.append(self.allocator, '=');
            try appendShellSingleQuoted(self.allocator, &stdout, value);
        }
        try stdout.append(self.allocator, '\n');
    }
    return .{ .allocator = self.allocator, .status = 0, .stdout = try stdout.toOwnedSlice(self.allocator), .stderr = try self.allocator.alloc(u8, 0) };
}

fn builtinUnset(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    _ = options;
    var mode: enum { variable, function } = .variable;
    var index: usize = 1;
    while (index < command.argv.len) {
        const option = command.argv[index].text;
        if (std.mem.eql(u8, option, "--")) {
            index += 1;
            break;
        } else if (std.mem.eql(u8, option, "-v")) {
            mode = .variable;
            index += 1;
        } else if (std.mem.eql(u8, option, "-f")) {
            mode = .function;
            index += 1;
        } else if (std.mem.startsWith(u8, option, "-") and !std.mem.eql(u8, option, "-")) {
            return variableBuiltinUsageError(self, "unset", "unsupported option");
        } else {
            break;
        }
    }
    for (command.argv[index..]) |arg| {
        if (!isShellName(arg.text)) return variableBuiltinUsageError(self, "unset", "invalid variable name");
        switch (mode) {
            .variable => {
                if (self.isReadonly(arg.text)) return variableBuiltinUsageError(self, "unset", "readonly variable");
                self.unsetEnv(arg.text);
            },
            .function => self.unsetFunction(arg.text),
        }
    }
    return emptyResult(self.allocator, 0);
}

fn builtinReadonly(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    _ = options;
    var index: usize = 1;
    const option_terminated = index < command.argv.len and std.mem.eql(u8, command.argv[index].text, "--");
    if (option_terminated) index += 1;
    if (index >= command.argv.len) return listReadonly(self);
    if (!option_terminated and std.mem.eql(u8, command.argv[index].text, "-p")) {
        if (command.argv.len != index + 1) return variableBuiltinUsageError(self, "readonly", "too many arguments");
        return listReadonly(self);
    }
    if (!option_terminated and std.mem.startsWith(u8, command.argv[index].text, "-") and !std.mem.eql(u8, command.argv[index].text, "-")) return variableBuiltinUsageError(self, "readonly", "unsupported option");
    for (command.argv[index..]) |arg| {
        if (std.mem.indexOfScalar(u8, arg.text, '=')) |equals| {
            const name = arg.text[0..equals];
            if (!isShellName(name)) return variableBuiltinUsageError(self, "readonly", "invalid variable name");
            if (self.isReadonly(name)) return variableBuiltinUsageError(self, "readonly", "readonly variable");
            try self.setEnv(name, arg.text[equals + 1 ..]);
            try self.setReadonly(name);
        } else {
            if (!isShellName(arg.text)) return variableBuiltinUsageError(self, "readonly", "invalid variable name");
            try self.setReadonly(arg.text);
        }
    }
    return emptyResult(self.allocator, 0);
}

fn listReadonly(self: *Executor) !CommandResult {
    var names: std.ArrayList([]const u8) = .empty;
    defer names.deinit(self.allocator);
    var iter = self.readonly.iterator();
    while (iter.next()) |entry| try names.append(self.allocator, entry.key_ptr.*);
    std.mem.sort([]const u8, names.items, {}, lessThanString);
    var stdout: std.ArrayList(u8) = .empty;
    errdefer stdout.deinit(self.allocator);
    for (names.items) |name| {
        try stdout.appendSlice(self.allocator, "readonly ");
        try stdout.appendSlice(self.allocator, name);
        if (self.env.get(name)) |value| {
            try stdout.append(self.allocator, '=');
            try appendShellSingleQuoted(self.allocator, &stdout, value);
        }
        try stdout.append(self.allocator, '\n');
    }
    return .{ .allocator = self.allocator, .status = 0, .stdout = try stdout.toOwnedSlice(self.allocator), .stderr = try self.allocator.alloc(u8, 0) };
}

fn appendShellSingleQuoted(allocator: std.mem.Allocator, out: *std.ArrayList(u8), value: []const u8) !void {
    try out.append(allocator, '\'');
    for (value) |byte| {
        if (byte == '\'') {
            try out.appendSlice(allocator, "'\\''");
        } else {
            try out.append(allocator, byte);
        }
    }
    try out.append(allocator, '\'');
}

fn variableBuiltinUsageError(self: *Executor, name: []const u8, message: []const u8) !CommandResult {
    setSpecialBuiltinErrorConsequence(self, 2);
    return errorResult(self.allocator, 2, name, message);
}

fn builtinShift(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    _ = options;
    const positionals = self.currentPositionalsPtr();
    const amount: usize = if (command.argv.len == 1) 1 else blk: {
        if (command.argv.len > 2) return shiftUsageError(self, "too many arguments");
        break :blk std.fmt.parseInt(usize, command.argv[1].text, 10) catch return shiftUsageError(self, "numeric argument required");
    };
    if (amount > positionals.params.len) {
        setSpecialBuiltinErrorConsequence(self, 1);
        return errorResult(self.allocator, 1, "shift", "shift count out of range");
    }
    if (positionals.owned) {
        for (positionals.params[0..amount]) |param| self.allocator.free(param);
        std.mem.copyForwards([]const u8, positionals.params[0 .. positionals.params.len - amount], positionals.params[amount..]);
        positionals.params = try self.allocator.realloc(positionals.params, positionals.params.len - amount);
    } else if (amount != 0) {
        positionals.params = &.{};
    }
    try positionals.rebuildDerived(self.allocator);
    return emptyResult(self.allocator, 0);
}

fn shiftUsageError(self: *Executor, message: []const u8) !CommandResult {
    setSpecialBuiltinErrorConsequence(self, 2);
    return errorResult(self.allocator, 2, "shift", message);
}

const RlimitValue = @TypeOf(@as(std.posix.rlimit, undefined).cur);

const UlimitResource = struct {
    option: u8,
    name: []const u8,
    unit: []const u8,
    scale: RlimitValue,
    resource: ?std.posix.rlimit_resource,
};

fn rlimitResource(comptime name: []const u8) ?std.posix.rlimit_resource {
    return switch (@typeInfo(std.posix.rlimit_resource)) {
        .@"enum" => blk: {
            if (@hasField(std.posix.rlimit_resource, name)) break :blk @field(std.posix.rlimit_resource, name);
            if (@hasDecl(std.posix.rlimit_resource, name)) break :blk @field(std.posix.rlimit_resource, name);
            break :blk null;
        },
        else => null,
    };
}

const ulimit_resources = [_]UlimitResource{
    .{ .option = 'c', .name = "core file size", .unit = "blocks", .scale = 512, .resource = rlimitResource("CORE") },
    .{ .option = 'd', .name = "data seg size", .unit = "kbytes", .scale = 1024, .resource = rlimitResource("DATA") },
    .{ .option = 'f', .name = "file size", .unit = "blocks", .scale = 512, .resource = rlimitResource("FSIZE") },
    .{ .option = 'n', .name = "open files", .unit = "descriptors", .scale = 1, .resource = rlimitResource("NOFILE") },
    .{ .option = 's', .name = "stack size", .unit = "kbytes", .scale = 1024, .resource = rlimitResource("STACK") },
    .{ .option = 'v', .name = "virtual memory", .unit = "kbytes", .scale = 1024, .resource = rlimitResource("AS") },
    .{ .option = 't', .name = "cpu time", .unit = "seconds", .scale = 1, .resource = rlimitResource("CPU") },
};

const UlimitOptions = struct {
    hard: bool = false,
    soft: bool = false,
    all: bool = false,
    selected: [ulimit_resources.len]bool = [_]bool{false} ** ulimit_resources.len,
    selected_count: usize = 0,
    arg_index: usize = 1,
};

fn builtinUlimit(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    _ = options;
    var parsed = parseUlimitOptions(command) catch |err| return ulimitOptionError(self, err);
    if (command.argv.len > parsed.arg_index + 1) return errorResult(self.allocator, 2, "ulimit", "too many arguments");
    const has_operand = parsed.arg_index < command.argv.len;
    if (parsed.all and has_operand) return errorResult(self.allocator, 2, "ulimit", "cannot set all resources");
    if (parsed.selected_count == 0 and !parsed.all) {
        selectUlimitResource(&parsed, 'f');
    }
    if (has_operand) return setUlimit(self, command.argv[parsed.arg_index].text, parsed);
    return reportUlimit(self, parsed);
}

const UlimitOptionError = error{UnsupportedOption};

fn parseUlimitOptions(command: ir.SimpleCommand) UlimitOptionError!UlimitOptions {
    var parsed: UlimitOptions = .{};
    while (parsed.arg_index < command.argv.len) {
        const arg = command.argv[parsed.arg_index].text;
        if (std.mem.eql(u8, arg, "--")) {
            parsed.arg_index += 1;
            break;
        }
        if (arg.len < 2 or arg[0] != '-') break;
        parsed.arg_index += 1;
        for (arg[1..]) |option| switch (option) {
            'H' => parsed.hard = true,
            'S' => parsed.soft = true,
            'a' => parsed.all = true,
            'c', 'd', 'f', 'n', 's', 'v', 't' => selectUlimitResource(&parsed, option),
            else => return error.UnsupportedOption,
        };
    }
    return parsed;
}

fn selectUlimitResource(parsed: *UlimitOptions, option: u8) void {
    for (ulimit_resources, 0..) |spec, index| {
        if (spec.option != option) continue;
        if (!parsed.selected[index]) {
            parsed.selected[index] = true;
            parsed.selected_count += 1;
        }
        return;
    }
    unreachable;
}

fn ulimitOptionError(self: *Executor, err: UlimitOptionError) !CommandResult {
    return switch (err) {
        error.UnsupportedOption => errorResult(self.allocator, 2, "ulimit", "unsupported option"),
    };
}

fn reportUlimit(self: *Executor, options: UlimitOptions) !CommandResult {
    if (options.all or options.selected_count > 1) {
        var stdout: std.ArrayList(u8) = .empty;
        errdefer stdout.deinit(self.allocator);
        for (ulimit_resources, 0..) |spec, index| {
            if (!options.all and !options.selected[index]) continue;
            if (spec.resource == null) continue;
            try appendUlimitReportLine(self.allocator, &stdout, spec, options);
        }
        return .{ .allocator = self.allocator, .status = 0, .stdout = try stdout.toOwnedSlice(self.allocator), .stderr = try self.allocator.alloc(u8, 0) };
    }
    const spec = selectedUlimitSpec(options) orelse unreachable;
    if (spec.resource == null) return unavailableUlimitResource(self, spec.option);
    const limits = readUlimitLimits(self, spec) orelse return errorResult(self.allocator, 1, "ulimit", "getrlimit failed");
    const text = try formatUlimitValue(self.allocator, selectedRlimitValue(limits, options), spec.scale);
    defer self.allocator.free(text);
    return stdoutLine(self.allocator, text, 0);
}

fn setUlimit(self: *Executor, operand: []const u8, options: UlimitOptions) !CommandResult {
    if (options.selected_count != 1) return errorResult(self.allocator, 2, "ulimit", "requires exactly one resource");
    const spec = selectedUlimitSpec(options) orelse unreachable;
    const resource = spec.resource orelse return unavailableUlimitResource(self, spec.option);
    var limits = readUlimitLimits(self, spec) orelse return errorResult(self.allocator, 1, "ulimit", "getrlimit failed");
    const value = parseUlimitLimit(operand, spec.scale) orelse return errorResult(self.allocator, 2, "ulimit", "invalid limit");
    const set_soft = options.soft or !options.hard;
    const set_hard = options.hard or !options.soft;
    if (set_soft) limits.cur = value;
    if (set_hard) limits.max = value;
    std.posix.setrlimit(resource, limits) catch |err| switch (err) {
        error.PermissionDenied => return errorResult(self.allocator, 1, "ulimit", "permission denied"),
        error.LimitTooBig => return errorResult(self.allocator, 1, "ulimit", "limit too large"),
        error.Unexpected => return errorResult(self.allocator, 1, "ulimit", "setrlimit failed"),
    };
    return emptyResult(self.allocator, 0);
}

fn selectedUlimitSpec(options: UlimitOptions) ?UlimitResource {
    for (ulimit_resources, 0..) |spec, index| {
        if (options.selected[index]) return spec;
    }
    return null;
}

fn readUlimitLimits(self: *Executor, spec: UlimitResource) ?std.posix.rlimit {
    _ = self;
    return std.posix.getrlimit(spec.resource.?) catch null;
}

fn selectedRlimitValue(limits: std.posix.rlimit, options: UlimitOptions) RlimitValue {
    return if (options.hard and !options.soft) limits.max else limits.cur;
}

fn parseUlimitLimit(operand: []const u8, scale: RlimitValue) ?RlimitValue {
    if (std.mem.eql(u8, operand, "unlimited")) return std.c.RLIM.INFINITY;
    if (operand.len == 0) return null;
    for (operand) |char| {
        if (!std.ascii.isDigit(char)) return null;
    }
    const units = std.fmt.parseInt(u128, operand, 10) catch return null;
    const raw = std.math.mul(u128, units, @intCast(scale)) catch return null;
    if (raw > std.math.maxInt(RlimitValue)) return null;
    return @intCast(raw);
}

fn formatUlimitValue(allocator: std.mem.Allocator, value: RlimitValue, scale: RlimitValue) ![]u8 {
    if (value == std.c.RLIM.INFINITY) return allocator.dupe(u8, "unlimited");
    return std.fmt.allocPrint(allocator, "{d}", .{@divTrunc(value, scale)});
}

fn appendUlimitReportLine(allocator: std.mem.Allocator, stdout: *std.ArrayList(u8), spec: UlimitResource, options: UlimitOptions) !void {
    const limits = std.posix.getrlimit(spec.resource.?) catch return;
    const value = try formatUlimitValue(allocator, selectedRlimitValue(limits, options), spec.scale);
    defer allocator.free(value);
    const line = try std.fmt.allocPrint(allocator, "{s} ({s}) {s}\n", .{ spec.name, spec.unit, value });
    defer allocator.free(line);
    try stdout.appendSlice(allocator, line);
}

fn unavailableUlimitResource(self: *Executor, option: u8) !CommandResult {
    const message = try std.fmt.allocPrint(self.allocator, "-{c}: resource unavailable", .{option});
    defer self.allocator.free(message);
    return errorResult(self.allocator, 2, "ulimit", message);
}

fn builtinUmask(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    _ = options;
    var arg_index: usize = 1;
    var option_terminated = false;
    var symbolic_output = false;
    while (arg_index < command.argv.len) {
        const option = command.argv[arg_index].text;
        if (std.mem.eql(u8, option, "--")) {
            option_terminated = true;
            arg_index += 1;
            break;
        } else if (std.mem.eql(u8, option, "-S")) {
            symbolic_output = true;
            arg_index += 1;
        } else if (std.mem.startsWith(u8, option, "-")) {
            break;
        } else {
            break;
        }
    }
    if (command.argv.len > arg_index + 1) return errorResult(self.allocator, 2, "umask", "too many arguments");
    const old = shellUmask(0);
    _ = shellUmask(old);
    if (arg_index >= command.argv.len) {
        if (symbolic_output) return symbolicUmaskResult(self.allocator, old);
        const stdout = try std.fmt.allocPrint(self.allocator, "{o:0>4}\n", .{@as(u16, @intCast(old & 0o777))});
        errdefer self.allocator.free(stdout);
        return .{ .allocator = self.allocator, .status = 0, .stdout = stdout, .stderr = try self.allocator.alloc(u8, 0) };
    }
    const operand = command.argv[arg_index].text;
    if (!option_terminated and std.mem.startsWith(u8, operand, "-")) return errorResult(self.allocator, 2, "umask", "unsupported option");
    const new_mask = parseOctalUmask(operand) orelse blk: {
        break :blk parseSymbolicUmask(operand, old) orelse return errorResult(self.allocator, 2, "umask", "invalid mask");
    };
    _ = shellUmask(new_mask);
    return emptyResult(self.allocator, 0);
}

fn parseOctalUmask(operand: []const u8) ?u16 {
    if (operand.len == 0) return null;
    for (operand) |char| {
        if (char < '0' or char > '7') return null;
    }
    return std.fmt.parseInt(u16, operand, 8) catch null;
}

fn parseSymbolicUmask(operand: []const u8, current_mask: u32) ?u16 {
    if (operand.len == 0 or std.ascii.isDigit(operand[0])) return null;
    var permissions: u16 = @intCast((~current_mask) & 0o777);
    const original_permissions = permissions;
    var index: usize = 0;
    while (index < operand.len) {
        var who_bits: u16 = 0;
        while (index < operand.len) : (index += 1) {
            switch (operand[index]) {
                'u' => who_bits |= 0o700,
                'g' => who_bits |= 0o070,
                'o' => who_bits |= 0o007,
                'a' => who_bits |= 0o777,
                else => break,
            }
        }
        if (who_bits == 0) who_bits = 0o777;
        if (index >= operand.len) return null;
        while (index < operand.len and operand[index] != ',') {
            const op = operand[index];
            if (op != '+' and op != '-' and op != '=') return null;
            index += 1;

            var action_permissions: u16 = 0;
            while (index < operand.len and operand[index] != ',' and operand[index] != '+' and operand[index] != '-' and operand[index] != '=') : (index += 1) {
                switch (operand[index]) {
                    'r' => action_permissions |= 0o444,
                    'w' => action_permissions |= 0o222,
                    'x' => action_permissions |= 0o111,
                    'X' => {
                        if (original_permissions & 0o111 != 0) action_permissions |= 0o111;
                    },
                    's', 't' => {},
                    'u' => action_permissions |= copySymbolicPermissions(original_permissions, 0o700),
                    'g' => action_permissions |= copySymbolicPermissions(original_permissions, 0o070),
                    'o' => action_permissions |= copySymbolicPermissions(original_permissions, 0o007),
                    else => return null,
                }
            }
            const affected_permissions = action_permissions & who_bits;
            switch (op) {
                '+' => permissions |= affected_permissions,
                '-' => permissions &= ~affected_permissions,
                '=' => permissions = (permissions & ~who_bits) | affected_permissions,
                else => unreachable,
            }
        }
        if (index < operand.len) {
            if (operand[index] != ',') return null;
            index += 1;
            if (index == operand.len) return null;
        }
    }
    return @intCast((~permissions) & 0o777);
}

fn copySymbolicPermissions(permissions: u16, source_bits: u16) u16 {
    const source: u16 = switch (source_bits) {
        0o700 => (permissions >> 6) & 0o7,
        0o070 => (permissions >> 3) & 0o7,
        0o007 => permissions & 0o7,
        else => unreachable,
    };
    var copied: u16 = 0;
    if (source & 0o4 != 0) copied |= 0o444;
    if (source & 0o2 != 0) copied |= 0o222;
    if (source & 0o1 != 0) copied |= 0o111;
    return copied;
}

fn symbolicUmaskResult(allocator: std.mem.Allocator, mask: u32) !CommandResult {
    var stdout: std.ArrayList(u8) = .empty;
    errdefer stdout.deinit(allocator);
    const permissions: u32 = (~mask) & 0o777;
    try stdout.appendSlice(allocator, "u=");
    try appendSymbolicPermissions(allocator, &stdout, @intCast((permissions >> 6) & 0o7));
    try stdout.appendSlice(allocator, ",g=");
    try appendSymbolicPermissions(allocator, &stdout, @intCast((permissions >> 3) & 0o7));
    try stdout.appendSlice(allocator, ",o=");
    try appendSymbolicPermissions(allocator, &stdout, @intCast(permissions & 0o7));
    try stdout.append(allocator, '\n');
    return .{ .allocator = allocator, .status = 0, .stdout = try stdout.toOwnedSlice(allocator), .stderr = try allocator.alloc(u8, 0) };
}

fn appendSymbolicPermissions(allocator: std.mem.Allocator, stdout: *std.ArrayList(u8), bits: u3) !void {
    if (bits & 0o4 != 0) try stdout.append(allocator, 'r');
    if (bits & 0o2 != 0) try stdout.append(allocator, 'w');
    if (bits & 0o1 != 0) try stdout.append(allocator, 'x');
}

test "umask octal parser rejects non-octal syntax" {
    try std.testing.expectEqual(@as(?u16, 0o022), parseOctalUmask("022"));
    try std.testing.expectEqual(@as(?u16, 0o7777), parseOctalUmask("7777"));
    try std.testing.expectEqual(@as(?u16, null), parseOctalUmask("0_22"));
    try std.testing.expectEqual(@as(?u16, null), parseOctalUmask("+022"));
    try std.testing.expectEqual(@as(?u16, null), parseOctalUmask("099"));
}

test "umask symbolic parser supports POSIX chmod grammar actions" {
    try std.testing.expectEqual(@as(?u16, 0o033), parseSymbolicUmask("go+r-w", 0o077));
    try std.testing.expectEqual(@as(?u16, 0o333), parseSymbolicUmask("u=g", 0o033));
    try std.testing.expectEqual(@as(?u16, 0o066), parseSymbolicUmask("+X", 0o077));
    try std.testing.expectEqual(@as(?u16, 0o777), parseSymbolicUmask("+X", 0o777));
    try std.testing.expectEqual(@as(?u16, 0o007), parseSymbolicUmask("u+rwx,g=u,o=g", 0o077));
    try std.testing.expectEqual(@as(?u16, null), parseSymbolicUmask("u+z", 0o077));
}

const JobPrintMode = enum { normal, long, pids };

const KillSignalSpec = struct {
    name: []const u8,
    signal: std.posix.SIG,
};

const kill_signal_specs = [_]KillSignalSpec{
    .{ .name = "HUP", .signal = .HUP },
    .{ .name = "INT", .signal = .INT },
    .{ .name = "QUIT", .signal = .QUIT },
    .{ .name = "ILL", .signal = .ILL },
    .{ .name = "TRAP", .signal = .TRAP },
    .{ .name = "ABRT", .signal = .ABRT },
    .{ .name = "BUS", .signal = .BUS },
    .{ .name = "FPE", .signal = .FPE },
    .{ .name = "KILL", .signal = .KILL },
    .{ .name = "USR1", .signal = .USR1 },
    .{ .name = "SEGV", .signal = .SEGV },
    .{ .name = "USR2", .signal = .USR2 },
    .{ .name = "PIPE", .signal = .PIPE },
    .{ .name = "ALRM", .signal = .ALRM },
    .{ .name = "TERM", .signal = .TERM },
    .{ .name = "CHLD", .signal = .CHLD },
    .{ .name = "CONT", .signal = .CONT },
    .{ .name = "STOP", .signal = .STOP },
    .{ .name = "TSTP", .signal = .TSTP },
    .{ .name = "TTIN", .signal = .TTIN },
    .{ .name = "TTOU", .signal = .TTOU },
};

fn builtinKill(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    _ = options;
    var signal: std.posix.SIG = .TERM;
    var index: usize = 1;

    if (index < command.argv.len) {
        const option = command.argv[index].text;
        if (std.mem.eql(u8, option, "--")) {
            index += 1;
        } else if (std.mem.eql(u8, option, "-l")) {
            return builtinKillList(self, command.argv[index + 1 ..]);
        } else if (std.mem.eql(u8, option, "-s")) {
            index += 1;
            if (index >= command.argv.len) return errorResult(self.allocator, 2, "kill", "missing signal");
            signal = parseKillSignal(command.argv[index].text) orelse return invalidKillSignal(self, command.argv[index].text);
            index += 1;
            if (index < command.argv.len and std.mem.eql(u8, command.argv[index].text, "--")) index += 1;
        } else if (option.len > 1 and option[0] == '-') {
            signal = parseKillSignal(option[1..]) orelse return invalidKillSignal(self, option[1..]);
            index += 1;
            if (index < command.argv.len and std.mem.eql(u8, command.argv[index].text, "--")) index += 1;
        }
    }

    if (index >= command.argv.len) return errorResult(self.allocator, 2, "kill", "missing operand");
    self.refreshBackgroundJobs();

    for (command.argv[index..]) |arg| {
        const pid = if (std.mem.startsWith(u8, arg.text, "%")) blk: {
            const job = self.findBackgroundJobBySpec(arg.text) orelse return errorResult(self.allocator, 127, "kill", "unknown job");
            break :blk killPidForJob(job.*);
        } else std.fmt.parseInt(std.posix.pid_t, arg.text, 10) catch return errorResult(self.allocator, 2, "kill", "invalid pid");
        sendKillSignal(pid, signal) catch |err| switch (err) {
            error.ProcessNotFound => return errorResult(self.allocator, 1, "kill", "no such process"),
            error.PermissionDenied => return errorResult(self.allocator, 1, "kill", "permission denied"),
            else => return err,
        };
    }

    return emptyResult(self.allocator, 0);
}

fn builtinKillList(self: *Executor, args: []const ir.WordRef) !CommandResult {
    if (args.len > 1) return errorResult(self.allocator, 2, "kill", "too many arguments");
    var stdout: std.ArrayList(u8) = .empty;
    errdefer stdout.deinit(self.allocator);
    if (args.len == 0) {
        for (kill_signal_specs, 0..) |spec, index| {
            if (index != 0) try stdout.append(self.allocator, ' ');
            try stdout.appendSlice(self.allocator, spec.name);
        }
        try stdout.append(self.allocator, '\n');
    } else {
        const name = killSignalListName(args[0].text) orelse return invalidKillSignal(self, args[0].text);
        try stdout.print(self.allocator, "{s}\n", .{name});
    }
    return .{ .allocator = self.allocator, .status = 0, .stdout = try stdout.toOwnedSlice(self.allocator), .stderr = try self.allocator.alloc(u8, 0) };
}

fn invalidKillSignal(self: *Executor, raw: []const u8) !CommandResult {
    const message = try std.fmt.allocPrint(self.allocator, "{s}: invalid signal", .{raw});
    defer self.allocator.free(message);
    return errorResult(self.allocator, 2, "kill", message);
}

fn parseKillSignal(raw: []const u8) ?std.posix.SIG {
    if (raw.len == 0) return null;
    if (parseKillSignalNumber(raw)) |signal| return signal;
    const name = if (std.ascii.startsWithIgnoreCase(raw, "SIG") and raw.len > 3) raw[3..] else raw;
    for (kill_signal_specs) |spec| {
        if (std.ascii.eqlIgnoreCase(name, spec.name)) return spec.signal;
    }
    return null;
}

fn parseKillSignalNumber(raw: []const u8) ?std.posix.SIG {
    for (raw) |byte| if (!std.ascii.isDigit(byte)) return null;
    const number = std.fmt.parseInt(u8, raw, 10) catch return null;
    if (number == 0) return @enumFromInt(0);
    for (kill_signal_specs) |spec| {
        if (number == signalStatusNumber(spec.signal)) return spec.signal;
    }
    return null;
}

fn killSignalListName(raw: []const u8) ?[]const u8 {
    const status = std.fmt.parseInt(u16, raw, 10) catch return null;
    const number = if (status > 128) status - 128 else status;
    if (number == 0) return "0";
    for (kill_signal_specs) |spec| {
        if (number == signalStatusNumber(spec.signal)) return spec.name;
    }
    return null;
}

fn killPidForJob(job: BackgroundJob) std.posix.pid_t {
    return if (job.pgrp) |pgrp| @intCast(-pgrp) else @intCast(job.pid);
}

fn sendKillSignal(pid: std.posix.pid_t, signal: std.posix.SIG) std.posix.KillError!void {
    return std.posix.kill(pid, signal);
}

fn builtinJobs(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    _ = options;
    self.refreshBackgroundJobs();
    self.refreshJobMarkers();
    var mode: JobPrintMode = .normal;
    var index: usize = 1;
    while (index < command.argv.len) : (index += 1) {
        const arg = command.argv[index].text;
        if (std.mem.eql(u8, arg, "--")) {
            index += 1;
            break;
        }
        if (arg.len == 0 or arg[0] != '-' or std.mem.eql(u8, arg, "-")) break;
        if (std.mem.eql(u8, arg, "-l")) {
            mode = .long;
        } else if (std.mem.eql(u8, arg, "-p")) {
            mode = .pids;
        } else {
            return errorResult(self.allocator, 2, "jobs", "unsupported option");
        }
    }

    var stdout: std.ArrayList(u8) = .empty;
    errdefer stdout.deinit(self.allocator);
    var reported_done_ids: std.ArrayList(usize) = .empty;
    defer reported_done_ids.deinit(self.allocator);
    if (index >= command.argv.len) {
        for (self.background_jobs.items) |job| {
            try appendJobLine(self.allocator, &stdout, job, self.jobMarker(job), mode);
            if (mode != .pids and job.state == .done) try reported_done_ids.append(self.allocator, job.id);
        }
    } else {
        for (command.argv[index..]) |arg| {
            const job = self.findBackgroundJobBySpec(arg.text) orelse return errorResult(self.allocator, 127, "jobs", "unknown job");
            try appendJobLine(self.allocator, &stdout, job.*, self.jobMarker(job.*), mode);
            if (mode != .pids and job.state == .done) try reported_done_ids.append(self.allocator, job.id);
        }
    }
    const stdout_slice = try stdout.toOwnedSlice(self.allocator);
    errdefer self.allocator.free(stdout_slice);
    for (reported_done_ids.items) |id| self.removeBackgroundJobById(id);
    return .{ .allocator = self.allocator, .status = 0, .stdout = stdout_slice, .stderr = try self.allocator.alloc(u8, 0) };
}

fn appendJobLine(allocator: std.mem.Allocator, stdout: *std.ArrayList(u8), job: BackgroundJob, marker: u8, mode: JobPrintMode) !void {
    switch (mode) {
        .pids => try stdout.print(allocator, "{d}\n", .{job.pid}),
        .long => {
            try stdout.print(allocator, "[{d}] {c} {d} ", .{ job.id, marker, job.pid });
            try appendJobState(allocator, stdout, job);
            try stdout.print(allocator, " {s}\n", .{job.command});
        },
        .normal => {
            try stdout.print(allocator, "[{d}] {c} ", .{ job.id, marker });
            try appendJobState(allocator, stdout, job);
            try stdout.print(allocator, " {s}\n", .{job.command});
        },
    }
}

fn appendJobState(allocator: std.mem.Allocator, stdout: *std.ArrayList(u8), job: BackgroundJob) !void {
    switch (job.state) {
        .running => try stdout.appendSlice(allocator, "Running"),
        .stopped => try appendStoppedJobState(allocator, stdout, job.stop_signal),
        .done => {
            if (job.termination_signal) |signal| {
                try stdout.appendSlice(allocator, "Terminated(");
                try appendSignalName(allocator, stdout, signal);
                try stdout.append(allocator, ')');
            } else if (job.status == 0) {
                try stdout.appendSlice(allocator, "Done");
            } else {
                try stdout.print(allocator, "Done({d})", .{job.status});
            }
        },
    }
}

fn appendStoppedJobState(allocator: std.mem.Allocator, stdout: *std.ArrayList(u8), signal: ?u8) !void {
    const sig = signal orelse {
        try stdout.appendSlice(allocator, "Stopped");
        return;
    };
    if (sig == signalStatusNumber(std.posix.SIG.TSTP) or
        sig == signalStatusNumber(std.posix.SIG.STOP) or
        sig == signalStatusNumber(std.posix.SIG.TTIN) or
        sig == signalStatusNumber(std.posix.SIG.TTOU))
    {
        try stdout.appendSlice(allocator, "Stopped (");
        try appendSignalName(allocator, stdout, sig);
        try stdout.append(allocator, ')');
        return;
    }
    try stdout.appendSlice(allocator, "Stopped");
}

fn appendSignalName(allocator: std.mem.Allocator, stdout: *std.ArrayList(u8), signal: u8) !void {
    if (signalName(signal)) |name| {
        try stdout.appendSlice(allocator, name);
    } else {
        try stdout.print(allocator, "signal {d}", .{signal});
    }
}

fn signalName(signal: u8) ?[]const u8 {
    if (signal == signalStatusNumber(std.posix.SIG.HUP)) return "SIGHUP";
    if (signal == signalStatusNumber(std.posix.SIG.INT)) return "SIGINT";
    if (signal == signalStatusNumber(std.posix.SIG.QUIT)) return "SIGQUIT";
    if (signal == signalStatusNumber(std.posix.SIG.ILL)) return "SIGILL";
    if (signal == signalStatusNumber(std.posix.SIG.ABRT)) return "SIGABRT";
    if (signal == signalStatusNumber(std.posix.SIG.FPE)) return "SIGFPE";
    if (signal == signalStatusNumber(std.posix.SIG.KILL)) return "SIGKILL";
    if (signal == signalStatusNumber(std.posix.SIG.SEGV)) return "SIGSEGV";
    if (signal == signalStatusNumber(std.posix.SIG.PIPE)) return "SIGPIPE";
    if (signal == signalStatusNumber(std.posix.SIG.ALRM)) return "SIGALRM";
    if (signal == signalStatusNumber(std.posix.SIG.TERM)) return "SIGTERM";
    if (signal == signalStatusNumber(std.posix.SIG.STOP)) return "SIGSTOP";
    if (signal == signalStatusNumber(std.posix.SIG.TSTP)) return "SIGTSTP";
    if (signal == signalStatusNumber(std.posix.SIG.TTIN)) return "SIGTTIN";
    if (signal == signalStatusNumber(std.posix.SIG.TTOU)) return "SIGTTOU";
    return null;
}

fn builtinBg(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    _ = options;
    if (!self.shell_options.monitor) return errorResult(self.allocator, 1, "bg", "job control disabled");
    self.refreshBackgroundJobs();
    self.refreshJobMarkers();
    var stdout: std.ArrayList(u8) = .empty;
    errdefer stdout.deinit(self.allocator);

    if (command.argv.len == 1) {
        const job = self.currentBackgroundJob() orelse {
            stdout.deinit(self.allocator);
            return errorResult(self.allocator, 1, "bg", "no current job");
        };
        try continueStoppedJob(job);
        self.selectCurrentJob(job.id);
        try stdout.print(self.allocator, "[{d}] {s}\n", .{ job.id, job.command });
    } else {
        for (command.argv[1..]) |arg| {
            const job = self.findBackgroundJobBySpec(arg.text) orelse {
                stdout.deinit(self.allocator);
                return errorResult(self.allocator, 127, "bg", "unknown job");
            };
            try continueStoppedJob(job);
            self.selectCurrentJob(job.id);
            try stdout.print(self.allocator, "[{d}] {s}\n", .{ job.id, job.command });
        }
    }

    return .{ .allocator = self.allocator, .status = 0, .stdout = try stdout.toOwnedSlice(self.allocator), .stderr = try self.allocator.alloc(u8, 0) };
}

fn builtinFg(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    const io = options.io orelse return error.MissingIoForBuiltin;
    if (command.argv.len > 2) return errorResult(self.allocator, 2, "fg", "too many arguments");
    if (!self.shell_options.monitor) return errorResult(self.allocator, 1, "fg", "job control disabled");
    self.refreshBackgroundJobs();
    self.refreshJobMarkers();
    const job = if (command.argv.len == 1)
        self.currentBackgroundJob() orelse return errorResult(self.allocator, 1, "fg", "no current job")
    else
        self.findBackgroundJobBySpec(command.argv[1].text) orelse return errorResult(self.allocator, 127, "fg", "unknown job");
    const job_id = job.id;
    const stdout = try std.fmt.allocPrint(self.allocator, "{s}\n", .{job.command});
    errdefer self.allocator.free(stdout);
    const foreground_terminal = try prepareForegroundTerminal(options.foreground_terminal and options.external_stdio == .inherit and self.shell_options.monitor);
    defer restoreForegroundTerminal(foreground_terminal);
    if (job.pgrp) |pgrp| try giveTerminalToForegroundPgrp(@intCast(pgrp), foreground_terminal);
    try continueStoppedJob(job);
    self.selectCurrentJob(job.id);
    const status = try waitBackgroundJob(io, job, false);
    if (job.state == .done) self.removeBackgroundJobById(job_id);
    return .{ .allocator = self.allocator, .status = status, .stdout = stdout, .stderr = try self.allocator.alloc(u8, 0) };
}

fn builtinWait(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    self.refreshBackgroundJobs();
    const operand_start: usize = if (command.argv.len > 1 and std.mem.eql(u8, command.argv[1].text, "--")) 2 else 1;
    if (operand_start >= command.argv.len and self.background_jobs.items.len == 0) return emptyResult(self.allocator, 0);
    const io = options.io orelse return error.MissingIoForBuiltin;
    if (operand_start >= command.argv.len) {
        for (self.background_jobs.items) |*job| {
            const status = try waitBackgroundJob(io, job, true);
            if (pending_trap_signal.load(.seq_cst) != 0) return emptyResult(self.allocator, status);
        }
        return emptyResult(self.allocator, 0);
    }

    var status: ExitStatus = 0;
    for (command.argv[operand_start..]) |arg| {
        const job = if (std.mem.startsWith(u8, arg.text, "%"))
            self.findBackgroundJobBySpec(arg.text) orelse return errorResult(self.allocator, 127, "wait", "unknown job")
        else blk: {
            const pid = std.fmt.parseInt(i64, arg.text, 10) catch return errorResult(self.allocator, 127, "wait", "invalid pid");
            break :blk self.findBackgroundJob(pid) orelse return errorResult(self.allocator, 127, "wait", "unknown pid");
        };
        status = try waitBackgroundJob(io, job, true);
        if (pending_trap_signal.load(.seq_cst) != 0) return emptyResult(self.allocator, status);
    }
    return emptyResult(self.allocator, status);
}

fn waitBackgroundJob(io: std.Io, job: *BackgroundJob, interruptible_by_traps: bool) !ExitStatus {
    if (job.state != .done) {
        if (interruptible_by_traps) {
            if (try waitBackgroundJobInterruptible(io, job)) |status| return status;
        } else {
            const term = try job.child.wait(io);
            applyBackgroundJobTerm(job, term);
        }
    }
    return job.status;
}

fn waitBackgroundJobInterruptible(io: std.Io, job: *BackgroundJob) !?ExitStatus {
    const pid = job.child.id orelse return null;
    if (zig_builtin.link_libc) {
        while (true) {
            var status: c_int = 0;
            const rc = std.c.waitpid(pid, &status, 0);
            switch (std.c.errno(rc)) {
                .SUCCESS => {
                    applyBackgroundJobWaitStatus(job, @bitCast(status));
                    cleanupWaitedChild(io, &job.child);
                    return null;
                },
                .INTR => if (pendingTrapSignalStatus()) |trap_status| return trap_status else continue,
                .CHILD => return error.ProcessNotFound,
                else => return error.Unexpected,
            }
        }
    }
    if (zig_builtin.os.tag == .linux) {
        while (true) {
            var status: u32 = 0;
            const rc = std.os.linux.waitpid(pid, &status, 0);
            switch (std.os.linux.errno(rc)) {
                .SUCCESS => {
                    applyBackgroundJobWaitStatus(job, status);
                    cleanupWaitedChild(io, &job.child);
                    return null;
                },
                .INTR => if (pendingTrapSignalStatus()) |trap_status| return trap_status else continue,
                .CHILD => return error.ProcessNotFound,
                else => return error.Unexpected,
            }
        }
    }
    return error.Unsupported;
}

fn pendingTrapSignalStatus() ?ExitStatus {
    const raw = pending_trap_signal.load(.seq_cst);
    if (raw == 0) return null;
    return 128 + raw;
}

fn applyBackgroundJobTerm(job: *BackgroundJob, term: std.process.Child.Term) void {
    job.status = exitStatusFromTerm(term);
    job.stop_signal = null;
    job.termination_signal = null;
    job.state = switch (term) {
        .stopped => |signal| blk: {
            job.stop_signal = signalStatusNumber(signal);
            break :blk .stopped;
        },
        .signal => |signal| blk: {
            job.termination_signal = signalStatusNumber(signal);
            break :blk .done;
        },
        else => .done,
    };
    if (job.state == .stopped) saveJobTerminalModes(job);
}

fn applyBackgroundJobWaitStatus(job: *BackgroundJob, wait_status: u32) void {
    job.status = exitStatusFromWaitStatus(wait_status);
    job.stop_signal = null;
    job.termination_signal = null;
    if (std.posix.W.IFSTOPPED(wait_status)) {
        job.state = .stopped;
        job.stop_signal = signalStatusNumber(std.posix.W.STOPSIG(wait_status));
        saveJobTerminalModes(job);
        return;
    }
    job.state = .done;
    if (std.posix.W.IFSIGNALED(wait_status)) job.termination_signal = signalStatusNumber(std.posix.W.TERMSIG(wait_status));
}

fn cleanupWaitedChild(io: std.Io, child: *std.process.Child) void {
    if (child.stdin) |file| {
        var owned = file;
        owned.close(io);
        child.stdin = null;
    }
    if (child.stdout) |file| {
        var owned = file;
        owned.close(io);
        child.stdout = null;
    }
    if (child.stderr) |file| {
        var owned = file;
        owned.close(io);
        child.stderr = null;
    }
    child.id = null;
}

fn continueStoppedJob(job: *BackgroundJob) !void {
    if (job.state != .stopped) return;
    restoreJobTerminalModes(job);
    const pid: std.posix.pid_t = if (job.pgrp) |pgrp| @intCast(-pgrp) else @intCast(job.pid);
    try std.posix.kill(pid, .CONT);
    job.state = .running;
    job.stop_signal = null;
    job.notified_state = null;
}

fn saveJobTerminalModes(job: *BackgroundJob) void {
    var termios: std.posix.termios = undefined;
    job.saved_termios = if (std.c.tcgetattr(std.Io.File.stdin().handle, &termios) == 0) termios else null;
}

fn restoreJobTerminalModes(job: *BackgroundJob) void {
    const termios = job.saved_termios orelse return;
    std.posix.tcsetattr(std.Io.File.stdin().handle, .FLUSH, termios) catch {};
}

fn builtinTimes(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    _ = options;
    if (command.argv.len != 1) return timesUsageError(self, "too many arguments");
    const usage = readResourceUsage();
    const self_user = try formatCpuTime(self.allocator, usage.self_user);
    defer self.allocator.free(self_user);
    const self_system = try formatCpuTime(self.allocator, usage.self_system);
    defer self.allocator.free(self_system);
    const children_user = try formatCpuTime(self.allocator, usage.children_user);
    defer self.allocator.free(children_user);
    const children_system = try formatCpuTime(self.allocator, usage.children_system);
    defer self.allocator.free(children_system);
    const stdout = try std.fmt.allocPrint(self.allocator, "{s} {s}\n{s} {s}\n", .{ self_user, self_system, children_user, children_system });
    errdefer self.allocator.free(stdout);
    return .{ .allocator = self.allocator, .status = 0, .stdout = stdout, .stderr = try self.allocator.alloc(u8, 0) };
}

fn timesUsageError(self: *Executor, message: []const u8) !CommandResult {
    setSpecialBuiltinErrorConsequence(self, 2);
    return errorResult(self.allocator, 2, "times", message);
}

const CpuUsage = struct {
    self_user: u64 = 0,
    self_system: u64 = 0,
    children_user: u64 = 0,
    children_system: u64 = 0,
};

fn readResourceUsage() CpuUsage {
    if (!zig_builtin.link_libc) return .{};
    var self_usage: std.c.rusage = undefined;
    var child_usage: std.c.rusage = undefined;
    const self_ok = std.c.getrusage(std.c.rusage.SELF, &self_usage) == 0;
    const child_ok = std.c.getrusage(std.c.rusage.CHILDREN, &child_usage) == 0;
    return .{
        .self_user = if (self_ok) timevalCentiseconds(self_usage.utime) else 0,
        .self_system = if (self_ok) timevalCentiseconds(self_usage.stime) else 0,
        .children_user = if (child_ok) timevalCentiseconds(child_usage.utime) else 0,
        .children_system = if (child_ok) timevalCentiseconds(child_usage.stime) else 0,
    };
}

fn timevalCentiseconds(value: std.c.timeval) u64 {
    const seconds: u64 = @intCast(if (value.sec < 0) 0 else value.sec);
    const micros: u64 = @intCast(if (value.usec < 0) 0 else value.usec);
    return seconds * 100 + micros / 10_000;
}

fn formatCpuTime(allocator: std.mem.Allocator, centiseconds: u64) ![]u8 {
    const minutes = centiseconds / 6000;
    const seconds = (centiseconds / 100) % 60;
    const hundredths = centiseconds % 100;
    return std.fmt.allocPrint(allocator, "{d}m{d}.{d:0>2}s", .{ minutes, seconds, hundredths });
}

test "times helpers format POSIX CPU time fields" {
    const zero = try formatCpuTime(std.testing.allocator, 0);
    defer std.testing.allocator.free(zero);
    try std.testing.expectEqualStrings("0m0.00s", zero);

    const centisecond = try formatCpuTime(std.testing.allocator, 1);
    defer std.testing.allocator.free(centisecond);
    try std.testing.expectEqualStrings("0m0.01s", centisecond);

    const minute_rollover = try formatCpuTime(std.testing.allocator, 6101);
    defer std.testing.allocator.free(minute_rollover);
    try std.testing.expectEqualStrings("1m1.01s", minute_rollover);

    try std.testing.expectEqual(@as(u64, 0), timevalCentiseconds(.{ .sec = 0, .usec = 9999 }));
    try std.testing.expectEqual(@as(u64, 1), timevalCentiseconds(.{ .sec = 0, .usec = 10_000 }));
    try std.testing.expectEqual(@as(u64, 123), timevalCentiseconds(.{ .sec = 1, .usec = 230_000 }));
    try expectTimesOutputShape("0m0.00s 1m2.03s\n4m5.06s 7m8.09s\n");
}

fn builtinReturn(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    _ = options;
    if (self.function_depth == 0 and self.source_depth == 0) return returnUsageError(self, "not in a function or dot script");
    if (command.argv.len > 2) return returnUsageError(self, "too many arguments");
    const status: ExitStatus = if (command.argv.len == 2) blk: {
        const parsed = std.fmt.parseInt(u8, command.argv[1].text, 10) catch return returnUsageError(self, "numeric argument required");
        break :blk parsed;
    } else self.lastStatus();
    self.pending_return = status;
    return emptyResult(self.allocator, status);
}

fn returnUsageError(self: *Executor, message: []const u8) !CommandResult {
    setSpecialBuiltinErrorConsequence(self, 2);
    return errorResult(self.allocator, 2, "return", message);
}

fn builtinSet(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;

    if (command.argv.len == 1) return printShellVariables(self);

    var index: usize = 1;
    var set_positionals = false;
    while (index < command.argv.len) {
        const arg = command.argv[index].text;
        if (std.mem.eql(u8, arg, "--")) {
            index += 1;
            set_positionals = true;
            break;
        }
        if (std.mem.eql(u8, arg, "-")) {
            self.shell_options.xtrace = false;
            self.shell_options.verbose = false;
            index += 1;
            set_positionals = index < command.argv.len;
            break;
        }
        if (std.mem.eql(u8, arg, "+")) {
            index += 1;
            set_positionals = index < command.argv.len;
            break;
        }
        if (std.mem.eql(u8, arg, "-o") or std.mem.eql(u8, arg, "+o")) {
            if (index + 1 == command.argv.len) return printShellOptions(self, arg[0] == '+');
            const enabled = arg[0] == '-';
            index += 1;
            if (!applyShellOptionName(&self.shell_options, command.argv[index].text, enabled)) return setUsageError(self, "unknown option name");
            if (options.interactive) self.shell_options.noexec = false;
            index += 1;
            continue;
        }
        if (arg.len >= 2 and (arg[0] == '-' or arg[0] == '+')) {
            if (!applyShellOptionShort(&self.shell_options, arg)) return setUsageError(self, "unsupported arguments");
            if (options.interactive) self.shell_options.noexec = false;
            index += 1;
            continue;
        }

        set_positionals = true;
        break;
    }

    if (set_positionals) try setCurrentPositionals(self, command.argv[index..]);
    return emptyResult(self.allocator, 0);
}

fn setUsageError(self: *Executor, message: []const u8) !CommandResult {
    setSpecialBuiltinErrorConsequence(self, 2);
    return errorResult(self.allocator, 2, "set", message);
}

fn setCurrentPositionals(self: *Executor, args: []const ir.WordRef) !void {
    var values = try self.allocator.alloc([]const u8, args.len);
    defer self.allocator.free(values);
    for (args, 0..) |arg, index| values[index] = arg.text;
    try self.currentPositionalsPtr().set(self.allocator, values);
}

fn printShellVariables(self: *Executor) !CommandResult {
    var names: std.ArrayList([]const u8) = .empty;
    defer names.deinit(self.allocator);
    var iter = self.env.iterator();
    while (iter.next()) |entry| try names.append(self.allocator, entry.key_ptr.*);
    std.mem.sort([]const u8, names.items, {}, lessThanString);

    var stdout: std.ArrayList(u8) = .empty;
    errdefer stdout.deinit(self.allocator);
    for (names.items) |name| {
        try stdout.appendSlice(self.allocator, name);
        try stdout.append(self.allocator, '=');
        try appendShellSingleQuoted(self.allocator, &stdout, self.env.get(name).?);
        try stdout.append(self.allocator, '\n');
    }
    const stdout_slice = try stdout.toOwnedSlice(self.allocator);
    errdefer self.allocator.free(stdout_slice);
    return .{ .allocator = self.allocator, .status = 0, .stdout = stdout_slice, .stderr = try self.allocator.alloc(u8, 0) };
}

fn printShellOptions(self: *Executor, reusable: bool) !CommandResult {
    const stdout = if (reusable)
        try std.fmt.allocPrint(self.allocator, "set {s}o allexport\nset {s}o emacs\nset {s}o errexit\nset {s}o ignoreeof\nset {s}o monitor\nset {s}o noclobber\nset {s}o noexec\nset {s}o noglob\nset {s}o notify\nset {s}o nounset\nset {s}o pipefail\nset {s}o vi\nset {s}o verbose\nset {s}o xtrace\n", .{ if (self.shell_options.allexport) "-" else "+", if (self.shell_options.emacs) "-" else "+", if (self.shell_options.errexit) "-" else "+", if (self.shell_options.ignoreeof) "-" else "+", if (self.shell_options.monitor) "-" else "+", if (self.shell_options.noclobber) "-" else "+", if (self.shell_options.noexec) "-" else "+", if (self.shell_options.noglob) "-" else "+", if (self.shell_options.notify) "-" else "+", if (self.shell_options.nounset) "-" else "+", if (self.shell_options.pipefail) "-" else "+", if (self.shell_options.vi) "-" else "+", if (self.shell_options.verbose) "-" else "+", if (self.shell_options.xtrace) "-" else "+" })
    else
        try std.fmt.allocPrint(self.allocator, "allexport\t{s}\nemacs\t{s}\nerrexit\t{s}\nignoreeof\t{s}\nmonitor\t{s}\nnoclobber\t{s}\nnoexec\t{s}\nnoglob\t{s}\nnotify\t{s}\nnounset\t{s}\npipefail\t{s}\nvi\t{s}\nverbose\t{s}\nxtrace\t{s}\n", .{ if (self.shell_options.allexport) "on" else "off", if (self.shell_options.emacs) "on" else "off", if (self.shell_options.errexit) "on" else "off", if (self.shell_options.ignoreeof) "on" else "off", if (self.shell_options.monitor) "on" else "off", if (self.shell_options.noclobber) "on" else "off", if (self.shell_options.noexec) "on" else "off", if (self.shell_options.noglob) "on" else "off", if (self.shell_options.notify) "on" else "off", if (self.shell_options.nounset) "on" else "off", if (self.shell_options.pipefail) "on" else "off", if (self.shell_options.vi) "on" else "off", if (self.shell_options.verbose) "on" else "off", if (self.shell_options.xtrace) "on" else "off" });
    errdefer self.allocator.free(stdout);
    return .{
        .allocator = self.allocator,
        .status = 0,
        .stdout = stdout,
        .stderr = try self.allocator.alloc(u8, 0),
    };
}

fn builtinEnv(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    var child = Executor.init(self.allocator);
    defer child.deinit();
    try child.copyStateFrom(self);

    var index: usize = 1;
    while (index < command.argv.len) {
        const option = command.argv[index].text;
        if (std.mem.eql(u8, option, "-i")) {
            child.clearEnvironment();
            index += 1;
            continue;
        }
        if (std.mem.eql(u8, option, "--")) {
            index += 1;
            break;
        }
        if (std.mem.startsWith(u8, option, "-") and !std.mem.eql(u8, option, "-")) return errorResult(self.allocator, 2, "env", "unsupported option");
        break;
    }

    while (index < command.argv.len) {
        const assignment = envAssignment(command.argv[index].text) orelse break;
        try child.setEnv(assignment.name, assignment.value);
        try child.setExported(assignment.name);
        index += 1;
    }

    if (index >= command.argv.len) {
        var process_env = try child.buildProcessEnv(&.{});
        defer process_env.deinit();
        return printProcessEnvironment(self.allocator, &process_env);
    }

    const nested: ir.SimpleCommand = .{
        .span = command.span,
        .assignments = &.{},
        .argv = command.argv[index..],
        .redirections = &.{},
    };
    const saved_umask = readShellUmask();
    defer restoreShellUmask(saved_umask);
    return child.executeSimpleCommandWithInput(nested, stdin, options);
}

fn printEnvironment(allocator: std.mem.Allocator, env: std.StringHashMapUnmanaged([]const u8)) !CommandResult {
    var names: std.ArrayList([]const u8) = .empty;
    defer names.deinit(allocator);
    var iter = env.iterator();
    while (iter.next()) |entry| try names.append(allocator, entry.key_ptr.*);
    std.mem.sort([]const u8, names.items, {}, lessThanString);

    var stdout: std.ArrayList(u8) = .empty;
    errdefer stdout.deinit(allocator);
    for (names.items) |name| {
        try stdout.appendSlice(allocator, name);
        try stdout.append(allocator, '=');
        try stdout.appendSlice(allocator, env.get(name).?);
        try stdout.append(allocator, '\n');
    }

    return .{
        .allocator = allocator,
        .status = 0,
        .stdout = try stdout.toOwnedSlice(allocator),
        .stderr = try allocator.alloc(u8, 0),
    };
}

fn printProcessEnvironment(allocator: std.mem.Allocator, env: *const std.process.Environ.Map) !CommandResult {
    var names: std.ArrayList([]const u8) = .empty;
    defer names.deinit(allocator);
    for (env.keys()) |name| try names.append(allocator, name);
    std.mem.sort([]const u8, names.items, {}, lessThanString);

    var stdout: std.ArrayList(u8) = .empty;
    errdefer stdout.deinit(allocator);
    for (names.items) |name| {
        try stdout.appendSlice(allocator, name);
        try stdout.append(allocator, '=');
        try stdout.appendSlice(allocator, env.get(name).?);
        try stdout.append(allocator, '\n');
    }

    return .{
        .allocator = allocator,
        .status = 0,
        .stdout = try stdout.toOwnedSlice(allocator),
        .stderr = try allocator.alloc(u8, 0),
    };
}

const EnvAssignment = struct {
    name: []const u8,
    value: []const u8,
};

fn envAssignment(text: []const u8) ?EnvAssignment {
    const equals = std.mem.indexOfScalar(u8, text, '=') orelse return null;
    if (equals == 0) return null;
    return .{ .name = text[0..equals], .value = text[equals + 1 ..] };
}

const IndexedArrayAssignment = struct {
    name: []const u8,
    index: usize,
    value: []const u8,
};

const IndexedArrayAssignmentSyntax = struct {
    name: []const u8,
    index_text: []const u8,
    value: []const u8,
};

fn indexedArrayAssignmentSyntax(text: []const u8) ?IndexedArrayAssignmentSyntax {
    if (text.len == 0 or !isShellNameStart(text[0])) return null;

    var name_end: usize = 1;
    while (name_end < text.len and isShellNameContinue(text[name_end])) : (name_end += 1) {}
    if (name_end >= text.len or text[name_end] != '[') return null;

    const index_start = name_end + 1;
    const close_offset = std.mem.findScalar(u8, text[index_start..], ']') orelse return null;
    const close_index = index_start + close_offset;
    if (close_index + 1 >= text.len or text[close_index + 1] != '=') return null;
    const index_text = text[index_start..close_index];
    if (index_text.len == 0) return null;
    return .{ .name = text[0..name_end], .index_text = index_text, .value = text[close_index + 2 ..] };
}

fn isShellNameStart(byte: u8) bool {
    return std.ascii.isAlphabetic(byte) or byte == '_';
}

fn isShellNameContinue(byte: u8) bool {
    return isShellNameStart(byte) or std.ascii.isDigit(byte);
}

fn builtinTest(self: *Executor, command: ir.SimpleCommand, stdin: []const u8, options: ExecuteOptions) !CommandResult {
    _ = stdin;
    const is_bracket = std.mem.eql(u8, command.argv[0].text, "[");
    const args = command.argv[1..];
    if (is_bracket) {
        if (args.len == 0 or !std.mem.eql(u8, args[args.len - 1].text, "]")) {
            return errorResult(self.allocator, 2, "[", "missing ]");
        }
        const matched = evalTest(self.allocator, options, args[0 .. args.len - 1]) catch return errorResult(self.allocator, 2, command.argv[0].text, "invalid expression");
        return emptyResult(self.allocator, if (matched) 0 else 1);
    }
    const matched = evalTest(self.allocator, options, args) catch return errorResult(self.allocator, 2, command.argv[0].text, "invalid expression");
    return emptyResult(self.allocator, if (matched) 0 else 1);
}

fn evalBashTest(allocator: std.mem.Allocator, options: ExecuteOptions, args: []const ir.WordRef) !bool {
    return switch (args.len) {
        0 => false,
        1 => args[0].text.len != 0,
        2 => try evalUnaryTest(allocator, options, args[0].text, args[1].text),
        3 => if (std.mem.eql(u8, args[0].text, "!"))
            !(try evalBashTest(allocator, options, args[1..]))
        else if (std.mem.eql(u8, args[1].text, "==") or std.mem.eql(u8, args[1].text, "="))
            shellPatternMatches(args[2].text, args[0].text)
        else if (std.mem.eql(u8, args[1].text, "!="))
            !shellPatternMatches(args[2].text, args[0].text)
        else
            try evalBinaryTest(allocator, options, args[0].text, args[1].text, args[2].text),
        4 => if (std.mem.eql(u8, args[0].text, "!")) !(try evalBashTest(allocator, options, args[1..])) else error.InvalidTestExpression,
        else => error.InvalidTestExpression,
    };
}

fn evalTest(allocator: std.mem.Allocator, options: ExecuteOptions, args: []const ir.WordRef) !bool {
    if (args.len == 3 and isBinaryTestOperator(args[1].text)) {
        return evalBinaryTest(allocator, options, args[0].text, args[1].text, args[2].text);
    }
    if (hasTestExpressionOperator(args)) {
        var test_parser: TestExpressionParser = .{ .allocator = allocator, .options = options, .args = args };
        const result = try test_parser.parseOr();
        if (test_parser.index != args.len) return error.InvalidTestExpression;
        return result;
    }
    return evalSimpleTest(allocator, options, args);
}

fn evalSimpleTest(allocator: std.mem.Allocator, options: ExecuteOptions, args: []const ir.WordRef) !bool {
    return switch (args.len) {
        0 => false,
        1 => args[0].text.len != 0,
        2 => try evalUnaryTest(allocator, options, args[0].text, args[1].text),
        3 => if (isBinaryTestOperator(args[1].text))
            try evalBinaryTest(allocator, options, args[0].text, args[1].text, args[2].text)
        else if (std.mem.eql(u8, args[0].text, "!"))
            !(try evalSimpleTest(allocator, options, args[1..]))
        else
            error.InvalidTestExpression,
        4 => if (std.mem.eql(u8, args[0].text, "!")) !(try evalSimpleTest(allocator, options, args[1..])) else error.InvalidTestExpression,
        else => error.InvalidTestExpression,
    };
}

fn hasTestExpressionOperator(args: []const ir.WordRef) bool {
    for (args) |arg| {
        if (std.mem.eql(u8, arg.text, "-a") or std.mem.eql(u8, arg.text, "-o") or std.mem.eql(u8, arg.text, "(") or std.mem.eql(u8, arg.text, ")")) return true;
    }
    return false;
}

const TestExpressionError = error{InvalidTestExpression};

const TestExpressionParser = struct {
    allocator: std.mem.Allocator,
    options: ExecuteOptions,
    args: []const ir.WordRef,
    index: usize = 0,

    fn parseOr(self: *TestExpressionParser) TestExpressionError!bool {
        var result = try self.parseAnd();
        while (self.match("-o")) {
            const rhs = try self.parseAnd();
            result = result or rhs;
        }
        return result;
    }

    fn parseAnd(self: *TestExpressionParser) TestExpressionError!bool {
        var result = try self.parseNot();
        while (self.match("-a")) {
            const rhs = try self.parseNot();
            result = result and rhs;
        }
        return result;
    }

    fn parseNot(self: *TestExpressionParser) TestExpressionError!bool {
        if (self.match("!")) return !(try self.parseNot());
        return self.parsePrimary();
    }

    fn parsePrimary(self: *TestExpressionParser) TestExpressionError!bool {
        if (self.index >= self.args.len) return error.InvalidTestExpression;
        if (self.match("(")) {
            const result = try self.parseOr();
            if (!self.match(")")) return error.InvalidTestExpression;
            return result;
        }
        if (self.index + 2 < self.args.len and isBinaryTestOperator(self.args[self.index + 1].text)) {
            const left = self.args[self.index].text;
            const op = self.args[self.index + 1].text;
            const right = self.args[self.index + 2].text;
            self.index += 3;
            return evalBinaryTest(self.allocator, self.options, left, op, right);
        }
        if (self.index + 1 < self.args.len and isUnaryTestOperator(self.args[self.index].text)) {
            const op = self.args[self.index].text;
            const operand = self.args[self.index + 1].text;
            self.index += 2;
            return evalUnaryTest(self.allocator, self.options, op, operand);
        }
        const value = self.args[self.index].text.len != 0;
        self.index += 1;
        return value;
    }

    fn match(self: *TestExpressionParser, text: []const u8) bool {
        if (self.index >= self.args.len or !std.mem.eql(u8, self.args[self.index].text, text)) return false;
        self.index += 1;
        return true;
    }
};

fn isUnaryTestOperator(op: []const u8) bool {
    return std.mem.eql(u8, op, "!") or std.mem.eql(u8, op, "-n") or std.mem.eql(u8, op, "-z") or
        std.mem.eql(u8, op, "-e") or std.mem.eql(u8, op, "-f") or std.mem.eql(u8, op, "-d") or std.mem.eql(u8, op, "-s") or
        std.mem.eql(u8, op, "-b") or std.mem.eql(u8, op, "-c") or std.mem.eql(u8, op, "-p") or std.mem.eql(u8, op, "-S") or
        std.mem.eql(u8, op, "-L") or std.mem.eql(u8, op, "-h") or std.mem.eql(u8, op, "-u") or std.mem.eql(u8, op, "-g") or
        std.mem.eql(u8, op, "-k") or std.mem.eql(u8, op, "-r") or std.mem.eql(u8, op, "-w") or std.mem.eql(u8, op, "-x") or
        std.mem.eql(u8, op, "-t");
}

fn isBinaryTestOperator(op: []const u8) bool {
    return std.mem.eql(u8, op, "=") or std.mem.eql(u8, op, "==") or std.mem.eql(u8, op, "!=") or
        std.mem.eql(u8, op, "<") or std.mem.eql(u8, op, ">") or std.mem.eql(u8, op, "-eq") or std.mem.eql(u8, op, "-ne") or
        std.mem.eql(u8, op, "-gt") or std.mem.eql(u8, op, "-ge") or std.mem.eql(u8, op, "-lt") or std.mem.eql(u8, op, "-le") or
        std.mem.eql(u8, op, "-ef") or std.mem.eql(u8, op, "-nt") or std.mem.eql(u8, op, "-ot");
}

fn evalUnaryTest(allocator: std.mem.Allocator, options: ExecuteOptions, op: []const u8, operand: []const u8) !bool {
    if (std.mem.eql(u8, op, "!")) return operand.len == 0;
    if (std.mem.eql(u8, op, "-n")) return operand.len != 0;
    if (std.mem.eql(u8, op, "-z")) return operand.len == 0;
    if (std.mem.eql(u8, op, "-e") or std.mem.eql(u8, op, "-f") or std.mem.eql(u8, op, "-d") or std.mem.eql(u8, op, "-s") or std.mem.eql(u8, op, "-b") or std.mem.eql(u8, op, "-c") or std.mem.eql(u8, op, "-p") or std.mem.eql(u8, op, "-S")) {
        const io = options.io orelse return false;
        const stat = statPath(allocator, io, operand) catch return false;
        if (std.mem.eql(u8, op, "-e")) return true;
        if (std.mem.eql(u8, op, "-f")) return stat.kind == .file;
        if (std.mem.eql(u8, op, "-d")) return stat.kind == .directory;
        if (std.mem.eql(u8, op, "-s")) return stat.size > 0;
        if (std.mem.eql(u8, op, "-b")) return stat.kind == .block_device;
        if (std.mem.eql(u8, op, "-c")) return stat.kind == .character_device;
        if (std.mem.eql(u8, op, "-p")) return stat.kind == .named_pipe;
        if (std.mem.eql(u8, op, "-S")) return stat.kind == .unix_domain_socket;
    }
    if (std.mem.eql(u8, op, "-L") or std.mem.eql(u8, op, "-h")) {
        const io = options.io orelse return false;
        const stat = statPathNoFollow(allocator, io, operand) catch return false;
        return stat.kind == .sym_link;
    }
    if (std.mem.eql(u8, op, "-u") or std.mem.eql(u8, op, "-g") or std.mem.eql(u8, op, "-k")) {
        const io = options.io orelse return false;
        const stat = statPathNoFollow(allocator, io, operand) catch return false;
        const mode = stat.permissions.toMode();
        if (std.mem.eql(u8, op, "-u")) return mode & 0o4000 != 0;
        if (std.mem.eql(u8, op, "-g")) return mode & 0o2000 != 0;
        if (std.mem.eql(u8, op, "-k")) return mode & 0o1000 != 0;
    }
    if (std.mem.eql(u8, op, "-r") or std.mem.eql(u8, op, "-w") or std.mem.eql(u8, op, "-x")) {
        const io = options.io orelse return false;
        std.Io.Dir.cwd().access(io, operand, .{
            .read = std.mem.eql(u8, op, "-r"),
            .write = std.mem.eql(u8, op, "-w"),
            .execute = std.mem.eql(u8, op, "-x"),
        }) catch return false;
        return true;
    }
    if (std.mem.eql(u8, op, "-t")) {
        const fd = std.fmt.parseInt(std.c.fd_t, operand, 10) catch return error.InvalidTestExpression;
        return std.c.isatty(fd) == 1;
    }
    return error.InvalidTestExpression;
}

fn evalBinaryTest(allocator: std.mem.Allocator, options: ExecuteOptions, left: []const u8, op: []const u8, right: []const u8) !bool {
    if (std.mem.eql(u8, op, "=") or std.mem.eql(u8, op, "==")) return std.mem.eql(u8, left, right);
    if (std.mem.eql(u8, op, "!=")) return !std.mem.eql(u8, left, right);
    if (std.mem.eql(u8, op, "<")) return std.mem.lessThan(u8, left, right);
    if (std.mem.eql(u8, op, ">")) return std.mem.lessThan(u8, right, left);

    if (std.mem.eql(u8, op, "-ef") or std.mem.eql(u8, op, "-nt") or std.mem.eql(u8, op, "-ot")) {
        return evalFileComparisonTest(allocator, options, left, op, right);
    }

    const lhs = std.fmt.parseInt(i64, left, 10) catch return error.InvalidTestExpression;
    const rhs = std.fmt.parseInt(i64, right, 10) catch return error.InvalidTestExpression;
    if (std.mem.eql(u8, op, "-eq")) return lhs == rhs;
    if (std.mem.eql(u8, op, "-ne")) return lhs != rhs;
    if (std.mem.eql(u8, op, "-gt")) return lhs > rhs;
    if (std.mem.eql(u8, op, "-ge")) return lhs >= rhs;
    if (std.mem.eql(u8, op, "-lt")) return lhs < rhs;
    if (std.mem.eql(u8, op, "-le")) return lhs <= rhs;
    return error.InvalidTestExpression;
}

fn evalFileComparisonTest(allocator: std.mem.Allocator, options: ExecuteOptions, left: []const u8, op: []const u8, right: []const u8) bool {
    const io = options.io orelse return false;
    const left_stat: ?std.Io.File.Stat = statPath(allocator, io, left) catch null;
    const right_stat: ?std.Io.File.Stat = statPath(allocator, io, right) catch null;

    if (std.mem.eql(u8, op, "-ef")) {
        const lhs = left_stat orelse return false;
        const rhs = right_stat orelse return false;
        if (lhs.inode != rhs.inode) return false;
        return sameExistingFile(allocator, left, right) orelse true;
    }
    if (std.mem.eql(u8, op, "-nt")) {
        const lhs = left_stat orelse return false;
        const rhs = right_stat orelse return true;
        return lhs.mtime.nanoseconds > rhs.mtime.nanoseconds;
    }
    if (std.mem.eql(u8, op, "-ot")) {
        const rhs = right_stat orelse return false;
        const lhs = left_stat orelse return true;
        return lhs.mtime.nanoseconds < rhs.mtime.nanoseconds;
    }
    unreachable;
}

const FileIdentity = struct {
    device: u64,
    inode: u64,
};

fn sameExistingFile(allocator: std.mem.Allocator, left: []const u8, right: []const u8) ?bool {
    const lhs = fileIdentity(allocator, left) orelse return null;
    const rhs = fileIdentity(allocator, right) orelse return null;
    return lhs.device == rhs.device and lhs.inode == rhs.inode;
}

fn fileIdentity(allocator: std.mem.Allocator, path: []const u8) ?FileIdentity {
    const path_z = allocator.dupeSentinel(u8, path, 0) catch return null;
    defer allocator.free(path_z);

    if (comptime zig_builtin.os.tag == .linux) {
        var statx_result: std.os.linux.Statx = undefined;
        if (std.c.statx(std.c.AT.FDCWD, path_z.ptr, 0, std.os.linux.STATX.BASIC_STATS, &statx_result) != 0) return null;
        return .{
            .device = (@as(u64, statx_result.dev_major) << 32) | statx_result.dev_minor,
            .inode = statx_result.ino,
        };
    }

    var stat_result: std.c.Stat = undefined;
    if (std.c.fstatat(std.c.AT.FDCWD, path_z.ptr, &stat_result, 0) != 0) return null;
    return .{
        .device = @intCast(stat_result.dev),
        .inode = @intCast(stat_result.ino),
    };
}

fn statPath(allocator: std.mem.Allocator, io: std.Io, path: []const u8) !std.Io.File.Stat {
    _ = allocator;
    return std.Io.Dir.cwd().statFile(io, path, .{});
}

fn statPathNoFollow(allocator: std.mem.Allocator, io: std.Io, path: []const u8) !std.Io.File.Stat {
    _ = allocator;
    return std.Io.Dir.cwd().statFile(io, path, .{ .follow_symlinks = false });
}

fn joinParams(allocator: std.mem.Allocator, params: []const []const u8) ![]const u8 {
    var joined: std.ArrayList(u8) = .empty;
    errdefer joined.deinit(allocator);
    for (params, 0..) |param, index| {
        if (index > 0) try joined.append(allocator, ' ');
        try joined.appendSlice(allocator, param);
    }
    return joined.toOwnedSlice(allocator);
}

fn lessThanString(_: void, a: []const u8, b: []const u8) bool {
    return std.mem.lessThan(u8, a, b);
}

fn isRedirectionOnlyExec(command: ir.SimpleCommand) bool {
    return command.argv.len == 1 and std.mem.eql(u8, command.argv[0].text, "exec") and command.redirections.len != 0;
}

fn targetName(redirection: ir.Redirection) []const u8 {
    return if (redirection.target) |target| target.text else "redirection";
}

fn noclobberTargetName(command: ir.SimpleCommand) []const u8 {
    for (command.redirections) |redirection| {
        if (redirection.operator == .greater) return targetName(redirection);
    }
    return "redirection";
}

fn badFdTargetName(command: ir.SimpleCommand) []const u8 {
    for (command.redirections) |redirection| {
        if (redirection.operator == .greater_and or redirection.operator == .less_and) return targetName(redirection);
    }
    return "redirection";
}

fn redirectionTargetName(command: ir.SimpleCommand) []const u8 {
    for (command.redirections) |redirection| {
        if (redirection.target != null) return targetName(redirection);
    }
    return "redirection";
}

fn inputTargetName(command: ir.SimpleCommand) []const u8 {
    for (command.redirections) |redirection| {
        if (isStdinFileRedirection(redirection)) return targetName(redirection);
    }
    return "redirection";
}

fn isHereDocRedirection(redirection: ir.Redirection) bool {
    const fd = redirectionFd(redirection) orelse 0;
    return fd == 0 and (redirection.operator == .dless or redirection.operator == .dless_dash);
}

fn isInputFdRedirection(redirection: ir.Redirection) bool {
    return switch (redirection.operator) {
        .less, .less_great, .dless, .dless_dash, .less_and => true,
        else => false,
    };
}

fn externalStdioCapturesStdout(stdio: ExternalStdio) bool {
    return stdio == .capture or stdio == .capture_stdout;
}

fn externalStdioCapturesStderr(stdio: ExternalStdio) bool {
    return stdio == .capture;
}

fn externalStdinUsesScriptInput(stdio: ExternalStdio) bool {
    return stdio == .capture or stdio == .capture_stdout or stdio == .inherit_output;
}

fn externalStdioInheritsStdin(stdio: ExternalStdio) bool {
    return stdio == .inherit;
}

fn commandDuplicatesStderrToStdout(redirections: []const ir.Redirection) bool {
    var stderr_to_stdout = false;
    for (redirections) |redirection| {
        if (isFileOutputRedirection(redirection)) {
            const fd = redirectionFd(redirection) orelse 1;
            if (fd == 2) stderr_to_stdout = false;
            continue;
        }
        if (redirection.operator != .greater_and) continue;
        const from_fd = redirectionFd(redirection) orelse 1;
        if (from_fd != 2) continue;
        const target = redirection.target orelse continue;
        stderr_to_stdout = std.mem.eql(u8, target.text, "1");
    }
    return stderr_to_stdout;
}

fn isStdinFileRedirection(redirection: ir.Redirection) bool {
    const fd = redirectionFd(redirection) orelse 0;
    return fd == 0 and (redirection.operator == .less or redirection.operator == .less_great);
}

fn redirectionOpensFd(redirection: ir.Redirection) ?std.posix.fd_t {
    return switch (redirection.operator) {
        .less, .less_great, .dless, .dless_dash => redirectionFd(redirection) orelse 0,
        .greater, .dgreat, .clobber => redirectionFd(redirection) orelse 1,
        else => null,
    };
}

fn isFileOutputRedirection(redirection: ir.Redirection) bool {
    return switch (redirection.operator) {
        .greater, .dgreat, .clobber => true,
        else => false,
    };
}

fn redirectionFd(redirection: ir.Redirection) ?std.posix.fd_t {
    if (redirection.io_number) |io_number| return parseFd(io_number.text);
    return null;
}

fn parseFd(text: []const u8) ?std.posix.fd_t {
    if (text.len == 0) return null;
    for (text) |byte| if (!std.ascii.isDigit(byte)) return null;
    const value = std.fmt.parseInt(std.posix.fd_t, text, 10) catch return null;
    if (value < 0) return null;
    return value;
}

fn emptyResult(allocator: std.mem.Allocator, status: ExitStatus) !CommandResult {
    return .{
        .allocator = allocator,
        .status = status,
        .stdout = try allocator.alloc(u8, 0),
        .stderr = try allocator.alloc(u8, 0),
    };
}

fn errorResult(allocator: std.mem.Allocator, status: ExitStatus, command: []const u8, message: []const u8) !CommandResult {
    const stderr = try std.fmt.allocPrint(allocator, "{s}: {s}\n", .{ command, message });
    errdefer allocator.free(stderr);
    return .{
        .allocator = allocator,
        .status = status,
        .stdout = try allocator.alloc(u8, 0),
        .stderr = stderr,
    };
}

const CasePattern = struct {
    text: []const u8,
    special: []const bool,

    fn deinit(self: *CasePattern, allocator: std.mem.Allocator) void {
        allocator.free(self.text);
        allocator.free(self.special);
        self.* = undefined;
    }
};

fn appendCasePatternPart(allocator: std.mem.Allocator, text: *std.ArrayList(u8), special: *std.ArrayList(bool), rendered: []const u8, meta_active: bool) !void {
    try text.appendSlice(allocator, rendered);
    for (rendered) |_| {
        try special.append(allocator, meta_active);
    }
}

fn shellPatternMatches(pattern: []const u8, text: []const u8) bool {
    return shellPatternMatchesFrom(pattern, null, text, 0, 0);
}

fn shellCasePatternMatches(pattern: CasePattern, text: []const u8) bool {
    std.debug.assert(pattern.text.len == pattern.special.len);
    return shellPatternMatchesFrom(pattern.text, pattern.special, text, 0, 0);
}

fn isSpecialPatternByte(special: ?[]const bool, index: usize) bool {
    return if (special) |mask| mask[index] else true;
}

fn shellPatternMatchesFrom(pattern: []const u8, special: ?[]const bool, text: []const u8, pattern_index: usize, text_index: usize) bool {
    if (pattern_index == pattern.len) return text_index == text.len;
    if (pattern[pattern_index] == '*' and isSpecialPatternByte(special, pattern_index)) {
        var next_text = text_index;
        while (next_text <= text.len) : (next_text += 1) {
            if (shellPatternMatchesFrom(pattern, special, text, pattern_index + 1, next_text)) return true;
        }
        return false;
    }
    if (text_index >= text.len) return false;
    if (pattern[pattern_index] == '[' and isSpecialPatternByte(special, pattern_index)) {
        if (matchShellBracket(pattern, special, pattern_index, text[text_index])) |matched| {
            return matched.ok and shellPatternMatchesFrom(pattern, special, text, matched.next_pattern, text_index + 1);
        }
    }
    if ((pattern[pattern_index] == '?' and isSpecialPatternByte(special, pattern_index)) or pattern[pattern_index] == text[text_index]) {
        return shellPatternMatchesFrom(pattern, special, text, pattern_index + 1, text_index + 1);
    }
    return false;
}

const ShellBracketMatch = struct { ok: bool, next_pattern: usize };

fn matchShellBracket(pattern: []const u8, special: ?[]const bool, pattern_index: usize, text: u8) ?ShellBracketMatch {
    var index = pattern_index + 1;
    if (index >= pattern.len) return null;
    const negated = pattern[index] == '!' or pattern[index] == '^';
    if (negated) index += 1;

    var matched = false;
    var first_expression = true;
    while (index < pattern.len) : (index += 1) {
        if (pattern[index] == ']' and !first_expression and isSpecialPatternByte(special, index)) {
            return .{ .ok = if (negated) !matched else matched, .next_pattern = index + 1 };
        }
        first_expression = false;

        if (matchShellBracketCharacterClass(pattern, special, index, text)) |class| {
            if (class.ok) matched = true;
            index = class.end_index;
            continue;
        }

        if (index + 2 < pattern.len and pattern[index + 1] == '-' and isSpecialPatternByte(special, index + 1) and pattern[index + 2] != ']') {
            const start = pattern[index];
            const end = pattern[index + 2];
            if (start <= text and text <= end) matched = true;
            index += 2;
            continue;
        }

        if (pattern[index] == text) matched = true;
    }

    return null;
}

const ShellBracketCharacterClassMatch = struct { ok: bool, end_index: usize };

fn matchShellBracketCharacterClass(pattern: []const u8, special: ?[]const bool, index: usize, text: u8) ?ShellBracketCharacterClassMatch {
    if (index + 3 >= pattern.len or pattern[index] != '[' or pattern[index + 1] != ':') return null;

    const name_start = index + 2;
    var name_end = name_start;
    while (name_end + 1 < pattern.len) : (name_end += 1) {
        if (pattern[name_end] == ':' and pattern[name_end + 1] == ']') {
            if (!shellPatternBytesAreSpecial(special, index, name_end + 2)) return null;
            const class_name = pattern[name_start..name_end];
            const ok = shellCharacterClassMatches(class_name, text) orelse return null;
            return .{ .ok = ok, .end_index = name_end + 1 };
        }
    }
    return null;
}

fn shellPatternBytesAreSpecial(special: ?[]const bool, start: usize, end: usize) bool {
    var index = start;
    while (index < end) : (index += 1) {
        if (!isSpecialPatternByte(special, index)) return false;
    }
    return true;
}

fn shellCharacterClassMatches(class_name: []const u8, text: u8) ?bool {
    if (std.mem.eql(u8, class_name, "alnum")) return std.ascii.isAlphanumeric(text);
    if (std.mem.eql(u8, class_name, "alpha")) return std.ascii.isAlphabetic(text);
    if (std.mem.eql(u8, class_name, "blank")) return text == ' ' or text == '\t';
    if (std.mem.eql(u8, class_name, "cntrl")) return std.ascii.isControl(text);
    if (std.mem.eql(u8, class_name, "digit")) return std.ascii.isDigit(text);
    if (std.mem.eql(u8, class_name, "graph")) return std.ascii.isGraphical(text);
    if (std.mem.eql(u8, class_name, "lower")) return std.ascii.isLower(text);
    if (std.mem.eql(u8, class_name, "print")) return std.ascii.isPrint(text);
    if (std.mem.eql(u8, class_name, "punct")) return std.ascii.isPunctuation(text);
    if (std.mem.eql(u8, class_name, "space")) return std.ascii.isWhitespace(text);
    if (std.mem.eql(u8, class_name, "upper")) return std.ascii.isUpper(text);
    if (std.mem.eql(u8, class_name, "xdigit")) return std.ascii.isHex(text);
    return null;
}

fn exitStatusFromTerm(term: std.process.Child.Term) ExitStatus {
    return switch (term) {
        .exited => |code| code,
        .signal => |sig| 128 + @as(u8, @intCast(@intFromEnum(sig))),
        .stopped => |sig| 128 + @as(u8, @intCast(@intFromEnum(sig))),
        .unknown => 1,
    };
}

fn exitStatusFromWaitStatus(status: u32) ExitStatus {
    if (std.posix.W.IFEXITED(status)) return std.posix.W.EXITSTATUS(status);
    if (std.posix.W.IFSIGNALED(status)) return 128 + signalStatusNumber(std.posix.W.TERMSIG(status));
    if (std.posix.W.IFSTOPPED(status)) return 128 + signalStatusNumber(std.posix.W.STOPSIG(status));
    return 1;
}

fn signalStatusNumber(signal: anytype) u8 {
    return switch (@typeInfo(@TypeOf(signal))) {
        .@"enum" => @intCast(@intFromEnum(signal)),
        else => @intCast(signal),
    };
}

const LoweredForTest = struct { parsed: parser.ParseResult, program: ir.Program };

fn expectTimesOutputShape(output: []const u8) !void {
    var lines = std.mem.splitScalar(u8, output, '\n');
    const first = lines.next() orelse return error.MissingTimesLine;
    const second = lines.next() orelse return error.MissingTimesLine;
    const third = lines.next() orelse return error.MissingTimesLine;
    try std.testing.expectEqualStrings("", third);
    try std.testing.expect(lines.next() == null);
    try expectTimesLineShape(first);
    try expectTimesLineShape(second);
}

fn expectTimesLineShape(line: []const u8) !void {
    var fields = std.mem.splitScalar(u8, line, ' ');
    const user = fields.next() orelse return error.MissingTimesField;
    const system = fields.next() orelse return error.MissingTimesField;
    try std.testing.expect(fields.next() == null);
    try expectCpuTimeFieldShape(user);
    try expectCpuTimeFieldShape(system);
}

fn expectCpuTimeFieldShape(field: []const u8) !void {
    const m_index = std.mem.findScalar(u8, field, 'm') orelse return error.InvalidCpuTimeField;
    const dot_index = std.mem.findScalarPos(u8, field, m_index + 1, '.') orelse return error.InvalidCpuTimeField;
    const s_index = std.mem.findScalarPos(u8, field, dot_index + 1, 's') orelse return error.InvalidCpuTimeField;
    if (s_index + 1 != field.len) return error.InvalidCpuTimeField;
    if (dot_index + 3 != s_index) return error.InvalidCpuTimeField;
    try expectDigits(field[0..m_index]);
    try expectDigits(field[m_index + 1 .. dot_index]);
    try expectDigits(field[dot_index + 1 .. s_index]);
}

fn expectDigits(bytes: []const u8) !void {
    if (bytes.len == 0) return error.ExpectedDigits;
    for (bytes) |byte| {
        if (!std.ascii.isDigit(byte)) return error.ExpectedDigits;
    }
}

fn parseAndLower(allocator: std.mem.Allocator, source: []const u8) !LoweredForTest {
    return parseAndLowerWithOptions(allocator, source, .{});
}

fn parseAndLowerWithOptions(allocator: std.mem.Allocator, source: []const u8, options: parser.ParseOptions) !LoweredForTest {
    var parsed = try parser.parse(allocator, source, options);
    errdefer parsed.deinit();
    var program = try ir.lowerSimpleCommands(allocator, parsed);
    errdefer program.deinit();
    return .{ .parsed = parsed, .program = program };
}

test "executor uses quote-removed argv text" {
    var lowered = try parseAndLower(std.testing.allocator, "echo 'hello world'");
    defer lowered.parsed.deinit();
    defer lowered.program.deinit();

    var executor = Executor.init(std.testing.allocator);
    defer executor.deinit();

    var result = try executor.executeProgram(lowered.program, .{});
    defer result.deinit();
    try std.testing.expectEqualStrings("hello world\n", result.stdout);
}

test "executor preserves quoted empty argv operands" {
    var lowered = try parseAndLower(std.testing.allocator, "printf ''; echo status=$?");
    defer lowered.parsed.deinit();
    defer lowered.program.deinit();

    var executor = Executor.init(std.testing.allocator);
    defer executor.deinit();

    var result = try executor.executeProgram(lowered.program, .{});
    defer result.deinit();
    try std.testing.expectEqual(@as(ExitStatus, 0), result.status);
    try std.testing.expectEqualStrings("status=0\n", result.stdout);
    try std.testing.expectEqualStrings("", result.stderr);
}

test "executor runs true false and echo builtins" {
    var lowered = try parseAndLower(std.testing.allocator, "true");
    defer lowered.parsed.deinit();
    defer lowered.program.deinit();

    var executor = Executor.init(std.testing.allocator);
    defer executor.deinit();

    var result = try executor.executeProgram(lowered.program, .{});
    defer result.deinit();
    try std.testing.expectEqual(@as(ExitStatus, 0), result.status);

    var lowered_false = try parseAndLower(std.testing.allocator, "false");
    defer lowered_false.parsed.deinit();
    defer lowered_false.program.deinit();
    var false_result = try executor.executeProgram(lowered_false.program, .{});
    defer false_result.deinit();
    try std.testing.expectEqual(@as(ExitStatus, 1), false_result.status);

    var lowered_echo = try parseAndLower(std.testing.allocator, "echo hello world");
    defer lowered_echo.parsed.deinit();
    defer lowered_echo.program.deinit();
    var echo_result = try executor.executeProgram(lowered_echo.program, .{});
    defer echo_result.deinit();
    try std.testing.expectEqual(@as(ExitStatus, 0), echo_result.status);
    try std.testing.expectEqualStrings("hello world\n", echo_result.stdout);
}

test "executor executes Bash conditional command baseline" {
    var pattern = try parseAndLowerWithOptions(std.testing.allocator, "[[ foobar == foo* ]]", .{ .features = compat.Features.bash() });
    defer pattern.parsed.deinit();
    defer pattern.program.deinit();

    var executor = Executor.init(std.testing.allocator);
    defer executor.deinit();

